with new_qas(youtube_id, doctor_slug, question, answer, meta, keywords) as (
  values
    ('YRaF1DQ4QUA', 'jeonghanmi', '보톡스 한 번 맞으면 평생 맞아야 한다는데 진짜인가요?', '아닙니다, 보톡스는 원할 때 맞고 언제든 중단할 수 있는 시술입니다. 보톡스 효과는 3~5개월 지속되다가 자연스럽게 사라지는데, 주름이 다시 생기면 본인이 그 모습을 견디기 어려워서 스스로 다시 맞게 되는 거예요. 새치 염색과 비슷하다고 생각하시면 됩니다. 염색해서 젊어진 모습이 좋으니까 새치가 다시 나면 또 하게 되는 것처럼요. 중독성이 있어서가 아니라 결과가 마음에 들기 때문에 반복하게 되는 개인의 선택이죠. 의학적으로 보톡스를 끊었을 때 부작용이 생기거나 이전보다 더 나빠지는 일은 없습니다. 맞기 전 상태로 돌아갈 뿐이에요. 그래서 부담 없이 시작하시고, 만족스러우면 유지하시면 됩니다.', '보톡스는 중독성이 아니라 결과가 마음에 들어서 반복하게 되는 시술입니다. 중단해도 원래 상태로 돌아갈 뿐 부작용은 없다는 점을 피부과 전문의 정한미가 설명합니다.', array['보톡스', '주름', '유지기간', '반복시술', '미간주름', '이마주름']::text[]),
    ('YRaF1DQ4QUA', 'jeonghanmi', '50대인데 이미 깊어진 주름에 보톡스 맞아도 효과 있나요?', '이미 깊이 고정된 주름은 보톡스만으로 완전히 펴지지 않지만, 그래도 맞는 것을 추천합니다. 보톡스를 맞지 않으면 주름이 계속 더 깊어지기 때문에 지금이라도 시작해서 악화를 예방하는 게 중요해요. 주름이 너무 깊지 않은 상태에서 1~2년 꾸준히 맞아주면 고정된 주름도 약간 펴지는 효과를 볼 수 있습니다. 다만 보톡스로 개선이 안 되는 매우 깊은 주름은 필러나 쥬베룩 같은 골진 주름을 채워주는 시술을 병행해야 해요. 순서로 보면 보톡스로 근육 움직임을 줄여 주름을 잡고, 그다음에 채움 시술로 골을 메우는 겁니다. 늦었다고 포기하지 마시고 지금부터라도 시작하시면 더 깊어지는 것을 막을 수 있습니다.', '50대 깊은 주름도 보톡스로 악화를 막을 수 있습니다. 1~2년 꾸준히 맞으면 고정 주름도 개선되며, 필러·쥬베룩 병행 전략을 피부과 전문의 정한미가 안내합니다.', array['보톡스', '미간주름', '이마주름', '필러', '쥬베룩', '주름예방', '안티에이징']::text[]),
    ('YRaF1DQ4QUA', 'jeonghanmi', '주름 보톡스랑 스킨 보톡스는 뭐가 다른 건가요?', '이름은 비슷하지만 목적과 원리가 완전히 다른 시술입니다. 주름 보톡스는 근육층에 작용해서 미간 찡그림, 눈 웃음, 이마 올림처럼 움직일 때 생기는 주름을 펴주는 시술이에요. 해당 근육이 덜 움직이거나 못 움직이게 해서 주름이 접히는 걸 방지하는 원리입니다. 반면 스킨 보톡스는 피부 아주 얕은 층에 보톡스를 묽게 희석해서 넓게 깔아주는 방식이에요. 피부결이 맨질맨질해지고 모공이 줄어들며, 유분기가 많은 분은 피지 조절 효과도 볼 수 있습니다. 전반적으로 피부에 광이 나고 반질반질해 보이는 게 목표죠. 정리하면 주름을 펴고 싶으면 주름 보톡스, 피부결을 좋게 만들고 싶으면 스킨 보톡스를 선택하시면 됩니다.', '주름 보톡스는 근육층에, 스킨 보톡스는 피부 얕은 층에 작용해 목적이 다릅니다. 주름 개선 vs 피부결·모공 개선 효과 차이를 피부과 전문의 정한미가 정리합니다.', array['보톡스', '스킨보톡스', '주름보톡스', '모공', '피지조절', '피부결']::text[]),
    ('YRaF1DQ4QUA', 'jeonghanmi', '사각턱 보톡스 맞고 볼이 패였는데 원래대로 돌아오나요?', '네, 시간이 지나면 자연스럽게 원래대로 돌아옵니다. 사각턱 보톡스는 교근이라는 턱 근육을 줄여서 갸름하게 만드는 시술인데, 근육이 너무 많이 줄어들면 마치 텐트 폴대가 가라앉은 것처럼 위의 피부가 함께 처지면서 볼이 패여 보이는 현상이 생길 수 있어요. 보톡스 효과가 사라지고 근육이 다시 돌아오면 패임도 회복되기 때문에 영구적인 부작용은 아닙니다. 다만 퀭해 보이는 동안 스트레스를 많이 받으실 수 있어요. 이런 경험이 있으셨다면 다음 시술 때 반드시 의사에게 미리 말씀하시는 게 중요합니다. 용량이나 주입 부위를 조절해서 같은 부작용을 예방할 수 있거든요.', '사각턱 보톡스 후 볼이 패여 보일 수 있지만 근육이 돌아오면 자연 회복됩니다. 교근 축소에 따른 볼 패임 원인과 예방법을 피부과 전문의 정한미가 안내합니다.', array['사각턱', '보톡스', '볼패임', '교근', '부작용', '리프팅']::text[]),
    ('HNGSScdAWfw', 'kimsoohyung', '망한 문신 레이저로 진짜 지울 수 있나요?', '네, 레이저로 충분히 지울 수 있습니다. 눈썹 문신은 보통 3~5회, 일반 문신은 8~10회 정도 시술이 필요해요. 원리는 피부 속 큰 잉크 덩어리를 레이저로 작은 조각으로 부수면, 혈액 속 면역세포가 그 조각을 잡아서 몸 밖으로 배출하는 방식입니다. 다만 레이저를 쏘면 색소가 열을 받아 터지면서 기포가 생기는데, 이 기포가 우산처럼 아래 문신을 가려서 한 번에 하나씩밖에 못 쏘는 한계가 있었어요. 그래서 예전에는 3~4주 간격으로 여러 번 병원에 방문해야 했습니다. 통증이 상당해서 마취 연고와 주사 마취를 병행하지만, 치료 기간이 길어 중간에 포기하시는 분도 많았죠. 하지만 최근에는 방문 횟수를 크게 줄이는 방법들이 나왔습니다.', '망한 문신을 레이저로 제거하는 원리와 필요한 횟수를 피부과 전문의 김수형이 설명합니다.', array['문신제거', '레이저', '눈썹문신', '피코레이저', '색소제거', '통증']::text[]),
    ('HNGSScdAWfw', 'kimsoohyung', '문신 제거 레이저를 한 번에 여러 번 쏘는 R0 테크닉이 뭔가요?', 'R0 테크닉은 PFD라는 특수 약물을 이용해 한 번 방문에 레이저를 3~4회 연달아 쏠 수 있게 해주는 방법입니다. 레이저를 쏘면 백화현상이라고 하는 하얀 기포층이 생기는데, PFD를 바르면 마치 기름 위에 비눗물을 떨어뜨리듯 이 기포를 빠르게 녹여버려요. 그러면 레이저가 다시 아래 문신에 도달할 수 있어서 바로 추가 시술이 가능해지는 겁니다. 예전에는 10번 병원을 방문해야 했다면 R0 테크닉으로는 3~4번이면 치료가 됩니다. 실제 비교 사진을 보면 같은 문신에 레이저를 한 번 쏜 것보다 4번 연달아 쏜 쪽이 3개월 뒤 훨씬 많이 지워져 있어요. 조직검사에서도 흉터나 부작용 없이 잉크만 더 잘 부서진 것이 확인되었습니다.', '문신 제거 치료 기간을 단축하는 R0 테크닉의 원리를 피부과 전문의 김수형이 설명합니다.', array['문신제거', 'R0테크닉', 'PFD', '백화현상', '레이저', '시술횟수']::text[]),
    ('HNGSScdAWfw', 'kimsoohyung', '디스크라이브 패치를 쓰면 문신이 더 빨리 지워지나요?', '네, 디스크라이브 패치를 사용하면 문신 제거 속도가 확실히 빨라집니다. 이 패치는 R0 테크닉에서 쓰는 PFD 약물을 실리콘 패치 안에 가둬 만든 건데, PFD가 휘발성이 강해 쉽게 날아가는 문제를 해결한 형태예요. 패치가 피부를 보호하는 역할도 해서 기존보다 1.5~1.8배 강한 에너지의 레이저를 안전하게 쏠 수 있다고 합니다. 논문 결과에서도 패치를 사용한 쪽이 사용하지 않은 쪽보다 문신이 훨씬 많이 지워진 것으로 나타났어요. 현재 미국에서 주로 사용되고 있으며 R0 테크닉과 원리는 비슷하되 약물 증발을 막고 피부 보호까지 더해진 업그레이드 버전이라고 보시면 됩니다. 피부색이 밝고 색소량이 적은 문신에 특히 적합해요.', '디스크라이브 패치로 문신 제거가 빨라지는 원리를 피부과 전문의 김수형이 안내합니다.', array['문신제거', '디스크라이브패치', 'PFD', 'R0테크닉', '레이저', '색소제거']::text[]),
    ('HNGSScdAWfw', 'kimsoohyung', 'R0 테크닉이랑 프렉타트 중 어떤 게 더 효과적인가요?', '둘 다 장단점이 있어서 문신 상태에 따라 적합한 방법이 다릅니다. R0 테크닉은 회복이 빠르고 자극이 덜해서 눈썹처럼 예민한 부위나 피부가 민감한 분, 피부색이 밝고 색소가 적은 문신에 좋아요. 프렉타트는 프랙셔널 레이저로 미세 구멍을 격자 모양으로 뚫어 빨대 역할을 하게 만든 뒤 제거 레이저를 쏘는 방식인데, 색소가 진하거나 피부색이 어둡거나 여러 번 덮어서 한 문신에 효과적입니다. 프렉셔널 레이저가 만드는 미세 상처가 오히려 피부 재생을 촉진해서 붓기도 3일 더 빨리 아물고 총 시술 횟수도 30% 감소했다는 논문 결과가 있어요. 다만 시술 후 약간의 회복 기간이 필요하죠. 가장 중요한 건 피부 상태와 문신 깊이를 보고 전문의와 상담해서 결정하는 것입니다.', 'R0 테크닉과 프렉타트의 차이점과 적합한 문신 유형을 피부과 전문의 김수형이 정리합니다.', array['문신제거', '프렉타트', 'R0테크닉', '프랙셔널레이저', '색소제거', '피부재생']::text[]),
    ('ilsThC5yjmA', 'jeonghanmi', '토너부터 크림까지 다 바르기 귀찮은데 하나만 바르면 안 되나요?', '됩니다, 핵심 성분이 들어있는 올인원 제품 하나만 제대로 골라 바르면 충분합니다. 중요한 건 내 피부에 필요한 성분이 들어있는지를 확인하는 거예요. 건성이면서 안티에이징이 필요한 분은 보습 성분과 펩타이드가 들어간 제품, 지성이면서 모공 고민이 있는 분은 피지 조절과 모공 케어 성분이 든 제품을 고르시면 됩니다. 화장품 고를 때 첫 번째로 내가 원하는 효과의 핵심 성분이 들어있는지, 두 번째로 내 피부 타입에 맞는 제형인지 이 두 가지만 체크하세요. 한 가지 제품으로 여러 효과를 경험해 본 후 미백에 더 집중하고 싶다거나 안티에이징에 포커스를 맞추고 싶으면 그때 전문 제품을 추가하시면 됩니다. 처음부터 여러 개 다 바를 필요 없어요.', '여러 단계 스킨케어 대신 올인원 제품을 고르는 핵심 기준을 피부과 전문의 정한미가 안내합니다.', array['올인원', '스킨케어', '기초화장품', '펩타이드', '보습', '지성피부', '건성피부']::text[]),
    ('ilsThC5yjmA', 'jeonghanmi', '레티놀이랑 비타민C 둘 다 든 제품이 진짜 효과 있나요?', '네, 레티놀과 비타민C가 동시에 들어간 제품은 주름과 미백을 한 번에 케어할 수 있어 효율적입니다. 레티놀은 피부 노화를 막아주고 이미 생긴 노화도 어느 정도 되돌려줄 수 있는 성분이고, 비타민C는 미백과 항산화 효과가 있어요. 예를 들어 스트라이벡틴 멀티액션 슈퍼C 레티놀 세럼은 레티놀 0.095%(거의 0.1%)에 순수비타민C와 비타민C 유도체가 같이 들어있고, 알부틴과 나이아신아마이드 같은 미백 성분도 포함되어 있습니다. 칙칙한 피부톤이 밝아졌으면 하면서 동시에 노화 방지와 탄력, 주름 케어까지 원하는 분에게 적합해요. 다만 향료가 있어서 향에 민감한 분은 주의가 필요하고, 바른 후 로션이나 크림으로 보습을 마무리해 주시면 됩니다.', '레티놀과 비타민C 복합 제품의 실제 효과와 추천 대상을 피부과 전문의 정한미가 설명합니다.', array['레티놀', '비타민C', '미백', '안티에이징', '나이아신아마이드', '알부틴', '주름']::text[]),
    ('ilsThC5yjmA', 'jeonghanmi', '레티놀 처음 써보는데 어떤 농도부터 시작해야 하나요?', '레티놀 입문자라면 0.015% 정도의 낮은 농도부터 시작하시는 게 안전합니다. 이 농도는 피부가 레티놀에 잘 적응할 수 있는 수준이고, 레티놀 성분에 예민해서 높은 농도를 못 바르는 분들에게도 적합해요. 프리메라 유스래디언스 비타티놀 세럼이 대표적인데, 레티놀 외에 비타민C 유도체 두 가지와 알부틴, 나이아신아마이드 같은 미백 성분이 들어있습니다. 특히 히알루론산, 판테놀, 마데카소사이드처럼 보습과 피부 진정 성분도 포함돼 있어서 발라보면 세럼보다 촉촉한 로션 느낌이 나요. 20대 후반에서 30대에 피부 탄력이나 미백에 신경 쓰기 시작하는 분, 혹은 민감한 피부인데 기능성 제품을 써보고 싶은 분에게 추천합니다. 충분히 적응된 후 농도를 올리시면 됩니다.', '레티놀 입문자에게 적합한 농도와 제품 선택 기준을 피부과 전문의 정한미가 정리합니다.', array['레티놀', '입문', '민감성피부', '비타민C', '판테놀', '마데카소사이드', '안티에이징']::text[]),
    ('ilsThC5yjmA', 'jeonghanmi', '지성 피부인데 모공이랑 피부결 동시에 좋아지는 제품 있나요?', '네, PHA와 AHA 산 성분이 들어간 제품이 각질 정리와 피부결 개선에 효과적입니다. 엑스비앙스 레디언스 세럼이 대표적인데, 이 브랜드가 PHA나 AHA 같은 산 성분에서 굉장히 전통 있는 곳이에요. 피부 각질이 메마르고 들뜨면 지저분하고 건조해 보이는데, 산 성분이 각질에 수분을 줘서 피부를 플럼핑시키고 불필요한 각질은 적절히 탈락되게 정리해 줍니다. 그러면 피부가 부드럽고 매끄러우면서 광이 나게 되죠. 민감성 피부도 자극 없이 순하게 각질 케어를 할 수 있고, 각질 케어와 보습을 동시에 원하는 분에게도 적합합니다. 바르면 피부결이 반질반질해지고 피부에 광이 나길 원하시는 분이라면 한번 시도해 보세요.', '지성 피부의 모공과 피부결을 동시에 개선하는 산 성분 제품을 피부과 전문의 정한미가 추천합니다.', array['PHA', 'AHA', '각질케어', '모공', '피부결', '지성피부', '민감성피부']::text[]),
    ('iZUrjz7HnNs', 'jeonghanmi', '노스카나 겔 바르는데 왜 여드름 흉터가 안 없어지는 거예요?', '노스카나 겔이 효과 없는 이유는 패인 흉터에는 겉에 바르는 것으로 해결이 안 되기 때문입니다. 여드름 흉터라고 부르는 것에는 세 가지가 있어요. 붉은 자국, 갈색 색소침착, 그리고 실제로 패인 흉터입니다. 노스카나 겔은 붉은 자국이나 색소침착에는 어느 정도 도움이 될 수 있지만 패인 흉터에는 효과가 없어요. 비유하자면 하얀 천에 커피를 쏟은 건 세탁하면 지워지지만, 천 자체가 찢어진 건 아무리 빨아도 소용없는 것과 같습니다. 핸드폰 플래시를 켜고 거울 앞에서 빛을 얼굴에 수직 90도로 비춰보세요. 피부가 움푹 패여 보이면 진짜 흉터이고, 색깔만 달라 보이면 자국이에요. 이 구분이 치료 방법을 결정하는 핵심입니다.', '노스카나 겔이 여드름 흉터에 효과 없는 이유와 자가진단법을 피부과 전문의 정한미가 설명합니다.', array['여드름흉터', '노스카나겔', '색소침착', '패인흉터', '홈케어', '자가진단']::text[]),
    ('iZUrjz7HnNs', 'jeonghanmi', '여드름 뒤에 남은 붉은 자국 빨리 없애려면 뭘 발라야 하나요?', '아젤라익산(아젤리아 크림)과 트라넥삼산 제품을 함께 쓰면 붉은 자국 개선에 효과적입니다. 붉은 자국은 여드름 염증으로 혈관이 늘어나서 빨갛게 남은 건데, 아젤라익산은 항염 작용과 피부 재생 촉진 효과가 있어요. 약국에서 처방전 없이 살 수 있는 일반의약품이라 접근성도 좋습니다. 트라넥삼산이 들어간 제품도 여드름 붉은 자국에 효과가 있다는 논문 보고가 있는데, 코스드바하 TN 세럼처럼 트라넥삼산과 나이아신아마이드가 같이 든 제품을 바르면 붉은기와 색소침착에 동시에 도움이 돼요. 아젤리아 크림은 빛에 민감하니 밤에, TN 세럼은 아침저녁 모두 바르시면 됩니다. 어떤 좋은 제품을 발라도 외출 시 자외선 차단제를 안 바르면 색소침착이 다시 생기니 선크림이 가장 중요합니다.', '여드름 후 붉은 자국을 없애는 효과적인 성분과 제품을 피부과 전문의 정한미가 안내합니다.', array['여드름자국', '붉은자국', '아젤라익산', '트라넥삼산', '나이아신아마이드', '선크림']::text[]),
    ('iZUrjz7HnNs', 'jeonghanmi', '여드름 색소침착이 까맣게 남았는데 비타민C만 바르면 되나요?', '비타민C도 효과적이지만, 트라넥삼산과 나이아신아마이드가 함께 든 제품을 병행하면 미백 효과를 극대화할 수 있습니다. 갈색 자국은 여드름 염증 때문에 멜라닌 색소가 과도하게 만들어진 것인데, 넘버즈인 5번 글루타치온C 흔적 앰플에는 나이아신아마이드 5%와 트라넥삼산 4%에 알파-알부틴, 비타민C 유도체까지 들어있어 멜라닌 생성을 억제해 줍니다. 폴라초이스 클리니컬 디스컬러레이션 리페어 세럼도 트라넥삼산, 나이아신아마이드에 바쿠치올까지 포함돼 색소침착 개선과 피부재생을 동시에 해줘요. 레티놀이나 레티날 제품을 이미 갖고 있다면 그것만 꾸준히 발라도 됩니다. 레티노이드는 붉은 자국, 색소침착, 패인 흉터 개선에 모두 효과가 있다고 알려져 있거든요. 핵심은 한두 번이 아니라 최소 한 달 이상 꾸준히 쓰는 것입니다.', '여드름 후 갈색 색소침착을 개선하는 미백 성분과 제품을 피부과 전문의 정한미가 정리합니다.', array['색소침착', '비타민C', '트라넥삼산', '나이아신아마이드', '알부틴', '바쿠치올', '레티놀']::text[]),
    ('iZUrjz7HnNs', 'jeonghanmi', '패인 여드름 흉터는 홈케어로 절대 안 채워지나요?', '네, 패인 흉터는 피부 속 구조가 실제로 망가진 것이라 겉에 뭘 아무리 좋은 걸 발라도 채워지지 않습니다. 천이 찢어진 것처럼 피부 내부가 파괴돼 없어진 거기 때문에 크림이나 에센스로는 해결이 안 되고, 병원에서 전문 치료를 받아야 해요. 그리고 반드시 알아두셔야 할 것이 있는데, 처음에 붉은 자국만 보이더라도 시간이 지나면서 패인 부위가 나타날 수 있습니다. 핸드폰 플래시로 종종 확인해 보시고 패여있는 게 보이면 병원에 빨리 가세요. 패인 흉터는 오래될수록 치료가 어렵고, 생긴 지 얼마 안 됐을 때 치료하면 반응이 빠르고 효과가 좋습니다. 붉은 자국이 남아있는 시기에 방심하지 말고 변화를 주의 깊게 관찰하시는 게 핵심이에요.', '패인 여드름 흉터가 홈케어로 안 되는 이유와 조기 치료의 중요성을 피부과 전문의 정한미가 설명합니다.', array['여드름흉터', '패인흉터', '프락셀', '흉터치료', '피부재생', '조기치료']::text[]),
    ('V-jTztD01M8', 'kimjongsik', '레디어스 맞았는데 효과가 1도 없는 이유가 뭔가요?', '레디어스 효과를 못 느끼는 데는 크게 세 가지 이유가 있습니다. 첫째, 시간이 필요해요. 필러처럼 넣자마자 볼륨이 올라오는 시술이 아니라 피부가 천천히 자라나면서 탄력이 생기는 방식이라, 하루 운동했다고 근육이 안 생기듯 충분한 시간을 줘야 합니다. 둘째, 시술하는 의사의 테크닉이 천차만별이에요. 희석 방법, 넣는 위치, 한 방울씩 살살 깔아주는 기술에 따라 결과가 완전히 달라집니다. 칼슘하이드록시아파타이트 성분이 한쪽에 몰려 들어가면 좋은 효과를 낼 수 없거든요. 셋째, 레디어스가 필요 없는 상태인데 다른 시술 대신 받았을 수 있어요. 레디어스는 피부가 차오르고 탄탄해지는 시술이지 볼륨을 만드는 시술이 아니라서, 볼륨이 필요하면 필러나 쥬베룩 볼륨, 스컬트라가 더 적합합니다.', '레디어스 시술 후 효과를 못 느끼는 세 가지 이유를 피부과 전문의 김종식이 설명합니다.', array['레디어스', '콜라겐', '칼슘하이드록시아파타이트', '필러', '쥬베룩', '스컬트라', '피부탄력']::text[]),
    ('V-jTztD01M8', 'kimjongsik', '레디어스 유지기간이 얼마나 되고 계속 맞아야 하나요?', '레디어스 유지기간은 1년에서 2년 정도로, 콜라겐 부스팅 시술 중 가장 오래가는 편입니다. 보통 한 달 간격으로 두세 번 시술해서 피부에 충분한 토대를 만들면, 그 다음부터는 1~2년에 한 번씩만 유지 시술을 하면 돼요. 비교하면 히알루론산 필러는 6개월~1년, 쥬베룩은 10개월~1년, 스컬트라도 약 1년인데 레디어스가 가장 깁니다. 꼭 세 번 연달아 받아야 효과가 있는 건 아니고 한 번만 받아도 효과는 있어요. 다만 더 확실하고 오래가는 결과를 위해 토대를 만드는 작업이라 보시면 됩니다. 시술 후 1~2주만 지나도 피부가 쫀쫀해지면서 탄력이 차올라오는 걸 느끼실 수 있어요. 사람마다 피부 상태와 노화 정도가 다르니 횟수는 상담 후 결정하시면 됩니다.', '레디어스의 유지기간과 다른 콜라겐 시술과의 비교를 피부과 전문의 김종식이 안내합니다.', array['레디어스', '유지기간', '콜라겐', '필러', '쥬베룩', '스컬트라', '피부탄력']::text[]),
    ('V-jTztD01M8', 'kimjongsik', '팔자주름에 필러 맞다가 이동돼서 트라우마인데 레디어스는 괜찮나요?', '레디어스는 필러와 달리 인위적으로 볼륨을 채우는 게 아니라 피부 자체가 자연스럽게 차오르게 만드는 시술이라 이동 걱정이 적습니다. 팔자주름이나 마리오네트 주변은 움직임이 많고 피부가 얇아서 필러를 넣으면 어색해지거나 쥬베룩은 결절 위험 때문에 꺼려지는 위치였어요. 레디어스는 이 가려운 부분을 정확히 긁어주는 시술이라고 할 수 있습니다. 구겨졌던 종이가 쫙 펴지듯이 탄탄해지면서 자연스럽게 차오르는 느낌이에요. 나이가 들면서 입가 주변이 일부는 꺼지고 일부는 튀어나와 울퉁불퉁해지는데, 이런 부위에 레디어스를 시술하면 가장 자연스럽게 좋아집니다. 사실 제가 가장 추천하는 위치가 바로 이 입가 주변, 팔자주름과 마리오네트 주변이에요.', '팔자주름과 마리오네트에 레디어스가 필러보다 적합한 이유를 피부과 전문의 김종식이 설명합니다.', array['레디어스', '팔자주름', '마리오네트', '필러', '콜라겐', '리프팅', '입가주름']::text[]),
    ('V-jTztD01M8', 'kimjongsik', '레디어스가 쥬베룩이나 스컬트라랑 뭐가 다른 건가요?', '가장 큰 차이는 레디어스가 1형 콜라겐뿐 아니라 3형 콜라겐, 엘라스틴, 프로테오글리칸 등 피부 전 구성 성분을 다 만들어낸다는 점입니다. 필러나 쥬베룩 볼륨은 PDLA 성분으로 이물질 반응을 일으켜 진피의 90% 이상을 차지하는 1형 콜라겐을 만들어내서 볼륨감을 주는 원리예요. 그래서 볼이나 이마처럼 꺼진 곳을 채우는 데는 이 시술들이 더 효과적이죠. 반면 레디어스는 칼슘하이드록시아파타이트를 물에 묽게 희석해서 전체적으로 깔아주는데, 마치 정원에 거름을 골고루 뿌려 잔디가 자라나듯 피부 스스로 건강해지는 느낌을 줍니다. 목 주름처럼 자글자글한 부위에서 진짜 내 피부처럼 자연스럽게 좋아지는 게 강점이에요. 볼륨 채움은 필러나 쥬베룩, 전반적 피부 개선은 레디어스로 구분하시면 됩니다.', '레디어스와 쥬베룩, 스컬트라의 원리 차이를 피부과 전문의 김종식이 정리합니다.', array['레디어스', '쥬베룩', '스컬트라', '콜라겐', '칼슘하이드록시아파타이트', '엘라스틴', '필러']::text[]),
    ('Fr78THIXUmg', 'parkhyojin', '뾰루지 짜도 되는 타이밍이 정확히 언제예요?', '노랗게 잘 익어서 뭔가 짜면 나올 것 같을 때가 바로 짜도 되는 타이밍입니다. 뾰루지는 크게 세 가지 형태로 나뉘는데, 빨갛고 작게 튀어나온 구진 형태, 노랗게 익은 형태, 크고 깊은 결절 형태가 있어요. 이 중 빨갛기만 하고 짤 게 안 보이는 구진은 절대 건드리면 안 됩니다. 손으로 덧대면 염증이 더 깊어지고 옆으로 번지기까지 하거든요. 반면 노랗고 하얗게 튀어나왔을 때는 문제가 되는 피지와 염증 성분을 빼내줘야 흉 안 지고 빨리 회복됩니다. 하얗게 튀어나온 비염증성 좁쌀 여드름(면포)도 1~2개 정도면 집에서 짜도 괜찮지만, 얼굴 전체에 많다면 반드시 피부과에서 압출 관리를 받으셔야 해요. 핵심은 짤만한 게 보이느냐 아니냐로 판단하시면 됩니다.', '뾰루지 형태별로 짜도 되는 타이밍과 절대 건드리면 안 되는 경우를 피부과 전문의 박효진이 정리합니다.', array['여드름', '뾰루지', '압출', '면포', '구진', '결절', '염증성여드름']::text[]),
    ('Fr78THIXUmg', 'parkhyojin', '깊고 크게 만져지는 결절형 여드름은 어떻게 해야 하나요?', '크고 깊은 결절형 여드름은 반드시 피부과에서 스테로이드 염증 주사를 맞아야 합니다. 이런 형태는 짜도 절대 안 나오고, 가만히 두면 염증이 점점 커지면서 흉터를 남길 가능성이 높아요. 병원에서는 바늘로 구멍을 뚫은 뒤 주사를 놓고 안쪽의 고름을 압출해 주는 게 원칙입니다. 너무 깊어서 잘 안 나오는 경우에는 펀치라는 도구로 작은 구멍을 뚫어 한꺼번에 빼내기도 해요. 중요한 행사나 결혼식을 앞두고 빨갛기만 한 상태에서 빨리 가라앉히고 싶을 때는 표면에 살짝 염증 주사만 놓는 방법도 있습니다. 어떤 방법을 쓰든 결절형은 집에서 해결하려 하면 감염이 생기고 진물까지 날 수 있으니 무조건 병원에 가시는 게 맞아요. 병변 상태에 따라 주사 방법이 달라지므로 전문의 판단을 받으세요.', '크고 깊은 결절형 여드름의 병원 치료법과 집에서 건드리면 안 되는 이유를 피부과 전문의 박효진이 설명합니다.', array['결절', '염증주사', '스테로이드', '여드름', '흉터예방', '압출', '피부과']::text[]),
    ('Fr78THIXUmg', 'parkhyojin', '여드름 패치 붙이면 오히려 악화된다는 말이 사실인가요?', '짜지 않은 상태에서 여드름 패치를 붙이면 오히려 염증이 더 깊어질 수 있어서 사실입니다. 여드름 패치는 하이드로콜로이드라는 상처 회복 성분을 함유하고 있어서 제대로 쓰면 도움이 되는 제품이에요. 문제는 피지가 갇혀 있는 공간에 패치를 붙이면 공기가 더 안 통하면서 여드름균이 번식하기 좋은 환경이 만들어진다는 점입니다. 그래서 셀프 압출이 가능한 상태에서 깨끗이 짠 뒤에 붙여야 효과가 있어요. 다만 본인이 통제가 안 돼서 자꾸 손으로 만지게 되는 분이라면 차라리 패치를 붙여서 물리적으로 손을 차단하는 편이 낫습니다. 결국 타이밍이 핵심인데, 완벽히 짠 직후에 붙이는 게 정답이에요. 짤 상태가 아닌데 무작정 붙이는 건 피하셔야 합니다.', '여드름 패치를 붙여도 되는 조건과 오히려 악화되는 경우를 피부과 전문의 박효진이 안내합니다.', array['여드름패치', '하이드로콜로이드', '압출', '여드름', '여드름관리', '셀프케어']::text[]),
    ('Fr78THIXUmg', 'parkhyojin', '뾰루지 자국이 갈색으로 남았는데 연고로 없앨 수 있나요?', '솔직히 노스카나 겔 같은 흉터 연고를 바른다고 붉은 자국이 빨리 좋아지진 않습니다. 마음의 위안으로 발라볼 수는 있지만, 빨리 없애고 싶다면 혈관을 타겟하는 GV 레이저나 브이빔 같은 시술이 훨씬 효과적이에요. 붉은 자국은 혈관이 미세하게 늘어나서 보이는 건데, 레이저는 한 번만으로도 충분히 좋아질 수 있어 결혼식이나 중요 행사 전에 추천드립니다. 이미 시간이 지나 갈색이나 검은색 자국으로 변한 경우에는 멜라닝 크림을 저녁에 소량 발라주시면 도움이 돼요. 더 빨리 없애고 싶으시면 레이저 토닝을 1~2주 간격으로 10회 정도 받으셔야 합니다. 염증 후 색소침착은 원래 6~12개월에 걸쳐 서서히 빠지지만, 새 뾰루지가 반복되면 계속 쌓이는 게 문제죠. 피부가 얇고 건조한 분일수록 자국이 오래 남으니 적극적인 관리가 필요합니다.', '뾰루지 후 남은 붉은 자국과 갈색 자국의 효과적인 관리법을 피부과 전문의 박효진이 설명합니다.', array['색소침착', '여드름자국', '레이저토닝', '브이빔', '멜라닝크림', '붉은자국', '갈색자국']::text[]),
    ('s41FFNFwC6A', 'jeonghanmi', '패인 여드름 흉터 치료해봤자 소용없다는 말이 진짜인가요?', '아닙니다, 패인 흉터도 꾸준히 잘 치료하면 분명히 좋아질 수 있어요. 많은 분이 수백만 원 써도 효과를 못 봤다고 포기하시는데, 여드름 흉터 치료는 등산과 비슷합니다. 본인 피부 상태, 흉터 깊이, 치료 경험자의 실력, 그리고 꾸준함에 따라 결과가 완전히 달라지거든요. 같은 흉터라도 누구는 5번 만에 좋아지고 누구는 10번을 해도 부족할 수 있어요. 핵심은 흉터가 생기자마자 붉은기가 있을 때 치료를 시작하면 효과가 훨씬 좋다는 점입니다. 20년 이상 된 살색 흉터와 최근 생긴 붉은 흉터는 같은 레이저 6개월 치료에도 결과가 크게 차이 나요. 흉터 치료는 마라톤이니 중간에 포기하지 말고 전문의와 계획을 세워 도전해 보세요.', '패인 여드름 흉터가 치료로 정말 좋아질 수 있는 이유와 핵심 조건을 피부과 전문의 정한미가 설명합니다.', array['여드름흉터', '흉터치료', '프랙셔널레이저', '콜라겐', '패인흉터', '피부재생']::text[]),
    ('s41FFNFwC6A', 'jeonghanmi', '프랙셔널 레이저가 피부를 갈아엎는 거라던데 부작용 없나요?', '프랙셔널 레이저는 피부를 전부 깎아내는 게 아니라 바둑판처럼 일부에만 레이저를 쏘는 방식이라 부작용이 훨씬 적습니다. 예전에는 흉터 부위를 통째로 깎아내서 진물, 딱지, 며칠간 세수 불가, 오래가는 붉은기, 높은 색소침착 확률 등 환자가 굉장히 불편했어요. 프랙셔널은 레이저가 들어간 부위보다 안 들어간 부위가 훨씬 많아서 회복이 빠르고 부작용도 적습니다. 원리는 패인 흉터에 일부러 상처를 내면 피부가 회복하려고 콜라겐을 만들어 그 자리를 채운다는 거예요. 피부의 자연 재생 성질을 이용하는 셈이죠. 다만 흉터 종류에 따라 레이저만으로 부족할 수 있어서 주사나 도트필, 서브시전 같은 방법을 병행하기도 합니다. 어떤 방법이든 목적은 하나, 패인 부위의 살을 채워 올리는 겁니다.', '프랙셔널 레이저의 원리와 예전 방식 대비 부작용이 적은 이유를 피부과 전문의 정한미가 안내합니다.', array['프랙셔널레이저', '흉터치료', '콜라겐', '여드름흉터', '레이저', '피부재생', '다운타임']::text[]),
    ('s41FFNFwC6A', 'jeonghanmi', '좁고 깊은 송곳형 여드름 흉터는 레이저로 안 없어지나요?', '좁고 깊은 송곳형 흉터는 레이저로 바닥까지 도달하기 어려워서 도트필이라는 방법이 훨씬 효과적입니다. 도트필은 TCA라는 강한 산성 약물을 좁은 흉터 안에 정확히 발라서 화학적으로 상처를 내는 치료예요. 레이저가 열로 상처를 내는 거라면, 도트필은 약물로 상처를 내서 콜라겐 재생을 유도하는 원리입니다. 그런데 이 방법은 모든 흉터에 쓸 수 있는 게 아니라 바늘이나 송곳으로 찍어놓은 것 같은 좁고 깊은 형태에 특화돼 있어요. 넓게 패인 흉터에는 히알루론산 필러로 밑에서 받쳐주거나 쥬베룩 같은 콜라겐 생성 유도 주사를 활용하는 게 더 좋습니다. 이렇게 흉터 모양과 깊이에 따라 적합한 치료법이 다르기 때문에 전문의가 한 땀 한 땀 판단해서 시술해야 하는 거예요. 흉터 치료가 어려운 이유가 바로 이 복합적 접근 때문입니다.', '좁고 깊은 송곳형 흉터에 도트필이 레이저보다 효과적인 이유를 피부과 전문의 정한미가 정리합니다.', array['도트필', '여드름흉터', 'TCA', '필러', '쥬베룩', '송곳형흉터', '흉터치료']::text[]),
    ('s41FFNFwC6A', 'jeonghanmi', '레이저 여러 번 받아도 흉터가 안 차오르는 이유가 뭔가요?', '아무리 레이저를 쏴도 안 차오르는 흉터는 밑에서 유착된 조직이 피부를 잡아당기고 있기 때문입니다. 여드름 염증이 심했던 부위는 이후에 피부 조직이 질기고 딱딱하게 굳는 유착이 생겨요. 원래 물 먹은 스펀지처럼 말랑했던 조직이 단단한 밧줄처럼 변해서 피부를 아래로 끌어당기는 거죠. 이 상태에서는 위에서 레이저로 자극을 줘도 채워질 공간이 확보되지 않아 치료 효과가 떨어집니다. 이때 필요한 게 서브시전이라는 시술인데, 피부를 당기고 있는 유착 조직을 끊어주는 방법이에요. 밧줄을 끊으면 피부가 자유롭게 차오를 수 있게 되니까 레이저나 주사 효과가 비로소 제대로 나타나게 됩니다. 여드름 흉터 치료에서 레이저 하나만으로 해결하려 하면 한계가 있을 수 있어요.', '레이저로 안 차오르는 흉터의 원인인 유착과 서브시전 치료를 피부과 전문의 정한미가 설명합니다.', array['서브시전', '유착', '여드름흉터', '흉터치료', '레이저', '콜라겐', '피부재생']::text[]),
    ('ptgJ2Rf7Sjw', 'kimjongsik', '수분크림 아무리 발라도 건조한데 피부 속에 수분을 직접 넣을 수 있나요?', '네, 레스틸렌 비탈이라는 스킨부스터로 피부 속에 히알루론산을 직접 주입해서 수분 저장 창고 자체를 만들 수 있습니다. 수분크림은 피부 겉에서 바르는 거라 히알루론산이 제 기능을 다하기 어려운 반면, 이 시술은 진피층에 직접 넣어 차오르게 하는 원리예요. 히알루론산이 자기 무게의 1000배에 달하는 수분을 끌어당기는 성질이 있어서, 피부가 탱탱해지고 잔주름이 펴지며 모공 개선과 광채 효과까지 기대할 수 있습니다. 마치 메마른 땅에 물을 부으면 차오르는 것처럼 자연스럽게 피부가 촉촉해지는 거죠. 레스틸렌 비탈은 체내에서 분해되지 않도록 특수하게 만들어져 효과가 오래 유지됩니다. 약 20년 전부터 800만 명 이상이 시술 받은 검증된 제품이에요. 건조하고 칙칙하며 잔주름 많은 분들께 특히 추천드립니다.', '수분크림으로 해결 안 되는 건조함에 레스틸렌 비탈 스킨부스터가 효과적인 이유를 피부과 전문의 김종식이 설명합니다.', array['스킨부스터', '레스틸렌비탈', '히알루론산', '수분', '물광주사', '보습', '잔주름']::text[]),
    ('ptgJ2Rf7Sjw', 'kimjongsik', '리쥬란이랑 쥬베룩이랑 레스틸렌 비탈은 뭐가 다른 거예요?', '세 가지 모두 좋은 스킨부스터지만 특징과 추천 대상이 완전히 다릅니다. 리쥬란은 연어 DNA 성분으로 피부 재생에 초점이 맞춰져 있어서 여드름, 홍조, 염증이 많은 분이나 화장 잘 먹게 하고 싶은 젊은 분들에게 좋아요. 쥬베룩은 콜라겐 생성을 자극하는 데 특화돼 탄력 저하, 모공 확대, 잔주름이 고민인 분께 추천합니다. 레스틸렌 비탈은 순수 히알루론산으로 수분 충전과 보습에 강점이 있고, 건조하고 칙칙한 피부에 가장 적합해요. 효과가 나타나는 방식도 다른데, 리쥬란은 즉각적으로 좋아졌다가 빠지는 느낌이고, 쥬베룩은 여러 번 맞으면서 천천히 콜라겐이 차오릅니다. 레스틸렌 비탈은 시작부터 효과가 나타나 3~6개월간 쭉 유지되는 패턴이에요. 내 피부에 뭐가 부족한지에 따라 골라야 하는 거죠.', '리쥬란, 쥬베룩, 레스틸렌 비탈의 차이점과 피부 타입별 추천을 피부과 전문의 김종식이 안내합니다.', array['리쥬란', '쥬베룩', '스킨부스터', '레스틸렌비탈', '콜라겐', '히알루론산', '피부재생', '보습']::text[]),
    ('ptgJ2Rf7Sjw', 'kimjongsik', '스킨부스터 맞으면 울퉁불퉁해진다는데 부작용 심하지 않나요?', '레스틸렌 비탈은 입자 자체가 매우 미세해서 엠보싱이 거의 하루 만에 사라지고, 히알루론산은 체내에서 자연 분해되는 성분이라 매우 안전합니다. 가장 흔한 부작용은 주사 후 멍인데, 사람에 따라 1~2주 정도 갈 수 있어요. 엠보싱이 1~2개 오래 지속되더라도 그냥 놔두면 없어지고, 정 걱정되시면 필러 녹이는 주사로 즉시 해결 가능합니다. 엠보싱이 너무 걱정되는 분을 위해 더 묽은 레스틸렌 비탈 라이트라는 제품도 있어요. 효과 지속력은 조금 떨어질 수 있지만 엠보싱이 덜 생기는 장점이 있습니다. 리도카인 마취 성분이 포함돼 있어 시술 통증도 생각보다 크지 않고, 시술 후 1~2일이면 평상시처럼 생활하실 수 있어요. 멍만 안 들면 다운타임이 거의 없는 셈입니다.', '레스틸렌 비탈 스킨부스터의 엠보싱 부작용과 안전성을 피부과 전문의 김종식이 정리합니다.', array['스킨부스터', '부작용', '엠보싱', '레스틸렌비탈', '히알루론산', '다운타임', '멍']::text[]),
    ('ptgJ2Rf7Sjw', 'kimjongsik', '20대 후반인데 스킨부스터 지금 맞아도 효과 있나요?', '당연히 있습니다. 오히려 20대 후반이면 관리 시작하기에 충분히 좋은 나이고, 예방 효과도 뛰어나요. 본격적으로 피부 노화가 시작되는 게 바로 그 나이대쯤이거든요. 지금은 본인이 못 느끼더라도 피부 속에서는 조금씩 노화가 밖으로 나오려 하고 있습니다. 30대가 되면 피부 탄력이 조금씩 떨어지고 잔주름도 보이기 시작하죠. 레스틸렌 비탈은 보통 한 달 간격으로 3회 시술을 추천하지만, 수분감이 크게 부족하지 않다면 1~2회만 맞아도 효과가 충분히 좋아요. 시술 후 1~2주면 효과가 나타나기 시작해서 6개월간 유지됩니다. 다른 시술과 병행도 가능해서, 보톡스나 실리프팅, 써마지, 울쎄라 같은 리프팅 시술과도 잘 어울려요.', '20대 후반 스킨부스터 시작 적기인 이유와 시술 횟수 가이드를 피부과 전문의 김종식이 안내합니다.', array['스킨부스터', '20대피부', '노화예방', '레스틸렌비탈', '피부관리', '탄력', '잔주름']::text[]),
    ('Ot6An6aOL_k', 'leedoyoung', '사각턱 보톡스 맞으면 볼이 꺼져서 늙어 보인다는 말이 사실인가요?', '네, 땅콩형 얼굴이나 볼살이 없는 분이 사각턱 보톡스를 맞으면 오히려 볼 꺼짐으로 늙어 보일 수 있습니다. 사각턱 보톡스에 가장 적합한 사람은 입을 꽉 닫았을 때 옆 부분이 알처럼 볼록 튀어나오는 분이에요. 그 튀어나온 게 근육(교근)이어야 효과가 있지, 뼈나 살이면 보톡스 효과가 없습니다. 광대 밑이 꺼져 있거나 30대 이상으로 볼살이 부족한 분은 시술 후 해골처럼 푹 패여 보일 수 있어요. 처음 맞고 패임이 생겼다면 대부분 돌아오지만, 반복적으로 맞아서 생긴 패임은 회복이 어려울 수 있습니다. 심술보가 처지기 시작한 분도 주의하셔야 하는데, 교근 볼륨이 텐트처럼 살을 위로 당겨주고 있기 때문에 이걸 줄이면 아래로 더 처지게 돼요. 얼굴형을 먼저 정확히 파악한 뒤에 시술 여부를 결정하세요.', '사각턱 보톡스로 볼이 꺼지는 얼굴형과 시술 적합 조건을 피부과 전문의 이도영이 설명합니다.', array['사각턱', '보톡스', '땅콩형얼굴', '볼꺼짐', '교근', '부작용', '얼굴형']::text[]),
    ('Ot6An6aOL_k', 'leedoyoung', '자갈턱 보톡스 맞고 입이 비뚤어지는 부작용이 있다던데요?', '자갈턱 보톡스의 가장 흔한 부작용은 비대칭 미소로, 아래입술 내림근이 마비되면서 한쪽 입만 내려가는 현상입니다. 한쪽에 보톡스가 과하게 퍼지면 그쪽 아래입술을 내릴 수 없게 돼서, 웃을 때 양쪽이 비대칭으로 보이게 되는 거예요. 해결 방법은 정상인 쪽에도 살짝 보톡스를 놔서 양쪽 대칭을 맞추는 겁니다. 입술을 내리는 근육이라 생활에 큰 지장은 없지만 약간 무거운 느낌은 있을 수 있어요. 보톡스의 장점이자 단점이 효과도, 부작용도 길어야 4~6개월이면 사라진다는 점입니다. 시간이 지나면 양쪽 다 기능이 돌아오면서 자연히 해결돼요. 주걱턱이신 분은 자갈턱 보톡스가 오히려 턱을 더 앞으로 나오게 할 수 있어 안 맞으시는 게 나을 수도 있습니다.', '자갈턱 보톡스의 비대칭 미소 부작용 원인과 해결법을 피부과 전문의 이도영이 안내합니다.', array['자갈턱', '보톡스', '비대칭', '부작용', '입술내림근', '턱보톡스']::text[]),
    ('Ot6An6aOL_k', 'leedoyoung', '침샘 보톡스 맞으면 입이 마른다는데 그래도 맞아야 하나요?', '턱밑샘을 마비시키면 가만히 있을 때 침 분비의 70% 이상을 담당하는 곳이라 거의 100% 입마름이 옵니다. 귀밑샘만 맞으면 10~15% 정도만 담당하니 크게 불편하지는 않지만, 턱밑샘까지 같이 맞으면 입마름이 상당할 수 있어요. 미리 불편하실 수 있다고 설명을 드리고 시술하는 편입니다. 다만 울쎄라나 다른 리프팅 시술로는 해결할 수 없는 부위라서, 불편하시더라도 효과를 한번 보시면 계속 맞으러 오시는 분들도 있어요. 본인 침샘을 확인하는 방법도 있는데, 턱밑에 포도알처럼 딱딱하게 만져지면 턱밑샘, 귀 아래 사각턱 뒤쪽에 말랑하게 만져지면 귀밑샘입니다. 침샘이 만져지지 않으면 효과를 보기 어려울 수 있으니 시술 전 확인이 중요해요. 4~6개월 간격으로 재시술하시고, 내성이 걱정되면 제오민이나 코어톡스 같은 제품을 추천드립니다.', '침샘 보톡스의 입마름 부작용과 효과를 보려면 알아야 할 핵심 사항을 피부과 전문의 이도영이 정리합니다.', array['침샘보톡스', '입마름', '턱밑샘', '귀밑샘', '보톡스', '내성', '제오민']::text[]),
    ('Ot6An6aOL_k', 'leedoyoung', '사각턱 보톡스 맞았더니 광대 밑이 볼록 튀어나왔는데 왜 그런 거예요?', '사각턱 보톡스를 맞은 부위의 근육이 마비되면서 그 위쪽 근육이 상대적으로 볼록 튀어나와 보이는 현상입니다. 아래쪽 교근이 줄어드니까 바로 위 부분이 더 도드라져 보이는 거예요. 이런 경우 볼록 튀어나온 부위에 아주 소량만 터치업을 해주면 해결됩니다. 비슷한 현상으로 관자부위가 울룩불룩 튀어나오는 분들도 있는데, 그런 분들은 사각턱과 관자를 같이 잡아주는 게 좋아요. 사각턱 보톡스는 효과도 부작용도 4~6개월이면 사라지기 때문에, 불편하시면 기다리셔도 되고 터치업으로 빠르게 교정하셔도 됩니다. 이런 부분까지 고려해서 얼굴형에 맞춰 용량과 주입 라인을 조절하는 게 중요해요. 마른 분이라면 용량을 줄이고, 볼이 패인 분이라면 라인을 낮게 잡는 식으로 접근합니다.', '사각턱 보톡스 후 광대 밑이 볼록해지는 원인과 터치업 해결법을 피부과 전문의 이도영이 설명합니다.', array['사각턱', '보톡스', '부작용', '광대', '교근', '터치업', '얼굴형']::text[]),
    ('uHH6MW7Ey3w', 'leedoyoung', '티타늄 리프팅 효과가 금방 떨어진다던데 정말인가요?', '효과가 떨어지는 게 아니라 시술 직후의 드라마틱한 리프팅이 몇 주에 걸쳐 원래 의도한 만큼으로 자연스럽게 안정화되는 과정입니다. 시술 직후에는 피부가 확 끌어올려지는데, 그 모습에 반해서 시간이 지나면 효과가 없어졌다고 느끼시는 분들이 있어요. 하지만 시술 전과 몇 주 후를 비교하면 확실히 차이가 납니다. 피부 안쪽에서는 탄력에 도움이 되는 콜라겐과 엘라스틴이 6개월에 걸쳐 계속 만들어지거든요. 효과를 더 오래 유지하고 싶다면 티타늄 리프팅과 고주파 시술을 병합해서 받아보세요. 이렇게 병합 시술을 받고 나서 효과가 오래 안 간다고 말한 분은 한 분도 없었습니다. 스킨부스터 중에서는 비타란이라는 주사와 같이 받으면 촉촉함과 광채까지 더해져 시너지 효과가 좋아요.', '티타늄 리프팅 효과가 금방 떨어진다는 오해의 진실과 지속력 높이는 법을 피부과 전문의 이도영이 설명합니다.', array['티타늄리프팅', '리프팅', '콜라겐', '엘라스틴', '고주파', '효과지속', '스킨부스터']::text[]),
    ('uHH6MW7Ey3w', 'leedoyoung', '티타늄 리프팅이 왜 연예인들 사이에서 핫한 시술인 거예요?', '하자마자 바로 예뻐지면서도 티가 안 나고, 다운타임이 전혀 없어서 소개팅, 결혼식, 촬영 직전에도 받을 수 있기 때문입니다. 시술 받으면 얼굴이 전체적으로 화사해지고, 피부가 쫀쫀해지고, 윤곽이 예뻐지는 BTS 효과(브라이트닝, 타이트닝, 슬리밍)가 즉각적으로 나타나요. 멍도 안 들고 붓기도 없어서 시술 당일 바로 일상생활이 가능합니다. 실제로 채정안 씨가 광고 촬영 전날 티타늄 리프팅을 받고 다음 날 바로 현장에 갔을 정도예요. 마취크림 20분 바르고 시술하면 통증도 거의 없고, 아플락 말락 할 때쯤 끝납니다. 얼굴 반쪽만 시술하고 거울 보여드리면 양쪽 차이가 확실해서 반대쪽도 다 하고 가시거든요. 리프팅 시술인데 부담 없이 받을 수 있다는 게 가장 큰 매력입니다.', '티타늄 리프팅이 연예인 사이에서 인기인 이유와 즉각적 효과를 피부과 전문의 이도영이 안내합니다.', array['티타늄리프팅', '리프팅', '다운타임', '브라이트닝', '타이트닝', '슬리밍', '통증']::text[]),
    ('uHH6MW7Ey3w', 'leedoyoung', '울쎄라나 써마지 대신 티타늄 리프팅만 받으면 되나요?', '각각 장점이 달라서 어떤 하나만 받아라 하기는 어렵고, 피부 상태에 따라 선택하거나 병합하는 게 좋습니다. 써마지는 피부 탄력에 확실히 좋고, 울쎄라는 처진 피부를 올려주거나 볼륨을 감소시키는 효과가 탁월해요. 티타늄 리프팅은 프로토콜이 두 가지인데, 한 부위에 집중적으로 에너지를 전달하는 스택 방식은 울쎄라와 비슷하면서 피부톤이 밝아지는 장점이 있습니다. 부드럽게 문지르며 에너지를 전달하는 러빙 방식은 써마지와 비슷한데 즉각적인 슬리밍 라인 개선과 피부톤 개선이 더 큰 편이에요. 특히 마리오네트 주름, 처진 볼, 턱선 개선에는 스택 방식이 효과적입니다. 안면 비대칭 교정도 가능한데, 더 처진 쪽에 에너지를 더 줘서 대칭을 맞출 수 있어요. 본인 고민에 따라 전문의와 상담해서 단독이든 병합이든 결정하시면 됩니다.', '티타늄 리프팅과 울쎄라, 써마지의 차이점과 프로토콜별 특징을 피부과 전문의 이도영이 정리합니다.', array['티타늄리프팅', '울쎄라', '써마지', '리프팅', '마리오네트', '턱선', '비대칭']::text[]),
    ('uHH6MW7Ey3w', 'leedoyoung', '티타늄 리프팅 받기 전에 주의할 사항이 있나요?', '티타늄 리프팅 받기 전에 필러, 보톡스, 리쥬란 같은 주사 시술을 받으시면 안 됩니다. 주사로 넣은 물질이 있는 상태에서 열에너지를 가하면 화상을 입을 수 있기 때문이에요. 주사 시술과 병행하고 싶다면 티타늄 리프팅을 먼저 하고 나서 주사를 맞거나, 주사 후 충분한 시간차를 두고 티타늄 리프팅을 받으시면 됩니다. 그 외에는 일상생활에 전혀 지장 없이 다 하실 수 있어요. 스킨부스터 중에서는 비타란이라는 주사가 티타늄과 궁합이 좋은데, 피부를 촉촉하게 하고 광을 내주면서도 다운타임이 전혀 없는 게 장점입니다. 보톡스나 실리프팅, 써마지, 울쎄라 같은 다른 시술과도 시너지가 있으니 순서는 전문의와 상의하시는 게 좋아요. 시술 당일부터 세수, 화장 등 일상 활동이 모두 가능합니다.', '티타늄 리프팅 전후 주사 시술 주의사항과 병합 가능한 시술을 피부과 전문의 이도영이 안내합니다.', array['티타늄리프팅', '주의사항', '화상', '필러', '보톡스', '비타란', '다운타임']::text[]),
    ('Ed-OE2iPysg', 'jeonghanmi', '임산부 튼살크림 바르면 예방이나 치료에 정말 효과 없는 건가요?', '이미 생긴 튼살에는 튼살크림이 거의 효과가 없습니다. 2012년 리뷰 논문에서 튼살크림의 예방 효과, 심한 정도 감소, 성분별 효과 세 가지를 모두 검증했는데 결과는 전부 효과 없음이었어요. 그 이후 나온 일부 논문에서는 효과가 있다는 보고도 있어서 100% 효과가 없다고 단정짓기는 어렵습니다. 다만 비싼 튼살크림을 일부러 구매할 필요는 없고, 선물 받은 게 있다면 바르되 없으면 기존 바디크림을 마사지하듯 발라주면 충분해요. 튼살크림보다 효과를 기대할 수 있는 연고는 따로 있으니 이미 튼살이 생긴 분이라면 트레티노인 성분의 약국 연고를 고려해 보시는 게 현실적입니다. 결국 하얗게 변한 오래된 튼살에는 크림류로는 의미 있는 개선이 어렵습니다.', '2012년 리뷰 논문에서 튼살크림의 예방·치료 효과는 모두 입증되지 않았습니다. 비싼 튼살크림 대신 현실적인 대안을 피부과 전문의 정한미가 정리합니다.', array['튼살', '튼살크림', '트레티노인', '투앤티크림', '임산부', '바디크림', '예방']::text[]),
    ('Ed-OE2iPysg', 'jeonghanmi', '이미 생긴 붉은 튼살에 바를 수 있는 약국 연고가 있나요?', '트레티노인 성분이 들어간 투앤티 크림을 바르면 붉은 튼살에 효과를 볼 수 있어요. 트레티노인은 피부의 표피층을 두껍게 만들고 콜라겐 생성을 촉진하는 성분입니다. 바르는 방법은 자기 전에 완두콩 절반 정도 크기를 손등에 덜어 튼살 부위에 얇게 펴 바르면 되고, 최소 3~6개월은 꾸준히 사용해야 합니다. 피부가 빨개지고 자극이 된다면 본인의 보습제 크림과 투앤티 크림을 반반 섞어서 바르는 것도 방법이에요. 단, 트레티노인 성분은 임신 중 절대 사용하면 안 되며 출산 후에 바르셔야 합니다. 모든 분께 효과가 있는 건 아니고 100%도 아니지만, 생긴 지 얼마 안 된 붉은 튼살이라면 시도해볼 가치가 있어요. 하얗게 변한 오래된 튼살에는 이 연고도 거의 효과가 없습니다.', '붉은 튼살에는 트레티노인 성분의 투앤티 크림이 콜라겐 재생에 도움됩니다. 사용법과 임산부 금기 등 주의사항을 피부과 전문의 정한미가 안내합니다.', array['트레티노인', '투앤티크림', '붉은튼살', '콜라겐', '임산부', '약국연고', '스티바A']::text[]),
    ('Ed-OE2iPysg', 'jeonghanmi', '하얗게 변한 오래된 튼살도 레이저로 치료할 수 있나요?', '네, 미라젯이나 큐어젯 같은 레이저 덕분에 하얀 튼살도 충분히 개선할 수 있는 시대가 됐습니다. 이 레이저는 약물을 장전해서 공기총처럼 압력으로 피부 속에 쏘는 원리인데, 튄살 부위 피부를 미세하게 찢으면서 약물이 피부 안에 박히게 해요. 패여 있는 튼살 부위를 미세하게 찢어주면 그 자리에서 살이 차오르는 재생 반응이 일어나 좋아집니다. 울트라펄스 같은 CO2 프랙셔널 레이저로도 치료가 가능하며 이쪽은 미세한 구멍을 여러 개 뚫어 피부 재생을 유도하는 방식이에요. 보통 2~3번 정도 치료하면 효과가 눈에 보이기 시작하지만 개인차가 있습니다. 100% 흔적 없이 사라지진 않더라도 멀리서 눈에 띄던 하얀 줄들이 가까이 봐야 보일 정도로 개선될 수 있어요.', '하얀 튼살도 미라젯·큐어젯 레이저로 개선 가능한 시대가 됐습니다. 압력으로 약물을 피부에 쏘는 원리와 치료 횟수를 피부과 전문의 정한미가 설명합니다.', array['튼살', '미라젯', '큐어젯', '울트라펄스', '레이저', '흰튼살', 'CO2프랙셔널']::text[]),
    ('Ed-OE2iPysg', 'jeonghanmi', '튼살 레이저 치료 아프진 않나요? 언제 시작하는 게 좋아요?', '솔직히 시술받을 때는 피부 속이 찢어지는 느낌이 나서 아프지만, 신기하게도 끝나면 전혀 안 아파요. 일반 레이저 치료처럼 끝나고 화끈거리거나 불편한 후유증이 없는 게 특징입니다. 치료를 시작하기 가장 좋은 시점은 튼살이 생긴 직후 아직 붉을 때이며, 이때 바로 치료할수록 효과가 가장 좋습니다. 물론 하얀색으로 변한 오래된 튼살도 치료할 수 있지만 더 많은 시간과 노력이 필요할 수 있어요. 완벽하게 없어지진 않더라도 자신감을 되찾을 만큼 개선시킬 수 있으니, 예전처럼 치료가 안 된다고 포기할 필요는 없습니다. 특히 종아리나 오금처럼 잘 보이는 부위에 심하게 생겼다면 조기 치료를 적극 고려해 보세요.', '튼살 레이저는 시술 중만 아프고 끝나면 후유증이 없습니다. 아직 붉을 때 시작하면 효과가 가장 좋은 이유와 치료 시기를 피부과 전문의 정한미가 안내합니다.', array['튼살', '레이저치료', '통증', '치료시기', '붉은튼살', '흰튼살', '피부재생']::text[]),
    ('60HHaLCPg68', 'leedoyoung', '이마·미간·눈가 보톡스 한꺼번에 맞아도 괜찮은 건가요?', '네, 한꺼번에 맞으셔도 됩니다. 오히려 내성 측면에서는 조금씩 자주 맞는 게 보톡스 노출이 많아져서 더 좋지 않아요. 이마, 미간, 눈가, 입가까지 맞는다 해도 용량이 많이 들어가는 게 절대 아니기 때문에 한번에 시술받는 게 합리적입니다. 다만 일반적으로 팔자주름에는 보톡스를 놓지 않아요. 한 가지 예외가 있다면, 연세가 있으시고 눈 뜰 때 이마 근육을 많이 사용하는 분은 이마와 미간을 따로 시술하는 편입니다. 이마와 미간에 동시에 보톡스를 맞으면 눈 뜨기가 너무 불편해질 수 있기 때문이에요. 그런 경우에는 한 군데 먼저 하고 적응된 후 다음 시술을 진행하면 됩니다.', '보톡스를 여러 부위에 한꺼번에 맞아도 되는지와 예외 상황을 피부과 전문의 이도영이 설명합니다.', array['보톡스', '이마', '미간', '눈가', '내성', '팔자주름', '여러부위']::text[]),
    ('60HHaLCPg68', 'leedoyoung', '이마 보톡스 맞았는데 눈 뜨기 힘들고 주름이 더 심해졌어요?', '눈을 뜰 때 이마 근육을 쓰시는 분들에게 흔히 생기는 부작용입니다. 눈꺼풀 힘이 약해서 이마를 같이 쓰는데, 그 이마 근육을 마비시키면 당연히 눈 뜨기가 힘들어지죠. 얼굴 근육들은 서로 연결되어 있어서 풍선처럼 한쪽을 쥐면 다른 쪽이 부풀어 오르는 원리와 같아요. 보톡스로 마비된 부분 대신 다른 쪽이 보상성으로 과하게 수축하면서 눈썹 위 주름이나 미간이 더 심해 보일 수 있습니다. 눈썹 바로 위에 주름이 생기는 경우에는 교정이 쉽지 않은데, 눈썹 바로 위에 보톡스를 놓으면 눈썹이 아래로 내려오기 때문이에요. 그래서 눈썹으로부터 2cm 위부터 시술하는 게 가이드라인이며, 조비나나 엠페이스 같은 EMS 장비로 부작용을 빨리 풀 수도 있습니다.', '이마 보톡스 후 눈 뜨기 힘들어지는 부작용 원인과 해결법을 피부과 전문의 이도영이 정리합니다.', array['보톡스', '이마주름', '부작용', '눈처짐', '스킨보톡스', '엠페이스', '조비나']::text[]),
    ('60HHaLCPg68', 'leedoyoung', '라인보톡스 효과가 얼마나 가고, 스킨보톡스랑 뭐가 다른가요?', '라인보톡스는 넓은 목근(목에서 시작해 아래턱에 달라붙는 근육)을 타겟으로 하는 보톡스입니다. 넓은 목근이 수축하면 턱 라인이 뭉개지는데, 이 근육을 마비시키면 라인이 선명하게 잡혀요. 시술 방법은 턱 라인을 따라 1~2줄에서 3줄 정도 주사하며, 일반적으로 스킨보톡스처럼 농도를 묽게 해서 놓습니다. 지속기간은 보통 1~2달, 최대 4달 정도인데 라인 잡아주는 효과 자체는 굉장히 좋아요. 다른 리프팅 시술과 조합하는 경우도 많고 추천드리는 시술 중 하나입니다. 스킨보톡스와 비슷하게 묽게 맞는 방식이지만 타겟 근육이 넓은 목근으로 명확히 다르다는 점이 핵심 차이에요.', '라인보톡스의 원리·효과·지속기간과 스킨보톡스와의 차이를 피부과 전문의 이도영이 안내합니다.', array['라인보톡스', '스킨보톡스', '턱라인', '리프팅', '넓은목근', '지속기간', '보톡스']::text[]),
    ('60HHaLCPg68', 'leedoyoung', '보톡스 부작용이 생겼을 때 어떻게 대처해야 하나요?', '보톡스 부작용은 나타날 수 있지만, 핵심은 리스크를 줄이는 시술과 생겼을 때 빠르게 극복하는 것 두 가지입니다. 첫째, 부작용을 줄일 수 있는 방향으로 시술하는 게 가장 중요하고요. 둘째, 만약 부작용이 생겼을 때 빠르게 해결하는 방법을 아는 것이 보톡스 치료의 핵심이에요. 예를 들어 이마 보톡스 후 눈 뜨기 힘들어진 경우에는 조비나나 엠페이스 같은 EMS 장비로 시술하면 부작용이 빨리 풀리는 느낌이 있습니다. 보톡스는 하면 할수록 쉬우면서도 어려운 시술이라 의사 입장에서도 공부를 계속할 수밖에 없어요. 시술 전 충분한 상담을 통해 본인 근육 상태와 리스크를 파악하는 게 후회 없는 결과를 만드는 출발점입니다.', '보톡스 부작용 발생 시 대처법과 예방 원칙을 피부과 전문의 이도영이 설명합니다.', array['보톡스', '부작용', 'EMS', '엠페이스', '조비나', '상담', '리스크']::text[]),
    ('fskQJJWST5s', 'kwonsuhyun', '붉고 만지면 아픈 여드름엔 약국에서 뭘 사서 발라야 하나요?', '염증이 생긴 붉은 여드름에는 애크논을 바르면 됩니다. 애크논에는 진통소염제 성분이 있어서 염증이 있는 여드름에 직접 발라주면 효과가 좋아요. 바르는 방법은 애크논을 짜서 여드름 부위에 얹은 다음 듀오덤 같은 걸 붙여 밀봉해주면 다음 날 염증이 많이 가라앉습니다. 그 자리에 붉은 자국이 남았다면 노스카나겔을 자국이 없어질 때까지 발라주시면 돼요. 큰 염증이 가라앉은 후 무르익은 농이 올라오면 면봉으로 살살 짜주고, 짠 자리에는 2차 감염 예방을 위해 에스로반을 발라주세요. 여드름이 막 올라오기 시작할 때부터 빨리 관리할수록 빨리 없어지니까 초기 대응이 핵심입니다. 아프다는 건 안에 염증이 생겼다는 뜻이라서 방치하면 안 됩니다.', '붉고 아픈 염증성 여드름에 바르는 약국 연고 순서를 피부과 전문의 권수현이 정리합니다.', array['여드름', '애크논', '듀오덤', '노스카나겔', '에스로반', '염증', '약국연고']::text[]),
    ('fskQJJWST5s', 'kwonsuhyun', '블랙헤드랑 화이트헤드 연고가 같은 건가요?', '둘 다 클리어틴을 사용하지만 접근 방식이 조금 다릅니다. 블랙헤드는 모공이 열린 상태에서 피지가 공기와 만나 산화되어 검게 변한 것이고, 다행히 염증을 동반하는 경우가 드물어서 클리어틴을 톡톡 발라주면 돼요. 클리어틴에 들어있는 살리실산이 피지와 각질을 녹여주는 역할을 합니다. 화이트헤드는 블랙헤드와 달리 모공이 막혀 있어서 피지가 피부 안에 갇힌 상태예요. 클리어틴을 먼저 발라보되 시간이 지나도 안 없어지면 살짝 구멍을 내서 짜줘야 합니다. 약으로 안 된다면 병원에서 압출을 받거나 병원용 연고가 필요할 수 있어요. 확실히 블랙헤드를 제거하고 싶다면 피부과에서 압출이나 아그네스 같은 피지선 레이저 시술도 고려해 보세요.', '블랙헤드와 화이트헤드의 차이와 클리어틴 사용법을 피부과 전문의 권수현이 안내합니다.', array['블랙헤드', '화이트헤드', '클리어틴', '살리실산', '피지', '모공', '압출']::text[]),
    ('fskQJJWST5s', 'kwonsuhyun', '여드름 자국이 거뭇거뭇하게 남았는데 뭘 발라야 없어지나요?', '색소침착을 동반한 여드름 자국에는 아젤리아 크림을 발라주시면 됩니다. 이건 여드름 흉터가 아니라 여드름이 지나간 자국이기 때문에 시간은 걸리지만 웬만하면 좋아질 수 있어요. 어둡게 거뭇거뭇한 자국이 남았다는 건 염증 반응으로 멜라닌 색소가 많이 만들어졌다는 뜻입니다. 아젤리아 크림에 들어있는 아젤라익산이 멜라닌 생성을 억제하는 효과가 있어서 색소침착 개선에 좋아요. 이 크림의 장점은 자연 유래 성분이라 임산부와 수유부도 사용할 수 있다는 점입니다. 보습 크림 위에 바를 때 초반에는 여드름 부위에만 콕콕 발라주시고, 따갑지 않으면 전반적으로 넓게 깔아도 됩니다. 다음 날까지 붉고 염증이 심하게 일어나면 사용을 중단하시고, 그렇지 않다면 정상 반응이니 계속 사용하세요.', '여드름 후 거뭇한 색소침착에 효과적인 아젤리아 크림 사용법을 피부과 전문의 권수현이 설명합니다.', array['여드름자국', '색소침착', '아젤리아크림', '아젤라익산', '멜라닌', '임산부', '여드름흉터']::text[]),
    ('fskQJJWST5s', 'kwonsuhyun', '지성피부인데 여드름 예방용으로 꾸준히 바를 수 있는 연고가 있나요?', '평소 여드름이 많이 나는 편은 아닌데 가끔 올라오는 걸 예방하고 싶다면 세비타비겔을 꾸준히 넓게 발라주는 게 도움됩니다. 세비타비겔에는 비타민 B3 성분이 있어서 피지 조절에도 도움이 되고 피부 장벽을 강화시켜 줘요. 보습제로는 아토베리어 AI크림 MD를 추천드리는데, 끈적이지 않고 산뜻하면서 보습 성분이 다 포함되어 있어 지성 피부에 적합합니다. 피지 분비량이 정말 많을 때는 스킨보톡스도 강력 추천하는데, 가성비 좋으면서 잔주름과 탄력까지 잡아주는 시술이에요. 특정 부위에만 반복적으로 큰 염증성 여드름이 생긴다면 아그네스로 피지선을 파괴하는 방법도 있으며 최소 3회 이상 시술이 필요합니다. 모낭염이 의심되면 에스로반 같은 항생제 연고를 쓰시되, 주변에 블랙헤드나 화이트헤드 없이 붉은 염증만 있다면 모낭염일 가능성이 큽니다.', '지성 피부의 여드름 예방과 피지 관리를 위한 연고·시술을 피부과 전문의 권수현이 추천합니다.', array['지성피부', '세비타비겔', '비타민B3', '스킨보톡스', '아그네스', '모낭염', '피지조절']::text[]),
    ('MsNRy2pW8AQ', 'gohyerim', '스마트폰이 변기보다 더럽다는데, 피부에 진짜 영향을 주나요?', '네, 스마트폰 위생이 피부 트러블의 직접적인 원인이 될 수 있습니다. 미국 애리조나 대학교 연구에 따르면 스마트폰에서 검출된 세균 수가 화장실 변기보다 약 10배 더 많았고, 대장균과 황색포도상구균 등 다양한 세균이 발견됐어요. 이렇게 오염된 액정이 통화할 때 얼굴에 닿으면 여드름이나 모낭염이 생길 수 있습니다. 기초 제품 바르기 전에 손을 깨끗이 씻어도 카톡 답장 한 번 하면 손 씻은 게 무용지물이 되는 셈이에요. 관리 방법은 다이소에서 천 원짜리 알콜 스왑을 사서 자주 닦거나, 소독용 알콜을 솜에 묻혀 휴대폰을 닦아주면 됩니다. 가능하다면 통화할 때 이어폰이나 스피커폰을 사용해서 액정이 얼굴에 닿지 않도록 하는 것이 좋아요.', '스마트폰에는 변기보다 10배 많은 세균이 있어 여드름·모낭염의 원인이 될 수 있습니다. 알콜 스왑 세정법과 예방 습관을 피부과 전문의 고혜림이 안내합니다.', array['스마트폰', '세균', '여드름', '모낭염', '위생관리', '트러블', '생활습관']::text[]),
    ('MsNRy2pW8AQ', 'gohyerim', '클렌징 열심히 하는데 왜 오히려 피부가 안 좋아지는 걸까요?', '과도한 세안이 오히려 피부를 보호하는 장벽까지 씻어내서 문제를 만드는 겁니다. 클렌징 티슈, 클렌징 오일, 폼 클렌징, 각질 제거, 클렌징 디바이스까지 동원하면 화장품뿐 아니라 피부 보호막까지 벗겨내는 셈이에요. 세안할 때 가장 중요한 건 먼저 손을 깨끗이 씻고, 손에서 충분히 거품을 낸 다음 그 거품으로 얼굴을 살살 문지르는 것입니다. 마른 손에 클렌징폼을 바로 비벼서 얼굴에 가져가면 안 돼요. 세안 시간이 너무 긴 것도 좋지 않고, 마무리를 찬물로 하는 것도 피부에 자극을 줍니다. 미온수로 헹구고 수건으로 가볍게 톡톡 두드려 마무리하세요. 빡빡 문지르는 습관 하나만 고쳐도 피부 상태가 달라질 수 있습니다.', '클렌징을 열심히 할수록 피부가 안 좋아지는 건 피부 보호막까지 벗겨내기 때문입니다. 거품 세안법과 세안 시간·온도 기준을 피부과 전문의 고혜림이 정리합니다.', array['세안', '클렌징', '피부장벽', '거품세안', '과도한세안', '미온수', '트러블']::text[]),
    ('MsNRy2pW8AQ', 'gohyerim', '샤워기 물을 얼굴에 바로 맞으면 안 되는 건가요?', '샤워기에서 나오는 물을 얼굴로 바로 맞으면 피부 장벽이 손상되고 건조해질 수 있습니다. 몸 피부보다 얇고 예민한 얼굴 피부는 수압에 의해 쉽게 자극을 받거든요. 특히 쌀쌀한 날씨에 뜨거운 물로 샤워하면서 얼굴로 바로 맞으면 수압 자극에 온도 자극까지 이중으로 가해지는 셈이에요. 이걸 반복하면 모공이 늘어지고 모세혈관이 확장되어 홍조가 생길 위험도 높아집니다. 세안할 때는 반드시 물을 받아서 해주셔야 하고, 몸 샤워도 너무 뜨거운 물로 오래 하는 건 피해주세요. 트리트먼트나 린스에 들어있는 실리콘·코팅제가 등과 가슴 모공을 막을 수 있으니 샴푸를 먼저 끝내고 마지막에 바디워시로 마무리하는 순서도 중요합니다.', '샤워기 수압을 얼굴에 직접 맞으면 모공 확장과 홍조를 유발할 수 있습니다. 물 받아 세안하기와 샴푸-바디 순서의 중요성을 피부과 전문의 고혜림이 설명합니다.', array['샤워', '수압', '피부장벽', '홍조', '모공', '뜨거운물', '세안순서']::text[]),
    ('MsNRy2pW8AQ', 'gohyerim', '베개 커버가 변기보다 96배 더럽다는데 정말인가요?', '서울대 생명과학부 연구팀 조사에 따르면 베개에서 변기보다 96배나 많은 세균이 검출됐다고 합니다. 베개 커버에는 머리카락에 딸려온 먼지, 자면서 흘리는 땀과 침, 피지와 각질 등이 쌓이면서 세균이 번식하기 좋은 환경이 되거든요. 세탁을 자주 안 하고 그 베개에 얼굴을 대고 자면 당연히 트러블의 원인이 됩니다. 엎드려서 자거나 옆으로 누워서 자는 분들은 장시간 베개에 피부가 눌리면서 주름의 원인까지 될 수 있어요. 이를 예방하려면 베개 커버를 일주일에 한두 번 세탁하거나, 귀찮으면 매일 베개 위에 세탁한 수건을 깔고 주무시면 됩니다. 웬만하면 똑바로 누워서 자는 습관을 들이고, 머리 감은 후에는 수건으로 장시간 감싸지 말고 빨리 드라이기로 말려주세요.', '베개에서 변기보다 96배 많은 세균이 검출됐다는 연구가 있습니다. 세균 번식을 막는 세탁 주기와 수면 자세 관리법을 피부과 전문의 고혜림이 안내합니다.', array['베개커버', '세균', '트러블', '수면자세', '주름', '두피관리', '위생']::text[]),
    ('pgAA5ySxd68', 'leedoyoung', '울쎄라·써마지 받았는데도 처지는 건 왜 그런 거예요?', '울쎄라와 써마지로는 개선할 수 없는 부분이 있는데, 바로 얼굴 근육의 노화입니다. 근육도 나이가 들면 힘이 떨어지는데, 이게 얼굴 처짐과 밀접한 연관이 있어요. 나이 들면 입꼬리가 처지는 건 큰 광대근의 힘이 떨어져 입꼬리를 못 올리기 때문이고, 눈꺼풀이 덮이는 건 이마 근육 힘이 빠져서 그래요. 입을 다무는 힘이 떨어지면 얼굴이 처진다는 논문도 있을 정도입니다. 얼굴 근육들은 서로 밀접하게 연결되어 있어서 한쪽이 약해지면 다른 쪽에 보상성으로 힘이 더 들어가요. 이마 근육 힘이 빠지면 눈썹 주름근과 눈둘레근이 보상성으로 세져서 미간 주름과 눈가 주름이 심해지는 거죠. 피부만 타이트하게 당겨도 근육 자체의 노화를 해결하지 못하면 처짐이 계속됩니다.', '울쎄라·써마지로 개선 안 되는 얼굴 근육 노화와 처짐의 원인을 피부과 전문의 이도영이 설명합니다.', array['울쎄라', '써마지', '리프팅', '얼굴근육', '처짐', '광대근', '노화']::text[]),
    ('pgAA5ySxd68', 'leedoyoung', '집에서 얼굴 근육 운동 기구 쓰면 팔자주름에 효과 있나요?', '네, 논문에 따르면 하루 2번 30초씩 8주간 주 6일 이상 사용했을 때 볼의 광대근과 턱 밑 두힘살근이 두꺼워졌다는 결과가 있습니다. 파오 같은 얼굴 운동 기구를 입술로 고정하고 고개를 위아래로 리듬감 있게 움직이면 광대 쪽과 턱 밑에 확실히 힘이 들어가요. 사용 시 치아가 아닌 입술로 기구를 고정하고, 귀·어깨·골반이 일직선이 되도록 자세를 유지하는 게 중요합니다. 입을 다물고 고개를 위아래로 흔들면 입 다무는 힘이 자연스럽게 강화되어 팔자주름과 턱 라인 개선 효과를 기대할 수 있어요. 운동 전에는 고개를 가볍게 스트레칭해서 근육을 풀어주시고요. 혼자 운동하는 게 어렵거나 작심삼일이 되는 분이라면 병원에서 EMS 장비를 활용하는 방법도 있습니다.', '얼굴 근육 운동 기구(파오)의 사용법과 팔자주름 개선 효과를 피부과 전문의 이도영이 정리합니다.', array['얼굴운동', '파오', '팔자주름', '턱라인', '광대근', '두힘살근', '리프팅']::text[]),
    ('pgAA5ySxd68', 'leedoyoung', '엠페이스랑 조비나 차이가 뭐예요? 얼마나 받아야 하나요?', '둘 다 EMS로 얼굴 근육을 수축시켜 운동시키는 장비인데, 방식이 다릅니다. 엠페이스는 이마와 양볼에 부착해서 20분간 한 군데를 집중적으로 자극하고, 열까지 줘서 콜라겐과 엘라스틴 생성도 촉진해요. 조비나는 문질문질하면서 얼굴 구석구석 골고루 근육을 자극하는 방식이라 넓은 범위를 커버할 수 있습니다. 시술 횟수는 일주일 간격으로 5번 정도가 기본이고, 이후에는 몇 달 쉬었다가 생각날 때마다 받으면 됩니다. 근육은 한번 트레이닝하면 그 상태를 기억하기 때문에, 자전거 타기처럼 한번 익히면 쉬어도 금방 그 느낌을 되찾을 수 있어요. 초반 5회로 근육 기억을 만들고 유지 차원에서 간헐적으로 시술받는 패턴이 가장 효율적입니다.', '엠페이스와 조비나의 차이점 및 적정 시술 횟수를 피부과 전문의 이도영이 안내합니다.', array['엠페이스', '조비나', 'EMS', '리프팅', '콜라겐', '근육운동', '시술횟수']::text[]),
    ('pgAA5ySxd68', 'leedoyoung', '보톡스 맞으면 근육 힘 빠지는데, 그럼 더 처지는 거 아닌가요?', '좋은 질문인데, 보톡스는 보상성으로 과하게 수축하는 근육에 맞는 거라 오히려 균형을 맞추는 역할을 합니다. 얼굴 근육은 서로 연결되어 있어서 한쪽 힘이 떨어지면 다른 쪽에 보상성으로 힘이 더 들어가요. 의자에 앉아 있다가 의자를 빼면 허벅지에 힘이 빡 들어가는 것처럼, 이마 근육이 약해지면 눈썹 주름근과 눈둘레근이 세지면서 미간·눈가 주름이 심해지는 겁니다. 이렇게 보상성으로 과수축하는 부위에 보톡스를 놓으면 주름이 쫙 펴지는 거죠. 반대로 힘이 약해진 근육에는 보톡스가 아니라 운동을 시켜야 합니다. 엠페이스나 조비나 같은 EMS 장비로 약해진 근육을 강화하고, 과수축하는 근육은 보톡스로 억제하는 게 균형 잡힌 접근이에요.', '보톡스가 얼굴 처짐을 악화시키지 않는 원리와 근육 균형을 피부과 전문의 이도영이 설명합니다.', array['보톡스', '얼굴근육', '처짐', '보상성수축', '엠페이스', '주름', '리프팅']::text[]),
    ('MrvJDn2FTxY', 'jeonghanmi', '레티놀이랑 레티날 뭐가 더 좋아요? 차이가 뭔가요?', '레티날이 레티놀보다 약 10배 강력한 효과를 냅니다. 둘 다 레티노이드 계열 성분이지만 피부 속에서 최종 활성형인 레티노익산으로 변환되는 단계가 다릅니다. 레티놀은 씨앗 단계처럼 여러 변환 과정을 거쳐야 효과가 나타나고, 레티날은 꽃이 핀 단계처럼 한 단계만 변환되면 바로 효과를 볼 수 있어요. 그래서 같은 농도로 바르면 레티날이 훨씬 빠르고 강하게 작용합니다. 대신 레티놀은 자극이 가장 적어서 누구나 쓸 수 있는 장점이 있어요. 처음 레티노이드를 시작하는 분이라면 레티놀로 피부를 적응시킨 뒤 레티날로 올리는 전략이 안전합니다. 최상위 레티노익산(스티바A)은 효과가 가장 강력하지만 피부가 벗겨지고 빨개지는 부작용이 심해 반드시 의사 처방이 필요한 전문의약품이에요.', '레티날과 레티놀의 효능 차이와 레티노이드 등급별 특성을 피부과 전문의 정한미가 설명합니다.', array['레티날', '레티놀', '레티노이드', '스킨케어', '안티에이징', '잔주름', '레티노익산']::text[]),
    ('MrvJDn2FTxY', 'jeonghanmi', '레티날 제품 뭘 사야 하나요? 피부과 의사가 쓰는 제품이 궁금해요', '안정화 기술이 잘 적용된 제품 세 가지를 추천드립니다. 첫째, 더마팩토리 레티날 1000ppm 크림은 가성비가 뛰어나고 판테놀과 나이아신아마이드가 함께 들어있어 자극받은 피부 장벽을 보호해 줍니다. 입문자는 0.03%부터, 적응 후 0.1%로 올리면 됩니다. 둘째, 디오디너리 레티날 0.2% 에멀전은 상급자용으로 에어리스 펌프가 공기 접촉을 차단해 주고 로션 제형이라 끈적임이 적어요. 셋째, 닥터디퍼런트 비타리프트 시리즈는 0.025%부터 0.2%까지 6단계 농도가 있어 입문자부터 고수까지 레벨업이 가능합니다. 세라마이드와 히알루론산이 들어있어 이것 하나면 별도 보습크림이 필요 없을 정도예요. 레티날은 빛과 공기에 취약하므로 리포좀 기술이나 에어리스 용기가 적용된 제품을 고르는 게 핵심입니다.', '안정화 기술이 적용된 레티날 크림 세 가지 추천과 선택 기준을 피부과 전문의 정한미가 정리합니다.', array['레티날', '더마팩토리', '디오디너리', '닥터디퍼런트', '비타리프트', '보습', '에어리스']::text[]),
    ('MrvJDn2FTxY', 'jeonghanmi', '레티날 처음 바르는데 매일 써도 되나요? 주의사항이 뭐예요?', '처음부터 매일 바르면 자극이 너무 심할 수 있으니 일주일에 1~2번만 시작하세요. 피부가 적응할 시간을 줘야 하기 때문에 크림에 섞어 희석해서 쓰는 것도 좋은 방법입니다. 반드시 밤에만 사용해야 하는데, 빛과 만나면 레티날이 분해될 수 있고 자외선과 만나면 피부 자극이 더 심해져요. 비타민C나 AHA, BHA 같은 각질제거 성분과는 같이 사용하지 마세요. 이런 성분과 함께 쓰면 피부가 과도하게 민감해질 수 있습니다. 특히 레티날을 바르면서 자외선 차단제를 제대로 바르지 않으면 오히려 색소침착이 생길 수 있어요. 또 한 가지, 레티날 자체가 노란색이어서 농도가 높을수록 색이 진해지니 베개나 옷에 묻지 않게 조심하시는 게 좋습니다.', '레티날 입문자를 위한 사용 빈도와 필수 주의사항을 피부과 전문의 정한미가 안내합니다.', array['레티날', '사용법', '자외선차단제', '각질제거', '부작용', '민감피부', '선크림']::text[]),
    ('MrvJDn2FTxY', 'jeonghanmi', '피부과 의사한테 화장품 딱 하나만 고르라면 뭘 골라요?', '여러 화장품 성분 중에 딱 하나를 고르라면 레티노이드를 선택하겠습니다. 레티날은 오래된 세포를 빨리 없애고 새로운 피부세포가 빠르게 생성되도록 도와줘서 잔주름, 모공 개선은 물론 색소침착까지 옅어지게 하는 노화 역전 효과가 있어요. 심지어 목주름까지 개선될 수 있습니다. 심플한 스킨케어 루틴을 원하시는 분은 이거 하나만 꾸준히 발라도 수백만 원어치 화장품을 바르는 사람보다 더 좋은 결과를 볼 수 있어요. 다만 피부 자극이 있을 수 있으니 컨디션이 안 좋거나 농도를 올릴 때는 조심해야 합니다. 만약 바르다가 피부가 뒤집어졌다면 사용을 중단하고 피부 장벽을 회복시킬 수 있는 크림을 발라서 피부를 회복시킨 다음 다시 쓰면 됩니다.', '피부과 의사가 화장품 한 가지만 고른다면 레티노이드인 이유를 피부과 전문의 정한미가 설명합니다.', array['레티날', '레티노이드', '안티에이징', '잔주름', '모공', '색소침착', '피부노화']::text[]),
    ('a1erQIFKqtc', 'leedoyoung', '결혼식 일주일 전에 어떤 시술 받으면 좋아요?', '다운타임 없이 즉각적으로 광이 나는 시술 세 가지 조합을 추천합니다. 티타늄 리프팅으로 탄력과 톤, 라인을 끌어올리고, 비타란으로 속 보습을 채우고, 제네오엑스로 피부결을 정돈하면 화장이 엄청 잘 먹고 얼굴 라인이 확 잡혀요. 티타늄은 세 가지 파장의 빛으로 표피, 진피, 피하지방층에 동시에 열을 줘서 즉각적인 리프팅 효과가 나타나고, 며칠 지나면 피부톤도 점점 밝아집니다. 비타란은 하이브리드 방식으로 피부 밑에 얇게 깔아줘서 엠보 없이 바로 광이 돌고요. 제네오엑스는 이산화탄소 버블로 산소 공급을 늘려 시술 직후 피부가 맑아지고 광이 납니다. 이 세 가지를 같은 날 받을 수 있어서 바쁜 웨딩 준비 중에도 한 번 방문으로 해결이 가능해요.', '결혼식 직전 다운타임 없는 벼락치기 시술 조합 세 가지를 피부과 전문의 이도영이 안내합니다.', array['결혼식시술', '티타늄리프팅', '비타란', '제네오엑스', '다운타임', '웨딩피부관리', '리프팅']::text[]),
    ('a1erQIFKqtc', 'leedoyoung', '티타늄 리프팅이 울쎄라랑 비슷한 거예요? 얼굴 안 까매져요?', '티타늄은 울쎄라, 써마지와 유사한 효과에 플러스 알파로 얼굴이 환해지는 시술입니다. 전혀 까매지거나 붓지 않고 효과가 즉각적이에요. BTS 효과라고 부르는데 B는 Brightening으로 얼굴이 화사해지고, T는 Tightening으로 피부가 탄탄해지며, S는 Slimming으로 얼굴 라인이 갸름해집니다. 시술하면 바로 리프팅 효과가 보이고 며칠 지나면 피부톤도 점점 더 밝아져요. 가장 큰 장점은 중요한 약속 전날에도 가능하다는 점인데, 붓기도 별로 없고 화장도 바로 가능하거든요. 그래서 연예인분들이 방송 전날에도 많이 받으세요. 통증도 거의 없어서 부담 없이 시술 받으실 수 있습니다.', '티타늄 리프팅의 즉각적 BTS 효과와 울쎄라 대비 장점을 피부과 전문의 이도영이 설명합니다.', array['티타늄리프팅', '울쎄라', '써마지', '리프팅', 'BTS효과', '피부톤', '슬리밍']::text[]),
    ('a1erQIFKqtc', 'leedoyoung', '결혼식 전에 보톡스 맞아도 되나요? 절대 하면 안 되는 시술이 뭐예요?', '중요한 이벤트 일주일 전에 보톡스는 절대 맞으면 안 됩니다. 일반 보톡스도 효과가 나타나기까지 일주일이 걸리고, 사각턱 보톡스는 한 달 정도 생각해야 해요. 게다가 사각턱 보톡스는 부작용이 생길 수 있는 부위라서 입이 비뚤어지면 중요한 날을 망칠 수 있습니다. 색소 레이저도 피해야 하는데, 어차피 메이크업으로 기미와 잡티는 다 가려지니까 지금 굳이 받을 이유가 없어요. 모공이나 여드름 흉터 치료도 회복에 꽤 오랜 시간이 걸려서 몇 달 전부터 서서히 준비해야 하는 시술입니다. 결혼식처럼 중요한 날 직전에는 다운타임이 없고 즉각 효과가 나타나는 시술만 선택하는 게 핵심이에요.', '중요한 날 직전에 절대 피해야 할 시술 세 가지와 그 이유를 피부과 전문의 이도영이 정리합니다.', array['보톡스', '사각턱', '결혼식', '색소레이저', '다운타임', '부작용', '벼락치기시술']::text[]),
    ('a1erQIFKqtc', 'leedoyoung', '돈 아끼면서 피부 관리하고 싶은데 가성비 시술 뭐가 좋아요?', '가성비 시술로는 코레지를 추천합니다. 원더걸스 소희 씨도 꾸준히 받는다고 알려진 시술인데, 16개의 고주파가 화음을 이루면서 피부 세포를 직접 자극하는 방식이에요. 마치 도, 미, 솔 각각보다 동시에 울릴 때 더 아름답게 들리듯이 고주파를 동시에 쏴주면 콜라겐과 엘라스틴 생성이 촉진되고 염증도 줄어들어요. 도자로 피부를 부드럽게 문지르면서 에너지를 전달하기 때문에 통증도 적습니다. 시술 직후부터 효과가 보이면서 시간이 갈수록 톤이 좋아지고 광이 나며 약간의 리프팅 효과까지 있어요. 부담 없는 비용으로 가끔 피부 컨디션을 올리고 싶을 때 받으면 정말 만족스러운 시술입니다.', '가성비 좋은 고주파 시술 코레지의 원리와 효과를 피부과 전문의 이도영이 안내합니다.', array['코레지', '가성비시술', '고주파', '콜라겐', '피부관리', '탄력', '피부톤']::text[]),
    ('rAa4jsDXbvE', 'jeonghanmi', '미세먼지가 자외선보다 피부에 더 안 좋다는 게 사실인가요?', '미세먼지는 자외선만큼이나 피부 노화를 일으키는 심각한 원인입니다. WHO 자료에 따르면 하루 동안 미세먼지에 노출된 피부가 일주일 동안 햇빛을 쬔 피부보다 손상이 더 심한 것으로 나타났습니다. 초미세먼지는 머리카락 굵기의 1/30 정도로 매우 작아서 모공을 통해 피부 속으로 침투할 수 있어요. 미국의 한 연구팀 실험에서는 피부를 통한 미세먼지 흡수량이 호흡기를 통한 흡수량과 비슷했고, 60대 참가자의 피부 흡수율은 20대보다 5배나 높았습니다. 피부 속으로 들어간 미세먼지는 쇠가 녹스는 것처럼 피부를 산화시키고, 염증을 일으키며, 피부 장벽까지 망가뜨려요. 특히 자외선과 미세먼지가 동시에 작용하면 염증 반응이 더 심해지기 쉽습니다. 이런 손상이 쌓이면 피부 노화, 색소침착, 기미, 여드름, 아토피 같은 피부 질환이 악화될 수 있으니 주의하세요.', '미세먼지가 피부를 손상시키는 메커니즘과 자외선과의 시너지 효과를 피부과 전문의 정한미가 설명합니다.', array['미세먼지', '피부노화', '피부장벽', '활성산소', '염증', '색소침착', '기미']::text[]),
    ('rAa4jsDXbvE', 'jeonghanmi', '비타민C 바르면 미세먼지 피부 손상을 진짜 막을 수 있나요?', '비타민C를 바르면 미세먼지로 인한 피부 노화를 효과적으로 막을 수 있습니다. 이탈리아 연구진이 밝혀낸 바에 따르면 비타민C는 미세먼지가 공격하는 세 가지 지점을 정확히 차단해요. 첫째, 미세먼지가 만드는 활성산소를 직접 제거하는 항산화 작용이 있고, 둘째 염증 반응을 진정시키는 항염 효과가 있으며, 셋째 피부 장벽의 단백질 생성을 촉진해서 장벽을 튼튼하게 만들어줍니다. 특히 비타민C로 전처리한 피부 세포는 자외선과 미세먼지에 동시에 노출되어도 거의 손상이 없었다는 연구 결과도 있어요. 다만 아무 비타민C나 바르면 안 되고, 순수 비타민C 함량이 15% 이상이어야 하며 비타민E나 페룰릭산 같은 안정제가 포함된 제품을 선택하셔야 합니다. 바르는 시점은 미세먼지를 만나기 전인 외출 전이 좋고, 선크림도 반드시 함께 발라주세요.', '비타민C가 미세먼지 피부 손상을 막는 원리와 올바른 사용법을 피부과 전문의 정한미가 안내합니다.', array['비타민C', '항산화', '미세먼지', '피부장벽', '항염', '선크림', '피부노화']::text[]),
    ('rAa4jsDXbvE', 'jeonghanmi', '건성이랑 지성 중 미세먼지에 더 취약한 피부가 뭔가요?', '건성, 지성, 민감성 피부 모두 미세먼지에 취약하지만 각각 다른 방식으로 영향을 받습니다. 건성 피부는 원래 수분이 부족한데 미세먼지가 피부 장벽을 손상시키면서 수분 손실이 더 빨라지고, 가려움이나 따가움 같은 염증 반응이 심해지기 쉬워요. 지성 피부는 피지 성분에 미세먼지가 잘 들러붙기 때문에 피지와 뭉친 미세먼지가 모공 속으로 들어가 염증을 일으키면서 여드름이 악화됩니다. 민감성 피부는 안 그래도 예민한 상태에서 미세먼지가 염증을 더 심하게 만들고 장벽을 손상시켜 더 예민해지게 만들어요. 더 큰 문제는 이 과정이 악순환을 일으킨다는 점입니다. 피부 장벽이 무너지면 더 많은 미세먼지가 침투하고, 그로 인해 또 심한 손상이 생기면서 피부가 계속 나빠져요. 건성이나 민감성 피부를 가진 분들이 특히 취약한 편이므로 장벽 강화에 신경 쓰시는 게 좋습니다.', '건성·지성·민감성 피부가 미세먼지에 각각 다르게 손상되는 이유와 장벽 악순환 원리를 피부과 전문의 정한미가 정리합니다.', array['미세먼지', '건성피부', '지성피부', '민감성피부', '여드름', '피부장벽', '피부타입']::text[]),
    ('rAa4jsDXbvE', 'jeonghanmi', '미세먼지 심한 날 외출하면 집에 와서 뭐부터 해야 하나요?', '미세먼지가 심한 날에는 이중세안과 보습 강화가 핵심입니다. 외출 전에는 항산화 성분인 비타민C 세럼을 먼저 바르고 선크림을 꼭 함께 발라서 미세먼지와 자외선의 시너지 손상을 막아주세요. 외출 시에는 가급적 피부에 공기가 닿지 않도록 마스크를 쓰고 긴팔을 입는 것이 좋습니다. 귀가 후에는 반드시 이중세안을 해주셔야 해요. 클렌징 오일이나 밀크 같은 1차 세안제로 먼저 노폐물을 녹여낸 다음, 폼클렌저로 한 번 더 씻어내야 피지와 결합해서 피부에 붙어있는 미세먼지까지 깨끗하게 제거할 수 있습니다. 세안 후에는 미세먼지로 약해진 피부 장벽을 강화해주는 보습이 중요해요. 세라마이드나 히알루론산 같은 성분이 풍부한 크림으로 충분히 보습해주시면 장벽 회복에 도움이 됩니다.', '미세먼지 심한 날 비타민C 세럼과 이중세안, 보습 강화까지 외출 전후 스킨케어 루틴을 피부과 전문의 정한미가 안내합니다.', array['미세먼지', '이중세안', '보습', '세라마이드', '히알루론산', '선크림', '비타민C', '피부장벽']::text[]),
    ('QMCQ2sOAjXU', 'jeonghanmi', '빨대 쓰면 진짜 입가 주름 생기나요?', '빨대 사용, 스마트폰 자세, 수면 자세 이 세 가지가 대표적인 주름 유발 습관입니다. 빨대를 쓸 때 입을 오므리는 동작이 반복되면 입 둘레에 주름이 생기기 쉽고, 한번 생기면 없어지지 않아서 나이 들어 보이는 원인이 돼요. 스마트폰을 볼 때 고개를 숙이면 목이 구부러지면서 턱살이 처지고 목주름이 생기는데 이를 텍스트넥이라고도 합니다. 스마트폰을 눈높이까지 올려서 보는 습관을 들이면 턱과 목 주름을 크게 줄일 수 있어요. 수면 자세도 중요한데, 옆으로 누우면 얼굴 한쪽에 압력이 가해져 시간이 지나면서 한쪽 팔자주름이 더 심해질 수 있습니다. 천장을 보고 똑바로 누워서 자는 게 좋고, 베개 높이도 너무 높지 않게 조절하면 목주름 예방에 도움이 되니 오늘부터 점검해 보세요.', '빨대 사용, 스마트폰 자세, 수면 자세 등 주름을 만드는 대표적인 생활습관과 예방법을 피부과 전문의 정한미가 설명합니다', array['주름', '팔자주름', '목주름', '생활습관', '빨대', '텍스트넥', '수면자세', '입가주름']::text[]),
    ('QMCQ2sOAjXU', 'jeonghanmi', '레티놀이랑 비타민C 같이 바르면 효과 더 좋은가요?', '레티놀은 이미 생긴 주름을 개선하는 데 가장 효과적인 안티에이징 성분입니다. 피부세포의 턴오버(세포 재생 주기)를 촉진하고 콜라겐 생성을 자극해서 피부를 탱탱하게 만들어줘요. 레티날은 레티놀보다 한 단계 더 강한 성분입니다. 처음 사용하시는 분들은 낮은 농도로 일주일에 2~3회 정도 시작해서 점점 늘려가야 하고, 자외선에 민감해질 수 있어서 주로 저녁에 바르고 다음 날 아침엔 꼭 선크림을 발라야 해요. 비타민C는 강력한 항산화제로 자외선으로부터 피부를 보호하고 콜라겐 합성을 도우며 멜라닌 색소 생성도 억제해 기미와 잡티 개선까지 가능한 성분입니다. 두 성분을 동시에 바르면 자극이 될 수 있으니 아침에 비타민C, 저녁에 레티놀로 시간을 나눠서 사용하시는 게 좋습니다.', '레티놀과 비타민C를 아침·저녁 나눠 바르는 방법과 주름 개선 원리를 피부과 전문의 정한미가 설명합니다', array['레티놀', '비타민C', '주름', '콜라겐', '안티에이징', '레티날', '기미', '잡티']::text[]),
    ('QMCQ2sOAjXU', 'jeonghanmi', '흐린 날이나 실내에서도 선크림 꼭 발라야 하나요?', '피부 노화의 80%는 자외선 때문에 생기므로 선크림은 주름 예방에 가장 중요한 단계입니다. 자외선에 노출되면 피부 속 콜라겐과 엘라스틴이 파괴되면서 피부가 얇아지고 주름이 생기게 돼요. 흐린 날에도 자외선의 90% 이상이 구름을 통과하기 때문에 반드시 발라야 합니다. 실내에서는 유리창을 통해 자외선이 들어올 수 있어서 운전을 많이 하거나 창가에 자리가 있는 경우에는 꼭 발라주셔야 해요. 다만 햇빛이 거의 안 드는 실내에서는 굳이 바를 필요는 없습니다. 형광등이나 LED 등에서도 자외선이 나올 수 있긴 하지만 양이 매우 적어 무시해도 될 수준이니 크게 걱정하지 않으셔도 돼요.', '피부과 전문의 정한미가 선크림을 흐린 날과 실내에서도 발라야 하는 이유와 예외 상황을 설명합니다', array['선크림', '자외선', '주름', '콜라겐', '피부노화', '실내자외선', '흐린날', '엘라스틴']::text[]),
    ('QMCQ2sOAjXU', 'jeonghanmi', '이마 주름엔 보톡스, 깊은 주름엔 필러라는데 정말인가요?', '표정 지을 때 생기는 이마, 눈가, 미간 주름에는 보톡스가 가장 확실한 방법입니다. 주름이 깊어지기 전인 30대부터 미리 맞는 게 좋은데, 이미 깊게 자리 잡으면 보톡스만으로는 해결이 안 되기 때문에 미리 관리하는 편이 훨씬 경제적이고 효과적이에요. 보톡스로도 안 펴지는 깊게 패인 주름에는 필러가 필요합니다. 필러는 피부의 얕은 층에 조금씩 주입해서 패인 부분을 채워 올리는 방식이라 깊은 주름에는 필러만한 게 없어요. 눈가, 눈 아래, 입가의 자글자글한 잔주름에는 스킨부스터가 효과적입니다. 스킨부스터는 히알루론산 등 영양성분을 피부 속에 주입해 수분과 탄력을 높여 잔주름을 개선시켜주는 시술로, 리쥬란이나 쥬베룩 등 종류가 다양하니 자기 피부 상태에 맞는 시술을 선택하시는 게 가장 좋습니다.', '피부과 전문의 정한미가 주름 깊이와 부위에 따라 보톡스 필러 스킨부스터 선택법을 설명합니다', array['보톡스', '필러', '스킨부스터', '주름', '리쥬란', '쥬베룩', '잔주름', '리프팅', '콜라겐']::text[]),
    ('RiLTNyvpQrc', 'kwonsuhyun', '지성 피부인데 세안만 잘해도 모공이 줄어드나요?', '지성 피부는 반드시 이중 세안을 해야 모공에 낀 피지와 노폐물을 깨끗하게 제거할 수 있습니다. 1차 세안은 클렌징 밀크나 오일로 화장과 피지를 녹여내고, 2차 세안은 폼클렌저로 남은 잔여물까지 헹궈내는 방식이에요. 제품 종류보다는 노폐물을 녹여낼 수 있는 단계를 반드시 거치는 게 핵심입니다. 세안 시에는 미지근한 물을 사용하고 마무리는 시원한 물로 해주시면 좋아요. 추가로 필링젤을 활용하면 다음 날 피부결이 매끈해지는데, 겨울에는 1~2주에 한 번, 여름에는 일주일에 두 번 정도가 적당합니다. 다만 필링젤은 피부 장벽에 자극을 줄 수 있으므로 본인 피부 상태를 보고 빈도를 조절해 보세요. 아침에도 물세안이 아닌 폼클렌징 세안을 꼭 해주셔야 밤사이 올라온 피지와 노폐물이 제대로 씻겨 나갑니다.', '피부과 전문의 권수현이 지성 피부를 위한 이중 세안법과 필링젤 사용 주기, 아침 폼클렌징의 중요성을 설명합니다.', array['지성피부', '이중세안', '클렌징', '모공', '피지', '필링젤', '폼클렌징', '세안법']::text[]),
    ('RiLTNyvpQrc', 'kwonsuhyun', '리들샷 바르고 비타민C 쓰면 흡수가 더 잘 되나요?', '리들샷을 먼저 바른 뒤 비타민C 앰플을 바르면 흡수력이 높아져 더 효과적으로 사용할 수 있습니다. 리들샷은 바늘 모양의 미세 입자가 피부 각질층을 뚫어주는 역할을 하기 때문에, 그 위에 바르는 화장품 성분이 피부 속으로 더 잘 침투하게 돕습니다. 비타민C 화장품 자체가 노화 예방, 탄력 개선, 피부톤 브라이트닝에 도움이 되는 성분이라 꾸준히 챙겨 바르시는 게 좋아요. 다만 리들샷이나 비타민C 앰플 모두 처음 바를 때 따가울 수 있습니다. 그래서 처음부터 두 가지를 한꺼번에 사용하지 마시고, 하나씩 먼저 적응한 뒤에 함께 사용해 보세요. 닦토(닦아내는 토너)로 잔여 피지와 각질을 한 번 더 정리한 후에 이 순서를 적용하면 기초 케어 효과를 극대화할 수 있습니다.', '피부과 전문의 권수현이 리들샷과 비타민C 앰플을 함께 사용하는 방법과 주의사항, 흡수력 높이는 순서를 알려줍니다.', array['비타민C', '리들샷', '흡수력', '항노화', '피부톤', '닦토', '각질층', '스킨케어']::text[]),
    ('RiLTNyvpQrc', 'kwonsuhyun', '스티바A 크림 단종됐는데 뭘로 대체하면 되나요?', '스티바A 크림의 대체제로는 갈더마코리아의 아크리프 크림이 가장 적합합니다. 아크리프 크림은 처방받아야 구매 가능한 전문 의약품이기 때문에 일반 레티놀이나 레티날 화장품보다 항노화 효과가 훨씬 뛰어나요. 또한 원래 여드름 치료에 쓰는 약이라서 여드름과 피지 조절에도 탁월한 효과를 기대할 수 있습니다. 다만 자극감이 있을 수 있으므로 처음에는 다른 보습 크림과 섞어서 바르다가, 적응이 되면 단독으로 사용하시는 게 좋아요. 참고로 여드름이 막 올라오기 시작할 때는 초기 대응이 가장 중요한데요, 붉어지고 만지면 아플 때 진통소염제 성분이 든 애크논 크림을 트러블 부위에 도톰하게 덮어주면 악화를 막을 수 있습니다. 애크논 크림은 약국에서 처방 없이 구매 가능하니 참고해 보세요.', '피부과 전문의 권수현이 단종된 스티바A 크림의 대체제인 아크리프 크림 사용법과 여드름 초기 대응법을 설명합니다.', array['스티바A', '아크리프', '항노화', '레티놀', '여드름', '피지조절', '애크논', '전문의약품']::text[]),
    ('RiLTNyvpQrc', 'kwonsuhyun', '지성 피부는 오후만 되면 화장 무너지는데 방법 없나요?', '지성 피부의 화장 지속력을 높이려면 파우더 밀착과 기름종이 활용이 핵심입니다. 파운데이션을 바른 후 세팅 파우더를 적당량 덜어서 힘 있게 밀착시켜 두드려 주면 화장이 두껍지 않으면서도 오래 유지돼요. 픽서 대신 파우더가 발린 기름종이를 2~3시간마다 피부에 눌러주는 방법이 지성 피부에는 훨씬 효과적입니다. 일반 파우더로 수정 화장을 하면 유분기는 잡히지만 오히려 화장이 뭉치기 쉽기 때문이에요. 기름종이 파우더 타입은 유분만 흡수하면서 화장 무너짐을 방지해 줍니다. 모공 커버가 필요할 때는 실리콘 베이스 프라이머를 모공 부위에 열감을 이용해 여러 번 문질러 넣고 톡톡 두드려 주면 파운데이션이 깔끔하게 발려요. 프라이머를 사용한 날에는 반드시 이중 세안을 해주셔야 합니다.', '피부과 전문의 권수현이 지성 피부의 화장 지속력을 높이는 파우더 밀착법과 기름종이 활용 팁을 공유합니다.', array['화장지속력', '파우더', '기름종이', '지성피부', '모공커버', '프라이머', '세팅파우더', '메이크업']::text[]),
    ('KUygxZviqWw', 'jeonghanmi', '스컬트라 맞으면 콜라겐이 진짜 새로 만들어지나요?', '스컬트라는 피부 속 섬유아세포를 자극해 콜라겐을 새로 만들어내게 하는 시술입니다. 나이가 들면 콜라겐을 만드는 섬유아세포의 기능이 떨어져 얼굴 볼륨이 줄어드는데, 스컬트라 성분이 이 세포들을 다시 활성화시켜 줘요. 새롭게 합성된 콜라겐이 서서히 차오르면서 자연스러운 볼륨이 만들어지는 방식입니다. 완성된 물질을 바로 넣는 게 아니라 피부가 스스로 콜라겐을 생성하는 구조이기 때문에 효과가 천천히 나타나는 편이에요. 보통 시술 후 3~4주부터 서서히 변화가 보이기 시작하고, 3~6개월에 걸쳐 점점 좋아집니다. 리프팅 없이 꺼진 부위만 채워도 5년은 젊어 보이는 효과를 기대할 수 있어요. 시술 티 없이 자연스러운 볼륨 회복을 원하시는 분들에게 추천드립니다.', '스컬트라가 섬유아세포를 자극해 콜라겐을 생성하는 원리와 볼륨 회복 시기를 피부과 전문의 정한미가 설명합니다', array['스컬트라', '콜라겐', '섬유아세포', '볼륨회복', '얼굴꺼짐', '노화', '자연스러운시술', '피부탄력']::text[]),
    ('KUygxZviqWw', 'jeonghanmi', '스컬트라랑 필러 중 얼굴 볼륨 채우기엔 뭐가 더 좋아요?', '스컬트라와 필러는 둘 다 볼륨을 채우지만 작용 방식과 지속기간이 다릅니다. 필러는 히알루론산이라는 젤리 같은 물질을 직접 넣어 즉시 볼륨을 만들어주고, 원하는 부위에 원하는 만큼 정확하게 채울 수 있어요. 반면 스컬트라는 피부가 콜라겐을 만들어내도록 유도하는 방식이라 효과가 서서히 나타나며, 사람마다 콜라겐 생성량이 달라 결과에 차이가 있을 수 있습니다. 지속기간은 필러가 보통 1년 정도인 반면 스컬트라는 약 2년 정도 유지돼요. 시술 횟수도 다른데, 필러는 한 번이면 되지만 스컬트라는 2~3회 시술이 필요합니다. 또한 스컬트라는 눈 주변, 이마, 입가처럼 움직임이 많고 피부가 얇은 부위에는 시술할 수 없어요. 각각 장단점이 있으니 본인 상황에 맞게 선택해 보세요.', '스컬트라와 필러의 성분, 작용 방식, 지속기간, 시술 횟수 등 핵심 차이를 피부과 전문의 정한미가 비교합니다', array['스컬트라', '필러', '히알루론산', '볼륨', '지속기간', '시술횟수', '콜라겐', '차이점']::text[]),
    ('KUygxZviqWw', 'jeonghanmi', '얼굴이 마르고 꺼진 사람은 스컬트라가 답인가요?', '스컬트라는 노화로 인한 얼굴 꺼짐이 있는 30대 중후반부터 60대까지 폭넓게 적합합니다. 특히 얼굴이 전체적으로 마르고 군데군데 꺼진 분들에게 효과가 좋아요. 볼륨이 필요하지만 시술 티 나지 않는 자연스러운 결과를 중요하게 생각하시는 분들에게도 잘 맞는 편입니다. 피부가 얇아 잔주름이 많고 탄력이 떨어진 분들도 좋은 대상이에요. 시술 부위는 관자놀이, 광대뼈 아래, 볼 꺼진 부위가 대표적입니다. 관자놀이가 꺼지면 해골 같은 인상을 주고, 광대와 볼이 꺼지면 뼈가 튀어나와 울퉁불퉁해 보이는데, 이런 부위들이 나이 들면서 볼륨이 가장 많이 줄어드는 곳이거든요. 스컬트라로 채우면 우아하고 귀티 나는 인상으로 개선할 수 있으니 해당되시는 분들은 상담받아 보세요.', '스컬트라 시술이 적합한 대상과 관자놀이·볼 등 효과 좋은 부위를 피부과 전문의 정한미가 안내합니다', array['스컬트라', '얼굴꺼짐', '관자놀이', '광대', '볼륨', '노화', '잔주름', '탄력', '시술부위']::text[]),
    ('KUygxZviqWw', 'jeonghanmi', '스컬트라 부작용으로 결절 생긴다는데 괜찮은 건가요?', '스컬트라의 대표적인 부작용은 피부에 딱딱하게 만져지는 결절(덩어리)이 생길 수 있다는 점입니다. 다만 스컬트라는 20년 넘게 전 세계에서 시술되어 온 만큼 충분히 검증된 시술이고, 시술 방법이 많이 개선되면서 최근에는 결절 발생 확률이 상당히 낮아졌어요. 효과 지속기간은 개인차가 있지만 대부분 약 2년 정도 유지됩니다. 필러가 보통 1년 정도 지속되는 것에 비하면 오래 유지되는 편이죠. 단, 시술 직후 볼륨이 생긴 것처럼 보이는 건 주사용수 때문이고 1~2일 내로 흡수되기 때문에 착각하기 쉽습니다. 실제 콜라겐 생성 효과는 3~4주 후부터 서서히 나타나므로 중요한 일정 직전에 맞는 시술은 아니에요. 인내심을 갖고 기다리시면 자연스럽고 오래가는 결과를 얻을 수 있습니다.', '스컬트라의 결절 부작용 가능성과 안전성, 약 2년 지속되는 효과 기간을 피부과 전문의 정한미가 설명합니다', array['스컬트라', '부작용', '결절', '지속기간', '효과', '콜라겐생성', '주사용수', '안전성']::text[]),
    ('Sqb-UwUTHIE', 'gohyerim', '여드름 흉터 치료해도 효과 없다는 말이 사실인가요?', '여드름 흉터는 치료하면 분명히 좋아지지만, 100% 원래 피부로 돌아가지는 않습니다. 패인 정도를 완화시켜 매끄러워 보이게 하고 남들이 봤을 때 흉터가 덜 보이도록 개선하는 것이 치료 목표예요. 치료한 흉터와 하지 않은 흉터를 비교하면 확실히 차이가 납니다. 다만 깊게 패인 흉터는 새살이 차오르는 데 시간이 걸리기 때문에 꾸준히 치료해야 효과를 볼 수 있어요. 하루 이틀 운동한다고 식스팩이 안 보이듯, 흉터 치료도 마라톤처럼 천천히 완주한다는 마음으로 접근하셔야 합니다. 흉터가 생긴 지 얼마 안 됐을 때 빨리 시작하는 게 중요한데, 소문만 듣고 무서워서 못 오시다가 뒤늦게 오시면 치료 기간이 훨씬 길어지기 쉽습니다. 포기하지 않고 꾸준히 받으시면 치료 전보다 확실히 좋아지실 수 있으니 제때 내원하시길 권합니다.', '여드름 흉터 치료의 현실적 효과와 조기에 꾸준히 치료해야 하는 이유를 피부과 전문의 고혜림이 설명합니다', array['여드름흉터', '흉터치료', '패인흉터', '여드름자국', '흉터개선', '흉터레이저', '치료효과', '피부재생']::text[]),
    ('Sqb-UwUTHIE', 'gohyerim', '여드름 흉터 치료가 너무 아프다던데 참을 만한가요?', '여드름 흉터 치료가 아픈 건 맞지만, 모든 치료 과정이 다 아픈 건 아닙니다. 레이저 중에는 마취크림만 발라도 충분히 받을 만한 시술들이 있어요. 다만 CO2 프락셀 레이저나 쥬베룩 같은 주사 시술은 마취크림만으로 부족할 수 있습니다. 이런 경우에는 비수면 호흡마취를 사용하면 통증을 훨씬 덜 느낄 수 있어요. 어린아이들이 치과에서 사용하는 웃음가스와 같은 원리인데, 통증을 완전히 못 느끼는 건 아니지만 많이 줄어들어서 예민한 분들도 치료를 받으실 수 있습니다. 본인이 통증에 취약하다면 비수면 호흡마취를 제공하는 병원을 찾는 것도 좋은 대안이에요. 통증이 두려워서 치료를 미루시기보다는 이런 방법을 활용해 제때 치료받으시는 게 훨씬 낫습니다.', '여드름 흉터 치료의 통증 정도와 비수면 호흡마취 등 통증을 줄이는 방법을 피부과 전문의 고혜림이 안내합니다', array['흉터치료통증', '비수면마취', '웃음가스', 'CO2프락셀', '마취크림', '호흡마취', '쥬베룩', '레이저통증']::text[]),
    ('Sqb-UwUTHIE', 'gohyerim', '여드름 흉터 치료 시작하기 전에 뭘 각오해야 하나요?', '여드름 흉터 치료를 결심했다면 시작 전에 꼭 알아야 할 세 가지가 있습니다. 첫째, 패인 흉터는 치료해도 흉터가 생기기 전 피부로 완전히 돌아갈 수는 없어요. 둘째, 치료 후 다운타임이 있을 수 있습니다. 치료 종류에 따라 진물이 나고 딱지가 생기거나, 하루 이틀 정도 세안을 못 하고 재생 테이프를 붙여야 하는 경우도 있고, 얼굴이 붓거나 붉은 기가 1~2주 지속될 수도 있어요. 셋째, 문신 제거나 수염 제모와 함께 꽤 아픈 치료에 속하기 때문에 통증에 취약한 분은 미리 고려하셔야 합니다. 이런 과정을 모르고 오셨다가 설명 듣고 돌아가시는 분들도 있으니, 충분히 이해하고 내원하시면 치료 과정이 훨씬 수월해집니다.', '여드름 흉터 치료 전 반드시 알아야 할 다운타임, 통증, 회복 과정 주의사항을 피부과 전문의 고혜림이 정리합니다', array['흉터치료주의사항', '다운타임', '재생테이프', '흉터치료후관리', '붉은기', '딱지', '여드름흉터', '치료전준비']::text[]),
    ('Sqb-UwUTHIE', 'gohyerim', '피부과에서 패인 여드름 흉터를 어떤 식으로 치료하나요?', '여드름 흉터 치료의 기본 원리는 피부에 의도적으로 자극을 주어 재생을 유도하는 것입니다. 흉터 주변과 경계가 뚜렷한 경우에는 어븀 레이저로 가장자리를 깎아 매끄럽게 만들어줍니다. 깊고 뾰족한 아이스픽 흉터에는 TCA라는 산을 이용한 크로스 치료로 콜라겐 형성을 촉진시켜요. 염증으로 피부 조직이 엉겨붙은 부위는 서브시전(바늘이나 CO2 가스로 섬유화 조직을 끊어내는 시술)으로 함몰 부위가 올라오게 합니다. 이후 CO2 프락셀이나 피코 프락셀 레이저, 니들 RF(고주파로 콜라겐 생성) 등을 사용해요. 최근에는 미라젯이나 큐어젯 같은 무바늘 기기로 쥬베룩 같은 콜라겐 부스터를 주입하는 방법도 많이 쓰입니다. 이런 다양한 방법들을 흉터의 모양과 깊이에 따라 적절히 조합해서 치료하게 됩니다.', 'CO2 프락셀, 서브시전, 니들RF 등 여드름 흉터 치료 방법의 종류와 원리를 피부과 전문의 고혜림이 설명합니다', array['흉터치료방법', 'CO2프락셀', '서브시전', '어븀레이저', '니들RF', '쥬베룩', 'TCA크로스', '피코프락셀', '콜라겐부스터']::text[]),
    ('i3IbyFQnb1Q', 'jeonghanmi', '딸기우유를 먹으면 가슴이 정말 커지나요?', '결론부터 말씀드리면 성인에게는 별다른 효과가 없고, 사춘기 발육기에 한해 영향이 있을 수 있습니다. 효과를 내는 건 우유가 아니라 딸기 안에 들어 있는 성분인데요, 딸기·베리류에는 우리 몸의 에스트로겐과 비슷한 분자식을 가진 식물성 화합물(파이토에스트로겐)이 들어 있어요. 사춘기 때 적당히 섭취하면 가슴 발육에 긍정적인 영향을 줄 수 있다는 자료가 있습니다. 다만 시중의 딸기우유는 실제 딸기 함유량이 매우 적고 향료 위주인 경우가 많아 효과를 기대하기 어려워요. 성인은 이미 발육이 끝난 상태라 식품으로 가슴 크기를 늘리는 건 사실상 불가능합니다. 그래서 음식으로 가슴이 커진다는 속설은 대부분 과장된 이야기예요. 가슴 모양이나 처짐 개선이 필요하다면 운동이나 의학적 방법이 더 현실적입니다.', '딸기우유로 가슴이 커진다는 속설의 진실과 사춘기 발육 영향을 피부과 전문의 정한미가 설명합니다.', array['딸기우유', '가슴크기', '파이토에스트로겐', '사춘기', '발육', '속설', '식품영향']::text[]),
    ('i3IbyFQnb1Q', 'jeonghanmi', '가슴이 커지는 크림이나 마사지가 진짜 효과가 있나요?', '일시적인 붓기와 혈류 증가만 있을 뿐 가슴을 실제로 키우는 효과는 없습니다. 크림을 바르면서 마사지를 하면 그 부위에 국소적으로 혈류가 늘고 미세한 자극이 가해져 잠시 부어 보일 수 있어요. 이건 운동 후 근육이 일시적으로 부푸는 것과 같은 원리이고 시간이 지나면 원래대로 돌아갑니다. 유선 조직이나 지방 자체가 늘어나는 게 아니기 때문에 실제 컵 사이즈에 변화를 주지는 못해요. 일부 광고에서 호르몬 유사 성분을 강조하는 제품들이 있는데, 피부 흡수만으로 호르몬 수치를 의미 있게 변화시키긴 어렵고 안전성도 확실치 않습니다. 오히려 자극 성분에 의한 피부염이 생기는 사례가 더 흔해요. 사이즈 변화를 원한다면 검증된 의학적 방법을 알아보시는 게 합리적입니다. 마사지는 림프 순환과 부기 관리 정도로 활용하시는 게 좋아요.', '가슴 키우는 크림과 마사지의 실제 효과와 한계를 피부과 전문의 정한미가 정리합니다.', array['가슴크림', '마사지', '일시적붓기', '혈류', '호르몬크림', '피부염', '속설']::text[]),
    ('i3IbyFQnb1Q', 'jeonghanmi', '가슴 운동을 열심히 하면 사이즈가 커지나요?', '사이즈는 늘 수 있지만 여성성 있는 가슴이 아니라 남성성 근육이 커지는 형태입니다. 이른바 가슴 운동은 대부분 흉부의 대흉근을 단련하는 동작인데, 이 근육이 발달하면 흉곽 전체 둘레가 늘어나서 브라 사이즈가 한 단계 올라가는 경우가 있어요. 그래서 친구가 A에서 B로 컵이 늘었다고 느끼는 게 실제 변화일 수 있습니다. 다만 커지는 부분은 유선 조직이나 지방이 아니라 근육 자체라 모양이 둥글고 여리여리한 가슴과는 결이 달라요. 보디빌더처럼 발달하면 컵은 커도 모양이 만족스럽지 않을 수 있습니다. 그래서 본인이 원하는 게 단순한 사이즈인지 자연스러운 모양인지 먼저 정리하시는 게 좋아요. 자세 교정이나 광배근·승모근 운동을 함께 하면 가슴이 모이고 라인이 살아 보이는 부수 효과가 있어요. 운동만으로 모양까지 바꾸기는 한계가 있습니다.', '가슴 운동으로 사이즈가 커지는 원리와 모양 변화의 한계를 피부과 전문의 정한미가 안내합니다.', array['가슴운동', '대흉근', '컵사이즈', '흉곽', '자세교정', '운동효과', '여성성']::text[]),
    ('i3IbyFQnb1Q', 'jeonghanmi', '시술이나 수술 같은 외형 개선이 자존감에 도움이 될까요?', '네, 외형 콤플렉스를 해결하는 시술이나 수술은 자존감과 일상 태도에 큰 영향을 줍니다. 외모 콤플렉스로 위축돼 있던 분들이 가슴 성형이나 얼굴 시술 후에 눈빛·말투·옷차림이 달라지는 사례를 진료실에서 자주 봅니다. 본인을 드러내는 게 어색했던 분들이 적극적으로 사람을 만나게 되고, MBTI가 I에서 E로 바뀐 듯한 변화를 보이기도 해요. 피부 시술도 마찬가지로 큰 외형 변화가 아니더라도 본인이 느끼는 자신감이 확연히 달라집니다. 다만 누구처럼 되겠다는 목표보다는 본인을 위해 한다는 마음가짐이 만족도를 결정해요. 다른 사람의 외모를 그대로 따라가려 하면 결과가 잘 나와도 실망하기 쉽습니다. 결국 가장 중요한 건 ''나다운 나를 좋아하게 만드는 변화''예요. 본인을 위한 투자라고 생각하시면 후회가 적습니다.', '시술과 수술이 자존감과 일상 태도에 어떤 영향을 주는지를 피부과 전문의 정한미가 설명합니다.', array['자존감', '시술효과', '성형', '자기계발', '콤플렉스', '자신감', '마음가짐']::text[]),
    ('Y3eMje8kgCQ', 'kimsoohyung', '윤곽 보톡스 맞으면 음식을 못 씹는 거 아니에요?', '음식을 못 씹을 정도는 아닙니다. 윤곽 보톡스는 근육을 아예 못 쓰도록 하는 게 아니라 과하게 수축되고 긴장되어 있는 근육을 풀어주는 정도이기 때문이에요. 거울을 보고 이를 앙 하고 물어보면 턱과 귀 위에 있는 근육이 움직이는 걸 느낄 수 있는데, 이 근육들이 얼굴 윤곽을 좌우합니다. 질긴 음식을 많이 먹거나 껌을 많이 씹으면 관자놀이와 턱 근육이 발달해서 얼굴이 넙데데하고 커 보이는 거예요. 오히려 스트레스 받을 때 두통이 있는 분들은 관자놀이 근육에 보톡스를 맞아 이완시키면 편두통이 많이 좋아집니다. 편두통 환자들에게 보톡스 치료가 미국 FDA에서 승인을 받기도 했어요. 씹는 기능에 대한 걱정보다는 긴장 완화와 윤곽 개선 효과에 집중해 보세요.', '윤곽 보톡스가 씹는 기능에 미치는 영향과 편두통 개선 효과를 피부과 전문의 김수형이 설명합니다.', array['윤곽보톡스', '보톡스', '사각턱', '교근', '측두근', '편두통', 'FDA']::text[]),
    ('Y3eMje8kgCQ', 'kimsoohyung', '이마가 꺼져서 필러 맞으려는데 보톡스로도 이마 볼륨이 나온다고요?', '네, 이마가 꺼진 것처럼 보이는 분들은 안에서 잡아당기는 근육 때문인 경우가 많아서 보톡스로도 볼륨 효과를 볼 수 있습니다. 이 부분에 보톡스를 놓으면 꺼진 부위를 잡아당기던 힘이 풀리면서 마치 필러를 맞은 것처럼 이마가 둥글게 볼륨이 살아나요. 윤곽 보톡스는 단순히 턱만 줄이는 게 아니라 이마 잔주름을 펴주면서 이마에 볼륨감을 갖게 해주고, 얼굴 라인을 따라 근육 부피를 줄여 전체 윤곽을 잡아주는 시술입니다. 최대 장점은 사람의 얼굴형에 맞게 디자인할 수 있다는 점인데, 사람마다 습관에 따라 어느 근육이 발달했는지 어디가 볼륨이 필요한지 다 다르거든요. 무조건 턱이 갸름하다고 다 예쁜 게 아니라 본인 얼굴에 맞는 커스터마이징이 가능합니다.', '이마 보톡스로 필러 없이 볼륨을 만드는 원리와 윤곽 디자인을 피부과 전문의 김수형이 안내합니다.', array['윤곽보톡스', '이마보톡스', '이마볼륨', '필러', '리프팅', '얼굴형', '커스터마이징']::text[]),
    ('Y3eMje8kgCQ', 'kimsoohyung', '윤곽 보톡스 효과 얼마나 가나요? 한 번 맞으면 끝인가요?', '시술 후 2주차에 효과가 나타나기 시작하고 3~4개월 정도 지속됩니다. 보톡스 자체가 급격하게 얼굴 부피를 줄이는 게 아니라 서서히 자연스럽게 변화를 만드는 시술이에요. 좋은 소식은 꾸준히 맞다 보면 근육이 점점 작아져서 효과가 더 오래 지속되기도 한다는 점입니다. 얼굴 면적이 줄어들면서 점점 입체적인 얼굴로 변하기 때문에 주기적으로 시술 받으시면 정말 좋아요. 부작용은 시술 후 멍이나 붓기가 생길 수 있는데 대부분 일주일 이내로 사라집니다. 아주 드물게 눈이 처지거나 씹는 힘이 약해지는 경우도 있지만 시간이 지나면 원래대로 돌아오니 너무 걱정하지 않으셔도 됩니다. 대신 정말 중요한 날 직전에는 조심해서 받으시는 게 좋겠죠.', '윤곽 보톡스의 효과 지속 기간과 부작용, 주기적 관리 필요성을 피부과 전문의 김수형이 정리합니다.', array['윤곽보톡스', '보톡스유지기간', '부작용', '멍', '붓기', '안티에이징', '리프팅']::text[]),
    ('Y3eMje8kgCQ', 'kimsoohyung', '윤곽 보톡스 맞고 나서 뭘 조심해야 하나요?', '시술 후 4~6시간 동안은 해당 부위를 누르거나 마사지하지 마세요. 보톡스가 확산에 의해 다른 곳으로 퍼질 수 있기 때문입니다. 24시간 동안은 과격한 운동, 사우나, 뜨거운 목욕도 피해야 하는데, 열에 의해 보톡스 효과가 빨리 떨어질 수 있어요. 처음 맞으시는 분 중에 이마 부분이 무거워서 눈 뜨기가 힘들어지는 경우가 있는데, 이건 평소 이마 근육으로 눈을 뜨는 습관이 있기 때문이에요. 이때는 눈을 부릅뜨는 연습으로 눈의 근육을 키워주시면 됩니다. 함께 받으면 좋은 시술로는 리쥬란이나 비타란 같은 스킨부스터가 있는데, 폴리뉴클레오타이드 성분이 피부 장벽을 튼튼하게 만들어 톤 개선과 탄력에 도움을 줘요. 모공이 고민이시면 스킨 보톡스를 추가하면 모공이 작아지고 피부결도 예뻐집니다.', '윤곽 보톡스 시술 후 주의사항과 함께 받으면 좋은 시술을 피부과 전문의 김수형이 안내합니다.', array['윤곽보톡스', '시술후관리', '스킨부스터', '리쥬란', '스킨보톡스', '모공', '폴리뉴클레오타이드']::text[]),
    ('vmI7WO35EeM', 'kwonsuhyun', '여드름 안 나게 세안만 잘하면 된다는 게 사실인가요?', '네, 여드름은 결론적으로 모공 안에 기름 덩어리가 끼어서 생기는 것이라 세안을 제대로 하면 호전될 수 있습니다. 핵심은 이중 세안인데, 모공에 낀 기름은 기름으로 씻어야 하거든요. 클렌징 오일이나 클렌징 밀크, 클렌징 크림으로 1차 세안을 해서 기름끼리 분해시킨 뒤 물로 헹구고, 2차로 폼클렌징을 해주면 됩니다. 클렌징 워터는 기름을 제거하는 힘이 약해서 지성 피부에는 부족해요. 그리고 바르는 제품도 중요한데, 지성 피부가 너무 꾸덕한 오일리 제품을 바르면 안에서 만들어지는 기름에다 바깥 기름까지 더해져 모공을 이중으로 막아버립니다. 지성 피부는 산뜻한 제형을 선택해야 여드름이 덜 나요. 이중 세안과 피부에 맞는 제형 선택, 이 두 가지만으로도 여드름이 조금 호전될 수 있습니다.', '여드름 예방을 위한 이중 세안 방법과 제형 선택 기준을 피부과 전문의 권수현이 안내합니다.', array['여드름', '이중세안', '클렌징오일', '지성피부', '모공', '폼클렌징', '세안법']::text[]),
    ('vmI7WO35EeM', 'kwonsuhyun', '팔자주름 집에서 관리할 수 있는 방법 없나요?', '팔자주름 같은 깊은 주름은 홈케어만으로는 어렵습니다. 팔자주름이 생기는 이유가 피부만 처지는 게 아니라 그 밑에 있는 지방, 근육, 뼈까지 모두 부피가 줄어들면서 한꺼번에 처져 버리는 것이기 때문이에요. 불독살이나 마리오네트 주름도 마찬가지입니다. 다만 할 수 있는 방법이 하나 있는데, 광대 근육 운동이에요. 얼굴에서 쓰면 쓸수록 예뻐지고 젊어지는 근육이 광대 근육인데, 이걸 올려주는 동작을 ''은'' 발음하듯이 해주시면 됩니다. 힙업 운동처럼 시간은 많이 걸리지만 꾸준히 하면 근육이 키워지면서 처졌던 피부를 좀 올릴 수 있어요. 크게 처지는 주름은 시술이 필요하지만, 습관적으로 광대 근육을 쓰는 연습을 하면 예방 차원에서 도움이 됩니다.', '팔자주름 홈케어의 한계와 광대 근육 운동법을 피부과 전문의 권수현이 설명합니다.', array['팔자주름', '홈케어', '마리오네트', '광대근육', '얼굴운동', '리프팅', '처짐']::text[]),
    ('vmI7WO35EeM', 'kwonsuhyun', '레티놀 1% 제품 쓰고 있는데 너무 센 거 아닌가요?', '이미 4년 정도 레티놀을 써오면서 문제가 없었다면 괜찮을 수 있지만, 처음 시작하시는 분들은 절대 1%부터 시작하면 안 됩니다. 레티놀은 죽은 각질을 벗겨내고 새살이 돋는 각질 턴오버 속도를 다시 돌려주는 원리로 잔주름 개선과 탄력을 만들어 줘요. 나이가 들면 한 달 주기의 턴오버가 느려지면서 노화 세포가 쌓이는데, 레티놀이 이 속도를 정상으로 되돌려 주는 겁니다. 처음 쓰시는 분은 0.2% 같은 저용량부터 시작해서 다음날 붉어짐이 없는지 확인하세요. 각질이 너무 심하게 벗겨지면 농도를 더 낮추거나 보습크림과 섞어서 바르는 게 좋습니다. 한국에서는 1% 제품을 살 수 없어서 해외직구를 해야 하는데, 오랜 기간 적응된 분들만 사용하시는 걸 권합니다.', '레티놀 고농도 사용 기준과 입문자 적정 용량을 피부과 전문의 권수현이 정리합니다.', array['레티놀', '턴오버', '잔주름', '탄력', '저용량', '각질', '안티에이징']::text[]),
    ('vmI7WO35EeM', 'kwonsuhyun', '집에서 각질 제거 자주 하면 피부에 좋은 거 아닌가요?', '사실 각질 제거는 대부분의 피부에 안 좋습니다. 피부는 만리장성처럼 외부로부터 보호해주고 안쪽 수분이 밖으로 나가지 않게 막아주는 장벽 역할을 하는데, 각질 제거는 이 장벽을 계속 깨부수는 행위예요. 건조해서 각질이 일어나는 분이 제거를 하면 겨우 회복된 장벽이 다시 무너져 수분이 새어나가고 얼굴이 시뻘게지는 악순환에 빠집니다. 다만 지성 피부나 여드름성 피부라면 이야기가 다른데, 기름과 각질이 많아서 이중 세안으로도 모공을 막는 피지가 다 제거되지 않을 수 있거든요. 이런 피부는 일주일에 1~2회 정도 각질 제거를 해주면 오히려 좋아집니다. 닦아내는 토너 패드도 마찬가지로, 건성이나 민감 피부는 굳이 할 필요 없고 지성 피부만 살살 해주시면 됩니다.', '피부 타입별 각질 제거의 득과 실, 안전한 빈도를 피부과 전문의 권수현이 안내합니다.', array['각질제거', '피부장벽', '지성피부', '건성피부', '민감피부', '닦토', '토너패드']::text[]),
    ('gn10PBM_WjY', 'jeonghanmi', '성형수술이 정말 사람의 인생을 바꿀 수 있나요?', '네, 성형수술은 자존감과 일상 행동에 영향을 줘서 인생을 크게 바꾸는 경우가 있습니다. 단순히 외모만 달라지는 게 아니라 마음가짐과 태도가 함께 변하는 게 핵심이에요. 외모 콤플렉스로 위축돼 있던 분들이 수술 후에 눈빛·말투·옷차림이 달라지고 사람을 만나는 걸 즐기게 되는 변화가 자주 보입니다. 가슴 성형 후 MBTI가 I에서 E로 바뀌었나 싶을 정도로 적극적이 되는 분들도 있어요. 피부 시술도 같은 맥락인데, 컴플렉스를 해결해 드리면 외부에서 보기엔 큰 차이가 아니어도 본인의 자신감이 확연히 달라집니다. 수술이나 시술을 결심하고 실행에 옮기는 것 자체가 자기 계발의 한 형태이기도 해요. 본인을 위한 투자라는 마음가짐이 결과를 더 긍정적으로 만들어 줍니다.', '성형수술과 피부 시술이 자존감과 일상에 어떤 변화를 만드는지를 피부과 전문의 정한미가 설명합니다.', array['성형수술', '자존감', '외모컴플렉스', '자기계발', '피부시술', '자신감', '인생변화']::text[]),
    ('gn10PBM_WjY', 'jeonghanmi', '시술 받기 전 누구처럼 되고 싶다고 사진을 가져가도 괜찮을까요?', '참고는 좋지만 누구처럼 되겠다는 집착은 오히려 만족도를 떨어뜨립니다. 사람마다 골격·피부·근육 분포가 달라서 같은 시술을 해도 결과가 다르고, 어떤 이상형은 본인에게 어울리지 않거나 아예 불가능할 수도 있어요. 이런 상태에서 특정 모습에만 꽂혀 있으면 결과가 본인에게 잘 어울리더라도 "내가 원한 그 사람과 다르다"는 이유로 실망하기 쉽습니다. 목표를 설정하는 건 좋지만 본인 얼굴의 장점과 비율을 살리는 방향으로 풀어가야 해요. 그래서 상담할 때는 사진을 참고만 하시고 최종 디자인은 전문의의 의견을 적극 반영하시는 게 좋습니다. 본인의 콤플렉스를 개선하는 게 목적이지 다른 사람이 되는 게 목적이 아니어야 만족도가 높아져요. 결국 가장 중요한 건 ''나다움을 찾는 것''입니다.', '시술 전 닮고 싶은 사진을 참고할 때의 주의점과 만족도 높은 상담법을 피부과 전문의 정한미가 안내합니다.', array['성형상담', '이상형사진', '시술디자인', '만족도', '컴플렉스', '자연스러움', '전문의의견']::text[]),
    ('gn10PBM_WjY', 'jeonghanmi', '시술 결정할 때 환자 본인의 욕심을 우선하면 어떻게 되나요?', '전문가 의견을 무시하고 본인이 원하는 방법만 고집하면 결과가 나빠질 수 있습니다. 시술이나 수술은 나이·피부 상태·해부학적 조건에 따라 적합한 방법이 다른데, 환자가 특정 기법만을 요구하면 의사가 그대로 따라가다가 실패로 이어지기 쉬워요. 예를 들어 40대 중반의 두꺼운 눈꺼풀에 매몰법을 고집하면 자연스럽지 못한 겹쌍커풀이 생길 수 있어요. 피부 시술도 마찬가지로, 본인이 본 영상이나 후기만 믿고 무리한 시술을 요구하면 부작용이나 부자연스러운 결과가 나올 수 있습니다. 그래서 상담 단계에서 본인의 니즈를 충분히 전달하되, 최종 시술 방법과 디자인은 전문의의 판단에 맡기시는 게 가장 안전합니다. 의사도 본인이 가장 잘하는 방식과 환자에게 맞는 방식을 알고 있어요. 결국 ''의사와 환자가 같은 팀''이라는 자세가 좋은 결과를 만듭니다.', '본인의 욕심으로 시술 방법을 고집했을 때 생길 수 있는 문제와 안전한 상담 자세를 피부과 전문의 정한미가 정리합니다.', array['시술상담', '매몰법', '쌍꺼풀', '전문의의견', '부작용', '디자인', '안전한시술']::text[]),
    ('gn10PBM_WjY', 'jeonghanmi', '울쎄라 같은 리프팅 시술이 자신감에도 영향을 주나요?', '네, 울쎄라 같은 리프팅 시술은 외모 변화와 함께 자신감 회복에도 큰 도움이 됩니다. 울쎄라는 고강도 집속 초음파(HIFU)로 SMAS층까지 자극해 처진 피부를 끌어올리는 비수술적 리프팅 시술이에요. 처짐이 개선되면 얼굴 인상이 또렷해지고 동안으로 보여서 주변에서 "살 빠졌어?" "젊어졌어"라는 피드백을 받게 됩니다. 이 외부 반응이 본인의 자존감을 높여주고 사람을 대하는 태도까지 자연스럽게 바뀌게 만들어요. 수술처럼 다운타임이 길지 않고 시술 다음 날부터 일상생활이 가능하다는 점도 부담을 줄여줍니다. 다만 효과를 극대화하려면 본인의 피부 처짐 정도와 부위에 맞게 샷 수와 깊이를 조절해야 해요. 기대치를 너무 높이지 마시고 본인을 위한 투자로 접근하시면 만족도가 높습니다.', '울쎄라 리프팅이 외모 변화와 자신감 회복에 어떻게 도움을 주는지를 피부과 전문의 정한미가 설명합니다.', array['울쎄라', '리프팅', '처짐개선', '자신감', 'HIFU', '동안', '안티에이징']::text[]),
    ('3nLgtbXkAfo', 'leedoyoung', '피부과 의사도 선크림 매일 안 바른다는 게 사실인가요?', '네, 자외선 노출이 거의 없는 생활 패턴이라면 피부과 전문의도 매일 바르지 않습니다. 선크림은 자외선을 차단해주는 화장품이기 때문에 출퇴근이 짧고 실내에서 대부분의 시간을 보내는 분이라면 굳이 매일 바를 필요가 없어요. 오히려 비타민D 결핍이 문제가 되는 분들은 선크림 없이 일주일에 3번, 30분 정도 햇빛을 쬐는 것을 권장합니다. 비타민D가 부족하면 뼈가 약해지고, 근육도 약해지고, 면역력과 기운도 떨어지거든요. 다만 창문으로 햇빛이 직접 들어오는 자리에서 일하는 분은 반드시 발라주셔야 합니다. UVA는 창문을 뚫고 들어와서 피부 깊숙이 침투해 주름, 기미, 주근깨를 만들기 때문이에요. 자외선 노출 상황에 따라 조절하는 게 매일 기계적으로 바르는 것보다 훨씬 현명한 방법입니다.', '선크림을 매일 안 발라도 되는 사람과 반드시 발라야 하는 상황을 피부과 전문의 이도영이 정리합니다.', array['선크림', '자외선차단', '비타민D', 'UVA', '실내자외선', '자외선노출', '피부노화']::text[]),
    ('3nLgtbXkAfo', 'leedoyoung', '선크림 바르기 귀찮은데 대신 바를 수 있는 게 있나요?', '비타민C 세럼을 발라주시면 선크림 없이도 자외선 손상을 어느 정도 방어할 수 있습니다. 비타민C는 자외선으로부터 피부를 보호해서 노화를 예방하고, 멜라닌 색소 생성을 억제해 기미와 잡티 개선에도 도움을 줘요. 하루 동안 손상된 피부를 빠르게 회복시키는 역할까지 합니다. 다만 비타민C는 공기나 빛, 열에 닿으면 금방 산화돼서 효과가 떨어지는 게 문제예요. 그래서 비타민C 15%에 비타민E와 페룰릭애씨드가 조합된 제품이 안정적으로 효과를 내는 데 유리합니다. 페룰릭애씨드는 비타민C와 비타민E의 광보호 효과를 2배 증가시킨다는 연구 결과도 있어요. 비타민C를 바르고 그 위에 자외선 차단제까지 바르면 가장 완벽하지만, 선크림이 부담스러운 분이라면 비타민C 세럼만이라도 꼭 챙겨 바르세요.', '선크림 대신 비타민C 세럼으로 자외선 손상을 방어하는 방법을 피부과 전문의 이도영이 안내합니다.', array['비타민C', '항산화', '페룰릭애씨드', '선크림대안', '피부보호', '자외선방어', '세럼']::text[]),
    ('3nLgtbXkAfo', 'leedoyoung', '피부염이나 민감성 피부인데 선크림 바르면 안 되나요?', '네, 피부염이 있거나 화장품 바를 때 따갑고 붉어지는 분은 당분간 선크림을 안 바르시는 게 좋습니다. 유기자차 선크림에 포함된 옥시벤존이나 아보벤존 같은 성분이 피부 자극이나 알러지 반응을 일으킬 수 있기 때문이에요. 이런 분들에게는 무기자차 선크림을 권합니다. 무기자차는 징크옥사이드나 티타늄디옥사이드 같은 성분으로 피부 표면에 물리적 막을 만들어 자외선을 차단하는 방식이라 자극이 적어요. 단점은 바르면 하얘지는 백탁현상과 뻑뻑한 사용감입니다. 또 한 가지 중요한 점은 선크림을 지우는 과정이에요. 이중 세안은 피부 장벽을 더 손상시킬 수 있으므로 클렌징 한 번으로 잘 지워지는 이지워시 타입 선크림을 선택하면 부담을 줄일 수 있습니다.', '피부염이 있을 때 선크림 선택법과 유기자차·무기자차 차이를 피부과 전문의 이도영이 설명합니다.', array['피부염', '무기자차', '유기자차', '민감성피부', '선크림', '백탁현상', '이지워시']::text[]),
    ('3nLgtbXkAfo', 'leedoyoung', '선크림 제대로 효과 보려면 어떻게 발라야 하나요?', '정석대로라면 500원 동전 크기(1.2~1.5g)만큼 발라야 100% 차단 효과를 볼 수 있습니다. 현실적으로 이만큼 바르기 어렵다면 세 가지 방법으로 효과를 높일 수 있어요. 첫째, 얼굴뿐 아니라 귀, 목, 눈가, 헤어라인까지 빠짐없이 바르셔야 합니다. 얼굴은 관리하면서 목에 주름이 자글자글하면 티가 확 나거든요. 둘째, 한 번에 많이 바르면 흡수가 안 되니까 적당량을 두 번에 나눠 레이어링하듯 발라주세요. 셋째, 외출 15~30분 전에 미리 바르고 2~3시간마다 덧발라주시면 차단 성분이 제대로 자리 잡을 수 있습니다. 양을 줄이더라도 이 세 가지만 지키면 훨씬 효과적으로 자외선을 막을 수 있어요.', '선크림 양이 부족해도 효과를 높이는 세 가지 바르는 법을 피부과 전문의 이도영이 안내합니다.', array['선크림', '바르는법', '자외선차단', '레이어링', '덧바르기', '목주름', '자외선차단제']::text[]),
    ('mTr0u2XmxWo', 'parkhyojin', '부모님 처음 피부과 모시고 갈 때 써마지나 울쎄라부터 받아야 하나요?', '아닙니다. 처음 피부과에 오시는 부모님께 써마지나 울쎄라는 잘 권해드리지 않습니다. 써마지는 비싸면서도 한 번 받는다고 즉각적으로 효과가 보이지 않고 축적되어야 결과가 나타나는 시술이에요. 울쎄라 역시 처진 피부에 딱 한 번 시술한다고 효과가 확 보이지 않습니다. 처음 피부과에 오신 분이 비용 대비 만족감을 못 느끼면 "피부과 한번 가봤는데 비싸고 효과 없더라"는 인식만 남기 쉬워요. 유명하다고 해서 꼭 먼저 받아야 할 시술인지는 생각해봐야 합니다. 입문용으로는 스킨보톡스처럼 한 번만 받아도 자연스럽게 바로 티가 나는 시술이 만족감이 훨씬 높습니다.', '부모님 첫 피부과 시술로 써마지·울쎄라를 권하지 않는 이유를 피부과 전문의 박효진이 설명합니다.', array['써마지', '울쎄라', '스킨보톡스', '50대시술', '부모님시술', '리프팅', '가성비시술']::text[]),
    ('mTr0u2XmxWo', 'parkhyojin', '스킨보톡스가 일반 보톡스랑 뭐가 다른 건가요?', '스킨보톡스는 근육층이 아니라 피부 얕은 층에 고르게 깔아주는 방식이라 자연스러움이 확 다릅니다. 일반 보톡스는 근육에 직접 주사해서 근육의 힘을 10에서 0으로 확 떨어뜨리는데, 50대 이상은 이미 눈꺼풀이 처지기 시작해서 강하게 맞으면 오히려 어색하고 화난 것처럼 보일 수 있어요. 스킨보톡스는 자글자글한 주름을 전체적으로 펴주면서 광까지 나기 때문에 자연스러움을 원하는 분들 만족감이 훨씬 높습니다. 효과는 3~4일 내에 바로 나타나고, 눈가와 눈 밑 세로주름 개선이 뚜렷해요. 3~4개월 유지되니까 그 간격으로 맞아주시면 되고, 눈가·미간·이마 기준 20~30만 원대에서 해결되는 가성비 좋은 시술입니다.', '스킨보톡스와 일반 보톡스의 차이점 및 50대 이상 만족도를 피부과 전문의 박효진이 안내합니다.', array['스킨보톡스', '보톡스', '주름', '눈가주름', '50대시술', '자연스러운시술', '가성비시술']::text[]),
    ('mTr0u2XmxWo', 'parkhyojin', '부모님 얼굴 검버섯이나 흑자 한두 번으로 없앨 수 있나요?', '네, 검버섯은 한 번에, 흑자는 한두 번이면 눈에 띄게 깨끗해질 수 있습니다. 검버섯은 점 제거 레이저로 물리적으로 깎아서 한 번에 날려버리는 방식이고, 흑자는 딱지가 생기게 해서 2주 동안 재생 테이프를 붙이는 방식으로 치료해요. 흑자는 추가 시술이 필요할 수도 있지만 그래도 전보다 꽤 깔끔하게 지워집니다. 생각보다 얼굴에 있는 검버섯과 흑자가 지저분한 인상을 만드는데, 조금만 없애줘도 얼굴이 환하고 깨끗해 보여요. 개수가 적으면 10만 원도 안 할 수 있고, 많더라도 얼굴 전체 시술로 50만 원 선에서 끝나기 때문에 가성비가 좋습니다. 기미처럼 깊게 깔린 색소와 달리 검버섯·흑자는 빠른 결과를 볼 수 있어 부모님 선물용으로 추천드려요.', '검버섯과 흑자를 한두 번 시술로 없앨 수 있는 방법과 비용을 피부과 전문의 박효진이 정리합니다.', array['검버섯', '흑자', '색소치료', '레이저', '50대피부', '부모님선물', '피부과시술']::text[]),
    ('mTr0u2XmxWo', 'parkhyojin', '레디어스도 필러인데 얼굴에 넣으면 처지지 않나요?', '레디어스는 일반 필러와 달리 CaHA(칼슘 하이드록시아파타이트) 입자가 콜라겐 재생까지 유도하기 때문에 처짐 걱정이 적습니다. 일반 필러는 넣는 데서 끝나지만 레디어스는 즉각적인 볼륨 효과를 주면서 동시에 피부 세포에 콜라겐, 엘라스틴, 프로테오글리칸 같은 구조물을 만들라고 자극하는 바이오 스티뮬레이터예요. 겔은 1~2개월이면 빠지지만 CaHA 입자가 남아서 계속 재생을 유도합니다. 스컬트라나 쥬베룩 볼륨은 재생은 좋지만 즉각적 효과가 떨어지는 반면, 레디어스는 시술 직후 팽팽해 보이면서 장기적으로도 탄탄해지는 게 장점이에요. 1년에 한 번만 하면 되니까 내원 부담도 적고, 모임 나가면 주변에서 달라졌다는 반응을 많이 받는 시술입니다.', '레디어스가 일반 필러와 다른 점과 즉각+재생 효과를 피부과 전문의 박효진이 설명합니다.', array['레디어스', '필러', '콜라겐', '바이오스티뮬레이터', '리프팅', '스컬트라', '볼륨']::text[]),
    ('kX5CCiLIxdg', 'kwonsuhyun', '비타민C 아침에 바르면 오히려 피부에 안 좋다는 말 사실인가요?', '아닙니다. 요즘은 오히려 아침에 비타민C를 바르라고 권합니다. 예전에는 비타민C가 자외선과 접촉하면 산화되어 효과가 떨어진다고 해서 밤에 바르라는 말이 많았어요. 하지만 비타민C는 자외선으로 인한 피부 손상을 막아주고, 미세먼지나 환경오염 물질로부터 피부를 보호하는 역할을 합니다. 비타민C를 바르고 그 위에 자외선 차단제까지 바르면 가장 완벽한 조합이 되죠. 자외선 차단제를 안 바른다고 피부가 난리 나는 건 아니지만 비타민C 효과가 떨어질 수 있으니 함께 사용하시는 게 좋습니다. 처음 시작한다면 너무 높은 농도보다 레티놀처럼 저용량부터 시작하세요. 아침 비타민C, 저녁 레티놀로 나눠 바르면 피부 관리를 굉장히 잘한다는 소리를 들을 수 있어요.', '비타민C를 아침에 바르라고 권하는 이유와 레티놀 병행법을 피부과 전문의 권수현이 안내합니다.', array['비타민C', '레티놀', '아침스킨케어', '항산화', '자외선차단', '피부관리', '기능성화장품']::text[]),
    ('kX5CCiLIxdg', 'kwonsuhyun', '먹는 콜라겐이 진짜 피부 탄력에 도움이 되나요?', '먹는 콜라겐은 드라마틱한 피부 개선보다는 건강식품 수준이라고 보시면 됩니다. 먹으면 소화 과정을 거치면서 상당량이 배출되고, 나머지도 여러 장기에 퍼지기 때문에 실제로 피부에 도달하는 양은 극히 적어요. 꾸준히 오래 먹으면 도움은 될 수 있겠지만, 피부를 위해서 콜라겐 효과를 제대로 보고 싶다면 콜라겐 주사를 직접 맞는 것이 가성비가 훨씬 좋습니다. 먹는 콜라겐 제품이 비싼 것에 비해 주사는 콜라겐이 바로 피부로 들어가니까 효율이 확실히 다르죠. 비싼 제품을 오래 사서 먹는 것과 한 번 주사로 직접 넣는 것을 비교하면, 생각보다 주사 쪽 가성비가 좋은 제품들이 있으니 피부과 상담을 받아보시는 걸 추천드립니다.', '먹는 콜라겐의 한계와 콜라겐 주사의 가성비 차이를 피부과 전문의 권수현이 정리합니다.', array['콜라겐', '이너뷰티', '콜라겐주사', '먹는콜라겐', '피부탄력', '가성비', '스킨케어']::text[]),
    ('kX5CCiLIxdg', 'kwonsuhyun', '피부 타입별로 꼭 써야 하는 화장품 성분이 따로 있나요?', '네, 피부 타입별로 핵심 성분이 다릅니다. 건성은 세라마이드가 정답이에요. 세라마이드는 피부 장벽을 구성하는 성분이라 발라주면 장벽이 튼튼해지고 피부가 건강해집니다. 지성은 나이아신아마이드를 바르세요. 피지 조절에 도움을 주기 때문에 번들거림이 줄어들어요. 복합성은 T존에 나이아신아마이드, U존에 세라마이드를 섞어 바르시면 됩니다. 민감성 피부는 판테놀이나 마데카소사이드 같은 재생 성분, 시카 계열 제품이 적합해요. 여드름성 피부는 살리실산 성분이 핵심인데, 모공에 낀 피지를 날려줄 수 있는 성분이거든요. 살리실산이 든 폼클렌저나 토너를 중복 사용해도 화장품 수준이라 큰 문제 없으니 부담 없이 쓰셔도 됩니다.', '건성·지성·민감성·여드름 피부 타입별 핵심 성분 추천을 피부과 전문의 권수현이 안내합니다.', array['세라마이드', '나이아신아마이드', '살리실산', '판테놀', '피부타입', '건성', '지성', '민감성피부']::text[]),
    ('kX5CCiLIxdg', 'kwonsuhyun', '튼살 크림으로 이미 생긴 튼살도 없앨 수 있나요?', '이미 생긴 튼살에는 크림만으로 효과를 보기 어렵지만, 예방 목적으로는 도움이 됩니다. 튼살 크림은 성분이 좋은 보습제에 피부 재생 물질이 들어간 제품이에요. 튼살은 살이 늘어나는 속도를 피부가 따라가지 못해 갈라지는 건데, 보습을 충분히 하고 마사지해주면 피부 장력이 개선되어 튼살이 덜 생길 수는 있습니다. 하지만 이미 생겨버린 튼살은 피부 구조 자체가 손상된 것이라 크림으로는 복구가 어려워요. 다행히 요즘에는 좋은 시술들이 많이 나와서 이미 생긴 튼살도 치료가 가능합니다. 비슷하게 셀룰라이트 크림도 지방층 깊은 곳의 문제를 표면에서 흡수시키기는 어려워서, 크림보다는 시술 도움을 받는 것이 현실적이에요.', '튼살 크림의 예방 효과와 이미 생긴 튼살 치료 가능 여부를 피부과 전문의 권수현이 설명합니다.', array['튼살', '튼살크림', '보습', '셀룰라이트', '피부재생', '임산부', '다이어트']::text[]),
    ('HFvW2-RVelc', 'jeonghanmi', '옷에서 나는 퀴퀴한 냄새가 땀 때문이 아니라고요?', '네, 옷 등 쪽에서 나는 쩐내의 주범은 땀이 아니라 피지입니다. 등에서 겨드랑이 땀이 날 리가 없는데도 냄새가 나는 건 등에 피지 분비가 다른 부위보다 많기 때문이에요. 여자도 피지가 나오니까 이 냄새는 남녀 모두에게 납니다. 다만 남자는 남성 호르몬 때문에 피지 분비가 여성보다 2배 정도 많아서 더 퀴퀴한 냄새가 잘 나는 거예요. 여기에 생활습관도 많이 영향을 미칩니다. 환기를 잘 안 하거나, 빨래를 자주 안 하거나, 이불이나 베개커버 세탁을 미루면 피지가 씻겨 나가지 않고 축적되면서 냄새가 쌓이죠. 냄새가 집 안에 한번 배어버리면 나중에 환기해도 잘 안 빠지니까 하루에 두 번은 꼭 창문을 열어주세요.', '옷 등 쪽의 퀴퀴한 냄새는 땀이 아니라 피지가 원인입니다. 남녀 피지 분비량 차이와 냄새를 줄이는 생활습관을 피부과 전문의 정한미가 설명합니다.', array['피지냄새', '체취', '피지분비', '등냄새', '생활습관', '환기', '세탁']::text[]),
    ('HFvW2-RVelc', 'jeonghanmi', '40대 넘으면 몸에서 노인 냄새 나기 시작하나요?', '네, 40대 중반부터 피부에서 나오는 피지 성분이 변하면서 노인 특유의 냄새 물질이 만들어지기 시작합니다. 팔미톨레산이라는 성분이 증가하고, 이것이 몸에 쌓인 활성산소와 반응하면서 노넨알데하이드라는 냄새 물질이 생성돼요. 쉽게 말하면 젊을 때는 피부의 항산화 시스템이 쓰레기를 바로 치워줬는데, 나이 들면서 그 기능이 떨어져 활성산소가 쌓이고 피지와 반응해 냄새가 나는 겁니다. 일본 연구에 따르면 75세 이상 노인 사이에서도 노넨알 농도가 개인별로 10배까지 차이가 났다고 해요. 유전적 요인도 있지만 스트레스, 흡연, 항산화 식품 섭취 부족, 당뇨 같은 질환이 있으면 더 많이 생성됩니다. 자연스러운 노화 과정이지만 관리하면 충분히 줄일 수 있어요.', '40대부터 피지 속 팔미톨레산이 활성산소와 반응해 노넨알데하이드라는 냄새 물질을 만듭니다. 노인 냄새의 과학적 원인을 피부과 전문의 정한미가 정리합니다.', array['노인냄새', '노넨알데하이드', '피지', '활성산소', '40대', '노화', '항산화']::text[]),
    ('HFvW2-RVelc', 'jeonghanmi', '내가 노인 냄새 나는 체질인지 간단하게 확인하는 방법 있나요?', '네, 집에서 간단하게 셀프 테스트할 수 있는 방법이 있습니다. 먼저 몸을 깨끗하게 씻고 3시간을 기다리세요. 그 후 팔 접히는 오금 부위를 손가락 두 개로 10초 정도 문지릅니다. 문지르고 나서 30분 동안 그냥 지내다가 그때 냄새를 맡아보세요. 마른 건초 냄새나 오래된 책 냄새가 난다면 나중에 노인 냄새가 나는 체질일 수 있어요. 이 냄새 물질은 타고난 유전적 요인도 있지만 생활 습관이 굉장히 중요합니다. 스트레스가 많거나 흡연을 하거나 항산화 음식을 잘 안 먹는 사람은 노넨알이 더 많이 생성됩니다. 또 당뇨병 같은 질환이 있어도 냄새가 심해질 수 있으니 평소 건강 관리와 함께 체크해보시면 좋습니다.', '팔 오금을 문질러 30분 후 냄새를 맡으면 노인 냄새 체질을 셀프 확인할 수 있습니다. 간단한 테스트 방법과 생활습관 영향을 피부과 전문의 정한미가 안내합니다.', array['노인냄새', '셀프테스트', '노넨알데하이드', '체질', '생활습관', '항산화', '피지']::text[]),
    ('HFvW2-RVelc', 'jeonghanmi', '나이 들어서 나는 냄새 줄이려면 어떻게 관리해야 하나요?', '가장 중요한 것은 피지가 많이 분비되는 부위를 바디클렌저로 잘 씻어내는 것입니다. 특히 귀 뒤, 등, 앞가슴처럼 피지 분비가 많은 곳을 꼼꼼히 세정해주세요. 두 번째로 항산화 식품을 자주 먹는 게 중요합니다. 베리류, 녹차, 토마토, 브로콜리 같은 음식이 항산화 성분이 풍부하고, 오메가3 영양제 복용도 도움이 돼요. 세 번째는 환기입니다. 아무리 몸 관리를 잘해도 냄새는 조금씩 날 수 있으니 자주 환기시켜 주셔야 합니다. 냄새 전용 제품을 찾는다면 노넨알을 중화시키는 클렌저를 사용해볼 수 있지만, 특정 제품보다 잘 씻는 게 핵심이에요. 그리고 보습도 중요한데, 피부가 건조하면 피지가 더 많이 분비되면서 냄새가 심해질 수 있으니 바디로션을 꼭 발라주세요.', '귀 뒤·등·앞가슴을 꼼꼼히 씻고 항산화 식품을 챙기면 노인 냄새를 줄일 수 있습니다. 세정·식이·보습·환기 4가지 관리법을 피부과 전문의 정한미가 정리합니다.', array['노인냄새', '피지관리', '항산화식품', '보습', '바디클렌저', '환기', '냄새예방']::text[]),
    ('7Igx2xG-2Qw', 'jeonghanmi', '하얗게 변한 오래된 튼살도 치료하면 없어질 수 있나요?', '네, 완전히 사라지진 않지만 멀리서 보면 잘 안 보이는 수준까지 개선할 수 있습니다. 하얘진 튼살은 이미 흉터처럼 자리 잡은 상태여서 크림이나 디바이스 같은 홈케어로는 효과를 보기 어렵습니다. 치료의 핵심은 피부 속을 미세하게 찢어 재생 반응을 유도하는 것인데, 미라젯이라는 장비가 센 압력으로 피부를 뚫고 들어가면서 패인 부위를 자극해 살이 차오르게 만듭니다. 이때 쥬베룩을 함께 주입하면 콜라겐 생성이 촉진되어 꺼진 튼살이 채워지는 효과가 있어요. 좁은 튼살은 한두 번만 해도 확 줄어들지만, 넓은 부위는 시간이 더 걸리고 완전히 없어지기 어렵습니다. 그래도 세 번 정도 치료하면 눈에 띄는 변화를 볼 수 있고, 시술 다음 날부터 일상생활이 가능할 정도로 회복이 빠른 편이에요. 딱지가 점처럼 생겼다 떨어지는 데 7-10일 정도 걸립니다.', '하얗게 변한 오래된 튼살을 미라젯과 쥬베룩으로 치료하는 원리와 효과를 피부과 전문의 정한미가 설명합니다.', array['튼살', '미라젯', '쥬베룩', '콜라겐', '흉터', '피부재생', '하얀튼살']::text[]),
    ('7Igx2xG-2Qw', 'jeonghanmi', '미라젯이 손주사보다 튼살 치료에 더 좋은 이유가 뭔가요?', '미라젯은 균일한 깊이에 약물을 넣으면서 동시에 피부를 찢어 재생을 유도하기 때문에 손주사보다 훨씬 효과적입니다. 튼살은 매우 얇은 부위여서 손으로 일정한 깊이에 균일하게 주사를 놓는 것 자체가 굉장히 어렵습니다. 미라젯은 센 압력으로 피부를 뚫고 들어가면서 피부 속을 미세하게 찢어주는데, 이 찢는 행위 자체가 튼살 치료의 핵심이에요. 튼살은 일종의 흉터처럼 피부가 패여 있는 구조인데, 패인 부위를 밑에서 미세하게 찢어주면 살이 차오르는 반응이 생기면서 개선됩니다. 단순히 쥬베룩을 넣는 것 이상으로 물리적 자극까지 동시에 주는 셈이죠. 통증도 마취크림을 바르면 참을 만한 수준이고, 시술 후 하루만 지나면 일상생활이 가능합니다. 치료 시 살을 늘려 튼살이 찢어진 방향을 확인한 뒤 그 방향을 따라 시술하면 효과가 더 좋아요.', '미라젯이 손주사보다 튼살 치료에 효과적인 원리를 피부과 전문의 정한미가 안내합니다.', array['미라젯', '튼살', '쥬베룩', '콜라겐', '피부재생', '주사시술']::text[]),
    ('7Igx2xG-2Qw', 'jeonghanmi', '붉은 튼살에 바르는 연고가 있다던데 정말 효과 있나요?', '네, 아직 색이 빨간 초기 튼살에는 트레티노인 성분이 든 투앤티 크림이 효과가 있습니다. 트레티노인은 피부 세포의 턴오버를 촉진하고 콜라겐 생성을 자극해 새로운 피부 재생을 도와주는 성분이에요. 다만 최소 3-6개월은 꾸준히 발라야 효과를 느낄 수 있고, 바르는 양은 완두콩 절반 크기를 손등에 덜어 얇게 펴 바르는 정도면 충분합니다. 처음에는 일주일에 2-3번만 바르다가 피부가 적응되면 매일로 늘려가는 게 좋아요. 너무 많이 바르면 오히려 피부가 붉어지고 자극이 심해질 수 있는데, 그럴 때는 보습제와 반반 섞어 희석해서 바르면 됩니다. 중요한 주의사항은 임신 중에는 절대 사용하면 안 된다는 것이에요. 다만 붉은 튼살이라고 연고만으로 100% 없어지는 건 아니니 피부과 진료를 병행하시는 게 좋습니다.', '붉은 튼살에 효과 있는 트레티노인 연고의 사용법과 주의사항을 피부과 전문의 정한미가 정리합니다.', array['튼살', '트레티노인', '투앤티크림', '붉은튼살', '콜라겐', '피부재생']::text[]),
    ('7Igx2xG-2Qw', 'jeonghanmi', '튼살 없앤다는 크림이나 커피 스크럽 같은 홈케어 정말 소용없나요?', '네, 하얗게 자리 잡은 오래된 튼살에는 크림이나 스크럽 같은 홈케어가 효과 없습니다. 튼살이 하얘졌다는 건 이미 흉터처럼 굳어졌다는 의미여서, 피부 속을 자극하거나 찢어주는 수준의 치료가 아니면 개선이 안 됩니다. 좋다는 크림, 연고, 디바이스, 심지어 커피 원두가루로 문지르는 방법까지 다 시도해 봐도 효과가 없는 이유가 바로 이것이에요. 홈케어 제품들은 피부 표면에만 작용할 뿐 패여 있는 피부 속까지 도달하지 못합니다. 반면 붉은색이 남아 있는 초기 튼살이라면 트레티노인 크림을 꾸준히 바르면 어느 정도 개선 가능해요. 그래서 피부에 어떤 흔적이 보일 때 가장 좋은 방법은 가까운 피부과에서 진료를 받아보는 것입니다. 빨리 대응할수록 치료 결과가 좋기 때문에 망설이지 마시고 상담받아 보세요.', '홈케어로 오래된 튼살이 안 없어지는 이유와 올바른 대처법을 피부과 전문의 정한미가 안내합니다.', array['튼살', '홈케어', '튼살크림', '트레티노인', '피부재생', '튼살연고']::text[]),
    ('OUeJq_4dlYs', 'kimjongsik', '데오드란트 바르면 겨드랑이 땀이 줄어드는 거 아닌가요?', '아닙니다. 데오드란트는 땀 자체를 줄여주는 게 아니라 땀 냄새만 줄여주는 제품입니다. 데오드란트는 땀이 났을 때 주변 세균 번식을 억제해서 냄새를 줄여주는 역할만 하지, 땀 분비 자체를 막지는 못해요. 땀 자체를 억제하려면 알루미늄클로로하이드레이트 성분이 포함된 제품을 써야 합니다. 대표적으로 노스엣이나 드리클로 같은 약국 제품이 있는데, 아이돌들이 무대에서 땀 없이 춤출 수 있는 비결이 바로 드리클로예요. 사용법이 중요한데, 저녁에 샤워 후 물기를 완전히 말린 뒤 바르고 다음 날 아침에 씻어내면 됩니다. 면도 직후에는 피부 자극이 되니 최소 하루 이상 지난 뒤에 발라야 해요. 만원 정도로 약국에서 쉽게 구할 수 있으니 겨드랑이 땀 때문에 회색 옷을 포기하셨던 분들은 한번 시도해 보세요.', '데오드란트와 땀 억제제의 차이점 및 약국 제품 사용법을 피부과 전문의 김종식이 설명합니다.', array['데오드란트', '겨드랑이땀', '노스엣', '드리클로', '다한증', '땀억제제']::text[]),
    ('OUeJq_4dlYs', 'kimjongsik', '겨드랑이 보톡스 한 번 맞으면 얼마나 효과가 지속되나요?', '겨드랑이 보톡스는 한 번 시술에 4-6개월 정도 효과가 지속됩니다. 시술 후 일주일 정도만 지나면 땀 분비가 확실하게 억제되기 시작해요. 6-8월 한여름을 대비해 4-5월에 맞으면 뽀송한 겨드랑이로 여름을 보낼 수 있습니다. 시술 자체는 마취크림 바르고 겨드랑이 전체에 보톡스를 주사하면 끝인데, 실제 시술 시간은 1분 정도밖에 안 걸려요. 마취크림 덕분에 통증도 거의 못 느낄 수준이고, 당일부터 일상생활이 가능합니다. 주기적으로 시술을 받다 보면 맞는 주기가 점점 길어지기도 하고, 심하지 않은 분들은 몇 년 맞고 나면 아예 안 맞아도 될 정도로 좋아지기도 해요. 당일 무리한 운동이나 카페인, 사우나는 피하시고 면도는 하루 전까지만 하시면 됩니다.', '겨드랑이 보톡스의 지속 기간과 시술 과정 및 주의사항을 피부과 전문의 김종식이 안내합니다.', array['보톡스', '겨드랑이땀', '다한증', '땀억제시술', '겨드랑이보톡스']::text[]),
    ('OUeJq_4dlYs', 'kimjongsik', '옷 소재만 바꿔도 겨드랑이 땀이 줄어들 수 있나요?', '네, 옷의 소재와 핏만 신경 써도 겨드랑이 땀이 확실히 줄어듭니다. 폴리에스터나 레이온 같은 합성 소재는 촉감은 좋지만 통풍이 안 돼서 체온이 올라가고 땀이 더 쉽게 나요. 통풍이 잘 되는 소재의 이너웨어를 입는 것만으로도 겨드랑이 땀에 큰 도움이 됩니다. 너무 달라붙는 핏보다는 여유 있는 핏이 땀 억제에 더 효과적이에요. 많은 분들이 땀 자국 때문에 한여름에도 긴팔을 걸치는데, 소재와 핏만 바꿔도 그럴 필요가 없어집니다. 물론 옷을 바꾸고 약국 제품도 써봤는데 효과가 없다면 피부과에서 보톡스 시술을 받는 게 확실한 방법이에요. 겨드랑이 털도 미는 게 좋은데, 털이 있으면 땀이 오래 머물면서 냄새가 더 나고 옷에도 더 많이 묻기 때문입니다.', '옷 소재와 핏이 겨드랑이 땀에 미치는 영향과 관리법을 피부과 전문의 김종식이 정리합니다.', array['겨드랑이땀', '다한증', '옷소재', '합성섬유', '통풍', '이너웨어']::text[]),
    ('OUeJq_4dlYs', 'kimjongsik', '레이저 제모랑 겨드랑이 보톡스 같은 날 맞아도 되나요?', '같은 날은 권하지 않지만, 두 시술을 병행하는 것 자체는 전혀 문제없습니다. 레이저 제모도 피부에 센 레이저를 쏘는 자극적인 시술이기 때문에 같은 날 보톡스까지 맞으면 피부에 부담이 될 수 있어요. 날짜를 나눠서 받으시면 됩니다. 겨드랑이 털이 많은 분이라면 제모를 하는 게 땀 관리에도 도움이 됩니다. 털이 많으면 땀이 털에 묻어 있는 시간이 길어져 냄새가 더 심해지고, 긴 털 때문에 옷에도 땀이 더 많이 묻거든요. 제모를 하면 더 깔끔하고 냄새도 덜 납니다. 보톡스 시술 전에 면도를 꼭 해야 하나 걱정하시는 분들도 있는데, 사실 안 해도 시술은 가능합니다. 다만 면도를 하신다면 시술 하루 전까지만 해주시면 돼요.', '겨드랑이 보톡스와 레이저 제모 병행 시 주의할 점을 피부과 전문의 김종식이 설명합니다.', array['겨드랑이보톡스', '레이저제모', '다한증', '겨드랑이땀', '제모']::text[]),
    ('X3lT-AxxxYM', 'baejungmin', '백반증 신약 옵젤루라 효과가 부족하면 어떻게 해야 하나요?', '옵젤루라 단독으로 초기 반응이 미흡한 경우 자외선 치료를 병행하면 치료 결과를 크게 높일 수 있습니다. 55명 대상 연구에서 12주간 옵젤루라를 하루 2회 도포한 뒤 25% 이상 개선된 반응군은 크림만으로 48주에 몸 전체 70%, 얼굴 91%까지 호전되었어요. 반면 25% 미만으로 반응이 미흡했던 35명에게 주 3회 자외선 치료를 추가하자 48주에 몸 전체 50%, 얼굴 86%까지 개선되었습니다. 심각한 부작용도 관찰되지 않았어요. 아직 우리나라에는 옵젤루라가 들어오지 않았지만, 소규모 비교 연구에서 프로토픽의 효과가 옵젤루라와 비슷한 수준으로 나타났습니다. 연고 단독으로는 부족할 수 있어도 자외선 치료를 병행하면서 연고를 열심히 바르면 치료 결과를 높일 수 있어요. 국내에서도 현재 쓸 수 있는 치료를 꾸준히 병행하는 것이 중요합니다.', '옵젤루라 크림과 자외선 치료 병합요법의 최신 연구 결과를 피부과 전문의 배정민이 설명합니다.', array['백반증', '옵젤루라', '자외선치료', 'JAK억제제', '프로토픽', '색소재생']::text[]),
    ('X3lT-AxxxYM', 'baejungmin', '백반증은 빨리 치료할수록 정말 효과가 좋은 건가요?', '네, 백반증은 발생 초기에 적극적으로 치료할수록 효과가 훨씬 좋습니다. ERASE Vitiligo 연구에서 발생 6개월 이내 초기 환자들은 같은 치료를 받아도 오래된 환자들보다 반응이 훨씬 뛰어났어요. 모든 환자에게 주 3회 자외선 치료와 경구 스테로이드 주 2회 주말요법을 6개월간 시행했는데, 초기 환자군의 치료 반응이 가장 우수했습니다. 초기에 강력한 스테로이드 치료를 받은 환자들에게서 백반증 재발에 관여하는 조직 상주 기억 T세포의 수와 활성도가 크게 감소한 것도 확인되었어요. 실제 진료실에서도 발생 한두 달 이내에 치료를 시작한 환자 중 10년이 지나도 재발하지 않는 경우가 있습니다. 백반증 초기에 지켜보자는 접근보다는 즉시 치료를 시작하는 것이 장기적으로 더 나은 결과를 가져올 수 있어요. 물론 치료는 환자 개인 상황과 주치의 상담을 통해 결정해야 합니다.', '백반증 조기 치료가 장기적 효과와 재발 방지에 중요한 이유를 피부과 전문의 배정민이 안내합니다.', array['백반증', '조기치료', '스테로이드', '자외선치료', '재발방지', 'T세포']::text[]),
    ('X3lT-AxxxYM', 'baejungmin', '얼굴 백반증도 타입에 따라 원인이 다른 건가요?', '네, 얼굴 백반증은 발생 양상에 따라 3가지 타입으로 분류되며 각각 원인과 치료 반응이 다릅니다. 473명을 분석한 연구에서 가장 흔한 얼굴 중앙형(10명 중 7명)은 눈, 코, 입 주변에 발생하며, 반복적인 마찰이 원인으로 손으로 얼굴을 자주 만지는 습관이 좋지 않습니다. 얼굴 전체형은 양 광대 주변으로 넓게 퍼지는 유형으로 평균 48세에 발생하고, 햇빛 노출이 원인이라 자외선 차단제를 열심히 바르는 것이 재발 방지에 도움됩니다. 이마선국한형은 이마선과 두피 경계에 집중 발생하며 주로 고령층에서 나타나요. 두피의 멜라닌 세포 소실과 관련이 있고, 발병 초기에는 치료 반응이 있지만 시간이 지나면 반응이 떨어집니다. 얼굴 중앙형과 전체형은 엑시머 레이저 치료 효과가 좋은 편이에요. 이렇게 타입별로 원인과 치료가 다르기 때문에 정확한 분류가 중요합니다.', '얼굴 백반증 3가지 타입별 원인과 치료 반응 차이를 피부과 전문의 배정민이 정리합니다.', array['백반증', '얼굴백반증', '엑시머레이저', '자외선차단', '멜라닌', '색소']::text[]),
    ('X3lT-AxxxYM', 'baejungmin', '백반증 새로운 분류법이 치료에 어떤 도움이 되나요?', '백반증을 5개 그룹으로 세분화하면 각 환자에게 맞는 치료 강도와 전략을 정할 수 있습니다. 기존에는 분절형과 비분절형 두 가지로만 분류했지만, 399명을 분석한 클러스터 연구에서 경증(31%, 평균 28세), 고활성(계속 번지는 유형, 35세), 광범위(15% 침범, 52세), 경증 마찰, 중등도 마찰 등 5개 그룹이 확인되었어요. 고활성 백반증은 현재 번지고 있어 스테로이드 같은 강력한 전신치료가 필요하고, 광범위 백반증은 여러 치료를 병용하는 장기적 접근이 필요합니다. 마찰 부위형은 손, 팔꿈치, 무릎 등 마찰이 잦은 곳에 생기는 유형으로 마찰을 줄이는 생활 관리가 중요해요. 이런 세분화된 분류를 통해 개인 맞춤형 치료 전략을 수립할 수 있고, 치료 효과를 극대화하면서 재발을 최소화하는 데 큰 도움이 됩니다. 같은 백반증이라도 타입에 따라 예후가 완전히 다르기 때문이에요.', '백반증 5개 그룹 분류법이 맞춤 치료 전략에 기여하는 방식을 피부과 전문의 배정민이 설명합니다.', array['백반증', '백반증분류', '스테로이드', '면역치료', '맞춤치료', '마찰백반증']::text[]),
    ('oOJeEFCMnPI', 'parkhyojin', '스킨보톡스가 피지 줄이는 데 진짜 효과 있나요?', '네, 스킨보톡스는 피지 분비를 논문 기준 최대 80%까지 줄여주는 가성비 끝판왕 시술입니다. 보톡스가 피지샘에서 피지가 분비되는 신경전달을 차단하기 때문에, 피부에 고르게 깔리면 전체적으로 피지 분비가 확 줄어듭니다. 한 번만 받아도 효과가 있고, 효과가 3-4개월까지 지속되는 게 큰 장점이에요. 다른 시술들은 꾸준히 계속 받아야 하는 경우가 많지만 스킨보톡스는 한 번으로도 체감 가능합니다. 4-5월에 맞아두면 7-8월 여름 피부 뒤집어짐을 예방할 수 있어요. 다만 주사로 한 땀 한 땀 놓는 방식이다 보니 콧구멍이나 콧볼 같은 좁은 부위까지 완벽하게 커버하기는 어렵습니다. T존 전체적으로 피지를 줄이고 싶으신 분들에게 딱 하나만 추천한다면 이 시술이 가장 가성비 좋은 선택이에요.', '스킨보톡스의 피지 분비 감소 효과와 시술 장단점을 피부과 전문의 박효진이 안내합니다.', array['스킨보톡스', '피지', '보톡스', '모공', '피지분비', '지성피부']::text[]),
    ('oOJeEFCMnPI', 'parkhyojin', '미세바늘 고주파가 피지선을 태워서 없앤다는데 정말인가요?', '네, 포텐자나 버츄RF, 실펌 같은 미세바늘 고주파 시술은 피지선을 파괴하면서 콜라겐도 재생시켜 피지 분비를 약 80% 줄여줍니다. 바늘들이 피부에 들어가 고주파 전류를 흘려보내면 피지선이 파괴되는 원리인데, T존, 콧구멍, 콧볼까지 집중적으로 시술할 수 있어 스킨보톡스가 커버 못하는 좁은 부위도 관리 가능해요. 다만 한 번으로는 조금 약하고 세 번 정도 꾸준히 받아야 확실한 효과를 볼 수 있습니다. 실제로 세 번만 받으면 매일 피지를 긁어내던 습관이 현저히 줄어들었다는 환자분들이 많아요. 통증이 꽤 있어서 마취크림을 보통보다 길게 45분 정도 바르는 게 좋고, 시술 후 2-3일 정도 살짝 붉을 수 있지만 화장으로 가려지는 수준입니다. 아쿠아필로 피지를 먼저 뽑아낸 뒤 미세바늘 고주파를 하면 시너지 효과가 제일 좋습니다.', '미세바늘 고주파 시술의 피지선 파괴 원리와 효과를 피부과 전문의 박효진이 설명합니다.', array['미세바늘고주파', '포텐자', '버츄RF', '실펌', '피지선', '피지', '모공']::text[]),
    ('oOJeEFCMnPI', 'parkhyojin', 'SNS에서 핫한 피지 제거 제품들 진짜 효과 있나요?', '피부과 전문의 입장에서 봐도 SNS에 나오는 피지 제거 영상들은 좋은 방법이 아닙니다. 바세린으로 오래 문지르거나 피지를 쏙쏙 뽑아내는 영상이 인기인데, 직접 구매해서 해봤더니 진정 효과 정도는 있지만 피지를 빼낼 정도로 탁월하지는 않았어요. 모공에서 직접 피지를 뽑아내는 행위는 모공을 넓히기 때문에 오히려 피부를 망칠 수 있습니다. 이런 광고 제품들을 맹신하지 말고, 진정 효과 정도만 기대하며 쓰는 게 맞아요. 홈케어는 이미 나온 기름과 피지를 녹여주는 수준일 뿐, 근본적으로 피지 분비를 줄이지는 못합니다. 피지가 진짜 없어졌으면 좋겠다면 스킨보톡스나 미세바늘 고주파처럼 피지 분비 자체를 줄이는 시술이 필요해요. 가장 기본은 피부 타입에 맞는 올바른 클렌징으로 모공이 막히지 않게 관리하는 것입니다.', 'SNS에서 유행하는 피지 제거법의 실제 효과와 올바른 관리법을 피부과 전문의 박효진이 정리합니다.', array['피지', '블랙헤드', '모공', '클렌징', '홈케어', '피지관리']::text[]),
    ('oOJeEFCMnPI', 'parkhyojin', '건성인데 T존만 기름지면 클렌징 어떻게 해야 하나요?', '건성인데 T존만 기름진 분들은 T존에만 집중해서 클렌징하고, 건조한 부위는 보습을 듬뿍 해주는 게 정답입니다. T존에는 클렌징 오일이나 밀크를 천천히 롤링해서 피지를 빼주되, 과하게 제거하려다 보면 건조한 부위가 더 당길 수 있으니 부위를 나눠 관리해야 해요. 기존에 속당김과 갈라짐이 있는 건조 부위에는 로션을 넉넉히 발라주시면 됩니다. 반면 낮이면 화장이 다 뜨는 지성 피부분들은 클렌징 오일보다 밀크나 젤을 추천드려요. 오일 제품이 지성 피부에는 잘 끼이기 때문에 덜 씻길 수 있거든요. 1차 세안 후 거품이 충분한 세안제로 2차 세안을 하면 됩니다. 여름에는 피지 분비가 활발해지는 데다 선크림까지 더해져 모공이 쉽게 막히니, 계절에 따라 산뜻한 보습제로 바꿔주는 것도 중요합니다.', '피부 타입별 올바른 클렌징 방법과 여름철 모공 관리법을 피부과 전문의 박효진이 안내합니다.', array['클렌징', '피지', 'T존', '지성피부', '건성피부', '모공', '세안']::text[]),
    ('TlOzDryC6Ck', 'kwonsuhyun', '마스크팩 1일 1팩 하면 진짜 피부가 좋아지나요?', '아닙니다. 1일 1팩이 오히려 피부에 독이 될 수 있습니다. 팩 안에는 좋은 성분뿐 아니라 방부제, 향료 같은 화학 성분도 들어 있기 때문에 매일 다양한 팩을 사용하면 피부에 자극이 축적돼요. 특히 피부 컨디션이 안 좋을 때 팩을 꺼내 쓰는 경우가 많은데, 그 상태에서 여러 성분에 노출되면 오히려 문제가 더 심해질 수 있습니다. 뭔가를 얼굴에 바르면 무조건 좋다고 생각하시는 분들이 많은데 그건 완전한 오해예요. 같은 팩만 매일 쓰더라도 방부제 등의 누적 자극이 생길 수 있고, 여러 종류를 돌려가며 쓰면 각기 다른 성분들이 피부를 더 혼란스럽게 만듭니다. 팩은 특별한 날 가끔 쓰는 정도가 적당하고, 매일 하는 것보다는 기본 보습을 확실히 해주는 게 피부 건강에 훨씬 좋습니다.', '1일 1팩이 피부에 오히려 독이 될 수 있는 이유를 피부과 전문의 권수현이 설명합니다.', array['1일1팩', '마스크팩', '피부자극', '방부제', '스킨케어', '피부관리']::text[]),
    ('TlOzDryC6Ck', 'kwonsuhyun', '화장품 스킨부터 크림까지 풀라인 다 발라야 효과 있나요?', '아닙니다. 같은 라인 제품을 전부 바르는 건 비슷한 성분을 7번 반복하는 것과 다름없어 의미가 없습니다. 예를 들어 미백 라인으로 스킨, 앰플, 세럼, 로션, 크림을 다 사도 결국 거의 같은 성분을 묽기만 다르게 계속 바르는 거예요. 피부가 흡수할 수 있는 양에는 한계가 있어서, 다 바른다고 다 스며드는 게 아닙니다. 추천하는 방법은 내가 원하는 기능성 제품 하나(예: 미백이면 비타민C)와 피부 장벽을 보호해주는 좋은 보습제 하나, 딱 두 가지면 충분해요. 보습을 더 추가하고 싶다면 히알루론산처럼 성분이 다른 제품을 하나 더 쓰는 건 의미가 있습니다. 중요한 건 같은 성분을 단계별로 바르는 게 아니라 다른 성분을 조합하는 것이에요. 기능성 하나, 보습 하나만 잘 골라도 그간 풀라인에 쓰던 돈을 아낄 수 있습니다.', '화장품 풀라인 사용이 불필요한 이유와 효율적인 조합법을 피부과 전문의 권수현이 안내합니다.', array['화장품', '스킨케어', '보습제', '비타민C', '히알루론산', '기능성화장품']::text[]),
    ('TlOzDryC6Ck', 'kwonsuhyun', '피부과 시술 자주 받으면 피부가 얇아진다는 게 사실인가요?', '아닙니다. 피부과 시술을 받는다고 피부가 얇아지는 건 아닙니다. 프락셀 같은 박피 시술 이후 이런 오해가 생긴 것 같은데, 정확히 말하면 피부가 얇아지는 게 아니라 일시적으로 민감해질 수 있는 것이에요. 바닥에 긁혀도 피부가 영구적으로 얇아지지 않듯이, 피부는 재생 능력이 있어서 충분한 회복 기간을 거치면 원래대로 돌아옵니다. 의사의 판단에 따라 적절한 주기로 받으면 문제가 없고, 오히려 고주파 시술 같은 경우는 피부를 더 건강하게 만들 수도 있어요. 레이저 시술을 많이 하면 더 이상 할 수 없다는 이야기도 사실이 아닙니다. 너무 자주 하거나 과하게 했을 때 민감해지는 현상이 생길 수는 있지만, 전문의와 함께 관리하면 안전하게 오래 시술을 받을 수 있습니다.', '피부과 시술이 피부를 얇게 만든다는 오해의 진실을 피부과 전문의 권수현이 정리합니다.', array['피부과시술', '레이저', '프락셀', '피부재생', '피부장벽', '고주파']::text[]),
    ('TlOzDryC6Ck', 'kwonsuhyun', '피부과 약은 독하다는데 먹어도 괜찮은 건가요?', '피부과 약이 특별히 독한 건 아닙니다. 스테로이드, 무좀약, 여드름약이 대표적으로 오해받는데, 이 약들은 다른 과에서도 쓰는 일반적인 치료 약제예요. 스테로이드에 대한 부정적 인식은 과거에 용량 조절 없이 오래 복용하면서 부작용이 생긴 경우 때문인데, 적재적소에 적당량으로 쓰고 끊으면 오히려 이보다 좋은 약이 없습니다. 병이 작을 때 빨리 짧게 먹고 치료하는 것이 오히려 부작용이 적고 몸에 더 낫습니다. 무좀약은 손발톱 무좀의 경우 최소 6개월은 복용해야 하지만, 중간에 간 기능 검사를 하면서 드시기 때문에 위험하지 않아요. 다만 여드름 피지 조절제는 임신 중 복용하면 기형아 출산 위험이 있어 이 약만은 임신 시 주의가 필요합니다. 보습제만으로 안 되는 피부 질환에는 전문의 처방을 믿고 치료받으시는 게 좋습니다.', '피부과 약이 독하다는 오해와 올바른 복용 원칙을 피부과 전문의 권수현이 설명합니다.', array['피부과약', '스테로이드', '무좀약', '여드름약', '부작용', '피부질환']::text[]),
    ('GAwFS2SaeKM', 'jeonghanmi', '여드름이 계속 같은 부위에만 나는데 원인이 뭔가요?', '사람마다 피지샘이 많이 발달한 부위가 달라서 그 부위에 여드름이 반복적으로 생깁니다. 피지샘에서 피지가 과도하게 만들어지면 문제가 시작되는데, 어떤 분은 턱에, 어떤 분은 볼에 피지샘이 집중 발달되어 있어요. 발달된 부위에서 피지 배출이 원활하지 않으면 거기서 계속 염증이 생기는 악순환에 빠지게 됩니다. 대부분은 T존(이마·코)에 피지가 많지만, 볼이나 턱에 집중되는 분들도 상당히 많아요. 결국 본인의 피지샘 분포가 여드름 위치를 결정짓는 셈이라서, 특정 부위만 관리하기보다 그 부위의 피지 조절에 집중하는 게 효과적입니다. 피부과에서는 부위별 상태를 보고 적절한 치료를 설계해 드리니까 반복되는 여드름이 있다면 한번 상담받아 보시는 걸 추천드려요.', '같은 부위에 반복되는 여드름의 원인과 피지샘 분포 차이를 피부과 전문의 정한미가 설명합니다.', array['여드름', '피지샘', '트러블', '반복여드름', '피지', 'T존', '지성피부']::text[]),
    ('GAwFS2SaeKM', 'jeonghanmi', '여드름 피부한테 가장 중요한 생활 습관이 뭐예요?', '여드름 관리에서 가장 중요한 생활 습관은 수면입니다. 여드름으로 병원에 오시는 분들을 보면 잠을 잘 주무시는 분이 거의 없어요. 늦게 자거나, 수면 시간이 부족하거나, 불규칙하게 주무시는 분이 대부분입니다. 실제로 밤낮이 바뀌어 새벽에 일하던 시기에 여드름이 미친 듯이 번졌다는 사례도 있을 정도로 수면과 여드름은 직접적인 관계가 있어요. 잠을 못 자면 얼굴이 뒤집어지듯이 여드름도 똑같이 반응합니다. 비싼 제품이나 시술보다 규칙적인 수면이 피부를 지키는 가장 기본적인 보약인 셈이죠. 여드름으로 고민이시라면 스킨케어 루틴을 바꾸기 전에 수면 패턴부터 점검해 보세요.', '여드름 피부에 수면이 가장 중요한 생활 습관인 이유를 피부과 전문의 정한미가 안내합니다.', array['여드름', '수면', '생활습관', '피부관리', '트러블', '수면부족', '피지']::text[]),
    ('GAwFS2SaeKM', 'jeonghanmi', '건성인데도 여드름이 나는 건 왜 그런 건가요?', '건성 피부도 여드름이 나는 원인은 지성과 동일하게 피지샘의 문제이지만, 해결법이 다릅니다. 악건성 피부는 물을 잘 만들어내지 못해 너무 건조해지면 오히려 피부가 기름을 과도하게 분비하게 돼요. 그 과잉 피지가 모공을 막으면서 여드름이 생기는 구조입니다. 이런 경우에는 기름을 줄이는 게 아니라 수분을 충분히 채워주는 게 핵심 해결법이에요. 지성 피부라면 유분 조절이 1순위지만, 건성 여드름은 보습이 치료의 시작입니다. 복합성이신 분들은 건조한 부위에 수분을 채워주고 기름기 많은 부위엔 가벼운 제품을 쓰는 식으로 나눠 관리해 주시면 됩니다. 원인은 같지만 피부 타입에 따라 접근법을 달리해야 효과를 볼 수 있어요.', '건성 피부에도 여드름이 생기는 원인과 수분 보충 중심 해결법을 피부과 전문의 정한미가 정리합니다.', array['건성여드름', '수분부족', '보습', '피지', '복합성피부', '여드름', '피부타입']::text[]),
    ('GAwFS2SaeKM', 'jeonghanmi', '여드름 약 효과 끊으면 다시 올라오지 않나요?', '오래된 여드름에는 먹는 약이 가장 강력하고 확실한 치료법이며, 유지는 홈케어로 가능합니다. 잠깐 올라온 여드름과 오랫동안 반복되는 여드름은 치료 접근이 달라야 하는데, 만성 여드름이라면 먹는 약을 가장 많이 처방합니다. 약만큼 빠르고 효과가 확실한 방법은 없기 때문이에요. 약을 끊고 나서의 유지가 관건인데, 이때 집에서의 꾸준한 케어가 중요합니다. 적절한 세안제 선택, 각질 관리, 스팟 제품 사용 같은 홈케어 루틴을 잘 잡아두면 약 없이도 피부 상태를 유지할 수 있어요. 약은 불을 끄는 역할이고 홈케어는 불이 다시 붙지 않게 관리하는 역할이라고 생각하시면 됩니다. 클래식한 기본 관리가 결국 가장 중요해요.', '여드름 약 복용 후 재발 방지를 위한 홈케어 유지 전략을 피부과 전문의 정한미가 안내합니다.', array['여드름약', '홈케어', '만성여드름', '여드름치료', '피부관리', '재발방지', '스킨케어']::text[]),
    ('jppKl6_0z9g', 'jeonghanmi', '여름에 피지 폭발하는데 실리마린 성분이 정말 도움 되나요?', '네, 실리마린은 피지 분비를 줄여주고 항산화·진정 효과까지 있어 여름철 지성 피부에 효자 성분입니다. 밀크씨슬(엉겅퀴)에서 추출한 성분인데 피부에서의 효과가 세 가지나 돼요. 첫째, 더위나 자극으로 붉어진 피부를 진정시켜 줍니다. 둘째, 활성산소를 제거하는 항산화 효과가 비타민 E보다 뛰어나서 피부 노화를 막아줘요. 셋째, 피지 분비를 줄여 모공과 블랙헤드 개선에도 도움이 됩니다. 피지가 산화되면 염증과 트러블을 일으키는데, 실리마린이 이 산화 자체를 차단해 주는 거죠. 기름이 많이 돌면서 트러블까지 잘 나는 피부라면 여름 세럼으로 실리마린 함유 제품을 선택해 보세요.', '밀크씨슬 추출 실리마린은 피지 조절·항산화·진정 3가지 효과를 가진 여름 피부 효자 성분입니다. 지성 피부 활용법을 피부과 전문의 정한미가 설명합니다.', array['실리마린', '밀크씨슬', '피지조절', '항산화', '모공', '블랙헤드', '여름스킨케어', '지성피부']::text[]),
    ('jppKl6_0z9g', 'jeonghanmi', '비타민C 세럼 중에 지성 여드름 피부용으로 좋은 게 있나요?', '스킨수티컬즈의 실리마린 CF 세럼이 지성·여드름성 피부를 위한 전용 항산화 비타민C 세럼으로 추천됩니다. 비타민C 15%와 페룰릭애씨드가 들어가 미백·항산화 효과를 제공하면서, 여기에 실리마린과 살리실산(BHA)이 추가로 배합돼 있어요. 실리마린이 염증과 트러블을 가라앉히고, 살리실산이 피지를 잡아주며 모공을 깨끗하게 관리해 줍니다. 같은 브랜드의 CE 페룰릭과 비교하면 제형이 훨씬 산뜻해서 여름에 끈적임 없이 쓰기 좋아요. 원래 비타민C 세럼을 쓰고 있는데 여름에 답답하다고 느끼시는 분들이 교체하기에 딱입니다. 여드름 후 색소침착 개선에도 비타민C가 도움이 되니 트러블 자국이 신경 쓰이는 분들도 고려해 보세요.', '스킨수티컬즈 실리마린 CF는 비타민C 15%에 살리실산까지 배합돼 지성·여드름 피부에 적합합니다. 여름용 비타민C 세럼 선택 기준을 피부과 전문의 정한미가 정리합니다.', array['비타민C세럼', '실리마린', '스킨수티컬즈', '여드름', '항산화', '색소침착', 'BHA', '지성피부']::text[]),
    ('jppKl6_0z9g', 'jeonghanmi', '실리마린 화장품 부작용은 없어요? 주의할 점이 있나요?', '실리마린은 식물 추출 성분이라 매우 안전하며, 임상 연구에서도 특별한 부작용이 보고되지 않았습니다. 다만 밀크씨슬이 국화과 식물이기 때문에 국화과 알레르기가 있는 분들은 주의가 필요해요. 그 외에 부작용이라 할 만한 건 거의 없지만 구매 시 체크해야 할 포인트는 있습니다. 전성분표에서 실리마린이나 밀크씨슬 추출물이 너무 하위에 적혀 있으면 함량이 적어 실질적인 효과를 보기 어렵거든요. 그래서 제품을 고를 때 성분이 전성분표 어디쯤에 위치하는지 확인하시는 게 좋습니다. 또 알코올이 상위 성분에 있는 제품은 민감 피부에 자극이 될 수 있으니 전성분표를 꼼꼼히 살펴보세요. 성분 위치만 잘 확인하면 안심하고 사용할 수 있는 순한 성분이에요.', '실리마린은 안전한 성분이지만 국화과 알레르기가 있으면 주의가 필요합니다. 전성분표에서 함량과 자극 성분을 확인하는 법을 피부과 전문의 정한미가 안내합니다.', array['실리마린', '밀크씨슬', '부작용', '국화과알레르기', '전성분표', '민감피부', '성분확인']::text[]),
    ('jppKl6_0z9g', 'jeonghanmi', '실리마린 화장품만 발라도 여드름이 나아질 수 있나요?', '임상연구에서 실리마린이 실제로 피지 분비량을 줄이고 염증성 여드름을 감소시킨 결과가 있어, 도움이 됩니다. 바르는 것뿐 아니라 먹었을 때도 여드름과 피부 유분 개선에 효과가 있다는 연구까지 있을 정도예요. 다만 실리마린 화장품 단독으로 극적인 변화를 기대하기는 어렵고 기초 루틴과 함께 써야 시너지가 납니다. 유분이 많은 피부라면 약알칼리성 클렌저로 피지를 깨끗이 씻어내 주시고, 자극 없는 진정 토너를 쓴 뒤 실리마린 세럼을 발라주면 좋아요. 거기에 살리실산이나 나이아신아마이드 성분 제품을 함께 쓰면 모공케어, 항산화, 피부 진정이 동시에 이뤄집니다. 실리마린은 단독 해결사라기보다 전체 루틴의 핵심 축으로 활용하시는 게 가장 효과적이에요.', '실리마린은 임상연구에서 피지 감소와 여드름 개선이 확인된 성분입니다. 나이아신아마이드·살리실산과 함께 쓰는 루틴을 피부과 전문의 정한미가 설명합니다.', array['실리마린', '여드름', '피지조절', '나이아신아마이드', '클렌징', '스킨케어루틴', '항산화']::text[]),
    ('iL-N8_oBHPE', 'parkhyojin', '모공은 홈케어로 진짜 줄일 수 없는 건가요?', '네, 모공은 홈케어로 절대 작아질 수 없습니다. 화장품은 피부 속으로 들어가지 못하기 때문이에요. 모공 문제는 겉이 아니라 속에서 해결해야 하는 건데, 홈케어는 당장 돌고 있는 기름을 닦거나 표면 진정 정도의 효과만 있을 뿐입니다. 화장품이 피부 깊숙이 침투해서 피지샘이나 콜라겐 구조를 바꿀 수는 없어요. 모공을 진짜 줄이려면 피지 분비 경로를 차단하거나 콜라겐을 새로 만들어주는 시술이 필요합니다. 다만 모공 타입에 따라 필요한 시술이 다르기 때문에 본인의 모공이 왜 넓어졌는지부터 파악하는 게 첫 단계예요. 셀프 진단으로 원인을 알고 병원에 가야 불필요한 시술을 피할 수 있습니다.', '모공이 홈케어로 줄지 않는 과학적 이유와 시술이 필요한 근거를 피부과 전문의 박효진이 설명합니다.', array['모공', '홈케어', '화장품한계', '피지', '모공축소', '모공시술', '콜라겐']::text[]),
    ('iL-N8_oBHPE', 'parkhyojin', '피지 많고 모공 큰 피부는 스킨보톡스가 답인가요?', '피지 과다로 늘어난 모공에는 스킨보톡스가 가성비 끝판왕 치트키입니다. 스킨보톡스가 피부에 들어가면 피지샘에서 피지를 분비시키는 신경 전달 경로를 차단하거든요. 논문에 따르면 최대 80%까지 피지 분비가 감소한다는 결과가 있습니다. 양쪽 볼에 쫙 깔아주면 피지 자체가 줄고 모공을 왔다갔다 하는 양이 적어지니 모공이 눈에 띄게 좁아져요. 자국이 좀 있어도 바로 화장 가능하고 일상생활도 문제없으며, 한 번만 해도 효과를 볼 수 있습니다. 다만 코·미간·이마처럼 근육 움직임이 중요한 부위에는 넣기 어려운 한계가 있어요. 그런 부위까지 관리하고 싶다면 미세바늘 고주파를 추가로 고려해 보세요.', '피지 과다 모공에 스킨보톡스가 효과적인 원리와 한계를 피부과 전문의 박효진이 안내합니다.', array['스킨보톡스', '모공', '피지', '보톡스', '모공축소', '가성비시술', '지성피부']::text[]),
    ('iL-N8_oBHPE', 'parkhyojin', '나이 들면서 모공이 세로로 늘어났는데 뭘 받아야 하나요?', '탄력 저하로 모공이 세로로 늘어난 분들에게 가장 추천하는 시술은 울쎄라입니다. 30대 이후 콜라겐이 줄고 피부가 아래로 처지면서 모공이 더 넓어져 보이는 게 특징인데, 울쎄라는 에너지를 집중시켜 피부 깊은 곳에서부터 탁 올려붙게 조여주는 원리예요. 특히 얕게 들어가는 울쎄라 모드는 모공 주변에만 에너지가 집중돼 조여줍니다. 다만 가격이 부담될 수 있는데, 그럴 때 가성비 대안이 쥬베룩과 피코프락셀 조합이에요. 피코프락셀이 피부에 미세 구멍을 만들고 거기에 콜라겐 씨앗인 쥬베룩을 심으면 콜라겐이 더 잘 자라나 모공이 조여집니다. 4주 간격으로 3회 정도 치료받으면 세안할 때 피부가 매끈해지는 걸 느끼실 수 있어요.', '탄력 저하형 모공에 울쎄라와 쥬베룩·피코프락셀 조합을 피부과 전문의 박효진이 비교합니다.', array['울쎄라', '모공', '탄력', '쥬베룩', '피코프락셀', '콜라겐', '리프팅', '모공축소']::text[]),
    ('iL-N8_oBHPE', 'parkhyojin', '모공도 크고 탄력도 떨어졌는데 하나만 받으면 안 되나요?', '피지형과 탄력형이 복합된 모공은 하나만으로는 부족하고, 여러 시술을 프로그램화해서 받아야 합니다. 이런 혼합형은 먼저 울쎄라와 스킨보톡스로 조여주고 피지 분비를 확 떨어뜨린 뒤, 이후에 쥬베룩+피코프락셀과 미세바늘 고주파를 교대로 반복하는 방식이 효과적이에요. 한 번에 해결되지 않고 시간이 걸리지만, 복합적으로 진행하면 확실히 좋아집니다. 실제로 쥬베룩과 피코프락셀을 받은 환자분들이 피부가 매끈해졌다며 재방문하는 경우가 많아요. 핵심은 병원의 모공 프로그램 안에 이런 시술들이 제대로 섞여 있는지 아는 것입니다. 본인이 모공 원인을 셀프 진단해서 알고 가야 불필요한 시술 없이 효율적으로 치료받을 수 있어요.', '피지+탄력 복합형 모공의 단계별 치료 프로그램을 피부과 전문의 박효진이 정리합니다.', array['모공', '스킨보톡스', '울쎄라', '쥬베룩', '미세바늘고주파', '복합시술', '탄력', '피지']::text[]),
    ('RXvGzvWVmYM', 'parkhyojin', '괄사 마사지가 과학적으로 진짜 효과 있는 건가요?', '네, 괄사는 붓기 빼기와 순환 개선에 실제 효과가 있으며, 논문에서도 증명된 바 있습니다. 자기 전에 얼굴과 목 라인에 해주면 다음 날 붓기가 확실히 빠져 얼굴이 작아 보이고 혈색이 좋아지는 걸 느낄 수 있어요. 다만 괄사로 주름이 펴지거나 피부 탄력이 개선된다는 주장은 비약이 있습니다. 괄사의 진짜 효과는 붓기 제거, 순환 촉진, 뭉친 근육 이완 정도로 생각해 주시면 적절해요. 노화 방지나 주름 개선과는 간접적 관계는 있을 수 있지만 직접적 효과라고 보기는 어렵습니다. 하고 잔 날과 안 하고 잔 날의 차이가 확실하니까 얼굴 라인 관리와 부기 제거 목적으로 가볍게 활용하시면 됩니다. 무거운 기대보다 꾸준한 가벼운 루틴으로 접근하는 게 현실적이에요.', '괄사는 붓기 빼기와 순환 개선에 논문으로 증명된 효과가 있습니다. 다만 주름 개선은 어려운 이유와 현실적 기대치를 피부과 전문의 박효진이 안내합니다.', array['괄사', '붓기', '순환', '림프마사지', '얼굴라인', '부기제거', '마사지']::text[]),
    ('RXvGzvWVmYM', 'parkhyojin', '괄사 할 때 올바른 방향이나 순서가 있나요?', '괄사는 머리부터 시작해서 림프절을 따라 아래로 밀어내리는 순서가 핵심입니다. 위에서부터 두피를 돌기 형태 괄사로 문질러 단단하게 굳은 부분을 풀어주고, 그다음 얼굴을 따라 위치한 림프절 방향으로 밀어줘야 해요. 귀 앞에서 밀어주고, 귀 뒤에서도 밀어준 뒤 결국 목 밑으로 내려주는 게 포인트입니다. 이렇게 하면 노폐물이 림프를 통해 빠져나가 다음 날 얼굴 붓기가 확 빠져 턱 라인이 달라진 걸 느낄 수 있어요. 가슴 앞쪽도 문질러주면 좋고, 특히 겨드랑이는 노폐물이 모이는 곳이라 풀어주면 상체 순환에 도움이 됩니다. 유난히 어깨가 뭉치고 피곤한 날에 마사지샵 대신 집에서 간단히 해줘도 잘 풀리니 루틴으로 넣어보세요.', '괄사는 두피부터 시작해 림프절 방향으로 아래로 밀어내려야 효과적입니다. 귀 앞·귀 뒤·목 밑 순서와 올바른 방법을 피부과 전문의 박효진이 정리합니다.', array['괄사', '림프절', '마사지순서', '붓기', '얼굴라인', '겨드랑이', '림프마사지']::text[]),
    ('RXvGzvWVmYM', 'parkhyojin', '괄사 하다가 멍들거나 트러블 생길 수도 있나요?', '네, 괄사를 잘못 쓰면 멍·접촉성 피부염·트러블 악화가 생길 수 있어 주의가 필요합니다. 처음에 가장 어려운 게 압력 조절인데, 시원하다고 계속 세게 하다 보면 멍이 들기 쉬워요. 소재에 따라 피부에 반복적 마찰을 주면 접촉성 피부염이 발생할 수도 있습니다. 특히 기름이 많고 트러블이 잘 생기는 피부라면 괄사 마찰 때문에 여드름이 더 심해질 가능성이 있어요. 여드름이 늘어나는 것 같으면 괄사를 반드시 의심해 봐야 합니다. 처음엔 가벼운 힘으로 시작해서 조금씩 적응하면서 압력을 높이는 연습이 필요해요. 플라스틱보다는 세라믹 소재가 묵직한 무게감 덕에 힘을 덜 주면서도 마사지 효과가 좋으니 참고하세요.', '괄사를 세게 하면 멍·접촉성 피부염·여드름 악화가 생길 수 있습니다. 압력 조절법과 세라믹 소재 선택 등 주의사항을 피부과 전문의 박효진이 안내합니다.', array['괄사', '부작용', '멍', '트러블', '접촉성피부염', '여드름', '압력조절', '세라믹']::text[]),
    ('RXvGzvWVmYM', 'parkhyojin', '고주파 괄사(파셀라)가 일반 괄사보다 뭐가 다른 건가요?', '파셀라는 괄사에 고주파 에너지를 접목시켜 심부 근막까지 깊이 도달하는 의료기기입니다. 일반 괄사는 물리적으로 표면을 누르는 것에 그치지만, 고주파가 흐르면 열 에너지가 깊은 근막층까지 들어가 유착된 근막과 셀룰라이트를 녹여줍니다. 그래서 일반 괄사보다 효과가 더 빨리 나타나고, 더 강력하며, 더 오래 지속돼요. 실제로 승모근 한쪽만 10분 시술했을 때 어깨 라인이 눈에 띄게 달라진 결과를 확인할 수 있었습니다. 식품의약품안전처 승인 의료기기라 피부과에서 받을 수 있고, 시술 중 하나도 아프지 않고 따뜻해서 잠드시는 분들이 많아요. 울쎄라·써마지 후 관리용으로 쓰거나 웨딩 전 승모근 보톡스와 병행하면 시너지 효과도 뛰어납니다.', '파셀라는 괄사에 고주파를 접목해 심부 근막까지 도달하는 의료기기입니다. 일반 괄사보다 빠르고 강력한 효과와 승모근 관리 활용법을 피부과 전문의 박효진이 설명합니다.', array['파셀라', '고주파괄사', '근막이완', '승모근', '셀룰라이트', '괄사', '붓기', '리프팅']::text[]),
    ('2eIHf-AGh_o', 'jeonghanmi', '얼굴 개기름이 사실은 피부에 좋다는 게 진짜예요?', '네, 피지(개기름)는 피부 노화를 막아주는 천연 보호막으로 무조건 없앨 게 아니라 적당히 유지해야 합니다. 피지가 만든 보호막이 수분 증발을 막아줘서 피부가 건조해지지 않게 지켜주거든요. 건조해지면 주름이 늘고 빨리 늙는데, 적당한 피지가 이걸 방지해 주는 겁니다. 게다가 피지는 항산화 작용과 항균 작용까지 해서 외부 자극으로부터 피부를 보호하는 역할도 합니다. 특히 피지의 핵심 성분인 스쿠알렌이 자외선 차단과 항산화를 담당하는 효자 성분이에요. 다만 피지가 너무 많으면 트러블, 너무 적으면 건조와 장벽 손상이 오니까 균형이 중요합니다. 번들거린다고 무작정 기름을 닦아내기보다 적정량을 유지하는 관리법을 아는 게 핵심이에요.', '피지(개기름)의 노화 방지·보습·항균 효과와 적정 균형 유지법을 피부과 전문의 정한미가 설명합니다.', array['피지', '스쿠알렌', '노화방지', '보습', '항산화', '피부장벽', '유분관리']::text[]),
    ('2eIHf-AGh_o', 'jeonghanmi', '피지 속 스쿠알렌 성분을 화장품으로 바를 수 있나요?', '네, 스쿠알렌에서 더 안정적으로 만든 스쿠알란이라는 성분이 화장품에 들어가 있어 바를 수 있습니다. 스쿠알란은 원래 피지에서 유래한 성분이라 피부 흡수력이 굉장히 좋고, 스쿠알렌보다 덜 끈적거리면서도 안정적이에요. 특히 피부 속건조가 있거나 악건성이신 분들에게 도움이 크게 됩니다. 보습크림이나 장벽크림 뒤 전성분표에서 스쿠알란이 적혀 있는지 확인하면 되는데, 대표 제품으로 에스네이처 아쿠아 스쿠알란 수분크림은 함유량이 높아 악건성에 적합해요. 일리윤 아토 집중크림도 스쿠알란이 들어가 촉촉하게 수분감을 채워줍니다. 다만 에스네이처는 끈적일 수 있어 지성 피부에는 맞지 않으니 본인 피부 타입에 맞게 선택하세요.', '피지 핵심 성분 스쿠알란이 담긴 보습크림 추천과 선택 기준을 피부과 전문의 정한미가 안내합니다.', array['스쿠알란', '스쿠알렌', '보습크림', '악건성', '장벽크림', '에스네이처', '일리윤']::text[]),
    ('2eIHf-AGh_o', 'jeonghanmi', '내가 피지가 많은 편인지 어떻게 알 수 있나요?', '간단한 5가지 체크리스트로 셀프 진단이 가능하며, 3개 이상 해당되면 피지 과다입니다. 첫째, 오후가 되면 얼굴이 번들번들해진다. 둘째, 코 옆에 블랙헤드가 잘 보인다. 셋째, 기름종이를 하루에 두 번 이상 사용해야 한다. 넷째, 화장이 자주 무너진다. 다섯째, 화장 안 했을 때도 핸드폰 통화하면 얼굴 자국이 묻어난다. 이 중 3개 이상이면 피지가 많은 편이라고 보시면 됩니다. 절대적인 기준은 아니지만 본인의 피부 타입을 간편하게 파악하는 데 도움이 돼요. 피지가 많은지 적은지를 알아야 그에 맞는 클렌징과 보습 전략을 세울 수 있으니 한번 체크해 보세요.', '피지 과다 여부를 판별하는 5가지 셀프 체크리스트를 피부과 전문의 정한미가 정리합니다.', array['피지', '지성피부', '셀프진단', '블랙헤드', '유분', '피부타입', '체크리스트']::text[]),
    ('2eIHf-AGh_o', 'jeonghanmi', '피지 많은 피부는 세안을 어떻게 해야 제대로 관리되나요?', '피지 관리의 핵심은 균형이며, 피부 타입에 맞는 클렌징 강도 선택이 가장 중요합니다. 기름이 많은 피부는 클렌징 오일이나 밤으로 1차 세안 후, 약알칼리성 클렌저나 계면활성제가 비교적 강한 폼클렌저로 2차 세안해 피지를 깨끗이 씻어내 주세요. 반대로 건조하고 예민한 피부는 과도한 세안이 피부장벽을 무너뜨리므로 반드시 약산성 클렌저로 살살 씻어야 합니다. 그리고 피지가 많든 적든 보습은 반드시 해줘야 해요. 번들거린다고 수분크림을 건너뛰면 피부가 더 건조하다고 느끼고 기름을 더 만들어내는 악순환에 빠집니다. 유분감 적고 수분을 채워주는 가벼운 보습제를 선택하시고, 생활 습관도 스트레스·수면부족·당분 과다는 피지 분비를 늘리니 함께 관리해 주세요.', '피지 과다·건성 피부별 올바른 세안법과 보습 필수 이유를 피부과 전문의 정한미가 안내합니다.', array['클렌징', '피지', '보습', '약산성클렌저', '피부장벽', '지성피부', '세안법', '수분크림']::text[]),
    ('R8nd2qBscLA', 'jeonghanmi', '좁쌀 여드름에 올리브영 1등 클렌저 쓰면 안 되나요?', '유명한 제품이라고 무조건 따라 쓰면 오히려 여드름을 악화시킬 수 있습니다. 좁쌀 여드름 환자분들 중 본인 피부 타입에 맞지 않는 클렌저를 쓰는 경우가 정말 많거든요. 지성이라 센 세정이 필요한데 너무 순한 걸 쓰거나, 민감해서 순한 게 필요한데 너무 센 걸 쓰는 식입니다. 지성이고 기름이 많이 도는 분은 유분기를 잘 씻어내줄 수 있는 약알칼리성 클렌저가 적합하고, BHA나 AHA 같은 각질 케어 성분이 포함된 제품이면 더 좋습니다. 반대로 건성이나 민감성은 피부 장벽을 보호해주는 약산성 클렌저를 사용하되, 진정 성분인 병풀 추출물이나 판테놀이 함께 들어간 제품을 고르세요. 핵심은 1등 제품을 따라가는 게 아니라 내 피부 타입에 맞는 세정력을 선택하는 것입니다.', '좁쌀여드름에 유명 클렌저 대신 피부 타입별 맞는 클렌저 고르는 법을 피부과 전문의 정한미가 안내합니다.', array['좁쌀여드름', '클렌저', '지성피부', '민감성피부', 'BHA', '약산성', '각질케어']::text[]),
    ('R8nd2qBscLA', 'jeonghanmi', '좁쌀 여드름 나면 기초 화장품을 다 바꿔야 하나요?', '아니요, 한꺼번에 다 바꾸면 오히려 트러블이 더 심해질 수 있습니다. 여러 제품을 동시에 바꾸면 안 맞는 게 있어도 어떤 제품이 문제인지 파악이 불가능하거든요. 피부 장벽을 보강해주는 성분 한두 개만 먼저 써보고, 괜찮으면 다음 단계로 넘어가는 식으로 하나씩 바꿔야 합니다. 과학적으로 효과가 입증된 대표 성분은 나이아신아마이드(비타민 B3)인데, 피부 장벽 강화와 피지 감소, 염증 억제까지 한 번에 해주는 다재다능한 성분이에요. 징크는 피지 조절에, 판테놀은 피부 진정과 장벽 회복에 탁월하고, 필로바이오마라는 석류 추출 성분도 장벽 강화와 피부 미생물 균형에 도움을 줍니다. 본인이 극지성이면 가벼운 토너나 세럼을, 건조하고 민감하면 로션이나 크림 타입으로 제형을 선택하세요.', '여드름 날 때 화장품 교체 순서와 과학적으로 검증된 장벽 보강 성분을 피부과 전문의 정한미가 정리합니다.', array['좁쌀여드름', '나이아신아마이드', '피부장벽', '판테놀', '징크', '필로바이오마', '스킨케어']::text[]),
    ('R8nd2qBscLA', 'jeonghanmi', '레티놀이 여드름에도 효과가 있다는 게 사실인가요?', '네, 레티노이드 계열 성분은 각질 탈락 주기를 촉진해서 막힌 모공 입구를 열어주는 데 가장 탁월한 성분입니다. 좁쌀 여드름은 모공에 각질과 피지가 쌓여 생기는 건데, 레티노이드가 이 각질을 계속 밀어내줘서 모공이 막히지 않도록 해줘요. 피부과를 망하게 한다는 스티바A 크림도 원래 여드름 약으로 나온 제품이었습니다. 다만 조건이 있는데, 피부 장벽이 괜찮고 건조하거나 따갑지 않은 상태에서 사용해야 합니다. 피부 장벽이 무너진 상태에서 바르면 자극만 심해지니까요. 장벽이 괜찮다면 레티놀이나 레티날 같은 성분을 스킨케어 루틴에 넣어 꾸준히 발라주는 걸 추천드려요. 좁쌀이 꾸준히 반복되는 분이라면 시도해볼 가치가 충분합니다.', '레티노이드가 좁쌀여드름 모공을 열어주는 원리와 사용 조건을 피부과 전문의 정한미가 설명합니다.', array['레티놀', '좁쌀여드름', '각질케어', '모공', '레티노이드', '스티바A', '피부장벽']::text[]),
    ('R8nd2qBscLA', 'jeonghanmi', '좁쌀인 줄 알았는데 안 없어지면 다른 병일 수도 있나요?', '네, 피부과에서 보면 좁쌀 여드름인 줄 알고 오시는 분 중 편평사마귀나 비립종인 경우가 정말 많습니다. 이 둘은 좁쌀처럼 홈케어로 없어지는 게 아니라서 구분이 중요해요. 좁쌀 여드름은 피지가 많은 T존, 이마, 코, 볼, 턱에 주로 생기고, 비립종은 눈 주변에 동그란 하얀 알갱이처럼 보입니다. 편평사마귀는 바이러스성이라 내버려 두면 점점 번지는 특징이 있어요. 피부가 하얀 분은 편평사마귀가 살색과 비슷해서 상당히 많아지기 전까지 눈에 잘 안 띄는데, 빛을 비춰서 음영을 만들면 확인할 수 있습니다. 아무리 케어해도 좁쌀이 줄지 않거나 오히려 번진다면 피부과에 가서 정확한 진단을 받아보세요.', '좁쌀여드름과 헷갈리기 쉬운 편평사마귀·비립종 구분법을 피부과 전문의 정한미가 안내합니다.', array['좁쌀여드름', '편평사마귀', '비립종', '여드름구분', '피부과진단', '바이러스']::text[]),
    ('NXMfafKe8pc', 'kimsoohyung', '민감성인데 바른 듯 안 바른 듯 가벼운 선크림 있나요?', '셀퓨전씨 엑스퍼트 배리덤 쉴드크림 MD가 딱 그런 제품입니다. 발라보면 촉촉한데 끈적임이 없고, 재생크림 바르듯 피부 위에 보호막을 씌운 느낌이에요. 유기자차라서 백탁도 없고, 가장 중요한 눈 시림이 없어서 민감한 피부도 부담 없이 쓸 수 있습니다. 제형이 가볍다 보니 수시로 덧바르기도 좋아서 여름철에 선크림 바르기 싫은 날 특히 추천드려요. 비슷한 사용감으로 조선미녀 맑은쌀선크림 아쿠아프레쉬도 있는데, 이건 수분크림 같은 질감이에요. 셀퓨전씨가 재생크림 느낌이라면 조선미녀는 수분크림 느낌이고 둘 다 자극은 거의 없습니다. 촉촉하면서도 선크림 답답함이 싫은 분이라면 이 두 제품 중 본인 취향에 맞는 질감을 골라보세요.', '민감성 피부도 부담 없는 가벼운 유기자차 선크림 두 가지를 피부과 전문의 김수형이 소개합니다.', array['선크림', '민감성피부', '셀퓨전씨', '조선미녀', '유기자차', '저자극', '자외선차단']::text[]),
    ('NXMfafKe8pc', 'kimsoohyung', '화장 전에 바르면 밀리지 않는 선크림 뭐가 좋아요?', '라로슈포제 유비데아 안뗄리오스 멜트인 크림이 화장 베이스로 정말 좋습니다. 혼합자차라서 살짝 톤업이 되면서 부드럽게 발리고, 그 위에 화장을 올리면 밀리지 않고 잘 먹어요. 좀 더 화사하게 광채를 원한다면 키엘 울트라 라이트 데일리 UV 디펜스 썬스크린도 추천드립니다. 키엘 제품은 은은하게 펄이 있어서 반짝이면서 톤업이 되고, 중요한 날 화사한 피부 연출에 제격이에요. 두 제품 모두 같은 로레알 그룹인데 느낌은 완전히 다릅니다. 깔끔하고 자연스러운 톤 보정이면 라로슈포제, 반짝이는 광채와 건강한 피부 표현이면 키엘을 선택하시면 됩니다. 화장 잘 먹히는 선크림 하나면 아침 루틴이 훨씬 편해져요.', '화장 전에 밀리지 않고 톤업되는 선크림 두 가지를 피부과 전문의 김수형이 비교합니다.', array['선크림', '화장밀림', '라로슈포제', '키엘', '톤업', '혼합자차', '메이크업베이스']::text[]),
    ('NXMfafKe8pc', 'kimsoohyung', '화장 안 하고 외출할 때 톤 보정까지 되는 선크림 있나요?', 'ASF 피지컬 톤업 선블럭은 무기자차인데도 발림감이 부드럽고 고르게 잘 발려서 노메이크업 외출에 딱입니다. 분홍색 제형이라 바르면 톤 보정이 되면서 노란 얼굴빛을 잡아줘요. 무기자차라 햇빛 차단력도 믿을 수 있고, 돌가루 입자가 피부에 막을 씌워주는 방식이라 유기자차보다 물리적 차단이 확실합니다. 다만 무기자차 특성상 돌가루가 모공에 끼면 트러블이 생길 수 있으니 세안 시 꼼꼼히 지워주는 게 중요해요. 이 제품은 잘 닦아주기만 하면 트러블도 잘 없어서 편하게 쓸 수 있습니다. 여름철에 유기자차만으로는 피부 보호가 불안하고, 생기 있는 얼굴로 간단히 외출하고 싶을 때 추천드려요.', '화장 없이 외출할 때 톤 보정과 자외선 차단을 동시에 해주는 무기자차 선크림을 피부과 전문의 김수형이 추천합니다.', array['선크림', '무기자차', '톤업', 'ASF', '노메이크업', '자외선차단', '피부보호']::text[]),
    ('NXMfafKe8pc', 'kimsoohyung', '선크림 바르는 양이랑 덧바르기, 정확히 어떻게 해야 돼요?', '얼굴에 500원짜리 동전 크기만큼 발라야 제품에 표시된 SPF 효과를 제대로 볼 수 있습니다. 대부분 이보다 적게 바르는데, 양이 부족하면 자외선 차단 효과가 크게 떨어져요. 덧바르기도 중요한데 아침에 한 번 바르고 끝이 아니라, 중간에 외출할 일이 있으면 선쿠션 같은 걸로 한 번 더 덧발라 주세요. 바르는 타이밍도 자차 종류에 따라 다릅니다. 유기자차는 피부에 흡수되어야 작용하기 때문에 외출 30분 전에 발라야 하고, 무기자차는 피부에 막을 씌우는 거라 외출 직전에 발라도 효과가 있어요. 세안은 톤업이나 색이 있는 제품은 모공을 막을 수 있으니 깨끗이 지워주되, 유기자차는 1번 세안으로도 충분하니 무리해서 이중세안하실 필요 없습니다.', '선크림 적정량과 덧바르기 타이밍, 유기자차·무기자차 세안법을 피부과 전문의 김수형이 정리합니다.', array['선크림', '자외선차단', '덧바르기', '유기자차', '무기자차', 'SPF', '이중세안']::text[]),
    ('JUmz9-G5i50', 'jeonghanmi', '건조하고 예민한데 여드름도 나면 닦토 해도 되나요?', '각질이 많고 건조한 피부라면 닦아내는 토너는 잠시 중단하는 게 좋습니다. 각질이 많으니 닦아서 정리해줘야 할 것 같지만, 이 각질은 피부장벽이 망가졌을 때 생기는 거거든요. 거기에 화장솜으로 문지르는 자극까지 더하면 장벽이 더 나빠질 수 있어요. 예민하고 건조한 피부는 애기 피부 다루듯 정말 살살 다뤄야 합니다. 대신 나이아신아마이드 성분이 들어간 세럼을 추가하는 걸 추천드려요. 이 성분은 염증도 줄이고 여드름 균도 줄이면서 피부 장벽과 피지 조절까지 해주는 만능 성분이거든요. 각질 케어가 필요하다면 물리적 스크럽 대신 PHA처럼 부드럽게 각질을 녹여줄 수 있는 성분이 든 토너를 사용하세요.', '건조하고 예민한 여드름 피부의 닦토 사용 여부와 대안을 피부과 전문의 정한미가 안내합니다.', array['닦토', '여드름', '건성피부', '피부장벽', '나이아신아마이드', 'PHA', '각질케어']::text[]),
    ('JUmz9-G5i50', 'jeonghanmi', '지성인데 약산성 클렌저만 고집하면 안 되나요?', '지성 피부가 무조건 약산성만 고집하면 세정력이 부족해서 유분이 제대로 안 씻길 수 있습니다. 약산성 클렌저가 피부 산도와 비슷해 장벽을 보호하는 건 맞지만, 순하게 만들다 보면 세정력이 떨어지는 제품도 있거든요. 기름이 많이 생성되는 지성 피부는 약알칼리성 클렌저를 번갈아 사용하거나, 약산성이면서 세정력이 강한 제품을 골라야 합니다. 예를 들면 BHA 같은 각질·피지 케어 성분이 들어간 클렌저가 좋아요. 점심때쯤 기름종이로 닦아야 할 정도로 유분이 많은 분이라면 매일 순한 것만 쓰는 건 부족할 수 있습니다. 기본은 약산성으로 쓰되 일주일에 몇 번은 세정력이 강한 클렌저로 유분기를 확실히 씻어내주세요.', '지성 피부가 약산성 클렌저만 쓰면 안 되는 이유와 세정력 보완법을 피부과 전문의 정한미가 설명합니다.', array['지성피부', '클렌저', '약산성', '약알칼리성', '세정력', 'BHA', '여드름']::text[]),
    ('JUmz9-G5i50', 'jeonghanmi', '여드름 피부가 꼭 써야 하는 성분이 정리된 게 있나요?', '여드름성 피부에 필요한 성분은 크게 다섯 가지 카테고리로 나뉩니다. 첫째 피지 조절 성분으로 나이아신아마이드, 징크, EGCG(녹차 추출물)가 있고, 둘째 각질을 녹여주는 BHA(살리실산), AHA, 레티노이드 계열이 있어요. 셋째 염증을 가라앉히는 항염 성분으로 살리실산, 나이아신아마이드, 바쿠치올이 있고, 넷째 여드름 균을 억제하는 항균 성분으로 티트리오일, 징크, 필로바이오마가 있습니다. 다섯째는 피부 장벽 강화 성분인 세라마이드, 판테놀, 글리세린이에요. 다섯 가지를 다 쓸 필요는 없고, 좁쌀이 많으면 각질 용해+피지 조절을, 화농성이면 항염+항균을, 장벽이 약하면 장벽 강화를 중심으로 골라 쓰시면 됩니다.', '여드름 피부에 필요한 5가지 성분 카테고리와 피부 상태별 선택법을 피부과 전문의 정한미가 정리합니다.', array['여드름', '나이아신아마이드', 'BHA', '티트리오일', '피부장벽', '바쿠치올', '세라마이드', '피지조절']::text[]),
    ('JUmz9-G5i50', 'jeonghanmi', '지성 여드름 피부인데 비타민C 세럼 발라도 괜찮나요?', '네, 비타민C는 여드름 피부에 아주 좋은 습관입니다. 강력한 항산화 효과가 있어서 여드름 때문에 계속 올라오는 염증으로 지치고 칙칙해지는 피부를 보호해주거든요. 미백 효과도 있기 때문에 여드름 자국이 남은 부위에도 도움이 많이 됩니다. 다만 지성 피부라면 일반 비타민C 세럼보다 실리마린이라는 피지 잡아주는 성분이 추가된 제품이 더 적합해요. 비타민C와 페룰릭애씨드 조합의 항산화 효과는 그대로 누리면서 피지까지 조절해주는 거죠. 그리고 크림은 나이아신아마이드, 티트리 추출물, 병풀 추출물이 들어간 제품을 쓰면 항균·항염·진정까지 한꺼번에 챙길 수 있습니다. 여드름 피부도 무조건 벗겨내는 것만이 답이 아니라 장벽 보호와 항산화를 함께 신경 써야 해요.', '지성 여드름 피부의 비타민C 사용법과 피지 조절 세럼 선택 팁을 피부과 전문의 정한미가 안내합니다.', array['비타민C', '여드름', '지성피부', '항산화', '실리마린', '티트리', '여드름자국']::text[]),
    ('5JN_OfEnREg', 'jeonghanmi', '스트레스 받으면 진짜 갑자기 늙을 수 있나요?', '네, 극심한 스트레스는 짧은 시간에 머리카락을 하얗게 만들고 피부를 쭈글쭈글하게 만들 수 있습니다. 이걸 마리 앙투아네트 증후군이라고 부르는데, 2020년 하버드대학 연구진이 실제로 쥐에게 극심한 스트레스를 줬더니 털이 하얗게 변한 걸 확인했어요. 스트레스 호르몬이 급증하면 털 색깔을 만드는 멜라닌 줄기세포가 빠르게 고갈되면서 새치가 급속히 늘어나는 원리입니다. 우주 비행사가 9개월 만에 백발에 피부까지 급격히 늙은 사례도 스트레스가 핵심 원인이었어요. 지구에 사는 우리도 3개월 만에 폭삭 늙을 수 있다는 얘기입니다. 흰머리 나기 싫고 늙기 싫으면 스트레스 관리를 일상에서 꾸준히 해주는 게 정말 중요합니다.', '극심한 스트레스가 급속노화를 일으키는 과학적 원리와 예방법을 피부과 전문의 정한미가 설명합니다.', array['급속노화', '스트레스', '새치', '마리앙투아네트증후군', '멜라닌', '피부노화', '슬로우에이징']::text[]),
    ('5JN_OfEnREg', 'jeonghanmi', '잠을 못 자면 피부가 빨리 늙는 게 사실인가요?', '맞습니다, 숙면을 못 취하면 피부 재생이 원활히 이루어지지 않아서 급속노화로 이어질 수 있어요. 피부 재생은 주로 숙면 중에 이루어지는데, 특히 밤 10시부터 새벽 2시 사이에 피부 재생과 관련된 성장 호르몬이 가장 많이 분비됩니다. 우주 비행사들의 평균 수면이 6시간 정도인데 수면의 질까지 떨어져서, 75% 이상이 수면제 없이는 잠을 못 잔다고 해요. 그 결과 6개월 만에 피부 표피 두께가 약 10% 감소했는데, 이건 7-10년의 노화에 맞먹는 수준입니다. 현실적으로 밤 10시 취침은 어렵더라도 12시 전에는 꼭 자려고 노력하는 게 좋아요. 수면 리듬이 깨지지 않도록 규칙적인 취침 시간을 유지하는 것이 피부 재생의 핵심입니다.', '숙면 부족이 피부 급속노화를 일으키는 원리와 적정 취침 시간을 피부과 전문의 정한미가 안내합니다.', array['수면', '피부재생', '성장호르몬', '노화', '숙면', '슬로우에이징', '피부노화']::text[]),
    ('5JN_OfEnREg', 'jeonghanmi', '중력이 없으면 피부가 안 처져서 오히려 좋은 거 아닌가요?', '아닙니다, 오히려 중력이 없어지면 피부가 더 빨리 늙을 수 있습니다. 중력이 피부를 아래로 당기면 얼굴 근육들이 무의식적으로 위쪽으로 수축해서 버텨내거든요. 이런 미세한 긴장이 반복되면서 콜라겐이나 엘라스틴 같은 단백질이 계속 생성되도록 자극하는 자연적인 운동 효과가 생깁니다. 중력이 사라지면 이 위로 올리는 힘이 없어져서 피부가 게을러지는 거예요. 실제로 우주에서 6개월 지낸 비행사들의 피부 표피 두께가 약 10% 감소했는데, 7-10년의 노화와 맞먹는 수준입니다. 지구에서도 이 원리를 활용해 얼굴 근육 운동을 해주면 처짐 예방에 도움이 됩니다. 앞볼 근육을 위로 올리는 동작을 꾸준히 해주세요.', '중력이 피부 콜라겐 생성을 자극하는 원리와 얼굴 근육 운동법을 피부과 전문의 정한미가 설명합니다.', array['중력', '피부처짐', '콜라겐', '얼굴운동', '리프팅', '엘라스틴', '노화예방']::text[]),
    ('5JN_OfEnREg', 'jeonghanmi', '급속노화를 막는 슬로우에이징 비결이 뭔가요?', '우주 비행사의 급속노화 사례에서 배울 수 있는 슬로우에이징 비결은 네 가지입니다. 첫째, 얼굴 근육 운동으로 적절한 자극을 주는 것인데, 중력에 대항해 근육을 위로 올려주는 동작을 꾸준히 하면 처짐이 덜해져요. 둘째, 자외선 차단을 철저히 해야 합니다. 자외선은 주름, 피부 얇아짐, 기미 잡티의 주요 원인이니 선크림을 꼭 바르고, 비타민C도 함께 사용하면 자외선으로 인한 노화 예방에 좋아요. 셋째, 스트레스 관리를 해야 하는데 운동이든 영화든 목욕이든 본인만의 해소법으로 스트레스가 쌓이지 않게 관리해주세요. 넷째, 규칙적인 수면이 필수입니다. 밤 10시~2시 사이 피부 재생 호르몬이 분비되니 현실적으로 12시 전에는 잠자리에 드시는 걸 추천합니다.', '급속노화를 막는 4가지 슬로우에이징 비결을 피부과 전문의 정한미가 정리합니다.', array['슬로우에이징', '자외선차단', '수면', '스트레스관리', '얼굴운동', '비타민C', '피부노화']::text[]),
    ('SAK00m8_5RY', 'kimsoohyung', '비타민C 바르면 따가운데 원래 그런 건가요?', '네, 비타민C는 아스크로브산이라는 산성 성분이라 바르면 따가운 게 정상입니다. 문제는 성분 자체가 아니라 제형과 바르는 방법에 있어요. 세안 후 물기를 닦고 바로 이마와 양 뺨에 한 방울씩 떨어뜨린 다음 문지르고 1-2분 흡수 시간을 주면 양 조절만 잘해도 별로 안 따갑습니다. 따가워도 참고 기다렸다가 판테놀 성분이 든 재생크림을 위에 덧발라주면 바로 진정돼요. 다만 피부 컨디션이 안 좋은 날엔 따가움이 더 심해지니까 그런 날은 비타민C를 아예 건너뛰고 재생크림만 바르세요. 모르고 발랐다면 재생크림을 바로 덧발라주면 됩니다. 자극 때문에 포기하지 말고 양과 타이밍을 조절하면 충분히 쓸 수 있어요.', '비타민C 앰플의 따가움이 정상인 이유와 자극 없이 바르는 방법을 피부과 전문의 김수형이 안내합니다.', array['비타민C', '자극감', '아스크로브산', '재생크림', '판테놀', '스킨케어', '항산화']::text[]),
    ('SAK00m8_5RY', 'kimsoohyung', '비타민C랑 레티놀 같이 바르면 안 되나요?', '같은 날 밤에 둘 다 바르면 피부가 뒤집어질 수 있어서 번갈아 쓰는 게 안전합니다. 레티놀 자체도 자극감이 있는 성분인데 비타민C의 산성까지 겹치면 피부 부담이 너무 커지거든요. 하루는 비타민C, 하루는 레티놀 이렇게 격일로 나이트 케어를 나누면 둘 다 효과를 누릴 수 있습니다. 아침에도 비타민C를 바르면 좋은데, 햇빛에 의한 활성산소를 막아주는 항산화 역할을 하기 때문이에요. 다만 고농도를 아침에 바르면 재생크림까지 올려야 해서 화장이 밀릴 수 있으니, 아침에는 저농도 앰플을 사용하는 게 편합니다. 저농도라도 꾸준히 한 통 다 쓰면 오히려 고농도보다 효과를 더 볼 수 있어요.', '비타민C와 레티놀을 안전하게 병행하는 격일 루틴과 아침 사용법을 피부과 전문의 김수형이 설명합니다.', array['비타민C', '레티놀', '나이트케어', '항산화', '자극', '저농도', '스킨케어루틴']::text[]),
    ('SAK00m8_5RY', 'kimsoohyung', '순수 비타민C 6% 저농도 앰플도 항산화 효과가 있나요?', '6%라도 비타민C, 토코페롤, 페룰릭애씨드 세 가지가 함께 들어가면 항산화 효과가 굉장히 좋습니다. 피지오겔 데일리뮨 비타민C 앰플이 바로 이 세 가지 조합인데, 논문에서도 이 세 성분이 같이 있을 때 항산화 시너지가 높아진다고 알려져 있어요. 제형이 조금 쫀득하긴 한데 쑥 흡수가 잘 돼서 화장 전에도 부담 없이 바르기 좋습니다. 대체로 저자극으로 쓸 수 있고 마무리감도 산뜻해서 데일리 아침 루틴으로 딱이에요. 비타민C는 산화되기 쉬운 성분이라 갈색병에 담겨 있으면 변질 걱정 없이 오래 쓸 수 있습니다. 고농도가 부담스럽거나 매일 아침 꾸준히 쓸 제품을 찾는 분에게 추천드려요.', '순수 비타민C 6% 앰플의 항산화 효과를 높이는 성분 조합을 피부과 전문의 김수형이 소개합니다.', array['비타민C', '피지오겔', '토코페롤', '페룰릭애씨드', '항산화', '저농도', '아침루틴']::text[]),
    ('SAK00m8_5RY', 'kimsoohyung', '가성비 좋은 고농도 비타민C 앰플은 뭐가 좋아요?', '가성비 좋은 고농도 앰플로는 닥터디퍼런트 CEQ 안티옥시던트 세럼 17%를 추천합니다. 스킨수티컬즈 CE 페룰릭의 가성비 버전으로도 유명한데, 비타민C 17%라서 스킨수티컬즈보다 조금 더 따갑게 느껴질 수 있지만 제형은 거의 비슷해요. 용량이 15ml라 산화 걱정 없이 금방 쓰기 좋아서 마음이 편합니다. 건성이라 보습감을 원한다면 코스알엑스 비타민C 23% 세럼도 있는데, 물과 오일 2층 제형이라 흔들어 쓰면 놀라울 정도로 촉촉하게 발려요. 23%인데도 오일 막이 자극을 줄여줘서 생각보다 안 따갑습니다. 다만 페룰릭애씨드가 안 들어있으니 냉장보관을 해야 오래 쓸 수 있어요. 본인 피부 타입과 예산에 맞게 골라보세요.', '가성비 좋은 고농도 비타민C 앰플 두 가지의 특징과 피부 타입별 선택법을 피부과 전문의 김수형이 비교합니다.', array['비타민C', '닥터디퍼런트', '코스알엑스', '고농도', '항산화', '스킨수티컬즈', '가성비']::text[]),
    ('nxok2MdqEFE', 'baejungmin', '백반증 먹는 약이 곧 나온다는데 정말인가요?', '네, 리트풀로라는 먹는 JAK 억제제가 백반증 치료제로 승인될 가능성이 매우 높습니다. 리트풀로는 이미 2024년 9월 우리나라에서 중증 원형 탈모증 치료제로 허가를 받았고, 백반증 임상연구가 종료되면 곧 처방이 가능해질 수 있습니다. 프랑스 연구에서 비분절형 백반증 환자들이 리트풀로 50mg을 매일 복용한 결과, 얼굴 백반증 회복률이 24주에 19%, 48주에는 63%까지 올라갔습니다. 치료 기간이 길어질수록 효과가 좋아졌고, 나이나 성별, 인종에 관계없이 거의 모든 환자 그룹에서 효과를 보였습니다. 기존 바르는 연고나 자외선 치료와 달리 알약이라 편리하고, 넓은 면적의 백반증 환자에게도 유용하다는 게 큰 장점이에요. 현재 리트풀로와 옵젤루라 두 가지 JAK 억제제가 백반증 치료의 새로운 시대를 열어가고 있습니다. 국내에서도 빠른 시일 내에 백반증 환자분들께 사용 가능해지기를 기대합니다.', '백반증 최초 경구약 리트풀로의 효과와 국내 승인 전망을 피부과 전문의 배정민이 정리합니다.', array['백반증', '리트풀로', 'JAK억제제', '옵젤루라', '경구약', '백반증치료', '면역억제제']::text[]),
    ('nxok2MdqEFE', 'baejungmin', '백반증 엑시머 레이저 세게 맞아야 효과 좋은 건가요?', '아닙니다. 얼굴 백반증은 오히려 저용량으로 치료해도 동일한 효과를 얻을 수 있습니다. 연구팀이 18명 환자의 얼굴 좌우를 나눠 한쪽은 표준 용량, 반대쪽은 절반 에너지로 치료한 결과 양쪽 모두 같은 치료 결과가 나왔습니다. 표준 용량 쪽에서는 화상과 색소침착이 종종 발생했지만, 저용량에서는 부작용이 단 한 명도 없었습니다. 반면 몸통과 팔다리처럼 치료 반응이 미진한 부위에서는 붉은기 에너지의 9배까지 높여 치료하면 멈췄던 효과를 다시 낼 수도 있다는 연구도 있습니다. 다만 고용량은 물집과 얼룩덜룩한 색소침착이 생기는 단점이 있어요. 결국 얼굴은 저용량으로 안전하게 시작하고, 팔다리는 필요에 따라 고용량을 고려하는 맞춤형 접근이 중요합니다. 모든 치료는 환자와 주치의가 잘 상의하여 조정하시는 게 좋습니다.', '백반증 엑시머 레이저의 최적 용량과 부위별 맞춤 치료법을 피부과 전문의 배정민이 안내합니다.', array['백반증', '엑시머레이저', '저용량치료', '색소침착', '부작용', '얼굴백반증', '광선치료']::text[]),
    ('nxok2MdqEFE', 'baejungmin', '손끝 백반증은 왜 이렇게 치료가 안 되나요?', '손끝은 피부가 두껍고 혈액공급이 제한적이며, 지속적으로 마찰과 압력을 받기 때문에 치료가 유독 어려운 부위입니다. 엑시머 레이저로도 잘 안 되고 수술 효과도 제한적인 경우가 많아요. 최근 이집트 카이로대학에서 새로운 수술법인 냉동 물집술을 시도했는데, 피부를 벗겨내지 않고 액체 질소로 물집을 만든 뒤 그 안에 멜라닌 세포를 주입하는 방식입니다. 12명 환자의 세 손가락에 각각 다른 수술을 적용한 결과, 냉동 물집술만 22%에서 75% 이상의 색소 회복을 달성했고 나머지 수술에서는 아무도 이를 달성하지 못했습니다. 회복기간도 짧고 부작용도 거의 없었다는 점이 장점이에요. 안타깝게도 국내에서는 세포 이식술 규제가 까다로워 당장 시도하기 어렵지만, 향후 규제가 완화되면 적용 가능할 것으로 기대됩니다.', '손끝 백반증이 치료가 어려운 이유와 새로운 냉동 물집술을 피부과 전문의 배정민이 설명합니다.', array['백반증', '손끝백반증', '냉동물집술', '세포이식', '멜라닌세포', '수술치료', '말단백반증']::text[]),
    ('nxok2MdqEFE', 'baejungmin', '백반증 재발을 완전히 막을 수 있는 약은 없나요?', '아직 시판된 약은 없지만, 재발을 장기간 막을 수 있는 새로운 타깃 치료제가 임상시험 중입니다. 현재의 JAK 억제제는 면역세포가 멜라닌 세포를 공격하는 것을 막지만, 면역세포가 완전히 사라지지는 않아 재발을 막을 수 있는지 불분명합니다. 연구 결과, 백반증이 회복된 후에도 피부에는 조직 상주 기억 T세포가 남아 있어 언제든 다시 공격할 수 있다는 것이 밝혀졌습니다. 이 T세포가 생존하려면 인터루킨-15라는 물질이 필요한데, 동물실험에서 이를 차단하자 약물 투입 종료 후에도 수십 주간 재발 없이 안정이 유지되었습니다. 현재 인터루킨-15를 차단하는 AMG-714라는 약물이 미국에서 1상 임상시험 중이에요. 인체 실험 결과는 아직 나오지 않았고 실제 적용까지는 10년 이상 걸릴 수 있지만, 언젠가 백반증 완치가 가능한 시대가 올 것으로 기대됩니다.', '백반증 재발을 막는 새로운 면역 타깃 치료제 연구 동향을 피부과 전문의 배정민이 안내합니다.', array['백반증', '재발', '인터루킨15', 'T세포', 'AMG714', '면역치료', '임상시험']::text[]),
    ('rB6cLbp6GAM', 'gohyerim', '팔꿈치랑 무릎이 까만데 때 밀면 하얘지나요?', '절대 안 됩니다. 오히려 때를 밀면 더 까매질 수 있어요. 팔꿈치나 무릎이 까매지는 원인은 마찰과 자극 때문인데, 때밀이는 그 자극을 더 심하게 주는 행위입니다. 피부가 자극을 받으면 공격받고 있다고 판단하고 멜라닌 색소를 만들어서 더 까매지는 거거든요. 그래서 제일 중요한 건 자극을 줄이는 것입니다. 꽉 끼는 옷이나 땀 차는 소재 대신 면이나 모달 같은 통기성 좋은 소재를 입고, 씻을 때도 타월로 거품만 내서 부드럽게 씻어주세요. 책상에 팔꿈치를 짚거나 무릎 꿇는 자세도 마찰이 되니 피하시는 게 좋습니다. 각질 관리가 필요하다면 때 타월 대신 AHA, BHA, PHA 같은 산성분이 포함된 제품으로 일주일에 1~2회 정도 관리하시면 됩니다.', '팔꿈치·무릎이 까매지는 원인은 마찰이라 때를 밀면 오히려 악화됩니다. AHA·BHA 각질 관리와 자극을 줄이는 생활 습관을 피부과 전문의 고혜림이 설명합니다.', array['색소침착', '팔꿈치', '무릎', '각질관리', 'AHA', 'BHA', '마찰']::text[]),
    ('rB6cLbp6GAM', 'gohyerim', '까만 팔꿈치에 미백 크림 바르면 진짜 효과 있나요?', '엄청난 효과는 아니지만, 꾸준히 사용하면 도움이 될 수 있습니다. 대표적인 미백 성분으로 비타민C, 나이아신아마이드, 알부틴 같은 것들이 있고 식약처 고시 미백 기능성 성분도 도움이 됩니다. 특히 팔꿈치나 무릎처럼 각질 때문에 더 까맣게 보이는 부위에는 우레아가 들어있는 유리아 크림을 같이 써주면 더 효과를 볼 수 있어요. 유리아 크림은 처방전 없이 약국에서 살 수 있는 일반 의약품입니다. 더 강한 효과를 원하면 멜라논 크림이나 아크리프 크림 같은 전문 의약품이 있지만, 부작용이 있어서 반드시 병원 진료 후 처방을 받으셔야 합니다. 무엇보다 보습이 기본인데, 샤워 후 욕실 안에서 3분 안에 보습해주시고 건조한 부위는 유분기가 많은 제품으로 수시 도포하시는 게 좋습니다.', '까만 팔꿈치에 나이아신아마이드·비타민C 미백 크림과 우레아 유리아 크림을 병행하면 개선 가능합니다. 미백 성분별 효과와 보습 병행법을 피부과 전문의 고혜림이 안내합니다.', array['미백', '색소침착', '비타민C', '나이아신아마이드', '우레아', '유리아크림', '보습']::text[]),
    ('rB6cLbp6GAM', 'gohyerim', '팔꿈치 색소침착이 심한데 레이저로 없앨 수 있나요?', '네, 홈케어로 호전이 없다면 레이저 토닝이 가장 대표적인 치료 방법입니다. 토닝 레이저는 상처 없이 피부의 멜라닌 색소만 골라서 잘게 없애주는 레이저예요. 얼굴 기미나 잡티에만 한다고 생각하시는 분이 많은데, 사실 몸 어디든 다 할 수 있습니다. 다만 1~2회만으로는 큰 효과가 없고, 보통 1~2주 간격으로 5~10회 이상 치료가 필요합니다. 꾸준히 받으시면 피부 톤이 서서히 밝아지는 걸 느끼실 수 있어요. 토닝 외에도 이온자임이나 미백관리, 고주파 같은 시술을 병행하면 효과가 더 좋습니다. 단, 크림이나 홈케어로 꾸준히 노력했는데도 호전이 없는 경우에 피부과 치료를 고려하시는 게 순서에 맞습니다.', '홈케어로 안 되는 색소침착은 레이저 토닝으로 멜라닌만 골라 제거할 수 있습니다. 1~2주 간격 5~10회 치료 과정과 병행 시술을 피부과 전문의 고혜림이 정리합니다.', array['레이저토닝', '색소침착', '멜라닌', '이온자임', '미백', '몸색소침착', '피부과치료']::text[]),
    ('rB6cLbp6GAM', 'gohyerim', '겨드랑이가 검은데 단순 색소침착인지 병인지 어떻게 구분하나요?', '피부 두께와 질감으로 구분할 수 있습니다. 단순 색소침착은 피부 두께가 그대로인 반면, 흑색가시세포증은 피부결이 벨벳처럼 두꺼워 보이고 빛을 받았을 때 검게 광택이 도는 모습이 관찰됩니다. 흑색가시세포증은 마찰이 아니라 비만이나 인슐린 저항성이 있는 분들에게서 주로 나타나요. 대부분 비만과 인슐린 저항성이 원인이므로 체중 감량과 인슐린 저항성 치료를 해주면 피부색도 같이 좋아집니다. 다만 드문 경우 위샘암종이나 난소암, 폐암, 유방암에서도 동반될 수 있어서, 성인인데 갑자기 광범위하게 발생했다면 위장관 내시경 등 검사를 해볼 필요가 있습니다. 암 때문에 생기는 경우는 흔치 않으니 너무 걱정하실 필요는 없지만, 의심 증상이 있다면 피부과를 방문해보세요.', '겨드랑이가 벨벳처럼 두껍고 검다면 흑색가시세포증일 수 있습니다. 단순 색소침착과의 구별법, 비만·인슐린 저항성 연관성을 피부과 전문의 고혜림이 설명합니다.', array['흑색가시세포증', '겨드랑이', '색소침착', '인슐린저항성', '비만', '피부질환감별', '체중감량']::text[]),
    ('4L1MKekRLp0', 'kwonsuhyun', '피부과 의사들이 진짜 쓰는 선크림 1위가 뭔가요?', '피부과 의사 120명에게 주관식으로 인생 선크림을 물었더니, 1위는 셀퓨전씨였습니다. 무려 30명 넘게, 전체의 4분의 1이 약속이나 한 것처럼 이 브랜드를 적었어요. 수백 개 브랜드 중 주관식으로 이 정도가 모인 건 정말 놀라운 결과입니다. 직접 발라보니 기본적으로 무겁지 않고 흡수력이 좋아서 착 붙는 느낌이 드는 게 가장 큰 이유였어요. 레이저 선스크린, 어드밴스드 클리어, 베리덤 쉴드, 베리덤 센서티브 쉴드 등 여러 제품이 언급됐는데 전부 발림성이 좋고 가벼운 게 공통점입니다. 2위는 라로슈포제로 17명이 선택했고, 3위는 ASF였습니다. 피부과 의사들도 굳이 비싼 백화점 브랜드를 쓰지 않고, 차단 잘 되고 발림성 좋은 제품을 선호한다는 점이 인상적이에요.', '피부과 의사 120명이 직접 쓰는 선크림 브랜드 순위를 피부과 전문의 권수현이 정리합니다.', array['선크림', '셀퓨전씨', '라로슈포제', 'ASF', '자외선차단제', '발림성', '피부과추천']::text[]),
    ('4L1MKekRLp0', 'jeonghanmi', '지성 피부인데 선크림 어떤 타입으로 골라야 하나요?', '지성 피부라면 유기자차 계열의 산뜻한 제품이 잘 맞습니다. 셀퓨전씨 제품 중 어드밴스드 클리어가 확실히 산뜻하고 답답하지 않아서 지성 피부에 화장도 잘 먹는다는 평가가 나왔어요. 반면 건조한 피부라면 보습력이 있으면서 잘 흡수되는 베리덤 쉴드 크림이 로션 바른 느낌처럼 촉촉해서 좋습니다. 무기자차와 유기자차의 차이를 알면 선택이 쉬운데, 무기자차는 자외선을 튕겨내는 물리적 차단이고, 유기자차는 자외선을 흡수해서 열에너지로 바꿔버리는 방식입니다. 유기자차가 보통 산뜻하고 발림성이 좋지만, 피부가 민감하면 눈 시림이나 따가움이 있을 수 있어요. 민감한 피부에는 무기자차를 추천하고, 두 장점을 합친 게 혼합자차라고 보시면 됩니다. 피부 타입에 맞게 골라 쓰시는 게 가장 중요합니다.', '지성과 건성 피부 타입별 선크림 선택법을 피부과 전문의 정한미가 안내합니다.', array['선크림', '지성피부', '유기자차', '무기자차', '혼합자차', '민감성피부', '발림성']::text[]),
    ('4L1MKekRLp0', 'kwonsuhyun', '피부과 의사도 선크림 하루에 한 번만 바르나요?', '네, 대부분의 피부과 의사도 하루 한 번 정도만 바릅니다. 남자 의사의 47%는 야외활동 있는 날에만 바르고, 여자 의사도 하루 1회 바르거나 야외활동 시 한 번 더 덧바르는 정도가 가장 많았습니다. 실내에서 선크림을 바르냐는 질문에는 62.5%가 안 바른다고 답했어요. 기본적으로 창문과 멀리 떨어진 실내에서는 안 발라도 되지만, 창가에서 계속 뭔가를 한다면 발라야 합니다. 자외선A는 창문을 뚫고 들어오기 때문이에요. 실내 형광등에서 나오는 자외선은 정말 미미해서 피부에 영향을 줄 정도는 아니니 걱정하지 않으셔도 됩니다. 정리하면 창가 옆이면 바르고, 일반 실내면 안 발라도 된다고 보시면 됩니다.', '피부과 의사들의 실제 선크림 사용 빈도와 실내 도포 기준을 피부과 전문의 권수현이 설명합니다.', array['선크림', '자외선차단', '실내자외선', '덧바르기', '자외선A', '형광등', '창가']::text[]),
    ('4L1MKekRLp0', 'jeonghanmi', '선크림 한 번에 얼마나 짜서 발라야 하나요?', '피부과 의사들 대부분도 권장량인 500원짜리 동전 크기만큼은 바르지 못하고 있습니다. 완두콩 크기 기준으로 조사한 결과, 1위가 완두콩 2개 정도 양으로 31.7%가 선택했고, 2위가 3개, 3위가 1개였어요. 원래는 손가락 두 마디 정도를 발라야 한다고 설명하지만, 실제 피부과 의사들도 그렇게까지 많이 바르지는 않는 거죠. 그래도 완두콩 4~5개 이상 바르시는 자기관리 철저한 분들도 일부 있었습니다. 얼굴에 완두콩 2개 크기를 바르고 하나 더 짜서 목에 바르는 것도 좋은 방법이에요. 결론적으로 권장량보다 적게 바르더라도 매일 꾸준히 바르는 습관이 중요하고, 야외활동이 있을 때는 충분한 양을 발라주시는 게 좋습니다.', '피부과 의사 120명의 실제 선크림 도포량과 적정 사용법을 피부과 전문의 정한미가 정리합니다.', array['선크림', '적정량', '자외선차단', '완두콩', '도포량', '자외선차단제사용법']::text[]),
    ('nAqWcFwO1ws', 'kimjongsik', '머리카락이 자꾸 빠지는데 진짜 탈모인지 어떻게 알 수 있나요?', '집에서 간단하게 해볼 수 있는 자가진단법 세 가지가 있습니다. 첫 번째는 50~60가닥 정도의 머리카락을 두 손가락으로 부드럽게 당겼을 때 6가닥 이상 빠지면 탈모를 의심해봐야 합니다. 두 번째는 파팅 테스트로, 평소 타는 가르마 쪽이 확연하게 하얘졌거나 넓어졌다면 주의 신호예요. 세 번째는 사진 비교법인데, 한 달에 한 번 정도 같은 위치의 정수리나 가르마를 핸드폰으로 찍어서 비교하면 됩니다. 3개월 전보다 숱이 확실히 줄었다면 경각심을 가져야 하죠. 여성형 탈모는 남성처럼 M자로 빠지기보다 점차 머리카락이 얇아지면서 전체적으로 비어 보이는 현상이 특징입니다. 정수리뿐 아니라 앞머리 라인이 뒤로 밀리는 느낌도 여성형 탈모의 신호이니 관심을 갖고 살펴보세요.', '집에서 할 수 있는 여성형 탈모 자가진단법 세 가지를 피부과 전문의 김종식이 안내합니다.', array['탈모', '여성형탈모', '자가진단', '정수리탈모', '가르마', '머리숱', '탈모초기']::text[]),
    ('nAqWcFwO1ws', 'kimjongsik', '과도한 다이어트하면 진짜 머리카락이 빠지나요?', '네, 과도한 다이어트는 탈모의 주요 원인 중 하나입니다. 우리 몸이 영양을 섭취하면 심장, 뇌, 근육 같은 중요한 기관에 먼저 보내고 나서 머리카락이나 손톱, 피부 바깥쪽에는 나중에 영양이 갑니다. 필수 영양소까지 부족할 정도로 안 먹으면 머리카락까지 영양이 도달하지 못하는 거예요. 특히 모발 성장에 필요한 케라틴을 만들지 못하게 되면서 실제로 빠지기도 합니다. 이런 현상을 휴지기 탈모증이라고 하는데, 큰 스트레스나 과도한 다이어트 후 약 3개월이 지나서 머리카락이 쑥 빠져버리는 겁니다. 여성형 탈모의 원인에는 유전, 호르몬 변화, 스트레스, 다이어트 이렇게 네 가지가 대표적이에요. 이미 마른데 더 안 먹는 것은 머리숱을 대가로 치르는 셈이니 필수 영양소는 반드시 챙기시기 바랍니다.', '과도한 다이어트가 탈모를 유발하는 원리와 예방법을 피부과 전문의 김종식이 설명합니다.', array['탈모', '다이어트', '휴지기탈모', '영양부족', '케라틴', '여성형탈모', '스트레스']::text[]),
    ('nAqWcFwO1ws', 'kimjongsik', '탈모 예방하려면 샴푸 말고 집에서 뭘 더 할 수 있나요?', '샴푸보다 중요한 홈케어 팁 세 가지를 알려드리겠습니다. 첫째, 머리는 꼭 밤에 감으세요. 얼굴에 화장하고 자지 않는 것처럼 두피도 밤에 샴푸로 하루의 기름때와 먼지를 씻어내야 합니다. 아침에는 린스만 하고 밤에는 샴푸만 하면 스타일링도 되고 두피도 건강해져요. 씻은 후에는 두피를 꼭 잘 말려주셔야 합니다. 둘째, 두피에도 자외선 차단이 필요합니다. 해변이나 야외에서 정수리가 직사광선을 그대로 맞으면 두피가 빨갛게 타고 각질이 떨어지는 경우가 많아요. 셋째, 두피에도 보습제를 바르는 게 좋습니다. 세라마이드, 콜레스테롤, 지방산이 들어있는 보습제를 손가락으로 두피와 머리카락 사이에 발라주세요. 이미 탈모가 진행 중이라면 약국에서 미녹시딜을 구매해 하루 한 번 발라주면 도움이 됩니다.', '탈모 예방을 위한 세 가지 홈케어 팁과 미녹시딜 사용법을 피부과 전문의 김종식이 정리합니다.', array['탈모', '두피관리', '홈케어', '미녹시딜', '두피보습', '샴푸', '자외선차단']::text[]),
    ('nAqWcFwO1ws', 'kimjongsik', '탈모가 심해지면 피부과에서 어떤 치료를 받을 수 있나요?', '피부과에서 받을 수 있는 탈모 치료는 크게 약제, 주사, 레이저 세 가지입니다. 첫 번째로 먹는 약이나 바르는 약제를 처방받을 수 있고, 두 번째는 메조테라피(모낭주사)로 모발 성장과 재생에 도움을 주는 약재를 두피에 직접 주사하는 방법이에요. 당연히 두피에 직접 넣으니 효과가 좋습니다. 세 번째는 레이저 치료인데, 두피에 직접 자극을 주는 레이저나 모발 재생을 돕는 유효 빛을 쬐는 치료가 있습니다. 물론 심한 경우 모발 이식도 가능하죠. 다만 병원 치료 전에 먼저 스트레스나 다이어트 같은 조절 가능한 원인을 해결해보시고, 홈케어도 해본 후에 방문하시는 게 순서에 맞습니다. 이런 치료를 받으면 모발의 숱과 굵기 모두 개선이 가능합니다.', '피부과에서 받을 수 있는 탈모 치료 종류와 효과를 피부과 전문의 김종식이 안내합니다.', array['탈모치료', '메조테라피', '모낭주사', '레이저치료', '모발이식', '피부과시술', '두피치료']::text[]),
    ('BVEjTja3AFA', 'kimjongsik', '20대인데 피부과 시술 하나만 받는다면 뭐가 좋아요?', '20대라면 보톡스 딱 하나만 추천합니다. 사실 20대는 일생에 피부가 가장 좋은 시기라서 세수, 선크림, 수면 이 세 가지만 잘 해도 반은 성공이에요. 이 세 가지도 안 하면서 시술을 고민하는 건 순서가 맞지 않습니다. 그래도 60대까지 좋은 피부를 유지하고 싶다면 이마든 미간이든 자주 찡그리는 부위에 보톡스를 맞아두는 게 미래를 위한 투자입니다. 보톡스는 주름을 펴는 기능보다 예방 기능이 훨씬 크거든요. 피부가 팽팽할 때 미리 예방하면 나중에 깊은 주름이 자리 잡는 걸 막을 수 있습니다. 20대는 주머니 사정도 가볍고 피부 자체가 좋으니, 비싼 시술 여러 개 받을 필요 없이 보톡스 정도만 꾸준히 맞아주시면 됩니다.', '20대는 보톡스 하나면 충분합니다. 피부가 팽팽할 때 미리 예방해야 나중에 깊은 주름이 안 생기는 이유를 피부과 전문의 김종식이 설명합니다.', array['보톡스', '20대', '주름예방', '이마주름', '미간주름', '피부관리', '안티에이징']::text[]),
    ('BVEjTja3AFA', 'kimjongsik', '30대부터 얼굴이 갑자기 처지는데 뭘 받아야 하나요?', '30대라면 고주파 리프팅을 양치질처럼 기본으로 받으시는 게 가장 좋습니다. 30대는 피부 탄력이 빠지고 턱선이 뭉개지며 눈가에 잔주름이 자리 잡기 시작하는 시기예요. 티 안 나는 선에서 관리하려면 고주파 리프팅이 핵심인데, 안 하면 어느 날 갑자기 얼굴선이 무너져 있는 걸 발견하게 됩니다. 그때 가서 울쎄라든 써마지든 받으면 돈도 더 들고 효과도 느리다는 게 문제예요. 고주파는 콜라겐을 유지시키는 시술이라 30대부터 받으면 가장 효과적입니다. 보톡스도 물론 계속 병행해주시는 게 좋고요. 정보가 너무 많아서 뭘 해야 할지 모르겠다면 고주파 하나만 꾸준히 하시는 게 답입니다. 지겹게 무난하지만 확실하게 효과를 볼 수 있는 시술이에요.', '30대는 고주파 리프팅을 양치질처럼 기본으로 받으시는 게 좋습니다. 탄력이 빠지기 시작하는 시기에 콜라겐을 유지하는 원리를 피부과 전문의 김종식이 안내합니다.', array['고주파', '리프팅', '30대', '탄력', '콜라겐', '울쎄라', '써마지']::text[]),
    ('BVEjTja3AFA', 'kimjongsik', '40대 피부 관리 시술 조합은 뭐가 정답인가요?', '40대는 리프팅, 스킨부스터, 그리고 기미가 있다면 레이저 토닝까지 이 3박자가 기본 조합입니다. 40대는 탄력, 주름, 모공, 윤기 하나하나 눈에 띄게 무너지는 시점이라 겉 라인은 당겨주고 피부 속은 채워주는 걸 동시에 해야 합니다. 스킨부스터 종류는 스킨 보톡스, 리쥬란, 쥬베룩 같은 다양한 시술이 다 좋아요. 여기에 특히 여성분들은 임신과 출산 후나 40대가 되면서 기미가 많아지는데, 피부가 지저분하면 어떤 시술을 받아도 티가 안 나고 깔끔해 보이지 않습니다. 그래서 기미가 있다면 레이저 토닝을 병행하시는 게 중요해요. 40대라고 다 같은 피부가 아니라 잡티 많은 사람, 탄력만 무너진 사람, 색소만 있는 사람 다 다르지만 이 세 가지가 가장 보편적으로 효과를 보는 조합입니다.', '40대는 리프팅·스킨부스터·레이저 토닝 3박자가 기본 조합입니다. 기미·탄력·주름을 동시에 관리하는 시술 전략을 피부과 전문의 김종식이 정리합니다.', array['리프팅', '스킨부스터', '레이저토닝', '40대', '기미', '리쥬란', '쥬베룩']::text[]),
    ('BVEjTja3AFA', 'kimjongsik', '50대부터는 피부 시술 뭘 해도 소용없는 거 아닌가요?', '아닙니다. 50대는 단품이 아니라 조합과 루틴으로 접근해야 효과가 남는 시기입니다. 울쎄라나 써마지 같은 레이저 리프팅은 기본으로 탑재하되, 50대에 추가로 꼭 필요한 건 볼륨을 채워주는 시술이에요. 스컬트라, 레디어스, 필러 같은 시술이 대표적입니다. 이 시기부터 볼륨이 빠지면서 볼륨 부족 때문에 더 처지는 현상이 생기거든요. 아무리 당겨도 구조 자체가 무너지면 피부가 더 처질 수밖에 없습니다. 50대는 70~80대를 준비하는 시기라고 생각하시면 됩니다. 지금 볼륨을 미리 채워두면 나중에 노화가 가속될 때 버틸 수 있어요. 지금 안 하면 나중엔 두 배로 해야 하고 비용도 노력도 결과도 다 아쉬워지니, 미리미리 복구공사를 시작하시는 게 좋습니다.', '50대는 리프팅에 스컬트라·필러 등 볼륨 시술을 추가해야 합니다. 볼륨 부족이 처짐을 가속하는 원리와 70~80대를 대비하는 전략을 피부과 전문의 김종식이 설명합니다.', array['리프팅', '스컬트라', '필러', '50대', '볼륨', '울쎄라', '써마지']::text[]),
    ('5o0KbFSRGzA', 'kimjongsik', '비싼 아이크림 안 바르면 눈가 주름 더 심해지나요?', '꼭 비싼 아이크림을 바를 필요는 없고, 판테놀이나 글리세롤이 들어간 보습제만으로도 충분합니다. 눈 주변은 원래 피부가 매우 건조한 부위라 수분을 유지해주는 게 핵심이지, 특정 아이크림 제품이 필수인 건 아닙니다. 아이크림은 일반 크림보다 양이 적으면서 비싸기만 한 경우가 많아서, 차라리 그 비용으로 좋은 보습제를 사는 게 나을 수 있어요. 중요한 건 수분을 공급하고 막을 형성해서 증발을 막아주는 것이기 때문에 보습이 되는 제품이면 뭐든 괜찮습니다. 바세린을 활용하는 것도 좋은데, 반드시 보습제를 먼저 바르고 그 위에 얇게 덮어야 해요. 바세린을 너무 두껍게 바르면 비립종이나 좁쌀 여드름처럼 모공이 막혀 트러블이 생길 수 있으니 주의하세요. 눈가 주름은 어느 날 갑자기 한꺼번에 생기는 특성이 있어서, 주름이 없을 때부터 미리 보습 습관을 들이는 게 가장 현명한 예방법입니다.', '눈가 주름 관리에 비싼 아이크림 대신 보습제로 충분한 이유를 피부과 전문의 김종식이 설명합니다.', array['눈가주름', '아이크림', '보습제', '바세린', '판테놀', '잔주름', '주름예방']::text[]),
    ('5o0KbFSRGzA', 'kimjongsik', '레티놀을 주름 많은 눈가에 직접 발라도 괜찮은 건가요?', '레티놀은 주름 개선에 가장 효과 좋은 성분이지만, 눈가에는 반드시 아주 소량만 얇게 펴 발라야 합니다. 레티놀은 피부 속 콜라겐 형성을 촉진시켜 피부를 탄탄하게 해주고 자외선으로 손상된 피부를 회복시키는 역할을 합니다. 레티날은 레티놀보다 약 10배 강력하지만 그만큼 자극도 심하기 때문에, 처음 사용하시는 분은 레티놀 낮은 농도부터 시작하셔야 해요. 눈가에 바를 때는 정말 눈꼽만큼만 펴서 발라야 하고, 많이 바르면 따갑거나 빨갛게 올라오거나 각질이 벗겨지는 트러블이 생길 수 있습니다. 레티놀은 빛에 매우 민감해서 자외선에 노출되면 분해되고 변질되어 염증이나 색소침착을 유발하니 반드시 저녁에만 사용하세요. 또한 비타민A 성분이 태아 기형을 유발할 수 있기 때문에 임산부나 임신을 준비 중인 분은 절대 사용해서는 안 됩니다. 처음이라면 낮은 농도로 차근차근 피부를 적응시키는 게 핵심입니다.', '눈가 레티놀 사용법과 주의사항을 피부과 전문의 김종식이 안내합니다.', array['레티놀', '레티날', '눈가주름', '콜라겐', '주름개선', '비타민A', '임산부']::text[]),
    ('5o0KbFSRGzA', 'kimjongsik', '눈가 보톡스 잘못 맞으면 표정이 이상해지지 않나요?', '적당한 양을 근육 모양에 맞춰 잘 놓으면 자연스럽게 주름도 개선되고 표정도 해치지 않습니다. 눈가 보톡스는 눈 둘레근을 일시적으로 마비시켜서 주름 자체가 생기지 않게 해주는 시술인데, 너무 많은 용량을 맞거나 엉뚱한 부위에 맞으면 웃는데 무표정인 어색한 얼굴이 될 수 있어요. 핵심은 주름이 더 깊어지지 않는다는 느낌으로, 근육이 생긴 방향대로 적당한 양을 살살 놓는 것입니다. 한 번 맞으면 효과가 4~5개월 정도 가고, 주기적으로 반복하면 근육의 힘이 점점 떨어져 시술 간격도 길어지게 됩니다. 5년, 10년 반복하면 주름이 생기는 시기를 계속 뒤로 밀어놓는 효과가 있어요. 금액도 크게 비싸지 않은 편이라 저렴하게 시술받을 수 있는 병원이 많으니 잘 알아보시면 좋은 방법이 됩니다. 주름 잡는 데 보톡스만큼 강력하고 효과 좋은 시술은 없다고 봐도 과언이 아닙니다.', '눈가 보톡스의 자연스러운 시술법과 반복 효과를 피부과 전문의 김종식이 정리합니다.', array['보톡스', '눈가주름', '눈둘레근', '리프팅', '주름시술', '잔주름']::text[]),
    ('5o0KbFSRGzA', 'kimjongsik', '이미 깊어진 눈가 주름에는 어떤 시술이 효과적인가요?', '아이써마지, 아이리쥬란, 아그네스, 울트라펄스 레이저 등 상태에 따라 효과적인 시술이 다릅니다. 아이써마지는 고주파로 눈꺼풀 주변에 콜라겐 생성을 유도해 탄력을 개선하고, 눈 뜨는 힘까지 좋아져 이마 주름 개선의 일석이조 효과가 있습니다. 아이리쥬란은 연어 DNA를 이용해 피부를 재생하는 시술로, 눈가 주변의 깊어진 주름에 피부를 도톰하고 탄력 있게 만들어줘요. 아그네스는 미세한 바늘로 찌르고 고주파 열을 가해 주름을 직접 펴주는 방식이라 눈 아래쪽 주름에는 가장 드라마틱한 효과를 보입니다. 50~60대 이상으로 피부 자체가 늘어진 경우에는 울트라펄스 레이저로 피부를 깎아내 매끈하게 만드는 방법이 효과적이에요. 필러는 꺼짐이 심하거나 다른 시술로 해결이 안 되는 깊은 주름에 소량만 넣는 것이 좋습니다. 어떤 시술이 본인에게 맞는지는 전문의와 상담 후 결정하시는 게 가장 안전합니다.', '깊어진 눈가 주름에 효과적인 시술 종류별 특징을 피부과 전문의 김종식이 안내합니다.', array['아이써마지', '아이리쥬란', '아그네스', '울트라펄스', '눈가주름', '리쥬란', '필러']::text[]),
    ('q0hIuB5M_-Y', 'kimjongsik', '스킨보톡스가 물광주사보다 광 나는 효과가 더 좋다는 게 사실인가요?', '네, 스킨보톡스가 히알루론산 물광주사보다 피부에 광을 내는 효과는 더 좋다고 자신합니다. 스킨보톡스를 받으면 잔주름이 쫙 사라지면서 얼굴이 반짝반짝 광이 나게 되는데, 주름이 많으면 얼굴 전체가 칙칙해 보이다가 그 주름을 펴주면 칙칙함이 사라지고 얼굴이 확 밝아지는 원리입니다. 시술 후 2~3일이면 바로 티가 나기 시작하고, 일주일 정도면 효과가 거의 다 올라와서 주변에서 즉시 알아챌 수 있어요. 살짝 리프팅 효과도 있어서 얼굴이 착 달라붙는 느낌이 나고, 많은 분들이 갸름해졌다거나 살 빠져 보인다는 이야기를 듣게 됩니다. 게다가 주사 자국이 하루 이틀이면 사라지고 나면 시술 받은 티가 전혀 나지 않아요. 그래서 소개팅이나 결혼식 같은 중요한 일정 앞두고 받으러 오시는 분들이 정말 많습니다. 과하지 않게 자연스럽게 예뻐지고 싶은 분에게 가장 추천하는 시술입니다.', '스킨보톡스의 광 나는 효과와 빠른 회복을 피부과 전문의 김종식이 설명합니다.', array['스킨보톡스', '물광주사', '피부결', '잔주름', '리프팅', '광채', '스킨부스터']::text[]),
    ('q0hIuB5M_-Y', 'kimjongsik', '얼굴 기름 많고 모공 넓은데 스킨보톡스로 진짜 줄어들어요?', '네, 스킨보톡스를 받으시면 피지선 활동이 줄어들면서 얼굴 기름기와 모공이 확 줄어듭니다. 오후만 되면 기름기가 올라오면서 화장이 지워지고 떡지는 지성 피부분들에게 특히 효과가 좋아요. 피지선 활동 자체가 억제되니까 여드름 피부에도 도움이 되고, 홍조나 얼굴이 붉은 분들에게도 개선 효과가 있습니다. 효과가 빨라서 시술 후 2~3일이면 티가 나기 시작하고, 일주일이면 거의 완성되어 바로 칭찬을 듣게 돼요. 보통 한 3~4개월 정도 충분히 유지되기 때문에, 한 가지 시술로 피부결과 모공, 피지까지 동시에 잡을 수 있는 셈이죠. 한번에 큰 돈 쓰기 부담스럽지만 뭔가 하나는 해보고 싶다는 분들에게 가성비 측면에서도 추천합니다. 어떤 분들은 울쎄라 시술 받은 것 같은 느낌이라고 할 만큼 리프팅 효과도 체감됩니다.', '스킨보톡스의 모공 축소와 피지 억제 효과를 피부과 전문의 김종식이 정리합니다.', array['스킨보톡스', '모공', '피지', '지성피부', '여드름', '기름기', '가성비']::text[]),
    ('q0hIuB5M_-Y', 'kimjongsik', '스킨보톡스에 윤곽 보톡스까지 같이 하면 얼굴이 정말 달라지나요?', '스킨보톡스만으로도 피부가 매끈해지는데, 윤곽 보톡스까지 함께하면 얼굴 전체 실루엣이 달라집니다. 윤곽 보톡스는 이마부터 얼굴 옆라인, 관자놀이 위, 귀 뒤, 턱 라인을 따라 주사를 놓는 시술로, 얼굴이 작아 보이고 쫙 정리된 느낌이 훨씬 살아나요. 마치 잘 빚어놓은 도자기처럼 갸름하고 반짝반짝한 인상을 만들어주는 효과가 있습니다. 보통 스킨보톡스 시술 시 용량을 남겨서 윤곽 쪽에도 같이 놔드리면 만족도가 매우 높은 편이에요. 다만 사각턱이나 침샘이 크시거나 이중턱, 턱 처짐이 심한 분들은 용량을 따로 조절해야 할 수 있습니다. 특히 남성분 중 사각턱이 많이 발달한 경우에는 스킨보톡스 정도로는 윤곽 개선이 부족해서 용량을 추가하기도 합니다. 두 시술을 병행하면 피부결 개선과 얼굴형 정리를 동시에 할 수 있어서 효율적인 조합이에요.', '스킨보톡스와 윤곽 보톡스 병행 효과를 피부과 전문의 김종식이 안내합니다.', array['스킨보톡스', '윤곽보톡스', '턱라인', '리프팅', '사각턱', '얼굴축소', '보톡스']::text[]),
    ('q0hIuB5M_-Y', 'kimjongsik', '스킨보톡스가 엄청 아프다던데 요즘도 그런가요?', '원래 엄청 아픈 시술이 맞지만, 요즘에는 마취크림만 잘 바르면 거의 안 아프게 받을 수 있습니다. 스킨보톡스는 얇은 바늘로 피부 표면에 계속 찔러서 보톡스를 넣는 시술이라 얼굴 전체를 찌르니까 원래 상당히 아파요. 피부 제일 바깥쪽에 신경세포가 많아 아픔이 강하게 느껴지는 부위라 예전에는 울면서 시술받는 분들도 많았습니다. 하지만 최근에는 안 아프게 놓는 방법이 개발되어서 마취크림만 잘 바르면 대부분 거의 안 아프다고 하시는 분들이 많아요. 별로 아프지도 않고, 가성비도 좋고, 효과까지 좋은 시술이라 진입장벽이 많이 낮아졌습니다. 스킨보톡스는 피부 제일 바깥쪽에 아주 넓고 얕게 고르게 보톡스를 주사해주는 시술이에요. 모공, 잔주름, 피부 윤곽, 피지 분비까지 전반적으로 개선해주는 올인원 시술이라 피부과 입문용으로도 최적입니다.', '스킨보톡스의 통증 여부와 시술 원리를 피부과 전문의 김종식이 설명합니다.', array['스킨보톡스', '통증', '마취크림', '피부결', '잔주름', '모공', '가성비']::text[]),
    ('DyqbYZJxr4I', 'kwonsuhyun', '지성 피부인데 선크림 바르면 모공 막히고 기름지는 거 어떡하죠?', '지성 피부라면 선앰플처럼 크림이 아닌 가벼운 제형을 선택하는 게 핵심입니다. 지성 피부에 무거운 선크림을 바르면 모공이 두드러지고 기름광이 흘러서 화장이 무너지고 다크닝이 오는 최악의 상황이 됩니다. 프롬리에 보송 선 앰플처럼 크림 타입이 아닌 앰플 타입 제품은 산뜻해서 지성 피부에 부담이 없어요. 닥터지 비타 선 앰플도 가볍고 여드름용 브랜드답게 산뜻한 편이라 지성 피부에 잘 맞습니다. 선크림 양은 완두콩 두 개 크기 정도를 바르되, 위에 파운데이션을 얹어서 커버하는 방법도 있어요. 파운데이션에도 자외선 차단 기능이 있기 때문에 선크림을 산뜻하게 바르고 파운데이션으로 보완하면 화장이 안 밀리면서 차단 효과를 높일 수 있습니다. 야외 활동이 길어질 때는 파운데이션을 좀 더 두텁게 하는 것이 지성 피부의 실전 팁이에요.', '지성 피부가 선크림 대신 선앰플을 고르는 팁을 피부과 전문의 권수현이 안내합니다.', array['선크림', '지성피부', '선앰플', '프롬리에', '모공', '피지', '자외선차단']::text[]),
    ('DyqbYZJxr4I', 'jeonghanmi', '선크림 500원 동전만큼 바르라는데 진짜 그렇게 발라야 하나요?', '이론상 500원 동전 크기가 맞지만, 일상에서는 솔직히 그만큼 바르기 어렵고 완두콩 정도로도 충분합니다. 야외 활동이 길거나 휴가 때처럼 제대로 차단해야 할 때는 500원 크기만큼 바르는 게 맞아요. 하지만 평소에 메이크업을 해야 하는 상황에서는 그만큼 바르면 화장이 밀리고 무너지기 때문에 현실적으로 어렵습니다. 피부과 의사 120명을 대상으로 설문조사를 했을 때도 500원 크기만큼 바르는 분보다 완두콩만큼 바르거나 아예 안 바르시는 분들이 많았어요. 다만 피부과 의사들은 대부분 실내에서 근무하고 햇빛을 볼 일이 적기 때문에 일반적 상황과 다르다는 점을 고려하셔야 합니다. 야구 선수 양현종처럼 야외에서 몇 시간씩 활동하시는 분은 500원 크기만큼 꼭 바르셔야 피부가 늙지 않고 유지될 수 있어요. 결국 야외 활동량에 따라 적정량을 조절하시는 게 합리적인 방법입니다.', '선크림 적정 사용량과 상황별 조절법을 피부과 전문의 정한미가 정리합니다.', array['선크림', '자외선차단', '자외선', '선크림양', '광노화', '기미']::text[]),
    ('DyqbYZJxr4I', 'jeonghanmi', '눈가에 선크림 안 바르면 진짜 문제 되나요?', '눈가야말로 선크림을 더 잘 발라야 하는 부위인데, 많은 분들이 빼놓고 바르는 실수를 합니다. 눈 주변은 피부가 가장 얇고 표정 지을 때 주름도 많이 생기며, 주근깨나 잡티 같은 것도 잘 생기는 취약한 부위입니다. 눈에 들어가면 안 될 것 같아서 본능적으로 피하게 되지만, 바르지 않으면 눈 주위만 타서 펜더처럼 빨갛게 되는 경우도 있어요. 선크림이 따가워서 안 바르겠다는 분도 있는데, 따갑다고 안 바르면 안 되고 안 시린 제품을 찾아서 꼭 눈가에도 발라야 합니다. 눈꺼풀까지 포함해서 꼼꼼하게 바르는 것이 중요하고, 무기자차 제품은 쌍꺼풀 라인이나 눈 밑 주름에 낄 수 있으니 확인하면서 발라주세요. 아이크림 바르는 부위라서 선크림은 안 바른다고 생각하기 쉽지만 실제로는 그 반대가 맞습니다. 오히려 피부가 가장 약한 곳이니까 자외선 차단에 더 신경 써야 해요.', '눈가 선크림 필수인 이유와 바르는 팁을 피부과 전문의 정한미가 설명합니다.', array['선크림', '눈가', '자외선차단', '주근깨', '무기자차', '쌍꺼풀', '광노화']::text[]),
    ('DyqbYZJxr4I', 'jeonghanmi', '기미 잡티 이미 있는데 라로슈포제 틴티드 발라도 의미 있나요?', '이미 있는 기미와 잡티를 지워주진 않지만, 앞으로 생길 기미와 잡티를 막아주는 효과가 있으니 당연히 의미가 있습니다. 선크림의 핵심 역할은 자외선을 차단해서 색소가 더 진해지거나 새로 만들어지는 것을 예방하는 것이에요. 라로슈포제 틴티드처럼 기미와 잡티 예방에 좋다고 알려진 제품은 이미 색소가 있는 분도 추가 악화를 막기 위해 사용하실 수 있습니다. 피부과 의사 120명이 뽑은 선크림 탑3에 포함될 만큼 전문가들 사이에서도 인정받는 제품이에요. 20대부터 꾸준히 선크림을 바르기 시작하면 나중에 확실히 안 늙는다는 것은 양현종 선수 같은 사례에서도 확인됩니다. 남녀 불문하고 자외선 차단을 꾸준히 하는 것 자체가 가장 확실한 안티에이징이니까 이미 잡티가 있어도 포기하지 마세요. 선크림은 치료가 아니라 예방이라는 점을 기억하시면 됩니다.', '기미 잡티가 있어도 선크림이 필요한 이유를 피부과 전문의 정한미가 안내합니다.', array['기미', '잡티', '라로슈포제', '선크림', '자외선차단', '미백', '광노화']::text[]),
    ('kiUtiO132Wk', 'jeonghanmi', '얼굴이 길고 가는 사람도 사각턱 보톡스 맞으면 좋아질까요?', '북방계처럼 얼굴이 길고 근육이 적은 분은 사각턱 보톡스를 신중하게 고려해야 합니다. 보톡스는 교근 같은 근육에 작용해 얼굴 라인을 줄여주는 시술인데, 이미 가늘고 긴 얼굴에 무리하게 놓으면 옆 라인이 더 빠지면서 바나나형이나 당근형처럼 길고 뾰족한 인상이 강해질 수 있어요. 김연아 선수처럼 콧대가 길고 갸름한 얼굴형이 대표적인 북방계입니다. 이런 얼굴형은 사각턱 보톡스보다는 얕은 층에 소량을 놓는 스킨 보톡스 정도가 안전해요. 모공·결을 정돈하는 효과만 보고 윤곽 자체를 더 깎지 않는 방향이 잘 맞습니다. 오히려 볼륨을 채워 계란형으로 다듬는 시술이 인상 개선에 효과적이에요. 무조건 가성비만 보고 보톡스부터 맞기보다 본인 얼굴형 진단 후 결정하시는 게 좋습니다.', '길고 가는 북방계 얼굴이 사각턱 보톡스에 주의해야 하는 이유를 피부과 전문의 정한미가 설명합니다.', array['사각턱', '보톡스', '북방계얼굴', '얼굴형', '스킨보톡스', '교근']::text[]),
    ('kiUtiO132Wk', 'jeonghanmi', '스컬트라가 정확히 뭐고 왜 필러보다 자연스럽다고 하는 건가요?', '스컬트라는 자가 콜라겐을 유도해 얼굴을 부드럽게 만들어주는 콜라겐 부스터 시술입니다. 폴리락틱애씨드(PLLA)라는 흡수성 성분이 진피층에 들어가 시간을 두고 본인 콜라겐 생성을 자극하기 때문에 결과가 서서히 자연스럽게 드러나요. 필러는 히알루론산이 물을 빨아들여 즉각 부피를 만들지만, 부었을 때 표시가 나거나 시간이 지나면서 울퉁불퉁해질 수 있다는 단점이 있어요. 반면 스컬트라는 자가 콜라겐이 채워지므로 표정이 움직여도 위치가 흔들리지 않고 자연스러운 라인이 유지됩니다. 효과가 보통 2~3년 지속되어 필러보다 유지 기간도 깁니다. "티 안 나게 예뻐졌다"는 후기가 많은 이유가 바로 이런 원리 때문이에요. 다만 결과가 1~3개월에 걸쳐 서서히 나타나므로 즉시 변화를 원하는 분께는 맞지 않을 수 있습니다.', '스컬트라가 필러와 다른 자연스러운 볼륨 원리와 지속 기간을 피부과 전문의 정한미가 정리합니다.', array['스컬트라', '콜라겐', '필러', '자연스러움', '볼륨', 'PLLA']::text[]),
    ('kiUtiO132Wk', 'jeonghanmi', '치아 교정한 뒤로 얼굴이 꺼져 보이는데 이런 얼굴에 맞는 시술이 있을까요?', '교정 후 광대·턱 아래가 꺼진 땅콩형 얼굴엔 스컬트라 같은 콜라겐 부스터가 잘 맞습니다. 치아 교정 과정에서 발치를 하고 단단한 음식을 잘 씹지 못하는 동안 안면 골격과 근육 발달이 줄면서 관자놀이·앞볼·턱 아래 볼륨이 빠지기 쉬워요. 그 결과 광대만 도드라지고 위아래가 꺼져 땅콩형·고구마형 인상이 만들어집니다. 필러로 한 번에 채우면 부자연스러울 수 있는 부위라 시간을 두고 콜라겐을 만들어주는 스컬트라가 자연스럽게 정돈해주는 데 유리해요. 보통 한 달 간격으로 2~3회에 걸쳐 나눠 시술하고, 부드러운 곡선이 1~3개월에 걸쳐 자리잡습니다. 시술 후엔 마사지와 충분한 수분 섭취로 균일한 분포를 유지하는 게 중요해요. 20~30대 땅콩형 고민자에게 만족도가 특히 높은 시술입니다.', '치아 교정 후 꺼진 땅콩형 얼굴에 스컬트라가 잘 맞는 이유를 피부과 전문의 정한미가 안내합니다.', array['땅콩형얼굴', '스컬트라', '치아교정', '볼륨', '콜라겐', '광대']::text[]),
    ('kiUtiO132Wk', 'jeonghanmi', '스컬트라는 결절(멍울) 부작용 때문에 무섭다는데 정말 위험한가요?', '현재 가이드라인을 따라 시술하면 결절 발생률은 매우 낮은 편입니다. 결절은 흔히 생각하는 돌이 아니라 콜라겐이 한 부위에 과하게 만들어져 완두콩처럼 만져지는 현상이에요. 초창기엔 7cc 정도의 적은 양으로 희석하라는 지침이 있어 농도가 높아 결절이 종종 생겼습니다. 지금은 10cc 이상으로 충분히 희석하고 48시간에서 일주일 정도 수화(약물 충분히 녹이기)를 한 뒤 시술하기 때문에 약물이 한 곳에 뭉칠 가능성이 크게 줄었어요. 거기에 깊은 층에 소량씩 골고루 분산해 주입하는 테크닉이 표준화되면서 부작용 빈도가 의미 있게 낮아졌습니다. 다만 시술자의 숙련도에 따라 차이가 있으니 풍부한 경험과 표준 프로토콜을 지키는 의료진을 선택하는 게 중요해요. 시술 후 마사지 가이드를 잘 지키시면 만족도와 안전성을 함께 챙길 수 있습니다.', '스컬트라 결절 부작용이 줄어든 이유와 안전 시술 조건을 피부과 전문의 정한미가 설명합니다.', array['스컬트라', '결절', '콜라겐', '부작용', '수화', '안전성']::text[]),
    ('uQHv4h4f3Hg', 'jeonghanmi', '선크림 발랐는데도 얼굴이 후끈거리면 기미가 생길 수 있나요?', '네, 선크림은 자외선은 막아줘도 적외선으로 인한 열까지는 차단하지 못하기 때문에 열감 자체가 기미와 색소를 악화시킬 수 있습니다. 피부가 햇빛을 받아 후끈거리는 열은 적외선 때문인데, 자외선 차단제가 이 적외선까지 다 막아주지는 못해요. 피부에 열이 들어오면 그 자체가 염증 반응을 일으키고, 이 염증이 기미나 색소를 유발하는 데 관여합니다. 또한 열 자체가 색소를 더 많이 만들게 하는 역할도 알려져 있어서 자외선만 신경 쓰면 안 돼요. 그래서 외출 후 얼굴이 후끈거린다면 빨리 선크림을 닦아내고 세안한 뒤 열을 식혀주는 게 중요합니다. 쿨링 패드를 볼에 붙이고 10분 정도 후 떼어내고 톡톡 두드려 흡수시키는 방법이 편리해요. 알로에 팩이나 쿨링 미스트도 좋지만, 패드는 붙이고 돌아다닐 수 있어서 귀찮지 않다는 장점이 있습니다.', '선크림은 자외선은 막아도 적외선 열감은 차단 못 해 기미가 악화될 수 있습니다. 외출 후 쿨링 패드로 열을 식히는 방법을 피부과 전문의 정한미가 설명합니다.', array['기미', '적외선', '선크림', '쿨링', '색소침착', '열감', '자외선차단']::text[]),
    ('uQHv4h4f3Hg', 'jeonghanmi', '여름에 미백 제품은 아침이랑 저녁 다르게 써야 하나요?', '반드시 다르게 써야 하는 건 아니지만, 아침에는 항산화 중심, 저녁에는 미백 성분 다양한 제품으로 나눠 쓰면 시너지를 낼 수 있습니다. 아침에는 스킨수티컬즈 실리마린 CF처럼 순수 비타민C 15% 고농도가 들어간 항산화 앰플을 쓰면 출근하며 햇빛에 노출될 때 자외선 손상을 줄여줘요. 저녁에는 넘버즈인 글루타치온C 흔적 앰플처럼 글루타치온, 트라넥사믹애씨드, 나이아신아마이드 등 여러 미백 성분이 조합된 제품으로 색소 억제에 집중할 수 있습니다. 글루타치온은 이미 만들어진 색소도 줄여주고 새 색소가 만들어지는 것도 억제하는 역할을 해요. 비타민C와 글루타치온을 같이 사용하면 항산화와 미백에서 시너지 효과가 납니다. 여름에는 자외선 노출이 길어지면서 피부가 어쩔 수 없이 타고 기미가 올라오기 때문에 다른 계절보다 미백 제품에 더 신경 쓰는 게 좋아요. 두 제품을 아침 저녁 바꿔 써도 상관없으니 편한 방식으로 꾸준히 쓰는 게 가장 중요합니다.', '아침엔 비타민C 항산화 앰플, 저녁엔 글루타치온 미백 앰플로 나눠 쓰면 시너지가 납니다. 여름 아침·저녁 미백 루틴 조합을 피부과 전문의 정한미가 정리합니다.', array['미백', '비타민C', '글루타치온', '나이아신아마이드', '스킨수티컬즈', '항산화', '색소']::text[]),
    ('uQHv4h4f3Hg', 'jeonghanmi', '여름에 선크림만으로는 부족한데 물리적 차단까지 꼭 해야 하나요?', '네, 자외선 차단제만으로는 자외선을 100% 막을 수 없고 가시광선이나 적외선은 아예 못 막기 때문에 물리적 차단이 꼭 필요합니다. 선크림을 바르더라도 선캡, 양산, 선글라스 중 적어도 두 가지는 챙기고 나가는 것이 안전해요. 선캡만 쓰면 옆쪽으로는 해가 다 들어오기 때문에 선글라스를 함께 착용하거나 양산을 쓰는 게 좋습니다. 아이 데리러 가는 것처럼 양산을 들기 애매한 상황에서는 UV 차단이 되는 넓은 챙의 선바이저가 옆까지 커버해줘서 편리해요. 자외선 차단제는 자외선은 막아줘도 다른 빛들, 즉 가시광선이나 적외선까지는 차단하지 못합니다. 그래서 물리적으로 빛 자체를 가려주는 것이 선크림을 보완하는 가장 확실한 방법이에요. 특히 여름철 강한 햇빛에는 선크림과 물리적 차단을 반드시 병행해야 피부를 제대로 보호할 수 있습니다.', '선크림만으로는 가시광선·적외선을 못 막아 물리적 차단이 꼭 필요합니다. 선캡·양산·선글라스·선바이저 활용법을 피부과 전문의 정한미가 안내합니다.', array['선크림', '자외선차단', '선캡', '양산', '선글라스', '적외선', '가시광선']::text[]),
    ('uQHv4h4f3Hg', 'jeonghanmi', '팔다리까지 여름에 미백 관리하려면 어떤 제품이 좋아요?', '바디에는 나이아신아마이드와 글루타치온이 들어간 산뜻한 바디로션을 샤워 후 매일 꾸준히 바르는 게 효과적입니다. 여름에는 반팔과 반바지를 입으니 팔다리가 새까매지기 쉽고, 관리를 안 하면 잡티도 눈에 띄게 생기기 시작해요. 나이아신아마이드는 이미 만들어진 색소가 피부 위쪽 각질세포로 전달되는 과정을 차단해주는 역할을 합니다. 쉽게 말하면 제품은 만들어졌지만 택배 배달을 막는 것과 같은 원리예요. 비타민C는 빛과 열에 불안정한 편인데, 나이아신아마이드는 빛과 열에 안정적이고 피부 자극도 적어서 바디에 넓게 바르기에 적합합니다. 바디로션은 끈적거리지 않고 산뜻한 제형이어야 여름에 매일 쓸 수 있어요. 가격보다 성분이 중요하고, 무엇보다 매일매일 꾸준히 바르는 것이 가장 확실한 미백 관리법입니다.', '팔다리 미백에는 나이아신아마이드·글루타치온 함유 바디로션을 매일 바르는 게 효과적입니다. 빛에 안정적인 미백 성분과 제품 선택법을 피부과 전문의 정한미가 설명합니다.', array['나이아신아마이드', '글루타치온', '바디로션', '미백', '잡티', '여름관리', '비타민C']::text[]),
    ('cNDqgARTmSw', 'gohyerim', '모기 물렸을 때 침 바르면 진짜 효과 있나요?', '침 바르기는 오히려 2차 감염 위험을 높이는 위험한 행동입니다. 모기에 물리면 미세한 상처가 생기는데, 거기에 침을 바르면 세균 덩어리를 상처에 직접 발라주는 것과 다름없어요. 잘못하면 붓고 진물 나고 곪아서 항생제를 먹어야 할 수도 있습니다. 손톱으로 십자가 모양을 내는 것도 좋은 방법은 아닌데, 통증이 가려움을 잠깐 덮어줄 뿐 근본적 해결이 안 돼요. 우리 뇌는 아픈 느낌과 가려운 느낌이 동시에 오면 더 강한 자극에 집중하게 되어 있어서, 손톱 통증에 집중하는 사이 가려움이 줄어든 것처럼 느끼는 거죠. 숟가락을 데워서 지지는 방법은 원리 자체는 타당하지만 온도 조절이 어려워 화상과 흉터 위험이 큽니다. 모기 물린 직후에는 흐르는 물과 비누로 헹구고, 얼음팩을 수건에 감싸 5~10분 냉찜질하는 게 가장 안전하고 효과적인 응급 처치법이에요.', '모기 물렸을 때 침 바르기와 민간요법의 위험성, 올바른 응급 처치법을 피부과 전문의 고혜림이 설명합니다.', array['모기', '벌레물림', '가려움증', '냉찜질', '2차감염', '응급처치', '여름피부']::text[]),
    ('cNDqgARTmSw', 'gohyerim', '모기한테 안 물리려면 어떤 색 옷을 입어야 하나요?', '흰색이나 밝은 파스텔톤 옷을 입으면 모기에게 덜 물릴 수 있습니다. 모기는 사람처럼 모든 색을 잘 보지 못하고 어두운 색은 잘 보되 밝은 색은 잘 못 보는 편이에요. 특히 검정, 빨강, 주황 같은 색은 열을 많이 머금고 주변과 대비가 커서 모기 눈에 잘 띄거든요. 잘 때 검은 옷을 입고 자면 모기를 위한 헌혈의 장을 마련해주는 셈이죠. 옷 색깔보다 더 중요한 건 냄새인데, 모기는 시각보다 후각이 더 발달되어 있어서 이산화탄소, 젖산, 암모니아 냄새를 추적합니다. 젖산은 땀에 포함되어 있어서 운동 후 안 씻고 자면 모기한테 많이 물리게 돼요. 자기 전 샤워만 잘해도 도움이 되고, 시트로넬라나 레몬, 유칼립투스 같은 모기가 싫어하는 향을 활용하면 접근을 막을 수 있습니다.', '모기가 좋아하는 옷 색깔과 냄새, 효과적인 모기 예방법을 피부과 전문의 고혜림이 안내합니다.', array['모기', '모기퇴치', '여름', '옷색깔', '땀', '후각', '시트로넬라']::text[]),
    ('cNDqgARTmSw', 'gohyerim', 'O형 혈액형이 진짜 모기한테 더 잘 물리나요?', '여러 연구에서 O형을 모기가 다른 혈액형보다 더 좋아한다는 결과가 나오긴 했지만, 모든 연구에서 일관된 건 아닙니다. 나머지 A형, B형, AB형 순위는 연구마다 조금씩 다르고, 상대적으로 많다는 거지 절대적이지는 않아요. 혈액형보다 훨씬 더 중요한 건 냄새인데, 모기는 시각보다 후각이 발달해서 호흡으로 나오는 이산화탄소만으로도 우리 위치를 추적할 수 있습니다. 또 땀 속 젖산 냄새를 좋아하기 때문에 운동 후나 덥고 습할 때 특히 잘 물리게 돼요. 선풍기나 에어컨 바람으로 모기의 저속 비행을 방해하는 것도 효과가 있고, 집 주변 화분 받침이나 양동이에 고인 물을 제거해 번식지를 없애는 것도 도움이 됩니다. 혈액형 때문에 절망하기보다는 샤워와 환경 관리에 신경 쓰는 게 현실적인 대책이에요.', 'O형이 모기에 더 잘 물리는지 여부와 혈액형보다 중요한 요인을 피부과 전문의 고혜림이 정리합니다.', array['모기', 'O형', '혈액형', '이산화탄소', '젖산', '모기퇴치', '여름']::text[]),
    ('cNDqgARTmSw', 'gohyerim', '모기 물린 데 버물리 바르면 되는 거 아닌가요?', '버물리 같은 제품은 효과적이지만, 이미 긁어서 상처가 난 곳에는 오히려 자극이 될 수 있어 주의해야 합니다. 버물리, 서버쿨, 물린디쿨 같은 약에는 디펜하이드라민 염산염이라는 항히스타민제 성분이 들어 있어 가려움증을 줄여주고, 제품에 따라 국소 마취제나 멘톨, 캄파 같은 냉감 성분도 포함돼요. 그런데 30개월 이하 아이에게는 캄파 성분이 피부를 통해 쉽게 흡수되어 경련 위험이 있으므로 절대 사용해서는 안 됩니다. 어린 아이들은 버물리 키드나 서버쿨 키드 같은 전용 제품을 쓰셔야 해요. 긁어서 상처가 난 부위에는 가려운 곳에 스테로이드 연고, 상처 난 곳에 박트로반 같은 항생제 연고를 따로 바르는 게 맞습니다. 그래도 가려우면 지르텍 같은 먹는 항히스타민제를 짧게 복용하는 방법도 있어요.', '모기 물린 뒤 버물리 사용법과 상처 난 경우의 올바른 약 선택을 피부과 전문의 고혜림이 안내합니다.', array['모기', '버물리', '항히스타민제', '스테로이드연고', '소아', '캄파', '벌레물림']::text[]),
    ('VZXWLZM-k9g', 'jeonghanmi', '결혼식 일주일 전에 받아도 티 안 나는 시술이 있나요?', '티타늄 리프팅은 시술 직후부터 효과가 보이면서 멍이나 붓기가 전혀 없어 결혼식 직전에 딱 맞는 시술입니다. 시술 받자마자 피부가 쫀쫀해지고 밝아지면서 리프팅 효과가 나타나거든요. 레이저 시술이라 피부 톤도 맑아 보이고, 얼굴이 약간 작아 보이는 효과까지 있어요. 시술 직후에는 약간 얼굴이 빨개져 있을 수 있지만 붓기, 멍, 딱지 같은 부작용이 전혀 없어서 일상생활에 바로 복귀 가능합니다. 붉은기가 빠지고 나면 효과가 눈에 확 들어오는데, 쫀쫀한 리프팅에 피부 톤까지 환해지니까 여러 가지를 동시에 잡을 수 있죠. 결혼식처럼 부작용이나 티가 나면 안 되는데 빠른 효과가 필요한 상황에서 가장 안전한 선택이에요. 시간이 촉박해서 한 번밖에 못 오시는 분들에게 특히 추천드립니다.', '결혼식 직전에도 받을 수 있는 티 안 나는 리프팅 시술을 피부과 전문의 정한미가 안내합니다.', array['티타늄리프팅', '결혼식', '리프팅', '부작용없는시술', '피부톤', '즉각효과', '예비신부']::text[]),
    ('VZXWLZM-k9g', 'jeonghanmi', '1년에 한 번만 받아도 효과가 유지되는 리프팅이 있나요?', '울쎄라는 피부 속 근막층과 지방층에 에너지를 줘서 처진 피부를 당겨주는 시술로, 한 번 받으면 약 1년 정도 효과가 유지됩니다. 얼굴에 살이 있으면서 처짐이 보이고 팔자가 깊어지는 분들에게 특히 적합해요. 울쎄라는 피부 깊은 층을 쪼아줘서 처져 있는 피부를 착 달라붙게 하고, 얼굴이 V라인으로 작아지는 효과를 줍니다. 써마지와 자주 비교되는데, 써마지는 울쎄라보다 피부 겉에 가까운 층에 작용해서 잔주름, 피부 탄력, 모공 개선에 더 강점이 있어요. 피부가 두껍고 살이 있어서 처짐이 고민이면 울쎄라, 피부가 얇고 잔주름이 있으면서 푸석거리면 써마지 같은 단극성 고주파를 같이 받으시면 좋습니다. 해외에 계시거나 바빠서 자주 못 오시는 분들도 1년에 한 번만 받으면 장기적으로 노화를 막을 수 있어요.', '1년에 한 번으로 효과가 유지되는 울쎄라와 써마지의 차이를 피부과 전문의 정한미가 설명합니다.', array['울쎄라', '써마지', '리프팅', '처짐', 'V라인', '노화예방', '근막층']::text[]),
    ('VZXWLZM-k9g', 'jeonghanmi', '잡티 한 번에 확 없앨 수 있는 시술이 진짜 있나요?', 'IPL과 GV레이저를 함께 받으면 한 번 시술로도 잡티가 드라마틱하게 사라질 수 있습니다. 레이저가 잡티에 흡수되면 까맣게 딱지가 생겼다가 일주일 정도 지나면서 딱지와 기미가 함께 떨어져 나가면서 피부가 환해져요. 잡티뿐 아니라 얼굴의 얼룩, 붉은기도 개선되고 피부 톤 자체를 맑게 만들어주기 때문에 한 번에 여러 효과를 볼 수 있죠. 다만 모든 사람에게 가능한 건 아닌데, 잡티 밑에 기미가 껴있거나 피부 색이 어두운 분은 강한 레이저에 오히려 기미가 진해지거나 피부 톤이 얼룩덜룩해질 수 있어요. 피부 타입이 맞다면 정말 좋은 효과를 볼 수 있고, 시술 후 비타민C나 글루타치온 성분의 화장품을 함께 쓰면 더 도움이 됩니다. 시간이 부족해서 한 번에 드라마틱한 효과를 내야 할 때 적합한 시술이에요.', '한 번 시술로 잡티를 드라마틱하게 없애는 IPL 레이저의 효과와 주의점을 피부과 전문의 정한미가 정리합니다.', array['IPL', '잡티', '기미', 'GV레이저', '미백', '피부톤', '색소치료']::text[]),
    ('VZXWLZM-k9g', 'jeonghanmi', '이마 필러 하면 너무 볼록해서 부자연스럽지 않나요?', '이마 필러는 과하게 넣지 않고 꺼진 부분만 자연스럽게 채워 연결해주면 오히려 여성스럽고 우아한 인상을 만들어줍니다. 이마가 울퉁불퉁하면 인상이 강해 보이는데, 필러로 고르게 채워서 라인만 예쁘게 만들어주면 빛이 고르게 반사되면서 세련된 느낌이 나거든요. 많은 분이 이마 필러 하면 볼록해지는 걸 걱정하시는데, 눈썹 뼈가 튀어나오고 위가 푹 들어간 이마를 매끈하게 다듬어주는 게 핵심이에요. 이 한 끗 차이로 정말 인상이 달라지는데, 포인트 부위에 적절한 양만 잘 넣으면 본인도 옛날 얼굴이 기억이 안 날 정도로 자연스럽습니다. 너무 과하게 용량을 많이 하면 어색해 보일 수 있지만, 꺼진 곳만 채워주는 정도라면 주변에서 뭔가 달라졌다, 예뻐졌다는 반응이 나오게 돼요. 얼굴이 작아진 것 같다는 말을 듣는 경우도 많아서 만족도가 높은 시술이에요.', '이마 필러의 자연스러운 효과와 부자연스럽지 않게 받는 핵심 포인트를 피부과 전문의 정한미가 설명합니다.', array['이마필러', '필러', '히알루론산', '이마라인', '볼륨', '여성스러움', '자연스러운시술']::text[]),
    ('lbl50k9AjVU', 'parkhyojin', '피부에서 광이 안 나고 칙칙해 보이는 이유가 뭔가요?', '피부에서 광이 나지 않는 가장 큰 이유는 피부결을 구성하는 네 가지 요소 때문입니다. 첫째 잔주름이 많아 자글자글하면 빛이 한 번에 반사되지 않아 광이 나지 않아요. 둘째 솜털이 많으면 화장이 매끄럽지 않고 뜨게 되면서 빛 반사를 방해합니다. 셋째 검버섯이나 편평사마귀, 좁쌀 여드름처럼 실질적으로 튀어나온 요철이 매끈한 결을 막고요. 마지막이 가장 어려운 모공인데, 모공이 늘어나거나 패여 있으면 올록볼록해서 광이 나지 않습니다. 잔주름은 보톡스로, 털은 레이저 제모로, 검버섯이나 사마귀는 레이저로 깎으면 해결이 비교적 쉬워요. 이 네 가지 중 자기에게 문제 되는 것들을 없애주면 광나는 피부가 될 수 있다는 게 핵심이에요.', '피부에서 광이 나지 않는 네 가지 원인과 해결법을 피부과 전문의 박효진이 정리합니다.', array['피부결', '광채피부', '모공', '잔주름', '솜털', '검버섯', '피부톤']::text[]),
    ('lbl50k9AjVU', 'parkhyojin', '30대 넘으면 누구나 세로 모공이 생기나요?', '네, 세로로 늘어난 모공은 30대가 넘어가면 피부 타입 상관없이 누구에게나 생깁니다. 나이가 들면 모공이라는 털구멍을 잡아주고 있던 콜라겐이 빠지면서 모공이 세로로 늘어나는 거예요. 그래서 여드름 없이 피부가 좋았던 분들도 30대 되면서 가장 많이 고민하는 게 나비존(코 주변)의 세로 모공이거든요. 피지가 들락날락하면서 늘어난 모공은 피지를 잡으면 어느 정도 해결이 되지만, 콜라겐이 빠져서 늘어난 모공은 그 콜라겐을 다시 채워줘야 합니다. 늘어난 티셔츠 목 부분이 쉽게 복구되지 않듯이, 한 번 늘어난 모공은 모공 앰플이나 홈케어로는 실제 효과를 보기 어려워요. 결국 모공은 속부터 콜라겐을 생성시켜서 해결하는 게 핵심입니다.', '30대 이후 세로 모공이 생기는 원리와 홈케어로 한계가 있는 이유를 피부과 전문의 박효진이 설명합니다.', array['모공', '세로모공', '콜라겐', '나비존', '30대', '피부노화', '피부결']::text[]),
    ('lbl50k9AjVU', 'parkhyojin', '모공 줄이는 데 써마지보다 효과 좋은 시술이 있나요?', '포텐자(미세바늘 고주파)는 모공 주변에 집중적으로 콜라겐을 생성시켜 써마지보다 눈에 띄게 모공을 줄여주는 시술입니다. 써마지는 피부 표면에서 열을 넓게 퍼뜨려 데워주는 방식이라 대형 스튜디오 조명처럼 은은하게 작용하는 반면, 포텐자는 핀 조명처럼 원하는 부위에 집중 포커싱하는 거예요. 26개의 촘촘한 바늘이 피부에 들어가 길을 열고 그 자리에 에너지를 흘려보내 콜라겐을 생성시키니까, 모공이 쪼여지는 효과가 확실하게 나타납니다. 한 번만 받아도 세로로 늘어났던 모공이 조여지고, 세안할 때 매끈한 느낌이 들고, 피부에 광이 나기 시작해요. 4주 간격으로 3번 받으면 객관적으로도 변화가 보이고, 이후에는 3개월에 한 번씩 유지하면 콜라겐이 계속 빠지는 것을 막을 수 있습니다. 피부가 얇아서 잔주름이 많은 분이든 지성 피부든 피부 두께 차별 없이 효과가 좋아요.', '써마지보다 모공 개선에 효과적인 포텐자의 원리와 시술 주기를 피부과 전문의 박효진이 안내합니다.', array['포텐자', '모공', '써마지', '콜라겐', '미세바늘고주파', '피부결', '나비존']::text[]),
    ('lbl50k9AjVU', 'parkhyojin', '포텐자 시술 많이 아프다는데 일상생활은 바로 되나요?', '포텐자는 솔직히 아프지만 시술 시간이 1~2분 이내로 매우 짧고, 다음 날 바로 화장이 가능할 정도로 회복이 빠릅니다. 바늘이 들어가는 것 자체는 크게 안 아프지만 바늘이 들어간 부분에 집중적으로 에너지가 나올 때 정말 아파요. 써마지처럼 30~40분 동안 아픈 걸 버텨야 하는 게 아니라 얼굴 한 바퀴 쫙 돌리면 끝나니까 그 순간만 꾹 참으면 됩니다. 딱지가 생기는 것도 없고, 다음 날 화장도 바로 가능해서 일상생활 복귀까지 시간이 정말 짧아요. 주기는 4주 간격으로 3번 정도 먼저 받아보고, 이후에는 분기별로 한 번씩 유지하면 빠질만 한 콜라겐을 계속 채워놓는 셈이 됩니다. 통증은 있지만 그 효과를 보면 다시 찾게 되는 시술이에요.', '포텐자 시술의 통증 수준과 빠른 일상 복귀가 가능한 이유를 피부과 전문의 박효진이 설명합니다.', array['포텐자', '통증', '다운타임', '콜라겐', '미세바늘고주파', '시술주기', '모공']::text[]),
    ('C6ETM4laIDc', 'jeonghanmi', '관상이랑 인상은 어떻게 다른 건가요?', '관상은 타고난 얼굴로 본 운명론에 가깝고, 인상은 살아온 습관과 표정으로 후천적으로 바뀌는 얼굴이에요. 관상학은 코가 크면 재물복이 있다는 식으로 타고난 형태를 보고 운명을 읽는 학문이고, 인상학은 어떤 얼굴이 어떤 성격·기질과 잘 맞는지를 통계적으로 정리한 분야입니다. 그래서 관상은 바꿀 수 없지만 인상은 후천적 노력과 시술, 표정 습관으로 충분히 바꿀 수 있어요. 인상이 좋아지면 주변에서 받는 호감과 자기 자신의 자신감까지 함께 올라가 결과적으로 사회생활에도 영향을 줍니다. 그래서 피부과 시술도 단순히 예뻐지는 데 그치지 않고 본인의 인상을 좋게 바꾸는 도구로 쓸 수 있어요. 자신의 직업·성향에 어울리는 얼굴로 다듬으면 자연스럽게 호감을 얻기가 쉬워져요. 결국 인상을 가꾼다는 건 본인을 더 좋은 방향으로 표현하는 일이에요.', '관상과 인상의 차이, 인상이 후천적으로 바뀌는 원리를 피부과 전문의 정한미가 정리합니다.', array['인상학', '관상', '인상', '호감형얼굴', '자존감', '피부과시술', '표정']::text[]),
    ('C6ETM4laIDc', 'jeonghanmi', '시술 없이도 인상을 좋게 바꾸는 방법이 있을까요?', '네, 가장 쉬운 방법은 자주 웃고 따뜻한 마음을 유지하는 거예요. 웃을 때 사용하는 중안면 근육이 발달하면 그 부위에 자연스럽게 볼륨이 생기면서 호감형 얼굴로 바뀌게 됩니다. 반대로 우울하거나 무표정으로 지내면 눈 아래가 꺼지고 입꼬리가 처지면서 슬프고 부정적인 인상이 굳어져요. 억지로라도 웃는 습관을 들이면 그 부위 근육이 발달하고, 주변에서도 좋은 인상으로 받아들여 더 좋은 반응이 돌아옵니다. 두 번째는 마음이 바뀌면 얼굴이 바뀐다는 점이에요. 너그럽고 온화한 마음을 가지면 그 감정이 표정으로 그대로 드러나 인상이 부드러워져요. 옛말에 웃으면 복이 온다는 말이 단순한 속담이 아니라 실제 근육 변화와 호감 형성으로 이어지는 과학적인 메커니즘이에요. 시술 전에 표정과 마음의 습관부터 점검해 보시길 권해드려요.', '시술 없이 표정과 마음 습관으로 인상을 바꾸는 방법을 피부과 전문의 정한미가 안내합니다.', array['인상학', '표정', '호감형얼굴', '미소', '중안면', '자존감', '생활습관']::text[]),
    ('C6ETM4laIDc', 'jeonghanmi', '광대가 두드러져서 세 보이는 얼굴은 시술로 부드럽게 만들 수 있나요?', '네, 광대 부위 근육에 보톡스를 주입해 광대를 자연스럽게 축소시키면 인상이 한결 부드러워져요. 광대는 뼈와 함께 근육이 두껍게 자리 잡고 있어서, 그 근육에 보톡스를 놓으면 시간이 지나며 근육 부피가 줄어 광대가 자연스럽게 작아지는 효과를 볼 수 있어요. 수술처럼 뼈를 깎지 않으면서도 인상의 강한 느낌을 누그러뜨릴 수 있다는 점이 큰 장점이에요. 광대가 두드러지면 능력 있어 보이지만 세 보이거나 팔자가 강해 보인다는 인상을 주기도 해서 여성분들이 특히 많이 신경 쓰시는 부위예요. 보톡스 효과는 보통 4-6개월 정도 유지되므로 주기적인 시술로 인상을 관리할 수 있어요. 광대 외에도 사각턱 보톡스, 이마 보톡스 등을 함께 쓰면 얼굴 라인 전체가 더 부드럽게 정돈돼요. 본인 얼굴형에 맞춰 신중하게 디자인하는 게 자연스러운 결과의 핵심이에요.', '광대를 부드럽게 만드는 보톡스 시술 원리와 효과를 피부과 전문의 정한미가 설명합니다.', array['광대', '보톡스', '광대축소', '사각턱', '인상학', '호감형얼굴', '얼굴라인']::text[]),
    ('C6ETM4laIDc', 'jeonghanmi', '자존감이 낮거나 대인관계가 어려운 분들에게 추천되는 시술이 있나요?', '네, 콧대가 낮은 분께는 코 필러, 눈썹이 약한 분께는 눈썹 문신처럼 인상의 핵심 부위를 보강해주는 시술을 권해드려요. 자존감이 낮은 분들 중에는 콧대가 평탄하고 낮은 경우가 많은데, 코에 필러를 채워 콧대를 살리면 얼굴 중심이 또렷해지면서 자기 표현력과 자신감이 함께 올라가는 경향이 있어요. 눈썹은 대인관계에서 인상의 첫인상을 좌우하는 부위라, 너무 흐리면 약해 보이고 표정이 잘 전달되지 않아요. 그래서 눈썹이 약한 분들께는 눈썹 문신을, 너무 진하고 거친 분들께는 정리해 주는 브로우바를 권합니다. 중년 남성은 얼굴 제모만으로도 깔끔하고 젊은 인상으로 정돈돼 비즈니스 미팅에서 호감을 얻기 좋아요. 또 얼굴빛(찰색)을 밝게 가꾸는 색소 치료, 영양 공급 시술도 인상을 환하게 바꾸는 데 도움이 돼요. 본인의 직업과 성격에 맞춰 핵심 부위 한두 가지만 살짝 다듬어도 인상이 크게 좋아질 수 있어요.', '자존감과 대인관계 향상에 도움 되는 인상 보정 시술을 피부과 전문의 정한미가 정리합니다.', array['코필러', '눈썹문신', '자존감', '인상학', '호감형얼굴', '제모', '찰색']::text[]),
    ('gJDm4FuAckM', 'parkhyojin', '마라톤 하면 얼굴이 빨리 늙는다는 게 사실인가요?', '네, 과도한 유산소 운동은 Runner''s Face라 불리는 얼굴 노화를 촉진할 수 있습니다. 마라톤 선수들의 얼굴을 보면 퀭하고 볼륨이 꺼져 있으며 축 처져 있는데, 이는 노화의 핵심인 깊은 지방 소실과 관련이 있어요. 얼굴 깊숙이 있는 깊은 지방이 빠지면 그 위의 얕은 지방이 처지면서 노화가 시작되거든요. 실제로 50~60대 중 얼굴이 통통하신 분들이 오히려 젊어 보이고, 마르고 호리호리하신 분들이 더 노안인 것도 같은 원리입니다. 거기에 운동 시간이 너무 길어지면 몸에서 활성산소가 나와서 콜라겐을 파괴하기까지 해요. 유산소 운동은 일주일에 3~4회 격일로, 한 번에 30분 정도로 가볍게 뛰는 게 피부 노화를 막으면서 건강 효과도 챙기는 적정선입니다.', '과도한 유산소 운동이 얼굴 노화를 앞당기는 Runner''s Face의 원리를 피부과 전문의 박효진이 설명합니다.', array['러너스페이스', '유산소운동', '노화', '콜라겐', '활성산소', '깊은지방', '처짐']::text[]),
    ('gJDm4FuAckM', 'parkhyojin', '운동 열심히 하는데 홍조가 안 낫는 이유가 뭔가요?', '운동 자체가 홍조와 여드름 같은 염증성 피부 질환을 악화시키는 원인이 될 수 있습니다. 운동하면 땀과 피지가 섞여서 모공을 막아 좁쌀 여드름이 생기기 쉽고, 심부 체온이 오르면서 얼굴 혈관이 확 늘어나거든요. 늘어난 혈관은 단순히 붉어 보이는 게 아니라 염증 물질들을 내보내는 통로 역할을 해서 트러블을 더 만듭니다. 기름으로 불이 난 집에 계속 물을 붓는 것과 같아서, 피부가 소강될 틈 없이 악화가 반복되는 거예요. 실제로 운동을 딱 2주만 쉬었더니 홍조가 개선된 사례도 있었습니다. 요가에서 거꾸로 자세를 하면 혈관이 쏠려서 역시 악화될 수 있고, 마스크까지 끼고 운동하면 모공을 막는 요소가 겹치니까 특히 조심하셔야 해요.', '운동이 오히려 홍조와 여드름을 악화시키는 원리와 대처법을 피부과 전문의 박효진이 안내합니다.', array['홍조', '여드름', '운동', '좁쌀여드름', '혈관확장', '염증', '피지']::text[]),
    ('gJDm4FuAckM', 'parkhyojin', '아침마다 야외 러닝하면 기미 치료에 방해가 되나요?', '네, 햇빛 아래에서 러닝하는 습관은 기미와 잡티 치료 효과를 크게 떨어뜨릴 수 있습니다. 실제로 매일 아침 러닝을 하던 환자분이 운동 시간만 저녁으로 바꿨더니 색소치료 결과가 드라마틱하게 좋아진 사례가 있었어요. 색소 치료는 단순히 멜라닌을 파괴하는 것만으로 끝나지 않고 피부 장벽이 튼튼해야 효과가 유지됩니다. 그런데 선크림을 바르고 땡볕에서 땀을 흘리면 이 장벽이 자극받아 무너지기 쉬워서, 레이저로 좋아지게 해도 밑바탕이 안 좋으니까 호전이 더딘 거예요. 특히 광대 라인이나 눈가 쪽 잡티처럼 자외선 영향을 많이 받는 부위는 더 민감합니다. 피부 관리에 신경 쓰시는 분이라면 바깥 러닝보다 실내 운동을 선택하는 게 치료 효과를 지키는 데 훨씬 유리해요.', '야외 러닝이 기미 치료를 방해하는 이유와 운동 시간 변경의 효과를 피부과 전문의 박효진이 정리합니다.', array['기미', '잡티', '러닝', '자외선', '색소치료', '피부장벽', '선크림']::text[]),
    ('gJDm4FuAckM', 'parkhyojin', '피부 노화 안 오게 운동하는 방법이 따로 있나요?', '운동은 피부에 분명히 좋지만, 과유불급이 핵심이고 짧고 굵게 하는 게 가장 이상적입니다. 운동하면 혈액이 영양분을 세포까지 배달해주고 노폐물도 회수하며, 림프 순환이 촉진되어 붓기도 빠지고 스트레스 호르몬인 코르티솔 수치도 낮아져요. 하지만 1시간 이상 넘어가는 운동은 유산소든 근력이든 피부에 좋지 않습니다. 유산소는 격일로 일주일에 3~4회, 30분 정도로 가볍게 하고 근력 운동도 과한 중량 없이 20~30분 짧게 해주는 게 좋아요. 운동 전에 피부 상태를 체크해서 트러블이 났거나 예민한 상태면 쉬고, 가벼운 산책 정도로 대체하는 것도 방법입니다. 운동이 끝났을 때 개운하다는 느낌이 먼저 들어야지, 힘들어 죽겠다고 느끼면 그날은 피부를 혹사시킨 거예요.', '피부 건강을 위한 올바른 운동 방법과 적정 시간, 주의사항을 피부과 전문의 박효진이 안내합니다.', array['운동', '피부관리', '저속노화', '유산소', '근력운동', '활성산소', '코르티솔']::text[]),
    ('rigKW7zrTeI', 'leedoyoung', '리쥬란 맞으면 진짜 아파서 운다는데 안 아프게 맞을 수 있나요?', '네, 리쥬란도 시술 방식에 따라 거의 통증 없이 맞을 수 있습니다. 리쥬란이 아픈 이유는 약물을 깊은 층에 넣으면서 엠보를 만들기 때문인데, 실제로 피부 재생이 일어나는 층은 그보다 더 얕은 층이에요. 약물을 얕은 층에 아주 작은 양으로 고르게 깔아주면 엠보도 안 생기고 통증도 거의 없으면서 효과는 동일하게 볼 수 있습니다. 이렇게 시술하면 하루 뒤에 다운타임 전혀 없이 화사해지고 광이 돌게 되죠. 리쥬란과 비타란은 연어, 송어에서 채취한 DNA 조각을 넣어 피부 재생을 유도하는 시술이라 푸석하고 예민한 피부, 속건조가 심한 분들에게 좋은 첫 걸음이 됩니다. 자극도 적고 부작용 걱정도 거의 없어서 스킨부스터 입문자분들께 추천드리는 시술이에요. 주사를 얕게 놓으면 아프지 않게 시술 받을 수 있다는 점 꼭 기억하세요.', '리쥬란 시술 통증 없이 받는 방법과 입문자 추천 이유를 피부과 전문의 이도영이 설명합니다.', array['리쥬란', '스킨부스터', '통증', '엠보', '피부재생', '속건조', '비타란']::text[]),
    ('rigKW7zrTeI', 'leedoyoung', '스컬트라랑 쥬베룩 중에 뭐가 더 효과 좋아요?', '스컬트라가 조금 더 빠르고 강하게 효과가 나타나는 편이고, 쥬베룩은 서서히 부드럽게 올라오는 타입입니다. 둘 다 옥수수 전분에서 추출한 미세한 가루를 피부 속에 넣어 섬유모세포를 자극하고 콜라겐을 새로 만들어내는 원리로, 시간이 지나면 입자는 물과 이산화탄소로 녹아 사라지고 새 콜라겐만 남게 돼요. 차이는 입자 모양에 있는데 스컬트라는 뾰족뾰족해서 자극이 빠르고 강한 채찍 같은 느낌이고, 쥬베룩은 둥글고 안이 비어있어 부드러운 몽둥이 같은 느낌이에요. 다만 두 제품 모두 결절이 생길 수 있는데, 스컬트라의 경우 초음파 분쇄로 입자를 고르게 분산시키면 결절 확률을 거의 없앨 수 있습니다. 땅콩형 얼굴처럼 옆볼이 꺼지거나 팔자주름이 깊은 분들에게 자연스러운 볼륨 회복 옵션으로 정말 좋은 선택이에요.', '스컬트라와 쥬베룩의 효과 차이와 결절 예방법을 피부과 전문의 이도영이 정리합니다.', array['스컬트라', '쥬베룩', '콜라겐', '땅콩형얼굴', '볼륨', '팔자주름', '결절']::text[]),
    ('rigKW7zrTeI', 'leedoyoung', '속건조가 심한데 스킨부스터로 보습 효과 오래 유지할 수 있나요?', '힐로웨이브라는 히알루론산 부스터를 맞으면 한 번 시술로 오랫동안 촉촉함을 유지할 수 있습니다. 힐로웨이브에는 작은 히알루론산과 큰 히알루론산이 함께 들어있는데, 시술 직후에는 작은 히알루론산이 즉각적으로 수분을 공급하고 그 효과가 사라질 즈음 큰 히알루론산이 서서히 분해되면서 새 수분을 계속 공급하는 구조예요. 마치 지갑 속 현금과 은행 예금을 동시에 가진 것처럼 즉각적인 촉촉함과 장기적인 보습을 모두 챙길 수 있습니다. 기존 히알루론산 부스터들이 효과가 금방 사라지거나 즉각적 효과가 아쉬웠던 것과 달리 꾸준하고 안정적인 촉촉함이 유지돼요. 병원에 자주 오기 힘드신 분들께 수분 연금 같은 시술이라 할 수 있습니다. 비싼 크림을 듬뿍 발라도 속건조가 해결이 안 되시는 분들에게 이상적인 선택이에요.', '속건조에 효과적인 힐로웨이브의 듀얼 보습 원리를 피부과 전문의 이도영이 안내합니다.', array['힐로웨이브', '히알루론산', '속건조', '보습', '스킨부스터', '수분']::text[]),
    ('rigKW7zrTeI', 'leedoyoung', '피부가 총체적 난국인데 어떤 스킨부스터 맞아야 해요?', '예민하고 푸석하고 속건조까지 있는 총체적 난국이라면 엘라비에 리투오가 가장 적합합니다. 리투오는 사람의 진피에서 세포를 제거하고 콜라겐, 엘라스틴, 라미닌 등 진피 구성 기질을 3차원 구조 그대로 보존한 스킨부스터예요. 콜라겐만 채우는 것과는 차원이 다르게, 건강한 진피 구조 전체를 3D 프린터로 복사해서 넣는 느낌이라고 보시면 됩니다. 시술 후 피부가 즉각적으로 탄탄해지면서 피부결과 모공이 정돈되고 쫀쫀한 질감이 생기며, 피부 장벽 기능이 회복되면서 보습력도 자연스럽게 좋아져요. 눈 밑, 손등에도 효과가 좋고 특히 패인 여드름 흉터에도 아주 잘 맞습니다. 전반적으로 피부 탄력이 떨어지신 분들이나 피부 바탕 자체를 근본적으로 개선하고 싶으신 분들께 추천드려요.', '피부 바탕 전체를 개선하는 엘라비에 리투오의 원리와 추천 대상을 피부과 전문의 이도영이 설명합니다.', array['엘라비에리투오', '콜라겐', '스킨부스터', '피부탄력', '피부결', '여드름흉터', '모공']::text[]),
    ('xLWMlI4mHlo', 'jeonghanmi', '데오도란트 바르는데도 겨땀 냄새가 나는 이유가 뭔가요?', '데오도란트는 땀 자체를 막아주는 게 아니라 냄새만 줄여주는 역할을 하기 때문입니다. 땀은 그대로 나오는 상태에서 향으로 냄새를 덮는 원리라, 땀을 많이 흘리다 보면 데오도란트 냄새와 땀 냄새가 섞여서 오히려 더 이상한 냄새가 나기도 해요. 이렇게 되면 물티슈로 닦아도 해결이 안 되고 빨리 씻는 수밖에 없습니다. 냄새가 아니라 땀 자체를 안 나게 하려면 약국에서 처방전 없이 살 수 있는 드리클로나 노스엣센스를 사용할 수 있어요. 이 제품들은 염화 알루미늄 성분이 땀 속 단백질과 만나 젤리 같은 물질을 형성해 땀샘관을 물리적으로 막아버리는 방식입니다. 바르면 진짜 땀이 안 나기 때문에 냄새도 사라지죠. 다만 사용법을 지키지 않으면 염산이 생겨 피부가 쓰라릴 수 있으니 주의가 필요해요.', '데오도란트로 겨땀 냄새가 안 잡히는 이유와 대안을 피부과 전문의 정한미가 설명합니다.', array['데오도란트', '겨땀', '땀냄새', '드리클로', '염화알루미늄', '다한증']::text[]),
    ('xLWMlI4mHlo', 'jeonghanmi', '드리클로 바르면 왜 겨드랑이가 쓰라린 건가요?', '드리클로에 들어있는 염화 알루미늄이 물을 만나면 염산으로 변하기 때문입니다. 염산은 매우 강한 산이라 피부에 닿으면 쓰라리고 따가워지는 거예요. 그래서 사용할 때는 밤에 샤워 후 겨드랑이를 드라이기로 완전히 바짝 말린 다음 바르고, 아침에 일어나서 반드시 씻어내야 합니다. 물기가 있을 때 바르거나 아침에 안 씻어내면 땀이나 수분과 만나 염산이 생기니까 엄청 쓰라려지는 거죠. 또한 겨드랑이 면도나 제모 직후에는 바로 사용하면 안 되고 2-3일 후에 써야 해요. 효과 자체는 확실해서 바르면 정말 땀이 안 나지만 이런 사용법의 번거로움이 단점입니다. 바쁜 아침에 씻어내는 과정이 불편하다면 다른 대안을 고려해보시는 것도 방법이에요.', '드리클로 사용 시 쓰라림이 생기는 원인과 올바른 사용법을 피부과 전문의 정한미가 안내합니다.', array['드리클로', '염화알루미늄', '염산', '겨땀', '다한증', '피부자극']::text[]),
    ('xLWMlI4mHlo', 'jeonghanmi', '에크락겔이 드리클로보다 좋다는데 진짜인가요?', '에크락겔은 드리클로와 작용 방식이 완전히 달라서 피부 자극이 훨씬 적으면서도 효과는 좋습니다. 드리클로가 땀샘관을 물리적으로 막는 방식이라면, 에크락겔은 땀을 만들게 하는 신호 자체를 차단해서 땀이 아예 안 만들어지게 하는 원리예요. 소프트 드러그라는 설계 방식으로 만들어져서 성분이 피부에서만 작용하고 피부 속으로 흡수되면 기능을 잃어버리도록 되어 있습니다. 그래서 다른 부위에 부작용을 일으킬 리스크가 확 줄어들죠. 사용법도 간단해서 하루에 한 번 편한 시간에 바르기만 하면 되고, 닦아낼 필요 없이 2-3분이면 마릅니다. 다만 2025년 8월 현재 국내 미출시이며 2025년 11월부터 병원 처방을 통해 사용할 수 있게 된다고 해요. 드리클로가 안 맞았던 분들에게 좋은 대안이 될 수 있습니다.', '에크락겔의 작용 원리와 드리클로 대비 장점을 피부과 전문의 정한미가 정리합니다.', array['에크락겔', '드리클로', '다한증', '겨땀', '소프트드러그', '땀억제']::text[]),
    ('xLWMlI4mHlo', 'jeonghanmi', '겨드랑이 보톡스 말고 매일 바르는 겨땀 치료제가 있나요?', '네, 기존에는 드리클로와 겨드랑이 보톡스 정도가 선택지였지만 이제 에크락겔이라는 새로운 치료제가 나왔습니다. 일본에서 개발된 다한증 치료제로, 이미 일본에서는 처방되고 있으며 발림성이 좋고 옷 이염도 없다는 평가를 받고 있어요. 하루에 한 번 바르기만 하면 되고 꼭 밤에 안 발라도 되며, 닦아낼 필요도 없어서 사용이 매우 간단합니다. 경미한 피부염이나 붉어짐이 생길 수 있지만 드리클로의 쓰라림에 비하면 훨씬 적은 편이에요. 국내에는 2025년 11월부터 사용 가능하며 전문의약품이라 병원 처방이 필요합니다. 매일 바르는 게 귀찮다면 겨드랑이 보톡스로 여름 한 시즌을 뽀송하게 보내는 방법도 있으니 본인 상황에 맞게 선택하시면 돼요.', '겨드랑이 보톡스 외 매일 바르는 신규 다한증 치료제를 피부과 전문의 정한미가 소개합니다.', array['에크락겔', '다한증', '겨땀', '보톡스', '겨드랑이', '땀치료']::text[]),
    ('MEWeY277TFc', 'jeonghanmi', '제로콜라 많이 마시면 피부에 안 좋을 수 있나요?', '네, 본인과 안 맞는 인공감미료가 들어있다면 장 건강을 해쳐서 피부에도 악영향을 줄 수 있습니다. 우리 장 속 미생물 생태계가 교란되면 장벽이 약해지고, 그 약해진 벽을 통해 나쁜 물질들이 혈관을 타고 온몸을 돌아다니며 염증을 일으키거든요. 이걸 장누수 증후군이라고 하는데, 여드름이 나거나 아토피가 심해지거나 홍조가 생기는 증상으로 이어질 수 있습니다. 놀랍게도 하루 한두 캔의 일상적인 양으로도 장내 미생물 교란이 생길 수 있다고 해요. 만약 제로 음식을 먹고 속이 더부룩하거나 가스가 자꾸 찬다면 그 제품의 감미료가 본인과 안 맞는 신호일 수 있습니다. 물론 모든 사람에게 해당되는 건 아니고 체질이나 감미료 종류에 따라 반응이 다르니 본인 몸의 신호를 잘 관찰해보시는 게 좋아요.', '제로콜라가 장과 피부에 미치는 영향과 주의할 신호를 피부과 전문의 정한미가 설명합니다.', array['제로콜라', '인공감미료', '장건강', '여드름', '아토피', '장누수', '피부트러블']::text[]),
    ('MEWeY277TFc', 'jeonghanmi', '설탕 대신 제로슈거 먹으면 피부 노화 예방에 도움 되나요?', '설탕보다는 제로슈거가 피부 노화 예방 관점에서 더 나은 선택이 될 수 있습니다. 설탕을 많이 먹으면 당이 혈관을 타고 돌아다니다가 피부 속 콜라겐과 엘라스틴에 달라붙어 딱딱하게 변성시키는데, 이걸 당독소(최종 당화산물)라고 해요. 당독소가 쌓이면 피부가 탄력을 잃고 주름이 깊어지며 색도 누렇고 칙칙하게 변합니다. 마치 달고나 만들 때 설탕이 갈색으로 끈적해지는 것처럼 피부 속에서도 같은 변화가 일어나는 거예요. 또한 당은 피지 분비를 늘려 여드름의 주범이 되기도 하죠. 제로슈거에는 설탕이 없으니 이런 당독소 생성이 줄어든다는 장점이 있습니다. 다만 가장 좋은 1순위는 물이나 차이고, 제로콜라는 어쩔 수 없이 단맛이 필요할 때 가끔 마시는 차선책 정도로 생각하세요.', '설탕이 피부 노화를 일으키는 원리와 제로슈거의 장단점을 피부과 전문의 정한미가 안내합니다.', array['제로슈거', '피부노화', '당독소', '콜라겐', '여드름', '설탕', '당화']::text[]),
    ('MEWeY277TFc', 'jeonghanmi', '제로콜라 하루에 몇 캔까지 괜찮은 건가요?', '식약처 기준 일일 섭취 허용량은 30-40캔 수준이지만, 장내 미생물 교란은 하루 한두 캔으로도 생길 수 있습니다. 일일 섭취 허용량은 독성이 나타나는 기준일 뿐이고, 장 속 미생물 균형을 흐트러뜨리는 것은 훨씬 적은 양에서도 가능하다는 거예요. 매일매일 여러 캔을 대놓고 마시는 것은 피해야 하고, 가끔 당이 너무 땡길 때 설탕 음료 대신 마시는 정도가 적절합니다. 가장 좋은 것은 물이나 몸에 좋은 차이고, 청량감이 필요하다면 탄산수에 레몬즙을 타서 마시는 것도 좋은 대안이에요. 단맛은 없지만 몸에 주는 부담은 훨씬 적죠. 제로슈거의 핵심은 설탕보다는 낫지만 만능이 아니라는 양면성을 이해하고, 본인 몸 상태를 관찰하면서 적절히 조절하는 게 중요합니다.', '제로콜라의 적정 섭취량과 더 나은 대안을 피부과 전문의 정한미가 정리합니다.', array['제로콜라', '인공감미료', '섭취량', '장건강', '탄산수', '당조절']::text[]),
    ('MEWeY277TFc', 'jeonghanmi', '같은 제로인데 어떤 건 쓴맛 나고 어떤 건 괜찮은 이유가 뭔가요?', '제로 음료마다 사용하는 인공감미료의 종류와 배합이 다르기 때문입니다. 인공감미료는 설탕이 아닌데 혀의 단맛 수용체에 나 단맛이야라고 착각 신호를 보내는 물질인데, 이 신호가 완벽하지 않아서 감각이 예민한 사람은 단맛이 아닌 쓴맛을 함께 느낄 수 있어요. 예를 들어 코카콜라 제로와 펩시 제로는 각각 다른 감미료 조합과 농도를 사용하기 때문에 한쪽에서만 쓴맛을 느끼는 경우가 실제로 있습니다. 이건 미각의 예민도에 따른 개인차여서 정상적인 반응이에요. 마찬가지로 제로 아이스크림 같은 제품을 먹고 유독 가스가 많이 차거나 속이 불편하다면 그 제품에 들어있는 특정 대체당이 본인과 안 맞는 거라고 볼 수 있습니다. 제로 제품을 고를 때는 본인에게 불편한 증상을 주는 것은 피하고 괜찮은 것을 찾아가는 게 현명한 방법이에요.', '제로 음료마다 맛과 반응이 다른 이유를 피부과 전문의 정한미가 설명합니다.', array['인공감미료', '제로콜라', '쓴맛', '대체당', '미각', '장건강']::text[]),
    ('v8XyCvkgD7w', 'leedoyoung', '얼굴은 관리하는데 손등은 나이가 보여요, 시술로 해결 가능한가요?', '네, 간단한 주사 시술만으로도 손등 나이를 10년은 되돌릴 수 있습니다. 손등 노화는 단순히 살이 빠져서가 아니라 피부 속 콜라겐, 엘라스틴, 프로테오글리칸 같은 세포 외 기질이 줄어들기 때문에 생기는 거예요. 이것들이 줄면서 피부가 얇아지고 탄력을 잃어 힘줄과 혈관이 도드라져 보이게 됩니다. 이불에 비유하면 안쪽 솜도 줄고 겉감도 낡아지는 것과 같아서, 단순 볼륨 채움이 아니라 피부 자체를 리모델링해야 자연스럽고 오래가는 효과를 볼 수 있어요. 손등 시술은 히알루론산, 인체유래 무세포 동종 진피(엘라비에 리투오), 콜라겐부스터(라풀렌, 레디어스) 이렇게 세 가지 방법이 있습니다. 얼굴만큼이나 손도 나이가 드러나는 부위이니 관심을 가져보시는 게 좋아요.', '손등 노화의 원인과 되돌릴 수 있는 시술 옵션을 피부과 전문의 이도영이 안내합니다.', array['손등노화', '콜라겐', '엘라비에리투오', '라풀렌', '레디어스', '주름', '손등시술']::text[]),
    ('v8XyCvkgD7w', 'leedoyoung', '엘라비에 리투오가 손등에 좋다는데 정확히 뭘 넣는 건가요?', '엘라비에 리투오는 사람의 실제 피부에서 세포와 면역 물질을 제거하고 콜라겐, 엘라스틴 등 3차원 구조를 그대로 남긴 조직을 주입하는 시술입니다. 쉽게 말하면 3D 프린터로 젊은 피부의 진피 성분을 그대로 복사해서 넣는 거라고 보시면 돼요. 콜라겐만 채우는 것과 달리 진피의 철근과 콘크리트를 모두 보강하는 셈이라 피부 탄력, 두께, 복원력을 한 번에 개선할 수 있습니다. 주입 후에는 진피구조 사이사이 공간에 섬유모세포들이 몰려들어 추가로 새 콜라겐과 엘라스틴을 만들어내며 재생이 계속 진행돼요. 초반 붓기가 거의 없어서 자연스러운 효과를 원하시는 분들에게 적합합니다. 실제로 시술 받으신 분들이 사람들도 만나야 하는데 붓기 부담 없이 할 수 있어서 좋다고 하세요.', '엘라비에 리투오의 원리와 손등 시술에 적합한 이유를 피부과 전문의 이도영이 설명합니다.', array['엘라비에리투오', '손등시술', '콜라겐', '엘라스틴', '진피', '피부재생']::text[]),
    ('v8XyCvkgD7w', 'leedoyoung', '라풀렌이 다른 콜라겐부스터보다 결절이 적다는 게 사실인가요?', '네, 라풀렌은 PCL 입자의 모양 덕분에 결절 가능성이 굉장히 낮습니다. 현미경으로 보면 다른 제품들은 입자 크기가 제각각이거나 모양이 불규칙한 반면, 라풀렌은 크기가 일정하고 동그란 공 모양이며 표면에 미세 구멍이 나있고 안도 비어있어요. 이런 균일한 구조 덕분에 주입할 때 부드럽게 잘 들어가고 뭉칠 가능성이 크게 줄어듭니다. 미세한 구멍들 덕에 콜라겐이 촘촘하고 균일하게 안정적으로 생성되는 효과도 있어요. 시술하면 CMC겔이 먼저 볼륨을 채워 손등이 바로 팽팽해지고, 1-2주 후부터 PCL 입자가 콜라겐 기둥을 새로 세워주는 2단계 효과가 나타납니다. PCL 입자는 역할을 다 한 뒤 물과 이산화탄소로 분해돼 사라지고, 남는 것은 내 몸이 만든 콜라겐이라 효과가 오래 지속돼요.', '라풀렌의 결절 위험이 낮은 이유와 듀얼 효과 원리를 피부과 전문의 이도영이 정리합니다.', array['라풀렌', '콜라겐부스터', '결절', 'PCL', '손등시술', '볼륨', '탄력']::text[]),
    ('v8XyCvkgD7w', 'leedoyoung', '손등 피부 나이 셀프 테스트하는 방법이 있나요?', '손등을 살짝 구부린 뒤 엄지와 검지로 살을 5초간 잡았다 놓고 원래 상태로 돌아가는 시간을 재면 됩니다. 1-2초면 아직 탱탱한 20-30대, 2-3초면 40-50대, 10초 이상이면 60대, 거의 돌아오지 않으면 70대 이상으로 볼 수 있어요. 이 테스트로 피부의 탄력 상태를 간단하게 확인할 수 있습니다. 손등 노화의 핵심은 지방뿐 아니라 콜라겐과 세포 외 기질이 함께 줄면서 피부가 얇아지고 탄력을 잃는 거예요. 그래서 히알루론산으로 즉각 볼륨을 채우거나, 엘라비에 리투오로 진피 구조를 복원하거나, 라풀렌이나 레디어스로 콜라겐 생성을 유도하는 시술을 선택할 수 있습니다. 빠른 효과를 원하면 라풀렌이나 레디어스, 자연스럽고 은은한 효과를 원하면 엘라비에 리투오가 적합해요.', '손등 피부 나이 자가진단법과 시술별 선택 기준을 피부과 전문의 이도영이 안내합니다.', array['손등노화', '피부나이', '탄력테스트', '엘라비에리투오', '라풀렌', '레디어스', '콜라겐']::text[]),
    ('0NfrVDt9kyc', 'kwonsuhyun', '울쎄라나 실리프팅으로도 효과가 없는데 안면거상술이 답일까요?', '울쎄라, 써마지, 실리프팅을 다 해도 만족스럽지 않다면 안면거상술이 마지막 종착지가 될 수 있어요. 안면거상술은 단순 피부만 당기는 게 아니라 SMAS라는 근막층을 박리하고 유지인대를 끊어 깊은 구조를 끌어올리는 시술이에요. 유지인대는 팔자주름과 마리오네트 라인을 만드는 주범인데 레이저로는 이걸 직접 풀어줄 수가 없어서 한계가 분명히 존재해요. 그래서 50대 이상으로 피부가 얇고 여분의 늘어진 피부가 많을수록 안면거상술의 드라마틱한 효과가 잘 나옵니다. 유지 기간도 5~10년 이상으로 다른 시술과 비교가 안 될 만큼 길어요. 다만 칼을 대는 수술이라 부담스럽다면 두피와 귀 앞쪽까지만 절개하는 미니거상술도 선택지가 됩니다. 미니거상은 회복이 빠르지만 효과는 풀거상보다 다소 약해요. 본인 처짐 정도와 회복 가능 기간에 맞춰 단계별로 선택하면 됩니다.', '울쎄라·실리프팅 한계와 안면거상술이 필요한 시점을 피부과 전문의 권수현이 설명합니다.', array['안면거상술', '리프팅', 'SMAS', '유지인대', '미니거상', '울쎄라', '50대']::text[]),
    ('0NfrVDt9kyc', 'kwonsuhyun', '안면거상술은 회복 기간이 얼마나 걸리고 많이 아픈가요?', '안면거상술은 생각보다 통증이 적지만 붓기 회복에는 시간이 꽤 필요한 시술이에요. 시술 다음 날 소독하러 오신 분들 대부분이 이렇게 안 아플 줄 몰랐다고 말씀하실 정도로 통증은 견딜 만한 수준입니다. 박리 범위가 넓을수록 효과가 크지만 그만큼 큰 붓기는 약 한 달, 잔붓기는 6개월 정도 이어진다고 보세요. 일상생활은 보통 3~4주 차에 충분히 가능하고 1~2주 차에는 실밥 제거 같은 과정이 있어 외출에 제약이 좀 있어요. 박리한 부위에 붓기가 다 생기는 거라 아픈 것보다 부어 있는 시간이 더 부담될 수 있어요. 미니거상술은 절개와 박리 범위가 작아 회복이 더 빠른 편입니다. 회복 기간 동안 체중이 급격히 변하면 잡아놓은 라인이 어그러질 수 있어 체중 관리는 필수예요. 평소 통증이 무서워 미루던 분들이 받고 나서 가장 많이 하는 말이 진작에 할 걸 그랬다는 후회예요.', '안면거상술의 통증 정도와 붓기·회복 기간을 피부과 전문의 권수현이 설명합니다.', array['안면거상술', '회복기간', '붓기', '통증', '미니거상', '다운타임', '리프팅']::text[]),
    ('0NfrVDt9kyc', 'kwonsuhyun', '풀거상술과 미니거상술 중 어느 쪽이 저에게 맞을까요?', '처짐이 심하고 나이가 50대 이상이면 풀거상술, 처짐이 적고 빠른 복귀가 필요하면 미니거상술이 적합해요. 풀거상술은 두피 안쪽에서 시작해 귀 앞과 뒤를 모두 돌아 절개선을 넣어 SMAS와 유지인대를 광범위하게 박리하는 방식이에요. 박리 범위가 넓은 만큼 턱선과 광대 밑 라인까지 얼굴형 자체가 바뀔 정도의 효과가 나오고 50~60대 이상에서 추천됩니다. 반면 미니거상술은 두피와 귀 앞쪽까지만 절개해 박리 범위를 좁히는 방식이라 붓기가 덜하고 일상 복귀가 빨라요. 효과는 풀거상보다 약하지만 마리오네트 주름이나 팔자주름을 줄이고 턱선을 정리하는 데는 충분합니다. 처짐이 본격적이지 않은 30~40대거나 울쎄라 효과가 부족한 분에게 좋은 선택이에요. 결국 늘어진 피부가 많을수록 풀거상의 효과가 드라마틱하니 본인 노화 정도를 정확히 평가받고 결정하세요. 무리한 선택은 오히려 부자연스러움을 만들 수 있어요.', '풀거상과 미니거상의 차이와 본인에게 맞는 선택 기준을 피부과 전문의 권수현이 정리합니다.', array['풀거상', '미니거상', '안면거상술', '리프팅', '마리오네트', '팔자주름', '턱선']::text[]),
    ('0NfrVDt9kyc', 'kwonsuhyun', '안면거상술 하고 나서 효과를 오래 유지하려면 어떻게 해야 하나요?', '안면거상술 후 효과를 오래 유지하려면 체중 관리와 보조 안티에이징 시술 두 가지가 핵심이에요. 거상술 직후부터도 노화는 쉬지 않고 진행되기 때문에 그 자리에 머물려면 노력이 계속 필요합니다. 첫째, 체중이 급격히 늘거나 빠지면 새로 잡아놓은 얼굴 라인이 흐트러져요. 그래서 시술 후에는 안정적으로 체중을 유지하는 게 가장 중요해요. 둘째, 시간이 좀 지난 뒤에는 보톡스로 표정 주름을 잡아주고 울쎄라나 써마지 같은 고주파 리프팅을 주기적으로 받아 콜라겐을 새로 만들어주세요. 우리는 노화의 강을 따라 내려가고 있어 거스를 수는 없지만 모터를 달아 천천히 내려가거나 같은 자리에 머무는 건 가능해요. 무리하지 않는 선의 얼굴 마사지도 도움이 됩니다. 한 번에 뒤집으려 하지 말고 꾸준한 관리로 5~10년 효과를 유지하는 게 가장 현명한 전략입니다.', '안면거상술 후 효과를 오래 유지하기 위한 보조 시술과 관리법을 피부과 전문의 권수현이 안내합니다.', array['안면거상술', '유지관리', '울쎄라', '써마지', '보톡스', '체중관리', '안티에이징']::text[]),
    ('LdT16AiuRLA', 'gohyerim', '발냄새가 심한데 땀만 안 나면 해결되는 건가요?', '아닙니다, 발냄새는 땀 자체가 아니라 땀과 세균이 만나면서 생기는 문제입니다. 땀은 99% 이상이 물이고 소량의 아미노산, 암모니아, 요소 같은 성분이 섞여 있는데, 이 소량 성분들이 세균의 먹이가 됩니다. 발에는 땀샘이 25만 개 이상 있어서 다른 부위보다 땀이 많이 날 수밖에 없는 구조이고, 통풍이 안 되는 신발 속에서 세균이 증식하기 좋은 온도와 습도가 형성됩니다. 세균이 땀에 젖은 각질을 분해하면서 이소발레르산이라는 시큼한 냄새의 원인 물질을 만들어내고, 여기에 다른 휘발성 화합물까지 합쳐져 특유의 자극적인 냄새가 나게 됩니다. 결국 발냄새의 핵심 원인은 땀, 각질, 세균 이 세 가지가 결합된 결과이므로 땀만 줄인다고 해결되지 않습니다. 통풍이 잘 되는 신발을 신고 발을 건조하게 유지하며 각질 관리를 병행하는 것이 효과적입니다.', '발냄새의 진짜 원인이 땀이 아닌 세균과 각질의 결합임을 피부과 전문의 고혜림이 설명합니다.', array['발냄새', '땀샘', '세균', '각질', '이소발레르산', '통풍', '여름철관리']::text[]),
    ('LdT16AiuRLA', 'gohyerim', '발냄새 줄이려면 매일 뭘 어떻게 관리해야 하나요?', '가장 중요한 건 발을 씻은 후 완전히 건조시키는 것입니다. 대부분 씻는 건 잘하는데 젖은 채로 두는 게 문제이고, 특히 발가락 사이에 물기가 남으면 곰팡이가 번식하기 쉽습니다. 수건으로 꼼꼼히 닦은 뒤 드라이기로 한 번 더 말리면 완벽하고요. 양말은 땀 흡수가 잘 되고 빨리 마르는 재질로 골라 매일 갈아 신되, 땀이 많은 분들은 2-3켤레를 갖고 다니며 젖으면 바로 갈아 신으세요. 신발은 메쉬 소재 운동화나 천연 가죽처럼 통풍이 잘 되는 제품을 택하고 같은 신발을 연속으로 신지 않는 것이 좋습니다. 일주일에 한 번 정도 AHA나 BHA, 우레아 성분이 든 발 전용 각질 제거제로 관리해주면 세균의 먹이인 각질이 줄어 냄새도 함께 줄어들 수 있어요. 단, 과하게 각질을 제거하면 오히려 자극이 되니 부드럽게 해주시고 각질 제거 후에는 보습도 꼭 챙기셔야 합니다.', '발냄새를 줄이는 건조·양말·각질 관리 실전 팁을 피부과 전문의 고혜림이 안내합니다.', array['발냄새', '각질제거', '양말', '통풍', 'AHA', 'BHA', '우레아', '발관리']::text[]),
    ('LdT16AiuRLA', 'gohyerim', '발냄새가 계속 안 없어지면 무좀인 건가요?', '관리를 해도 냄새가 계속되면 무좀이나 다른 질환을 의심해 볼 수 있습니다. 무좀은 곰팡이 감염인데, 안 씻어서 걸리는 게 아니라 수영장이나 목욕탕처럼 맨발로 다니는 곳에서 쉽게 옮을 수 있고, 가족 간에 발매트나 슬리퍼를 공유하며 감염되기도 합니다. 정확히 말하면 곰팡이 자체가 심한 냄새를 유발하진 않지만, 무좀이 잘 생기는 축축한 발가락 사이 환경이 세균 번식에도 좋아서 냄새가 심해지는 거예요. 무좀은 항진균제 연고를 바르되 증상이 좋아진 후에도 최소 2주는 더 도포해야 재발을 줄일 수 있습니다. 한편, 발바닥 압력 받는 부위에 1-3mm 크기의 작은 구멍이 여러 개 생기면서 냄새가 유독 심하다면 오목융해각화증이라는 세균성 질환일 수 있어요. 이건 무좀과 치료가 완전히 다르므로 반드시 병원에서 정확한 진단을 받으셔야 합니다.', '발냄새가 안 사라질 때 의심할 무좀과 오목융해각화증의 차이를 피부과 전문의 고혜림이 정리합니다.', array['무좀', '발냄새', '항진균제', '곰팡이', '오목융해각화증', '발가락', '감염']::text[]),
    ('LdT16AiuRLA', 'gohyerim', '무좀에 잘 걸리는 발 모양이 따로 있다는데 사실인가요?', '네, 발가락 사이가 좁아져 습기가 차고 통풍이 안 되는 구조의 발이 무좀에 더 취약합니다. 첫째, 선천적으로 발가락 사이 간격이 좁은 발은 그 자체로 습기가 차기 쉽습니다. 둘째, 발볼이 넓은 사람이 앞이 좁아지는 구두를 신으면 발가락이 강제로 모여 통풍을 막는 직접적 원인이 됩니다. 셋째, 무지외반증(엄지발가락이 새끼 방향으로 휘는 증상)이 있으면 엄지가 다른 발가락을 밀어내면서 전체적으로 빽빽하게 밀집되어 무좀 위험이 올라갑니다. 넷째, 평발인 경우 발바닥 아치가 무너지면서 지면과 닿는 면적이 넓어지고, 열이 빠져나가기 어려워 땀이 더 많이 찰 수 있습니다. 이런 발 구조를 가졌다면 통풍이 좋은 신발 선택과 발가락 사이 건조에 더 신경을 쓰셔야 무좀을 예방할 수 있어요.', '무좀에 취약한 네 가지 발 구조와 예방법을 피부과 전문의 고혜림이 설명합니다.', array['무좀', '발모양', '무지외반증', '평발', '발가락', '통풍', '예방']::text[]),
    ('ODzUPhN_dL0', 'jeonghanmi', '선크림 말고 피부 노화 막는 데 진짜 효과 있는 성분이 뭔가요?', '레티노이드 계열(레티놀, 레티날 등)이 광노화를 되돌려주는 효과가 과학적으로 입증된 유일한 성분입니다. 선크림이 자외선을 차단해 노화를 예방하는 역할이라면, 레티노이드는 이미 진행된 광노화를 개선해주는 역할을 해요. 그래서 선크림에 더해 레티노이드만 꾸준히 발라도 피부 상위 10%는 유지할 수 있다고 봅니다. 다만 자극감이 있어서 피부에 따라 안 맞는 분이 있을 수 있고, 적응 기간을 거쳐야 대부분 괜찮아집니다. 처음 사용할 때는 소량부터 시작해서 피부 반응을 보며 늘려가시는 게 좋습니다. 비타민C(CE페룰릭)를 함께 사용하면 자외선 손상을 빠르게 복구시키는 전략도 효과적이에요. 결국 선크림으로 예방하고, 레티노이드로 회복하는 이중 전략이 노화를 늦추는 가장 확실한 홈케어 방법입니다.', '광노화를 되돌리는 레티노이드의 효과와 사용법을 피부과 전문의 정한미가 안내합니다.', array['레티놀', '레티노이드', '광노화', '선크림', '비타민C', '홈케어', '노화예방']::text[]),
    ('ODzUPhN_dL0', 'leedoyoung', '피부과에서 고주파 시술을 그렇게 추천하는 이유가 뭔가요?', '고주파 시술(써마지, 세르프, 덴서티, 텐써마 등)은 나쁠 게 하나도 없는 일종의 피부 적금 같은 시술입니다. 필러처럼 볼륨을 채우는 게 아니라 피부 자체의 콜라겐을 자극해 탄탄하게 만들어주기 때문에 과해질 위험이 적어요. 특히 피부가 얇고 주름이 잘 생기는 분에게는 필수적인 시술이라고 할 수 있습니다. 리프팅도 뭔가 볼륨이 있어야 끌어올릴 수 있지, 피부가 너무 자글거리면 먼저 깔아줘야 하거든요. 고주파를 한 달에 한 번 혹은 몇 달에 한 번씩 꾸준히 받는 것만으로도 동년배 대비 훨씬 젊은 피부를 유지할 수 있습니다. 크게 욕심내지 않고 보험처럼 꾸준히 관리하는 것이 우아하게 나이 드는 핵심이에요. 한 방에 역전하려고 과하게 하면 오히려 부자연스러워질 수 있으니 절제가 중요합니다.', '고주파 시술이 피부 노화 예방에 적금 같은 역할을 하는 이유를 피부과 전문의 이도영이 설명합니다.', array['써마지', '고주파', '리프팅', '콜라겐', '세르프', '텐써마', '노화관리']::text[]),
    ('ODzUPhN_dL0', 'jeonghanmi', '시술을 과하게 받으면 오히려 이상해진다는데 적정선이 어딘가요?', '핵심은 채우는 시술을 욕심내지 않고, 피부 퀄리티를 높이는 시술 위주로 꾸준히 가는 것입니다. 필러를 과하게 넣으면 표정이 어색해지고 부자연스러운 인상이 되기 쉬워요. 실제로 헐리우드 배우 멕 라이언처럼 지방이든 필러든 너무 많이 넣어서 원래 모습을 잃어버린 사례가 대표적입니다. 반대로 볼륨이 필요하다면 필러보다는 스컬트라처럼 서서히 자연스럽게 올라오는 시술이 안전하고요. 거기에 고주파로 피부를 탄탄하게 유지하고, 레디어스 같은 스킨부스터로 피부결을 개선하는 정도면 충분합니다. 한국 50-60대 배우들이 자연스럽게 관리된 모습을 보여주듯, 꾸준함과 절제가 핵심이에요. 한 번에 뒤집으려 하지 말고 노화의 강에서 천천히 내려가거나 그 자리를 유지하는 것만으로도 성공이라고 보시면 됩니다.', '시술 과잉 없이 자연스럽게 나이 드는 적정 관리 전략을 피부과 전문의 정한미가 정리합니다.', array['필러', '스컬트라', '스킨부스터', '레디어스', '과잉시술', '자연스러운노화']::text[]),
    ('ODzUPhN_dL0', 'leedoyoung', '먹는 콜라겐이 진짜 얼굴 피부에 효과가 있나요?', '피부과 의사 입장에서는 내 돈 주고 사 먹진 않을 정도의 효과라고 봅니다. 도움이 된다는 논문이 있긴 하지만 그렇지 않다는 연구도 있어서 확신하기 어려운 상태예요. 콜라겐도 결국 단백질이라서 먹으면 소화 과정에서 쪼개지는데, 이게 다시 피부 콜라겐을 증가시킨다는 건 도가니를 먹으면 관절이 좋아진다는 논리와 비슷합니다. 무조건 효과가 없다고 단정할 수는 없지만, 적극적으로 추천할 만한 근거도 부족한 게 현실이에요. 누가 선물로 주면 버리지 않고 먹을 정도, 요즘 제품들은 맛있게 나오니까 간식 삼아 먹는 정도로 생각하시면 됩니다. 피부 콜라겐을 늘리고 싶다면 먹는 것보다는 직접 피부에 넣어주는 스킨부스터나 고주파로 콜라겐 생성을 자극하는 시술이 훨씬 확실합니다.', '먹는 콜라겐의 실제 효과에 대한 피부과 의사의 솔직한 견해를 피부과 전문의 이도영이 전합니다.', array['콜라겐', '먹는콜라겐', '스킨부스터', '고주파', '단백질', '피부탄력']::text[]),
    ('gZZLVoYeuk0', 'parkhyojin', '도미나 크림이 기미에 좋다는데 아무나 써도 괜찮은 건가요?', '아닙니다, 도미나 크림은 하이드로퀴논 4%가 들어간 강력한 기미 크림이라 피부가 예민한 분에게는 오히려 독이 될 수 있습니다. 하이드로퀴논은 멜라닌 생성 자체를 억제하는 효과가 매우 강력해서 빠르게 효과가 나타나지만, 그만큼 작열감이나 홍조 같은 자극 반응도 심하게 나타납니다. 예민한 피부에 이 크림을 쓰면 피부 장벽이 무너지면서 오히려 색소가 더 진해지는 경우가 많아요. 이런 분들은 도미나 대신 도미나스 크림(유비퀴논 성분)을 아침저녁으로 쓰거나, 하이드로퀴논 2%인 멜라토닝 크림을 격일로 희석해서 테스트하며 사용하는 게 안전합니다. 또한 하이드로퀴논은 반드시 저녁에만 발라야 하고, 아침에 세안을 꼼꼼히 해야 해요. 성분이 남은 채로 자외선을 받으면 광독성 반응을 일으켜 피부가 더 나빠질 수 있기 때문입니다.', '도미나 크림의 올바른 사용법과 예민한 피부의 대안을 피부과 전문의 박효진이 안내합니다.', array['도미나크림', '하이드로퀴논', '기미', '도미나스', '멜라토닝', '예민한피부', '광독성']::text[]),
    ('gZZLVoYeuk0', 'parkhyojin', '기미 화장품 여러 개 쓰고 있는데 왜 안 좋아지는 걸까요?', '고기능성 제품을 너무 많이 쓰면 과유불급으로 오히려 피부에 자극이 되기 때문입니다. 비타민C, 레티날, 나이아신아마이드 모두 좋은 성분이지만 한꺼번에 쓰면 피부 부담이 커지고, 특히 비타민C와 레티날을 같은 시간대에 사용하면 과도한 자극을 줄 수 있어요. 비타민C는 pH가 낮은 환경에서 활성화되고, EGF 같은 재생 성분은 중성 pH에서 작동하기 때문에 함께 쓰면 서로 효과를 방해합니다. 가장 흔한 실수는 보습제 없이 기능성 제품만 쓰는 건데, 세라마이드와 콜레스테롤 지질이 든 보습제가 없으면 아무리 좋은 성분을 발라도 무의미합니다. 정리하자면 비타민C는 아침에, 레티날은 저녁에 쓰고, 나이아신아마이드는 아침저녁 모두 가능하며, 보습제는 반드시 아침저녁으로 추가하세요. 각질 정리 패드와 레티날은 같은 날 함께 쓰면 자극이 배가 되니 분리해서 사용하셔야 합니다.', '기미 화장품의 올바른 조합과 사용 순서를 피부과 전문의 박효진이 정리합니다.', array['비타민C', '레티날', '나이아신아마이드', '보습제', '기미', '화장품순서', '피부장벽']::text[]),
    ('gZZLVoYeuk0', 'parkhyojin', '올리브영에서 기미 잡티 화장품 고를 때 뭘 확인해야 하나요?', '핵심 성분 네 가지를 확인하시면 됩니다: 나이아신아마이드, 비타민C, 하이드로퀴논, 레티날입니다. 나이아신아마이드는 미백뿐 아니라 항염증, 모공 관리, 피지 조절까지 두루 도움이 되고 피부 타입과 관계없이 무난하게 쓸 수 있어요. 비타민C는 항산화의 여왕으로 톤을 화사하게 만들어줍니다. 빠르게 기미를 없애고 싶은 분은 하이드로퀴논 제품을 약국에서 구매할 수 있는데, 피부가 튼튼한 분에게만 추천드립니다. 레티날은 묵은 색소를 탈락시켜 미백 효과를 내는 성분이에요. 본인 피부가 예민하면 순한 나이아신아마이드 위주로, 튼튼하면 하이드로퀴논까지 사용할 수 있습니다. 제형도 중요한데, 고농축 효과를 원하면 앰플이나 세럼을, 특정 부위를 집중 공략하고 싶으면 크림 타입을 면봉으로 콕콕 찍어 바르시는 게 좋습니다.', '기미 잡티 화장품을 고를 때 확인할 핵심 성분 네 가지를 피부과 전문의 박효진이 안내합니다.', array['나이아신아마이드', '비타민C', '하이드로퀴논', '레티날', '기미', '미백', '올리브영']::text[]),
    ('gZZLVoYeuk0', 'parkhyojin', '기미 관리 열심히 하는데 보습제를 안 쓰면 정말 소용없나요?', '네, 보습제 없이 기능성 화장품만 쓰는 건 사실상 무의미합니다. 어떤 피부 타입이든 세라마이드, 콜레스테롤 지질이 포함된 피부 장벽 보충 보습제는 필수이고, 이게 없으면 아무리 비싼 미백 성분을 발라도 밑바탕이 무너진 상태라 효과를 제대로 볼 수 없어요. 피부가 얇고 예민하고 잔주름이 있다면 더더욱 보습이 탄탄해야 기능성 성분들이 자극 없이 흡수될 수 있습니다. 보습제는 아침저녁 모두 빠지면 안 되고, 레티날처럼 자극이 있는 성분을 쓸 때는 보습제를 먼저 바르고 그 위에 올리는 샌드위치 방법도 효과적이에요. 제로이드, 아토베리어, 인트린직, 셀퓨전씨 같은 MD 제품처럼 지질 성분이 충분히 들어있는 제품을 선택하시면 됩니다. 기미를 공략하면서 동시에 피부 밑바탕을 튼튼히 하는 게 장기적으로 색소 관리에 훨씬 효과적입니다.', '기미 관리에 보습제가 필수인 이유와 추천 제품 기준을 피부과 전문의 박효진이 설명합니다.', array['보습제', '세라마이드', '피부장벽', '기미', '콜레스테롤지질', '제로이드', '아토베리어']::text[]),
    ('0PG6XihYA1A', 'kwonsuhyun', '화상 입었을 때 집에서 가장 먼저 뭘 해야 하나요?', '가장 먼저 시원하게 흐르는 물에 10분에서 15분 정도 화상 부위를 대고 있어야 합니다. 아이가 뜨거운 물에 데이거나 고데기에 화상을 입었을 때 당황해서 뭔가를 해주려고 하는 경우가 많은데, 오히려 그것 때문에 문제가 생기는 경우가 꽤 많습니다. 물집을 바늘로 터뜨리거나 반창고를 덕지덕지 붙이는 것은 절대 하면 안 됩니다. 화상 부위가 충분히 식은 후에 옷이 닿아있다면 벗기는 게 좋은데, 바로 벗기지 않으면 옷이 피부에 들러붙어 흉터가 더 커질 수 있어요. 쿨링이 끝나면 감염을 막기 위한 항생제 연고를 발라야 하는데, 실마진이 가장 좋지만 집에 없다면 후시딘이나 바스포 같은 항생제 연고를 바르셔도 충분합니다. 물집이 잡혔다면 집에서 처리하지 말고 바로 병원에 가시는 게 가장 안전합니다.', '화상 직후 올바른 응급처치 순서와 주의사항을 피부과 전문의 권수현이 안내합니다.', array['화상', '응급처치', '물집', '후시딘', '항생제연고', '실마진', '쿨링']::text[]),
    ('0PG6XihYA1A', 'kwonsuhyun', '후시딘이랑 마데카솔 아무거나 바르면 되는 건가요?', '아닙니다, 후시딘과 마데카솔은 완전히 다른 연고이므로 상황에 맞게 써야 합니다. 후시딘은 항생제 연고로 세균 감염을 막는 용도이고, 마데카솔은 재생 연고(새살 연고)로 새로운 피부가 잘 돋아나게 도와주는 역할입니다. 화상 초기에는 감염 예방이 우선이므로 후시딘을 먼저 사용하고, 감염 위험이 어느 정도 줄어든 후에 마데카솔로 바꿔서 새살이 잘 돋도록 하는 순서가 맞습니다. 연고를 바른 후에는 드레싱 재료로 화상 부위를 보호해야 하는데, 보습 환경을 충분히 만들어주는 게 중요합니다. 진물이 적을 때는 듀오덤을 쓸 수 있고, 진물이 많은 경우에는 메디폼 같은 폼 재제가 습윤 환경을 더 잘 유지해줘서 효과적이에요. 드레싱 없이 상처가 외부에 노출되면 감염 위험이 높아지므로 연고를 듬뿍 바르고 반드시 덮어주셔야 합니다.', '후시딘과 마데카솔의 차이와 올바른 사용 순서를 피부과 전문의 권수현이 설명합니다.', array['후시딘', '마데카솔', '항생제연고', '재생연고', '듀오덤', '메디폼', '드레싱']::text[]),
    ('0PG6XihYA1A', 'kwonsuhyun', '화상 입었을 때 언제 병원에 가야 하는 건가요?', '물집이 생겼다면 일단 병원에 가시는 게 가장 안전합니다. 화상은 단계별로 나뉘는데, 햇빛에 피부가 빨갛게 익는 정도의 1도 화상은 집에서 관리가 가능합니다. 물집이 작게 생긴 얕은 2도 화상도 가정에서 처리할 수 있지만, 화상 부위가 핑크색이 아니고 하얗게 보인다면 깊은 2도 이상이므로 반드시 병원에 가셔야 합니다. 특히 손으로 눌러도 아무 느낌이 없는 경우는 3도 화상으로 지방층까지 손상된 것이라 오히려 안 아픈 게 더 위험한 신호예요. 얼굴이나 손, 관절 부위의 화상은 흉터 구축으로 관절 움직임이 제한될 수 있어 작은 화상이라도 병원 치료가 필요합니다. 아이나 고령 어르신은 피부가 약하고 면역력이 떨어져 있어 작은 화상도 감염으로 번질 수 있으니 꼭 진료를 받으시는 게 좋습니다.', '화상 단계별 병원 방문 기준과 위험 신호를 피부과 전문의 권수현이 정리합니다.', array['화상', '물집', '2도화상', '3도화상', '흉터구축', '병원', '응급처치']::text[]),
    ('0PG6XihYA1A', 'kwonsuhyun', '화상 흉터가 남았는데 언제부터 어떻게 관리해야 하나요?', '상처 겉피부가 어느 정도 아물었을 때부터 흉터 연고와 흉터 실리콘 시트로 관리를 시작하면 됩니다. 진물이 나거나 연고를 계속 발라야 하는 단계에서는 흉터 관리를 할 수 없고, 바깥 피부가 다 나은 후에 시작해야 합니다. 흉터 연고(메피폼 등)를 바르거나 실리콘 시트(시카케어 등)를 붙여서 흉터를 최소화하는 노력이 첫 단계예요. 상처가 아물고 3-4주 이후부터는 레이저 치료도 받을 수 있는데, 붉은기가 남았다면 브이빔 같은 혈관 레이저가, 거뭇한 착색이 남았다면 토닝 레이저가, 표면이 울퉁불퉁하다면 프렉셔널 레이저가 도움이 됩니다. 상처가 성숙되는 데는 보통 6개월에서 1년이 걸리므로, 이 기간 동안 레이저와 연고를 병행하며 꾸준히 관리하셔야 합니다. 이 6개월에서 1년간의 관리가 평생 흉터를 적게 남기는 첫걸음이라고 할 수 있어요.', '화상 흉터의 단계별 관리법과 레이저 치료 시기를 피부과 전문의 권수현이 안내합니다.', array['화상흉터', '흉터연고', '실리콘시트', '브이빔', '토닝레이저', '프렉셔널', '흉터관리']::text[]),
    ('5zlNOjoOnb8', 'jeonghanmi', '달달한 음료가 피부를 망친다는데 과일 주스도 안 되나요?', '네, 카페에서 파는 생과일 주스도 시럽을 많이 넣기 때문에 피부에는 좋지 않습니다. 당이 많은 음료를 계속 마시면 혈관을 타고 도는 당이 피부를 탱탱하게 만드는 콜라겐과 엘라스틴에 달라붙어서 이 단백질들을 딱딱하게 변성시킵니다. 그러면 원래 부드럽고 탄력 있어야 할 피부가 단단해지면서 주름이 생기고, 푸석푸석해지고, 색깔도 누렇게 변하게 돼요. 탄력이 떨어지고 칙칙한 피부가 되는 핵심 원인 중 하나가 바로 이 당화 반응입니다. 대안으로는 야채를 갈아 만든 스무디를 추천드리는데, 적채, 토마토, 브로콜리, 아보카도, 블루베리에 레몬즙과 대체당(알룰로스)을 약간 넣으면 맛있게 마실 수 있어요. 이걸 1년 정도 꾸준히 마시면 얼굴이 맑아지는 변화를 느낄 수 있고, 아침 포만감도 있어서 편의점 달달한 커피를 대체하기에 좋습니다.', '달달한 음료가 피부 콜라겐을 망치는 원리와 대안 음료를 피부과 전문의 정한미가 설명합니다.', array['당화반응', '콜라겐', '엘라스틴', '스무디', '피부노화', '주름', '당분']::text[]),
    ('5zlNOjoOnb8', 'jeonghanmi', '클렌징 티슈가 편한데 매일 쓰면 진짜 안 좋은 건가요?', '피부가 민감하거나 건조한 분이라면 클렌징 티슈는 매일 쓰시면 안 됩니다. 티슈로 메이크업을 닦아내려면 어느 정도 힘을 줘야 하는데, 그 마찰 때문에 닦고 나면 피부가 부분적으로 빨개져 있는 경우가 많아요. 어쩌다 한두 번은 괜찮지만 매일 365일 반복되면 피부 장벽을 무너뜨리는 주범이 됩니다. 장벽이 무너지면 트러블, 기미, 건조함, 홍조까지 연쇄적으로 생길 수 있어요. 올바른 클렌징은 클렌징 밀크나 오일을 피부에 얹어 손가락으로 부드럽게 문질러 메이크업을 녹인 뒤, 물을 살짝 묻혀 유화시키고 미온수로 헹군 후 약산성 폼 클렌저로 이중 세안하는 방식입니다. 다만 피부가 두껍고 지성이어서 아무리 문질러도 빨개지지 않는 분은 써도 괜찮으니, 본인 피부 타입에 맞게 판단하시면 됩니다.', '클렌징 티슈의 마찰 위험과 올바른 클렌징 순서를 피부과 전문의 정한미가 안내합니다.', array['클렌징티슈', '클렌징', '피부장벽', '마찰', '이중세안', '클렌징오일', '민감피부']::text[]),
    ('5zlNOjoOnb8', 'jeonghanmi', '기초화장품 여러 개 바르는 게 왜 오히려 안 좋은 건가요?', '피부가 흡수할 수 있는 양은 무한대가 아니기 때문에 5개 이상 바르면 오히려 문제가 생깁니다. 흡수되지 못한 성분들이 피부 겉에서 때처럼 밀리거나 메이크업이 뜨고 무너지는 원인이 되고, 더 심하면 남은 성분들이 피지와 엉겨붙어 모공을 막으면서 여드름을 유발할 수 있어요. 피부 관리를 열심히 하는데 왜 자꾸 트러블이 나지 하는 분들은 화장품을 줄이는 것 자체가 해결책일 수 있습니다. 또한 화장품 하나에 보통 20-30개 성분이 들어있는데, 여러 개를 바르면 그만큼 피부에 접하는 성분 수가 많아져 안 맞는 성분을 만날 확률도 높아지고 민감성 피부로 변할 수 있어요. 선택과 집중이 중요한데, 본인 피부 상태에 필요한 핵심 성분 하나를 골라 세럼과 가벼운 크림 정도만 쓰면 충분합니다. 많이 바른다고 좋은 게 절대 아닙니다.', '기초화장품을 5개 이상 바르면 안 되는 세 가지 이유를 피부과 전문의 정한미가 정리합니다.', array['화장품다이어트', '기초화장', '여드름', '피부장벽', '모공', '민감피부', '화장품성분']::text[]),
    ('5zlNOjoOnb8', 'jeonghanmi', '얼굴 관리만 하고 목이랑 손은 안 해도 괜찮은 건가요?', '아닙니다, 목과 손이 피부 나이를 가장 정직하게 보여주는 부위라서 반드시 함께 관리해야 합니다. 얼굴에만 신경 쓰고 목과 손은 방치하면 나이가 들었을 때 목에 자글자글 주름이 생기고 손등에 검버섯이나 잡티가 나타나게 돼요. 목과 손도 사계절 내내 자외선에 노출되는데 피부까지 얇아서 관리하지 않으면 노화가 빠르게 진행됩니다. 방법은 아주 간단한데, 얼굴에 뭔가를 바를 때 목과 손에도 똑같이 발라주면 끝이에요. 토너, 에센스, 선크림 무엇이든 얼굴에 바를 때 3개 세트로 바른다고 생각하시면 됩니다. 돈이 추가로 드는 게 아니라 지금 쓰는 제품을 조금 더 넓게 바르는 것뿐이에요. 이것만 꾸준히 해도 5년, 10년 뒤에 동년배보다 훨씬 젊어 보일 수 있으니 오늘부터 바로 시작하시길 추천드립니다.', '목과 손까지 함께 관리해야 하는 이유와 간단한 실천법을 피부과 전문의 정한미가 안내합니다.', array['목주름', '손등관리', '선크림', '자외선', '검버섯', '노화예방', '피부관리']::text[]),
    ('rE_PXlqT-Qo', 'jeonghanmi', '보톡스 맞아도 안 펴지는 깊은 주름은 어떻게 해야 하나요?', '보톡스로 펴지지 않는 깊은 주름에는 쥬브젠 시술이 가장 효과적입니다. 주름이 오래되면 종이를 반복해서 접었다 펼 때 자국이 남는 것처럼, 보톡스를 아무리 맞아도 이미 패인 선은 해결되지 않거든요. 쥬브젠은 일반 필러와 달리 히알루론산을 소량씩 촘촘하게 넣으면서 이산화탄소 가스도 함께 주입합니다. 이 이산화탄소가 피부 속에서 콜라겐 생성을 유도하기 때문에 단순히 채우는 것 이상의 효과를 냅니다. 1-2개월이 지나면 일반 필러만 넣었을 때보다 훨씬 단단하게 주름 부위가 채워지는 걸 느끼실 수 있어요. 필러의 절반도 안 되는 양으로도 충분히 좋은 결과가 나오고, 한두 번 시술만으로도 드라마틱하게 개선되는 게 큰 장점입니다. 팔자주름, 이마, 미간처럼 보톡스가 안 통하는 부위에 특히 추천드립니다.', '보톡스로 안 펴지는 깊은 주름에 쥬브젠이 효과적인 이유를 피부과 전문의 정한미가 설명합니다.', array['쥬브젠', '보톡스', '팔자주름', '깊은주름', '히알루론산', '콜라겐', '이마주름']::text[]),
    ('rE_PXlqT-Qo', 'jeonghanmi', '이마·팔자 주름에 쥬브젠이 일반 필러랑 뭐가 다른 거예요?', '쥬브젠은 히알루론산에 이산화탄소 가스를 함께 넣어 콜라겐 재생까지 유도하는 점이 일반 필러와 근본적으로 다릅니다. 일반 필러는 많은 양을 한꺼번에 주입해서 볼록 튀어나오거나 웃을 때 어색한 느낌이 생길 수 있어요. 반면 쥬브젠은 소량의 히알루론산을 미세하게 촘촘히 넣어주기 때문에 이런 부자연스러움이 없습니다. 게다가 이산화탄소 가스가 새살이 돋게 하는 효과를 줘서, 시간이 지날수록 내 콜라겐으로 단단하게 차오르게 됩니다. 일반 필러 대비 절반도 안 되는 양으로 훨씬 자연스럽고 단단한 결과를 얻을 수 있어요. 한 번만 해도 드라마틱한 변화가 나타나서, 여러 병원에서 프락셀 등을 받아본 환자도 이게 제일 좋다고 말할 정도입니다. 채움과 재생을 동시에 원하신다면 쥬브젠을 고려해보세요.', '쥬브젠과 일반 필러의 차이점과 콜라겐 재생 원리를 피부과 전문의 정한미가 안내합니다.', array['쥬브젠', '필러', '히알루론산', '콜라겐', '이산화탄소', '주름치료', '피부재생']::text[]),
    ('rE_PXlqT-Qo', 'gohyerim', '쥬브젠 시술 후 부작용이나 다운타임은 어떤가요?', '쥬브젠 시술 후에는 붉은 자국과 약간의 울퉁불퉁함이 생길 수 있지만, 시간이 지나면 자연스럽게 사라집니다. 피부가 얇은 여자분은 붉은 자국이 1-2주, 오래가면 한 달 정도 갈 수 있고 두꺼운 남자분은 티가 덜 납니다. 채워진 부위가 처음에 약간 울퉁불퉁하게 느껴지지만, 내 콜라겐이 생성되면서 저절로 부드러워지고 자연스러워집니다. 통증의 경우 마취 연고를 충분히 바르면 할 만하다는 반응이 대부분이고, 보톡스 맞는 것과 비슷한 따끔따끔한 정도라고 표현하시는 분도 계세요. 흉터 치료 레이저에 비하면 훨씬 편하다는 게 공통된 피드백입니다. 사람에 따라 울퉁불퉁함이 한두 달 정도 남을 수 있다는 게 단점이긴 하지만, 점점 좋아지므로 크게 걱정하지 않으셔도 됩니다.', '쥬브젠 시술 후 부작용과 다운타임 기간을 피부과 전문의 고혜림이 정리합니다.', array['쥬브젠', '부작용', '다운타임', '붉은자국', '콜라겐', '통증', '마취연고']::text[]),
    ('rE_PXlqT-Qo', 'jeonghanmi', '쥬브젠 하고 나면 보톡스는 안 맞아도 되나요?', '아니요, 쥬브젠을 했더라도 보톡스는 꼭 함께 맞으셔야 합니다. 두 시술은 역할이 완전히 다르기 때문이에요. 쥬브젠은 이미 깊게 패인 골짜기를 메워주는 역할을 하고, 보톡스는 얼굴 근육이 계속 움직이면서 다시 새로운 골짜기를 만드는 것을 막아주는 예방 역할입니다. 쥬브젠으로 주름을 채웠더라도 보톡스를 안 맞으면 근육이 반복적으로 수축하면서 또 다른 주름이 생길 수 있어요. 두 가지를 같이 해주셔야 주름 없는 최상의 상태를 오래 유지할 수 있습니다. 쥬브젠은 치료, 보톡스는 예방이라고 기억하시면 됩니다. 눈가, 입 주변, 마리오네트 주름 등 다양한 부위에도 같은 원리로 병행하시면 좋습니다.', '쥬브젠과 보톡스를 병행해야 하는 이유를 피부과 전문의 정한미가 설명합니다.', array['쥬브젠', '보톡스', '주름예방', '깊은주름', '미간주름', '마리오네트', '콜라겐']::text[]),
    ('iohyYCMzbdk', 'parkhyojin', '뭘 발라도 속이 당기고 건조한데 수분크림만으로 해결 안 되나요?', '겉에 수분만 발라서는 속건조를 해결할 수 없습니다. 건포도에 분무기로 물을 뿌린다고 탱탱한 포도가 되지 않는 것과 같은 원리예요. 피부가 마른 상태에서는 겉에 수분 크림이나 앰플을 아무리 발라도 다 뱉어내는 느낌만 들 뿐이거든요. 속건조를 진짜 잡으려면 먼저 피부 속 볼륨을 만들고, 그 볼륨에 수분을 채워주는 접근이 필요합니다. 기존에는 쥬베룩 같은 걸로 볼륨을 만들고, 그 위에 리쥬란으로 수분을 채워야 해서 시간도 돈도 통증도 2배였어요. 하지만 벨로테로 리바이브라는 스킨부스터는 히알루론산과 글리세롤의 조합으로 볼륨과 수분을 한 번에 해결합니다. 속에서부터 채워주는 방식이라 세안 후 아무것도 안 발라도 당기지 않는다는 피드백이 공통적으로 나옵니다.', '수분크림으로 해결 안 되는 속건조의 원인과 스킨부스터 해결법을 피부과 전문의 박효진이 안내합니다.', array['속건조', '벨로테로리바이브', '스킨부스터', '히알루론산', '글리세롤', '보습', '수분크림']::text[]),
    ('iohyYCMzbdk', 'parkhyojin', '벨로테로 리바이브랑 리쥬란은 뭐가 다른 거예요?', '벨로테로 리바이브와 리쥬란은 건조함을 잡는 기전 자체가 다릅니다. 리쥬란은 연어 DNA 기반의 재생 성분으로 피부 장벽 겉부분을 재생시켜 수분 증발을 막아주는 방식이에요. 반면 리바이브는 피부 더 깊은 속에 들어가서 히알루론산으로 수분을 끌어당기고 글리세롤이 그 수분을 가둬두는 원리입니다. 통증과 다운타임도 차이가 큰데, 리쥬란은 엄청난 통증과 엠보 현상으로 유명한 반면 리바이브는 캐뉼라(뭉뚱한 관)로 시술하면 멍이나 통증 없이 끝나는 경우가 많아요. 유지 기간도 다릅니다. 리쥬란은 4주 간격 3회를 받아야 하고 유지가 1-3주로 짧지만, 리바이브는 한 번 맞으면 6개월에서 길게는 9개월까지 유지될 수 있습니다. 통증과 내원 부담을 줄이면서 보습 효과를 오래 원하는 분께 추천드려요.', '벨로테로 리바이브와 리쥬란의 기전 및 유지기간 차이를 피부과 전문의 박효진이 설명합니다.', array['벨로테로리바이브', '리쥬란', '스킨부스터', '속건조', '히알루론산', '글리세롤', '엠보현상']::text[]),
    ('iohyYCMzbdk', 'parkhyojin', '여드름 피부인데 스킨부스터 맞아도 효과 있나요?', '네, 벨로테로 리바이브는 여드름이나 수부지(피지는 나는데 속은 건조한 피부) 분들에게도 효과가 좋습니다. 일반적으로 리쥬란은 피부가 얇고 자글자글한 분들에게 만족도가 높고, 피부가 두껍거나 여드름성 피부는 효과를 잘 못 느끼는 경우가 있어요. 하지만 리바이브는 속에서부터 수분을 끌어당겨 채워주기 때문에 피부 타입을 가리지 않고 보습력과 광 효과가 일정합니다. 특히 글리세롤 성분이 피지 분비를 조절하고 항염증 효과까지 있어서, 좁쌀 여드름이 많거나 홍조가 있는 분들에게도 도움이 됩니다. 피부과에서 치료 목적으로도 쓰일 수 있을 정도로 기대되는 스킨부스터예요. 누구에게나 권하기 좋은 점이 다른 스킨부스터 대비 큰 장점이라고 할 수 있습니다.', '여드름·수부지 피부에도 효과 좋은 벨로테로 리바이브의 글리세롤 효과를 피부과 전문의 박효진이 정리합니다.', array['벨로테로리바이브', '여드름', '수부지', '스킨부스터', '글리세롤', '피지조절', '항염증']::text[]),
    ('iohyYCMzbdk', 'parkhyojin', '벨로테로 리바이브 맞으면 진짜 광이 나나요?', '네, 시술 후 2-3일째부터 속에서 은은하게 광이 올라온다는 피드백이 거의 100% 돌아옵니다. 히알루론산이 피부 속에서 어느 정도의 볼륨을 만들면서 수분까지 잡아당겨 놓기 때문에 속에서부터 은은하게 광이 도는 원리입니다. 환자분들 스스로가 직접 느낄 정도로 주관적인 만족도가 굉장히 높아요. 그리고 극강의 보습력도 큰 특징인데, 시술 후 세안하고 10분간 아무것도 안 발라도 당기지 않는다는 반응이 가장 공통적입니다. 볼륨 개선, 수분, 피부톤까지 세 가지를 한꺼번에 잡고 싶으셨던 분들에게 딱 맞는 시술이에요. 다만 만능은 아니고, 보습과 광에 있어서 현재 나와 있는 스킨부스터 중 최상급 수준이라고 보시면 됩니다.', '벨로테로 리바이브 시술 후 광과 보습 효과가 나타나는 원리를 피부과 전문의 박효진이 안내합니다.', array['벨로테로리바이브', '피부광', '보습', '스킨부스터', '히알루론산', '볼륨', '피부톤']::text[]),
    ('8uKQgx5a1x8', 'leedoyoung', '리프팅 시술 종류가 너무 많은데 제일 중요한 기준이 뭐예요?', '리프팅에서 가장 중요한 포인트는 바로 치료 깊이입니다. 피부에는 여러 층이 있고, 각 층마다 공략해야 하는 목적이 다르거든요. 진피층을 공략하면 탄력을 줄 수 있고, 지방층을 공략하면 얼굴 라인이 개선되며, SMAS층을 공략하면 실제 리프팅 효과를 볼 수 있습니다. 예를 들어 울쎄라가 유명하지만, 치료 깊이를 제대로 디자인하지 않으면 효과가 안 나거나 오히려 볼패임 같은 부작용을 겪을 수도 있어요. 고주파(써마지, 세르프), 초음파(울쎄라, 슈링크), 레이저(티타늄) 등 기기마다 도달하는 깊이가 달라서, 본인의 얼굴 상태에 맞는 깊이를 선택하는 게 핵심입니다. 단순히 좋다는 시술을 받는 게 아니라, 내 피부 층에 맞는 시술을 받으셔야 합니다.', '리프팅 선택의 핵심은 치료 깊이입니다. 진피·지방·SMAS층별로 효과가 다른 고주파·초음파·레이저 기기의 특성을 피부과 전문의 이도영이 설명합니다.', array['리프팅', '울쎄라', '써마지', '치료깊이', 'SMAS', '진피층', '볼패임']::text[]),
    ('8uKQgx5a1x8', 'leedoyoung', '써마지 너무 아프다던데, 덜 아프면서 효과 좋은 고주파가 있나요?', '세르프라는 단극성 고주파 장비가 써마지보다 확실히 통증이 덜하면서 효과도 좋습니다. 써마지는 탕탕탕 일정하게 에너지가 나가는 반면, 세르프는 펄스를 잘게 쪼개서 우리 몸이 통증으로 인지하기 어렵게 만들어요. 깊이 조절도 shallow, middle, deep 세 단계로 가능해서 환자 맞춤형 치료가 됩니다. 깊이 조절을 잘 활용하면 울쎄라와 써마지의 효과를 동시에 낼 수 있어서 탄력 개선은 물론 라인 정리까지 가능합니다. 실제로 반쪽만 시술한 직후 사진을 보면 눈썹이 올라가고 볼륨이 줄면서 전체적으로 리프팅 된 느낌이 즉각적으로 드러나요. 다만 세게 치료할수록 효과가 더 좋지만 그만큼 아플 수 있으니, 본인의 통증 감수 수준에 맞춰 강도를 조절하시면 됩니다.', '세르프는 펄스를 잘게 쪼개 써마지보다 통증이 확실히 적습니다. 3단계 깊이 조절로 울쎄라+써마지 효과를 동시에 내는 원리를 피부과 전문의 이도영이 안내합니다.', array['세르프', '써마지', '고주파', '리프팅', '통증', '탄력', '라인정리']::text[]),
    ('8uKQgx5a1x8', 'leedoyoung', '울쎄라 효과 못 봤는데, 그럼 울쎄라가 안 맞는 건가요?', '울쎄라 자체가 안 맞는 게 아니라 에너지 레벨과 디자인을 어떻게 했느냐에 따라 결과가 크게 달라집니다. 최근 연구에 따르면 가장 낮은 에너지와 가장 높은 에너지로 시술한 결과에 큰 차이가 없거든요. 그래서 최근 트렌드는 에너지를 낮춰서 편안하게 하되 라인 수를 많이 늘리는 방향으로 바뀌고 있습니다. 더 중요한 건 디자인인데, 얼굴 근육은 서로 연결돼 있어서 한쪽을 당기면 다른 쪽 변화도 유발할 수 있어요. 살이 있는 부위는 지방층을 타겟하는 4.5 팁을, 살이 빠지면 안 되는 곳은 얕은 1.5 팁을 쓰는 식으로 적절히 배분하는 게 좋은 효과의 지름길입니다. 특히 1.5 팁을 많이 쓰면 고주파를 한 것 같은 쫀쫀함까지 얻을 수 있어요.', '울쎄라 효과가 없었다면 에너지보다 디자인 문제일 수 있습니다. 부위별 팁 배분과 라인 수를 늘리는 최신 트렌드를 피부과 전문의 이도영이 설명합니다.', array['울쎄라', '리프팅', '디자인', '에너지레벨', 'SMAS', '초음파', '1.5팁']::text[]),
    ('8uKQgx5a1x8', 'leedoyoung', '티타늄 리프팅은 제모 레이저라던데 진짜 리프팅 효과 있나요?', '네, 티타늄 리프팅은 원래 제모용 레이저지만 리프팅에도 확실한 효과가 있습니다. 제모는 멜라닌에 레이저가 흡수돼 모낭을 파괴하는 원리인데, 리프팅은 헤모글로빈과 물, 색소에 흡수되면서 주변 콜라겐과 엘라스틴을 재생시키는 기전으로 작동해요. 결국 둘 다 열로 조직을 변화시키는 같은 원리입니다. 티타늄은 1064, 810, 753 세 파장이 한꺼번에 나가서 얕은 층부터 깊은 층까지 동시에 타겟할 수 있어요. BTS 효과라고 해서 브라이트닝(화사), 타이트닝(쫀쫀), 슬리밍(슬림)을 한 번에 기대할 수 있습니다. 즉각적인 효과가 좋고 통증이 상대적으로 적어서, 결혼식 같은 중요한 이벤트 직전에 받으시는 분이 많아요.', '티타늄은 제모 레이저지만 3파장 동시 조사로 브라이트닝·타이트닝·슬리밍(BTS) 효과를 냅니다. 즉각적 효과와 적은 통증이 장점인 원리를 피부과 전문의 이도영이 정리합니다.', array['티타늄리프팅', '레이저리프팅', 'BTS효과', '콜라겐', '제모레이저', '브라이트닝', '타이트닝']::text[]),
    ('gCEJ-AX2DDo', 'kimjongsik', '울쎄라, 써마지 받았는데 효과를 못 느꼈어요. 왜 그런 거예요?', '내 얼굴 상태를 모른 채 좋다는 시술만 받는 게 가장 흔한 실수입니다. 울쎄라, 써마지, 티타늄은 모두 좋은 시술이지만, 본질적으로는 현재 피부 상태를 보존하고 유지시키는 역할이에요. 팔자주름이 생겼거나 볼이 꺼졌거나 처진 문제가 있는 상태에서 리프팅만 받으면, 문제 있는 피부 그대로를 유지하는 중인 셈이죠. 그러니 마음에 들 리가 없습니다. 먼저 내 얼굴형과 피부 상태, 노화 정도, 개선하고 싶은 부분을 정확히 파악하고 그에 맞는 시술로 충분히 개선한 후에 리프팅을 받아야 합니다. 리프팅은 좋은 상태를 오래 유지하는 유지 시술이지, 문제를 해결하는 시술이 아니라는 점을 꼭 기억하세요.', '울쎄라·써마지 효과를 못 느끼는 이유와 올바른 리프팅 순서를 피부과 전문의 김종식이 설명합니다.', array['울쎄라', '써마지', '리프팅', '피부관리', '얼굴형', '노화', '유지관리']::text[]),
    ('gCEJ-AX2DDo', 'kimjongsik', '리프팅 받기 전에 준비 운동처럼 먼저 해야 할 시술이 있나요?', '네, 리프팅 전에 본인의 얼굴 문제에 맞는 준비 시술을 먼저 해주면 효과가 훨씬 좋아집니다. 운동할 때 바로 무거운 걸 드는 게 아니라 준비 운동부터 하는 것과 같은 원리예요. 볼륨이 부족한 분은 스컬트라나 쥬베룩 볼륨으로 자연스럽게 채워주고, 얼굴 라인이 울퉁불퉁하거나 사이즈가 크신 분은 윤곽 보톡스나 레비나스 같은 시술로 윤곽을 다듬으세요. 전반적으로 피부 탄력이 떨어지고 노화가 진행된 분은 레디어스나 리투오 같은 스킨부스터가 좋습니다. 피부가 건조하고 푸석한 분은 힐로웨이브 같은 히알루론산 시술을, 민감하거나 트러블 있는 분은 리쥬란이나 비타란을 먼저 받으시면 됩니다. 이런 준비 작업 후에 울쎄라나 써마지를 받아야 진짜 리프팅 효과를 제대로 볼 수 있어요.', '리프팅 시술 전 얼굴 상태별 준비 시술 순서를 피부과 전문의 김종식이 안내합니다.', array['리프팅', '스컬트라', '쥬베룩', '스킨부스터', '힐로웨이브', '리쥬란', '레비나스']::text[]),
    ('gCEJ-AX2DDo', 'kimjongsik', '리프팅 받고 나서 효과를 오래 유지하려면 어떻게 해야 하나요?', '리프팅 후에는 티타늄이나 근육 시술, 보습 관리를 병행해야 효과가 2-3배 더 오래 유지됩니다. 운동 끝나고 스트레칭과 단백질 섭취를 하는 것처럼, 피부도 후 관리가 필수예요. 티타늄은 리프팅된 상태를 슬림하고 밝게, 쫀쫀하게 유지해주는 데 최적화돼 있습니다. 엠페이스나 이브시너지 같은 근육 시술은 평소에 쓰지 않는 얼굴 근육을 운동시켜서 리프팅된 표정과 자세를 편하게 유지하도록 도와줍니다. LDM 같은 보습 관리는 콜라겐이 머금고 있는 수분을 채우고 유지시켜주는 역할을 하고요. 이렇게 플랜을 짜서 준비 운동, 본 운동(리프팅), 마무리 운동을 순서대로 받으면 원하는 얼굴형과 리프팅을 효율적으로 달성할 수 있습니다.', '리프팅 효과를 오래 유지하기 위한 후 관리 방법을 피부과 전문의 김종식이 정리합니다.', array['리프팅', '티타늄리프팅', '엠페이스', 'LDM', '유지관리', '근육운동', '콜라겐']::text[]),
    ('gCEJ-AX2DDo', 'kimjongsik', '30대 중반인데 아직 리프팅은 이르지 않나요?', '30대 중반부터 얼굴이 예전 같지 않다고 느끼는 건 당연하고, 이때부터 플랜을 짜서 관리하면 5-10년 뒤 아주 좋은 피부를 유지할 수 있습니다. 나이가 들수록 꺼지고, 처지고, 주름지는 건 피할 수 없지만 관리 방법에 따라 속도가 크게 달라져요. 잘못된 관리를 하느니 차라리 안 하는 게 낫다고 할 만큼, 내 피부 상태에 맞지 않는 시술은 헛돈을 쓰는 셈입니다. 핵심은 커스터마이징이에요. 비대칭이 있는 분, 눈가만 주름이 많은 분, 전체적으로 탄력이 없는 분 모두 접근법이 달라야 합니다. 좋다니까 이거 받고, 유행이니까 저거 받는 식이 아니라, 내 피부는 이런 상태니까 이런 순서로 관리해야겠구나 하고 플랜을 세우는 게 가장 효율적인 방법입니다.', '30대부터 시작하는 효율적인 리프팅 관리 플랜의 중요성을 피부과 전문의 김종식이 설명합니다.', array['30대피부', '리프팅', '노화관리', '커스터마이징', '피부탄력', '주름', '얼굴형']::text[]),
    ('l6DxXIpL_Dg', 'kwonsuhyun', '칼에 베여서 상처가 벌어졌는데 병원 안 가고 봉합템 붙이면 되나요?', '상처가 벌어진 열상(찢어진 상처)은 봉합템만으로는 해결이 안 되는 경우가 많으니 병원에 가셔야 합니다. 예리한 칼로 깨끗하게 베여서 절단면이 딱 맞는다면 봉합템을 써도 무방하지만, 넘어져서 울퉁불퉁하게 찢어진 경우에는 봉합템으로 예쁘게 아물게 할 수 없어요. 절단면이 보이는 열상은 제대로 닫아줘야 상처가 회복되고, 예쁘게 닫혀야 흉터가 적게 남습니다. 특히 얼굴 상처라면 성형외과 전문의를 찾아가시는 게 좋아요. 성형외과는 얇은 실로 촘촘하게 절단면을 맞추고, 느슨함과 팽팽함을 고려해서 봉합하기 때문에 흉터가 훨씬 덜 남습니다. 만약 급해서 다른 병원에서 먼저 봉합했더라도, 24시간 내에 성형외과에서 재봉합하면 흉터 예후에 큰 차이가 없으니 참고하세요.', '상처가 벌어졌을 때 봉합템 사용 기준과 병원 방문 판단법을 피부과 전문의 권수현이 안내합니다.', array['봉합', '열상', '흉터', '성형외과', '상처관리', '봉합템', '재봉합']::text[]),
    ('l6DxXIpL_Dg', 'kwonsuhyun', '실밥 뽑고 나서 흉터 관리는 어떻게 해야 하나요?', '실밥 제거 후 흉터가 붉은 초기 6개월 동안 집중적으로 관리하는 게 가장 중요합니다. 흉터는 보통 1년에 걸쳐 변화하는데, 붉을 때 관리를 해야 효과가 크기 때문에 처음 6개월이 골든타임이에요. 흉터 연고로는 더마틱스 울트라, 켈로코트 같은 실리콘 기반 제품이 있고, 흉터 시트로는 메피폼이나 시카케어 같은 실리콘 시트가 있습니다. 관절처럼 움직임이 많은 부위는 떨어지기 쉬우니 연고를, 얼굴처럼 잘 안 움직이는 부위에는 시트를 붙이면 좋아요. 3-4주 간격으로 병원에서 흉터 레이저도 병행하면 호전도가 훨씬 높고요. 무엇보다 상처 부위에 자외선 차단제를 6개월간 꼼꼼히 발라야 거뭇거뭇한 색소침착을 막을 수 있습니다.', '실밥 제거 후 흉터 관리 골든타임과 연고·시트 선택법을 피부과 전문의 권수현이 설명합니다.', array['흉터관리', '흉터연고', '흉터시트', '더마틱스', '시카케어', '자외선차단', '흉터레이저']::text[]),
    ('l6DxXIpL_Dg', 'kwonsuhyun', '집에서 상처 소독할 때 듀오덤 바로 붙이면 되나요?', '감염 위험이 있는 초기 상처에 듀오덤을 바로 붙이면 오히려 감염이 심해질 수 있으니 주의하세요. 듀오덤은 접착력이 강하고 밀폐된 환경을 만들기 때문에, 세균이 번식하기 좋은 조건이 됩니다. 상처 초기에는 지혈 후 생리식염수로 세척하거나, 없으면 베타딘(빨간 약)을 바르고, 그것도 없으면 흐르는 물에 충분히 씻어주세요. 깨끗해진 상처에 후시딘이나 마데카솔 같은 연고를 듬뿍 바르는 게 핵심입니다. 가장 중요한 건 딱지가 안 생기게 보습을 유지하는 거예요. 딱지가 많이 생기고 떨어지면 그 자체가 흉터가 되거든요. 연고 바른 후에는 메디폼이나 거즈로 덮어주시고, 듀오덤은 감염이 없고 상처가 어느 정도 아문 뒤에 사용하시면 됩니다.', '상처 초기 소독 시 듀오덤 사용 주의점과 올바른 응급처치법을 피부과 전문의 권수현이 정리합니다.', array['듀오덤', '메디폼', '상처소독', '감염', '보습', '후시딘', '마데카솔']::text[]),
    ('l6DxXIpL_Dg', 'kwonsuhyun', '작은 찰과상은 병원 안 가도 되나요? 기준이 뭐예요?', '피부가 까진 찰과상의 경우, 범위가 손가락 두 마디보다 좁으면 집에서 소독해도 충분히 회복 가능합니다. 하지만 손가락 두 마디가 넘는 넓은 범위는 감염 위험이 있으니 병원에 오시는 게 좋아요. 그리고 상처가 벌어져서 절단면이 보이는 열상은 범위와 관계없이 반드시 봉합이 필요하므로 병원에 내원하셔야 합니다. 응급 상황에서는 먼저 깨끗한 수건이나 거즈로 강하게 눌러서 지혈을 하세요. 피가 멈추면 생리식염수나 흐르는 물로 세척하고, 연고를 듬뿍 발라서 딱지가 안 생기게 보습을 유지하는 게 핵심입니다. 연고 위에 메디폼을 덮어주면 진물도 흡수하면서 보습 환경이 잘 유지돼요. 상처가 작더라도 얼굴이면 흉터를 최소화하기 위해 성형외과 방문을 권합니다.', '찰과상과 열상의 병원 방문 기준과 집에서 하는 응급처치법을 피부과 전문의 권수현이 안내합니다.', array['찰과상', '상처관리', '응급처치', '지혈', '소독', '메디폼', '흉터예방']::text[])
)
insert into public.qas (video_id, doctor_id, question, answer, meta, keywords, published)
select v.id, d.id, nq.question, nq.answer, nq.meta, nq.keywords, true
from new_qas nq
join public.videos  v on v.youtube_id = nq.youtube_id
join public.doctors d on d.slug = nq.doctor_slug
where not exists (
  select 1 from public.qas q
  where q.video_id = v.id and q.question = nq.question
);
